    internal static class Program
    {
        [STAThread]
        private static void Main()
        {
            try
            {
                Console.OutputEncoding =
                    new UTF8Encoding(false);
                Console.InputEncoding =
                    new UTF8Encoding(false);
            }
            catch
            {
            }

            Application.SetUnhandledExceptionMode(
                UnhandledExceptionMode.CatchException
            );
            Application.ThreadException += delegate(object sender, ThreadExceptionEventArgs e)
            {
                ErrorLogger.Write("Napaka grafičnega vmesnika", e.Exception);
                MessageBox.Show(
                    "Prišlo je do napake v programu, vendar se program ne bo namerno zaprl.\r\n\r\n" +
                    e.Exception.Message,
                    "Video Downloader",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Error
                );
            };

            AppDomain.CurrentDomain.UnhandledException += delegate(object sender, UnhandledExceptionEventArgs e)
            {
                Exception exception = e.ExceptionObject as Exception;
                ErrorLogger.Write(
                    "Neobravnavana napaka",
                    exception ?? new Exception(Convert.ToString(e.ExceptionObject))
                );
            };

            Application.EnableVisualStyles();
            Application.SetCompatibleTextRenderingDefault(false);
            Application.Run(new MainForm());
        }
    }

    internal static class AppPaths
    {
        public static readonly string AppDataFolder = Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
            "BorutVideoDownloaderCSharp"
        );

        public static readonly string LocalDataFolder = Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
            "BorutVideoDownloaderCSharp"
        );

        public static readonly string SettingsFile = Path.Combine(
            AppDataFolder,
            "settings.xml"
        );

        public static readonly string ErrorLog = Path.Combine(
            AppDataFolder,
            "errors.log"
        );

        public static readonly string ExtractorList = Path.Combine(
            AppDataFolder,
            "supported_extractors.txt"
        );

        public static readonly string WorkFolder = Path.Combine(
            LocalDataFolder,
            "Work"
        );

        public static readonly string PluginFolder = Path.Combine(
            Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
            "yt-dlp",
            "plugins",
            "VideoDownloader"
        );

        public static void Ensure()
        {
            Directory.CreateDirectory(AppDataFolder);
            Directory.CreateDirectory(LocalDataFolder);
            Directory.CreateDirectory(WorkFolder);
            Directory.CreateDirectory(PluginFolder);

            try
            {
                File.SetAttributes(
                    WorkFolder,
                    File.GetAttributes(WorkFolder) | FileAttributes.Hidden
                );
            }
            catch
            {
            }
        }
    }

    internal static class ErrorLogger
    {
        public static void Write(string context, Exception exception)
        {
            try
            {
                AppPaths.Ensure();
                string text =
                    "[" + DateTime.Now.ToString("dd.MM.yyyy HH:mm:ss") + "] " +
                    context + Environment.NewLine +
                    exception + Environment.NewLine +
                    new string('-', 80) + Environment.NewLine;
                File.AppendAllText(AppPaths.ErrorLog, text, Encoding.UTF8);
            }
            catch
            {
            }
        }

        public static void WriteText(string context, string text)
        {
            Write(context, new Exception(text));
        }
    }

    internal static class SettingsStore
    {
        public static AppSettings Load()
        {
            AppPaths.Ensure();

            if (!File.Exists(AppPaths.SettingsFile))
            {
                return new AppSettings();
            }

            try
            {
                XmlSerializer serializer = new XmlSerializer(typeof(AppSettings));
                using (FileStream stream = File.OpenRead(AppPaths.SettingsFile))
                {
                    AppSettings settings = serializer.Deserialize(stream) as AppSettings;
                    return settings ?? new AppSettings();
                }
            }
            catch (Exception e)
            {
                ErrorLogger.Write("Branje nastavitev", e);
                return new AppSettings();
            }
        }

        public static void Save(AppSettings settings)
        {
            AppPaths.Ensure();

            try
            {
                XmlSerializer serializer = new XmlSerializer(typeof(AppSettings));
                using (FileStream stream = File.Create(AppPaths.SettingsFile))
                {
                    serializer.Serialize(stream, settings);
                }
            }
            catch (Exception e)
            {
                ErrorLogger.Write("Shranjevanje nastavitev", e);
            }
        }
    }

    internal static class ToolLocator
    {
        public static string FindYtDlp()
        {
            return FindExecutable("yt-dlp.exe", "yt-dlp");
        }

        public static string FindFfmpeg()
        {
            return FindExecutable("ffmpeg.exe", "ffmpeg");
        }

        public static string FindFfprobe()
        {
            return FindExecutable("ffprobe.exe", "ffprobe");
        }

        public static string FindFfplay()
        {
            return FindExecutable("ffplay.exe", "ffplay");
        }

        public static string FindWinget()
        {
            return FindExecutable("winget.exe", "winget");
        }

        public static void ConfigureUtf8Process(
            ProcessStartInfo info
        )
        {
            if (info == null)
            {
                return;
            }

            try
            {
                info.EnvironmentVariables[
                    "PYTHONUTF8"
                ] = "1";
                info.EnvironmentVariables[
                    "PYTHONIOENCODING"
                ] = "utf-8";
                info.EnvironmentVariables[
                    "PYTHONLEGACYWINDOWSSTDIO"
                ] = "0";
                info.EnvironmentVariables[
                    "LANG"
                ] = "C.UTF-8";
                info.EnvironmentVariables[
                    "LC_ALL"
                ] = "C.UTF-8";
            }
            catch
            {
            }
        }

        private static string FindExecutable(string windowsName, string commandName)
        {
            string baseFolder = AppDomain.CurrentDomain.BaseDirectory;
            string local = Path.Combine(baseFolder, windowsName);
            if (File.Exists(local))
            {
                return local;
            }

            string wingetLink = Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData),
                "Microsoft",
                "WinGet",
                "Links",
                windowsName
            );
            if (File.Exists(wingetLink))
            {
                return wingetLink;
            }

            string path = Environment.GetEnvironmentVariable("PATH") ?? "";
            string[] folders = path.Split(new char[] { Path.PathSeparator }, StringSplitOptions.RemoveEmptyEntries);
            foreach (string folderRaw in folders)
            {
                string folder = folderRaw.Trim().Trim('"');
                try
                {
                    string candidate = Path.Combine(folder, windowsName);
                    if (File.Exists(candidate))
                    {
                        return candidate;
                    }
                }
                catch
                {
                }
            }

            try
            {
                ProcessStartInfo info = new ProcessStartInfo();
                info.FileName = "where.exe";
                info.Arguments = Quote(commandName);
                info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
                info.CreateNoWindow = true;
                info.RedirectStandardOutput = true;
                info.RedirectStandardError = true;

                using (Process process = Process.Start(info))
                {
                    string output = process.StandardOutput.ReadToEnd();
                    process.WaitForExit(3000);
                    string first = output
                        .Split(new string[] { "\r\n", "\n" }, StringSplitOptions.RemoveEmptyEntries)
                        .FirstOrDefault();
                    if (!string.IsNullOrWhiteSpace(first) && File.Exists(first.Trim()))
                    {
                        return first.Trim();
                    }
                }
            }
            catch
            {
            }

            return "";
        }

        public static string Quote(string value)
        {
            if (value == null)
            {
                return "\"\"";
            }

            if (value.Length == 0)
            {
                return "\"\"";
            }

            if (value.IndexOfAny(new char[] { ' ', '\t', '"' }) < 0)
            {
                return value;
            }

            StringBuilder builder = new StringBuilder();
            builder.Append('"');
            int backslashes = 0;

            foreach (char character in value)
            {
                if (character == '\\')
                {
                    backslashes++;
                    continue;
                }

                if (character == '"')
                {
                    builder.Append('\\', backslashes * 2 + 1);
                    builder.Append('"');
                    backslashes = 0;
                    continue;
                }

                if (backslashes > 0)
                {
                    builder.Append('\\', backslashes);
                    backslashes = 0;
                }

                builder.Append(character);
            }

            if (backslashes > 0)
            {
                builder.Append('\\', backslashes * 2);
            }

            builder.Append('"');
            return builder.ToString();
        }

        public static string JoinArguments(IEnumerable<string> arguments)
        {
            return string.Join(" ", arguments.Select(Quote).ToArray());
        }
    }

