    public sealed class EffectLayerItem
    {
        public string Kind { get; set; }
        public string Mode { get; set; }
        public decimal X { get; set; }
        public decimal Y { get; set; }
        public decimal Width { get; set; }
        public decimal Height { get; set; }
        public int Strength { get; set; }
        public double StartSeconds { get; set; }
        public double EndSeconds { get; set; }
        public string FilePath { get; set; }
        public string Text { get; set; }
        public int Opacity { get; set; }

        public EffectLayerItem()
        {
            Kind = "region";
            Mode = "Močan mozaik";
            X = 5M;
            Y = 5M;
            Width = 20M;
            Height = 15M;
            Strength = 28;
            StartSeconds = 0.0;
            EndSeconds = 0.0;
            FilePath = "";
            Text = "";
            Opacity = 100;
        }

        public override string ToString()
        {
            string time = EndSeconds > StartSeconds
                ? "  " + StartSeconds.ToString("0.##") + "–" + EndSeconds.ToString("0.##") + " s"
                : "  ves video";
            string detail = Kind == "image"
                ? Path.GetFileName(FilePath)
                : (Kind == "text" ? Text : Mode + " / moč " + Strength);
            return detail + "  [X " + X + " %, Y " + Y + " %, " + Width + " × " + Height + " %]" + time;
        }
    }

