        private sealed class SupportedSiteEntry
        {
            public string Name;
            public string Url;
            public string Domain;
            public string Extractor;
            public string Support;
            public string Description;
            public string SearchText;
            public bool SearchFallback;

            public SupportedSiteEntry(
                string name,
                string url,
                string extractor,
                string support,
                string description,
                bool searchFallback
            )
            {
                Name =
                    string.IsNullOrWhiteSpace(name)
                        ? extractor
                        : name;
                Url = url ?? "";
                Extractor = extractor ?? "";
                Support = support ?? "";
                Description = description ?? "";
                SearchFallback = searchFallback;

                try
                {
                    Uri uri =
                        new Uri(Url);
                    Domain =
                        uri.Host;
                }
                catch
                {
                    Domain =
                        Url;
                }

                SearchText =
                    (
                        Name + " " +
                        Domain + " " +
                        Url + " " +
                        Extractor + " " +
                        Support + " " +
                        Description
                    ).ToLowerInvariant();
            }
        }

        private sealed class SupportedSiteMetadata
        {
            public string Key;
            public string Description;
            public bool Broken;

            public SupportedSiteMetadata(
                string key,
                string description,
                bool broken
            )
            {
                Key = key ?? "";
                Description = description ?? "";
                Broken = broken;
            }
        }

        private sealed class ConverterFormatOption
        {
            public string Id;
            public string Extension;
            public string Name;
            public string Category;
            public string Usage;
            public string Note;
            public string OutputKind;
            public string RequiredEncoders;
            public string RequiredMuxers;
            public bool Selectable;

            public ConverterFormatOption(
                string id,
                string extension,
                string name,
                string category,
                string usage,
                string note,
                string outputKind,
                string requiredEncoders,
                string requiredMuxers,
                bool selectable
            )
            {
                Id = id;
                Extension = extension;
                Name = name;
                Category = category;
                Usage = usage;
                Note = note;
                OutputKind = outputKind;
                RequiredEncoders = requiredEncoders;
                RequiredMuxers = requiredMuxers;
                Selectable = selectable;
            }

            public override string ToString()
            {
                return Extension + "   " + Name;
            }
        }

