        private static readonly ConverterFormatOption[] ConverterOutputFormats =
            ConverterFormats
            .Where(
                delegate(ConverterFormatOption option)
                {
                    return option.Selectable;
                }
            )
            .OrderBy(
                delegate(ConverterFormatOption option)
                {
                    int position =
                        Array.IndexOf(
                            ConverterPreferredOrder,
                            option.Id
                        );

                    return position < 0
                        ? int.MaxValue
                        : position;
                }
            )
            .ThenBy(
                delegate(ConverterFormatOption option)
                {
                    return option.Extension;
                },
                StringComparer.OrdinalIgnoreCase
            )
            .ToArray();

        public MainForm()
        {
            AppPaths.Ensure();
            settings = SettingsStore.Load();

            Text = "Video Downloader 10.0.5";
            StartPosition = FormStartPosition.CenterScreen;
            MinimumSize = new Size(1320, 780);
            Size = new Size(1640, 940);
            Font = new Font("Segoe UI", 9.5F);
            BackColor = Color.FromArgb(245, 247, 250);
            Icon = SystemIcons.Application;

            BuildInterface();
            ApplySettings();
            RefreshToolStatus();

            FormClosing += OnFormClosing;
            Shown += delegate
            {
                Log(
                    "Program je pripravljen. Različica 10.0.5 prenovi postavitev vseh zavihkov, časovnico, podnapise, brskalniške piškotke ter večplastne učinke in prekrivanja.",
                    "SISTEM"
                );
                Log(
                    "Za javne videe piškotke iz Firefoxa pusti izključene. Vključi jih samo za strani, kjer si prijavljen.",
                    "SISTEM"
                );
                Log(
                    "Orodja, hitrost, posodobitve in vtičniki so v zgornjem zavihku »Orodja in nastavitve«.",
                    "SISTEM"
                );
            };
        }

        private void BuildInterface()
        {
            SuspendLayout();

            TableLayoutPanel root =
                new TableLayoutPanel();
            mainRootLayout =
                root;
            root.Dock =
                DockStyle.Fill;
            root.ColumnCount = 1;
            root.RowCount = 2;
            root.Margin =
                new Padding(0);
            root.Padding =
                new Padding(0);
            root.ColumnStyles.Add(
                new ColumnStyle(
                    SizeType.Percent,
                    100F
                )
            );
            root.RowStyles.Add(
                new RowStyle(
                    SizeType.Absolute,
                    590F
                )
            );
            root.RowStyles.Add(
                new RowStyle(
                    SizeType.Percent,
                    100F
                )
            );
            Controls.Add(root);

            mainTabs =
                new TabControl();
            mainTabs.Dock =
                DockStyle.Fill;
            mainTabs.Font =
                new Font(
                    "Segoe UI Semibold",
                    10F
                );
            mainTabs.Padding =
                new Point(18, 6);
            mainTabs.Margin =
                new Padding(6, 5, 6, 0);
            root.Controls.Add(
                mainTabs,
                0,
                0
            );

            TabPage downloadTab =
                new TabPage(
                    "Video Downloader"
                );
            downloadTab.BackColor =
                Color.White;
            downloadTab.Padding =
                new Padding(0);
            downloadTab.AutoScroll = true;
            mainTabs.TabPages.Add(
                downloadTab
            );

            Panel settingsPanel =
                BuildSettingsPanel();
            downloadTab.Controls.Add(
                settingsPanel
            );

            TabPage subtitleTab =
                new TabPage(
                    "Podnapisi"
                );
            subtitleTab.BackColor =
                Color.White;
            subtitleTab.Padding =
                new Padding(4);
            subtitleTab.AutoScroll = true;
            mainTabs.TabPages.Add(
                subtitleTab
            );
            subtitleTab.Controls.Add(
                BuildSubtitleStudioPanel()
            );

            TabPage converterTab =
                new TabPage(
                    "Pretvornik"
                );
            converterTab.BackColor =
                Color.White;
            converterTab.Padding =
                new Padding(4);
            converterTab.AutoScroll = true;
            mainTabs.TabPages.Add(
                converterTab
            );
            converterTab.Controls.Add(
                BuildConverterPanel()
            );

            TabPage editorTab =
                new TabPage(
                    "Urejevalnik"
                );
            editorTab.BackColor =
                Color.White;
            editorTab.Padding =
                new Padding(4);
            editorTab.AutoScroll = true;
            mainTabs.TabPages.Add(
                editorTab
            );
            editorTab.Controls.Add(
                BuildEditorPanel()
            );

            TabPage effectsTab =
                new TabPage(
                    "Učinki in prekrivanje"
                );
            effectsTab.BackColor =
                Color.White;
            effectsTab.Padding =
                new Padding(4);
            effectsTab.AutoScroll = true;
            mainTabs.TabPages.Add(
                effectsTab
            );
            effectsTab.Controls.Add(
                BuildEffectsPanel()
            );

            lowerLayout =
                new TableLayoutPanel();
            lowerLayout.Dock =
                DockStyle.Fill;
            lowerLayout.ColumnCount = 1;
            lowerLayout.RowCount = 2;
            lowerLayout.Margin =
                new Padding(0);
            lowerLayout.Padding =
                new Padding(0);
            lowerLayout.ColumnStyles.Add(
                new ColumnStyle(
                    SizeType.Percent,
                    100F
                )
            );
            lowerLayout.RowStyles.Add(
                new RowStyle(
                    SizeType.Percent,
                    55F
                )
            );
            lowerLayout.RowStyles.Add(
                new RowStyle(
                    SizeType.Percent,
                    45F
                )
            );
            root.Controls.Add(
                lowerLayout,
                0,
                1
            );

            sharedQueuePanel =
                BuildQueuePanel();
            sharedQueuePanel.Margin =
                new Padding(0, 3, 0, 2);
            lowerLayout.Controls.Add(
                sharedQueuePanel,
                0,
                0
            );

            sharedLogPanel =
                BuildLogPanel();
            sharedLogPanel.Margin =
                new Padding(0, 2, 0, 0);
            lowerLayout.Controls.Add(
                sharedLogPanel,
                0,
                1
            );

            subtitleQuickHelpPanel =
                BuildSubtitleQuickHelpPanel();
            subtitleQuickHelpPanel.Visible = false;
            lowerLayout.Controls.Add(
                subtitleQuickHelpPanel,
                0,
                0
            );
            lowerLayout.SetRowSpan(
                subtitleQuickHelpPanel,
                2
            );

            editorQuickHelpPanel =
                BuildEditorQuickHelpPanel();
            editorQuickHelpPanel.Visible = false;
            lowerLayout.Controls.Add(
                editorQuickHelpPanel,
                0,
                0
            );

            mainTabs.SelectedIndexChanged += delegate
            {
                if (mainTabs.SelectedIndex != 3)
                {
                    StopEditorPreview(
                        false
                    );
                }

                UpdateLowerAreaForSelectedTab();
            };

            toolsContentPanel =
                BuildToolsContentPanel();

            UpdateLowerAreaForSelectedTab();

            ResumeLayout(true);
        }

