        private void DrawSubtitleOpacityPreview(
            object sender,
            PaintEventArgs e
        )
        {
            Panel panel = sender as Panel;
            if (panel == null)
            {
                return;
            }

            Rectangle bounds = panel.ClientRectangle;
            e.Graphics.Clear(Color.FromArgb(205, 216, 224));
            using (Brush sky = new SolidBrush(Color.FromArgb(188, 218, 235)))
            using (Brush ground = new SolidBrush(Color.FromArgb(87, 132, 93)))
            {
                e.Graphics.FillRectangle(sky, bounds.Left, bounds.Top, bounds.Width, bounds.Height / 2);
                e.Graphics.FillRectangle(ground, bounds.Left, bounds.Top + bounds.Height / 2, bounds.Width, bounds.Height / 2);
            }

            bool enabled = chkStyledEmbeddedSubtitles != null && chkStyledEmbeddedSubtitles.Checked;
            int opacity = numSubtitleBackgroundOpacity == null
                ? 0
                : Convert.ToInt32(numSubtitleBackgroundOpacity.Value);

            Rectangle textBox = new Rectangle(4, Math.Max(2, bounds.Height / 2 - 8), Math.Max(4, bounds.Width - 8), 17);
            if (enabled && opacity > 0)
            {
                using (Brush dark = new SolidBrush(Color.FromArgb(
                    Convert.ToInt32(255.0 * opacity / 100.0), 0, 0, 0)))
                {
                    e.Graphics.FillRectangle(dark, textBox);
                }
            }
            using (Brush white = new SolidBrush(Color.White))
            using (Font font = new Font("Segoe UI", 7.5F, FontStyle.Bold))
            {
                StringFormat format = new StringFormat();
                format.Alignment = StringAlignment.Center;
                format.LineAlignment = StringAlignment.Center;
                e.Graphics.DrawString("Podnapis", font, white, textBox, format);
            }
        }

        private Panel BuildToolsContentPanel()
        {
            Panel panel =
                new Panel();
            panel.Dock =
                DockStyle.Fill;
            panel.BackColor =
                Color.White;
            panel.Padding =
                new Padding(16);

