        private void ShowDownloaderInformation()
        {
            ShowSubtitleInformation(
                "Video Downloader – podrobna navodila",
                "1. POVEZAVE IN VIR\r\n\r\n" +
                "V veliko polje prilepi eno ali več povezav. Vsaka povezava naj bo v svoji vrstici.\r\n\r\n" +
                "Primeri:\r\n" +
                "• https://www.youtube.com/watch?v=...\r\n" +
                "• https://365.rtvslo.si/arhiv/...\r\n" +
                "• neposredna povezava .m3u8, .mpd ali .mp4\r\n\r\n" +
                "»Prilepi« prebere odložišče. »Dodaj v vrsto« pripravi opravilo, »Dodaj in začni« pa ga tudi takoj zažene.\r\n\r\n" +
                "»Neposredni medijski URL« označi samo takrat, ko imaš dejanski naslov medijskega toka, ne običajne strani predvajalnika. Referer uporabi le, kadar ga strežnik zahteva.\r\n\r\n" +
                "Lokalno video ali zvočno datoteko lahko tudi povlečeš v ta del programa.\r\n\r\n" +
                "2. VIDEO, IZHOD IN MAPA\r\n\r\n" +
                "Kakovost določa največjo ločljivost. »Originalna« prenese najboljšo razpoložljivo različico brez umetne omejitve.\r\n\r\n" +
                "Končni format določa, ali program datoteko samo shrani ali jo po prenosu ponovno kodira.\r\n" +
                "• Original: najhitreje in brez izgube zaradi ponovnega kodiranja.\r\n" +
                "• MP4 H.264 + AAC: najbolj univerzalno za televizor, telefon in splet.\r\n" +
                "• H.265/HEVC: manjša datoteka, vendar slabša podpora na starejših napravah.\r\n" +
                "• MP3/FLAC/WAV: samo zvok.\r\n\r\n" +
                "Mapa je cilj končne datoteke. Pri OneDrive program poskuša datoteko označiti kot lokalno dostopno.\r\n\r\n" +
                "Piškotke lahko program prebere iz Firefoxa, Microsoft Edgea ali Google Chroma. Izberi isti brskalnik, v katerem si prijavljen oziroma si odprl samodejni prevod. Pred začetkom prenosa brskalnik popolnoma zapri, da lahko yt-dlp prebere sveže piškotke. Program ne obide prijave, naročnine, regijskih omejitev ali DRM.\r\n\r\n" +
                "3. PODNAPISI\r\n\r\n" +
                "Izbereš lahko brez podnapisov, ločen SRT, izbirne podnapise v MKV ali trajno zapečene podnapise v MP4.\r\n\r\n" +
                "Jezikovni izbor določa, katere podnapise program prenese. YouTube samodejni prevod zahteva, da je za video na voljo izvorna samodejna transkripcija.\r\n\r\n" +
                "YOUTUBE SAMODEJNI PREVOD – FIREFOX, EDGE ALI CHROME\r\n\r\n" +
                "Postopek ni omejen samo na Firefox. Deluje tudi z Microsoft Edgeom in Google Chromom, kadar program lahko prebere piškotke iz izbranega profila.\r\n\r\n" +
                "1. V izbranem brskalniku odpri isti YouTube video.\r\n" +
                "2. Izberi Podnapisi → Samodejni prevod → Slovenščina.\r\n" +
                "3. Video s slovenskimi podnapisi predvajaj nekaj sekund.\r\n" +
                "4. Brskalnik popolnoma zapri, tudi v ozadju.\r\n" +
                "5. V programu označi uporabo piškotkov in izberi isti brskalnik: Firefox, Microsoft Edge ali Google Chrome.\r\n" +
                "6. Nato začni prenos.\r\n\r\n" +
                "Če YouTube vrne HTTP 429, počakaj nekaj minut, ponovno odpri prevod v istem brskalniku, ga zapri in ponovi. Sveža seja lahko zmanjša težavo, vendar uspeh ni vedno zagotovljen.\r\n\r\n" +
                "4. ČAKALNA VRSTA IN STANJE\r\n\r\n" +
                "• Stanje: čakanje, prenašanje, pretvorba, končano ali napaka.\r\n" +
                "• Napredek: odstotek opravljenega dela.\r\n" +
                "• Hitrost: trenutna hitrost prenosa ali obdelave.\r\n" +
                "• ETA: ocenjeni čas do konca.\r\n" +
                "• Vir: spletna stran ali lokalna datoteka.\r\n" +
                "• Kakovost in format: nastavitvi, ki sta veljali ob dodajanju opravila.\r\n\r\n" +
                "Z dvoklikom končane vrstice odpreš datoteko v Raziskovalcu. Spodnji zapis uporablja barve: rdeče za napake, modro za opozorila in temno besedilo za uspešne ali običajne operacije."
            );
        }

        private void ShowToolsPopup()
        {
            if (
                toolsPopup != null &&
                !toolsPopup.IsDisposed
            )
            {
                toolsPopup.Show();
                toolsPopup.Activate();
                return;
            }

            Form popup =
                new Form();
            toolsPopup = popup;
            popup.Text =
                "Orodja in nastavitve – Video Downloader 10.0.5";
            popup.StartPosition =
                FormStartPosition.Manual;
            popup.Size =
                new Size(920, 470);
            popup.MinimumSize =
                new Size(820, 420);
            popup.MaximizeBox = false;
            popup.MinimizeBox = false;
            popup.ShowInTaskbar = false;
            popup.FormBorderStyle =
                FormBorderStyle.SizableToolWindow;
            popup.BackColor =
                Color.White;
            popup.KeyPreview = true;

            Rectangle workArea =
                Screen.FromControl(this).WorkingArea;
            int popupX =
                Left + (Width - popup.Width) / 2;
            int popupY =
                Top + 70;

            popup.Location =
                new Point(
                    Math.Max(
                        workArea.Left,
                        Math.Min(
                            popupX,
                            workArea.Right - popup.Width
                        )
                    ),
                    Math.Max(
                        workArea.Top,
                        Math.Min(
                            popupY,
                            workArea.Bottom - popup.Height
                        )
                    )
                );

            Panel footer =
                new Panel();
            footer.Dock =
                DockStyle.Bottom;
            footer.Height = 52;
            footer.Padding =
                new Padding(10, 8, 12, 8);
            footer.BackColor =
                Color.FromArgb(
                    245,
                    247,
                    250
                );
            popup.Controls.Add(
                footer
            );

            Label closeHint =
                new Label();
            closeHint.Text =
                "Zapri z X, tipko Esc ali klikom zunaj okna.";
            closeHint.ForeColor =
                Color.DimGray;
            closeHint.AutoSize = true;
            closeHint.Location =
                new Point(12, 16);
            footer.Controls.Add(
                closeHint
            );

            Button closeButton =
                NewButton(
                    "Zapri",
                    100
                );
            closeButton.Dock =
                DockStyle.Right;
            closeButton.Click += delegate
            {
                popup.Close();
            };
            footer.Controls.Add(
                closeButton
            );

            if (toolsContentPanel.Parent != null)
            {
                toolsContentPanel.Parent.Controls.Remove(
                    toolsContentPanel
                );
            }

            toolsContentPanel.Dock =
                DockStyle.Fill;
            popup.Controls.Add(
                toolsContentPanel
            );
            toolsContentPanel.BringToFront();

            popup.KeyDown += delegate(
                object sender,
                KeyEventArgs e
            )
            {
                if (e.KeyCode == Keys.Escape)
                {
                    popup.Close();
                }
            };

            popup.FormClosing += delegate
            {
                SaveCurrentSettings();

                if (
                    toolsContentPanel != null &&
                    toolsContentPanel.Parent != null
                )
                {
                    toolsContentPanel.Parent.Controls.Remove(
                        toolsContentPanel
                    );
                }

                toolsPopup = null;
            };

            popup.Deactivate += delegate
            {
                if (
                    popup.Visible &&
                    !popup.ContainsFocus
                )
                {
                    popup.BeginInvoke(
                        new Action(
                            delegate
                            {
                                if (
                                    !popup.IsDisposed &&
                                    popup.Visible &&
                                    !popup.ContainsFocus
                                )
                                {
                                    popup.Close();
                                }
                            }
                        )
                    );
                }
            };

            RefreshToolStatus();
            popup.Show(this);
            popup.Activate();
        }

