        private Control CreateInfoHeader(
            string title,
            Action showInfo
        )
        {
            TableLayoutPanel header = new TableLayoutPanel();
            header.Dock = DockStyle.Fill;
            header.ColumnCount = 2;
            header.RowCount = 1;
            header.Margin = new Padding(0);
            header.ColumnStyles.Add(
                new ColumnStyle(SizeType.Percent, 100F)
            );
            header.ColumnStyles.Add(
                new ColumnStyle(SizeType.Absolute, 72F)
            );

            Label label = new Label();
            label.Text = title;
            label.Dock = DockStyle.Fill;
            label.Font = new Font("Segoe UI Semibold", 10F);
            label.TextAlign = ContentAlignment.MiddleLeft;
            header.Controls.Add(label, 0, 0);

            Button info = NewButton("Info", 66);
            info.Dock = DockStyle.Fill;
            info.Margin = new Padding(4, 1, 0, 1);
            info.Click += delegate
            {
                showInfo();
            };
            header.Controls.Add(info, 1, 0);

            return header;
        }

        private void ShowSubtitleInformation(
            string title,
            string content
        )
        {
            Form popup = new Form();
            popup.Text = title;
            popup.StartPosition = FormStartPosition.CenterParent;
            popup.Size = new Size(850, 700);
            popup.MinimumSize = new Size(680, 560);
            popup.ShowInTaskbar = false;
            popup.MaximizeBox = false;
            popup.MinimizeBox = false;
            popup.BackColor = Color.White;

            RichTextBox text = new RichTextBox();
            text.Dock = DockStyle.Fill;
            text.ReadOnly = true;
            text.BorderStyle = BorderStyle.None;
            text.BackColor = Color.White;
            text.ForeColor = Color.FromArgb(35, 42, 52);
            text.Font = new Font("Segoe UI", 11.5F);
            text.ScrollBars =
                RichTextBoxScrollBars.Vertical;
            text.WordWrap = true;
            text.Text = content;
            popup.Controls.Add(text);

            Panel footer = new Panel();
            footer.Dock = DockStyle.Bottom;
            footer.Height = 52;
            footer.Padding = new Padding(10, 8, 12, 8);
            footer.BackColor = Color.FromArgb(242, 246, 251);
            popup.Controls.Add(footer);

            Button close = NewButton("Zapri", 100);
            close.Dock = DockStyle.Right;
            close.Click += delegate
            {
                popup.Close();
            };
            footer.Controls.Add(close);

            popup.ShowDialog(this);
        }

        private Control CreateSubtitleAdjustmentRow(
            string labelText,
            string leftText,
            Action leftAction,
            NumericUpDown valueControl,
            string rightText,
            Action rightAction
        )
        {
            TableLayoutPanel row =
                new TableLayoutPanel();
            row.Dock =
                DockStyle.Fill;
            row.ColumnCount = 4;
            row.RowCount = 1;
            row.Margin =
                new Padding(0);
            row.ColumnStyles.Add(
                new ColumnStyle(SizeType.Absolute, 84F)
            );
            row.ColumnStyles.Add(
                new ColumnStyle(SizeType.Absolute, 48F)
            );
            row.ColumnStyles.Add(
                new ColumnStyle(SizeType.Percent, 100F)
            );
            row.ColumnStyles.Add(
                new ColumnStyle(SizeType.Absolute, 48F)
            );

            row.Controls.Add(
                CreateSectionLabel(labelText),
                0,
                0
            );

            Button left =
                NewButton(leftText, 42);
            left.Dock =
                DockStyle.Fill;
            left.Margin =
                new Padding(0, 3, 4, 3);
            left.Click += delegate
            {
                leftAction();
            };
            row.Controls.Add(left, 1, 0);

            valueControl.Dock =
                DockStyle.Fill;
            valueControl.Margin =
                new Padding(0, 4, 4, 4);
            row.Controls.Add(
                valueControl,
                2,
                0
            );

            Button right =
                NewButton(rightText, 42);
            right.Dock =
                DockStyle.Fill;
            right.Margin =
                new Padding(0, 3, 0, 3);
            right.Click += delegate
            {
                rightAction();
            };
            row.Controls.Add(right, 3, 0);

            return row;
        }

        private void ChangeNumericValue(
            NumericUpDown control,
            decimal change
        )
        {
            decimal next =
                control.Value + change;
            next = Math.Max(
                control.Minimum,
                Math.Min(
                    control.Maximum,
                    next
                )
            );
            control.Value = next;
        }

        private void UpdateSubtitleStudioControls()
        {
            bool burn =
                cmbSubtitleStudioMode != null &&
                cmbSubtitleStudioMode.SelectedIndex == 1;

            if (numSubtitleStudioOpacity != null)
            {
                numSubtitleStudioOpacity.Enabled = burn;
            }
            if (numSubtitleStudioFontSize != null)
            {
                numSubtitleStudioFontSize.Enabled = burn;
            }
            if (numSubtitleStudioMarginV != null)
            {
                numSubtitleStudioMarginV.Enabled = burn;
            }
            if (btnSubtitleStudioColor != null)
            {
                // Barvo lahko uporabnik vedno izbere in preveri v predogledu.
                // Pri izbirnih MKV podnapisih končni videz določa predvajalnik,
                // pri zapečenem MP4 pa se izbrana barva dejansko uporabi.
                btnSubtitleStudioColor.Enabled = true;
