        private void UpdateSubtitleColourButton()
        {
            if (btnSubtitleStudioColor == null)
            {
                return;
            }

            btnSubtitleStudioColor.UseVisualStyleBackColor = false;
            btnSubtitleStudioColor.BackColor =
                subtitleStudioTextColor;
            btnSubtitleStudioColor.ForeColor =
                subtitleStudioTextColor.GetBrightness() > 0.58F
                    ? Color.Black
                    : Color.White;
            string colourCode =
                ColorTranslator.ToHtml(
                    subtitleStudioTextColor
                );

            btnSubtitleStudioColor.Text =
                subtitleStudioTextColor.ToArgb() == Color.White.ToArgb()
                    ? "Bela (privzeto) – izberi barvo"
                    : "Izbrana: " + colourCode + " – spremeni";
        }

        private Image GetSubtitlePreviewImage()
        {
            if (subtitlePreviewImage != null)
            {
                return subtitlePreviewImage;
            }

            try
            {
                using (
                    Stream stream =
                        System.Reflection.Assembly
                        .GetExecutingAssembly()
                        .GetManifestResourceStream(
                            "BorutVideoDownloader.SubtitlePreview.jpg"
                        )
                )
                {
                    if (stream != null)
                    {
                        using (
                            Image loaded =
                                Image.FromStream(stream)
                        )
                        {
                            subtitlePreviewImage =
                                new Bitmap(loaded);
                        }
                    }
                }
            }
            catch
            {
                subtitlePreviewImage = null;
            }

            return subtitlePreviewImage;
        }

        private RectangleF GetFittedVideoRectangle(
            Rectangle client
        )
        {
            if (client.Width <= 0 || client.Height <= 0)
            {
                return RectangleF.Empty;
            }

            float targetRatio = 16F / 9F;
            float availableRatio =
                client.Width / (float)client.Height;

            float width;
            float height;

            if (availableRatio > targetRatio)
            {
                height = client.Height;
                width = height * targetRatio;
            }
            else
            {
                width = client.Width;
                height = width / targetRatio;
            }

            return new RectangleF(
                client.Left +
                (client.Width - width) / 2F,
                client.Top +
                (client.Height - height) / 2F,
                width,
                height
            );
        }

        private void DrawSubtitleStudioPreview(
            object sender,
            PaintEventArgs e
        )
        {
            Panel preview = sender as Panel;

            if (preview == null)
            {
                return;
            }

            e.Graphics.Clear(Color.FromArgb(25, 28, 33));
            e.Graphics.SmoothingMode =
                System.Drawing.Drawing2D.SmoothingMode.AntiAlias;
            e.Graphics.InterpolationMode =
                System.Drawing.Drawing2D.InterpolationMode.HighQualityBicubic;
            e.Graphics.PixelOffsetMode =
                System.Drawing.Drawing2D.PixelOffsetMode.HighQuality;
            e.Graphics.TextRenderingHint =
                System.Drawing.Text.TextRenderingHint.AntiAliasGridFit;

            RectangleF videoRect =
                GetFittedVideoRectangle(
                    preview.ClientRectangle
                );

            if (videoRect.Width <= 1F || videoRect.Height <= 1F)
            {
                return;
            }

            Image background =
                GetSubtitlePreviewImage();

            if (background != null)
            {
                e.Graphics.DrawImage(
                    background,
                    videoRect
                );
            }
            else
            {
                using (
                    SolidBrush fallback =
                        new SolidBrush(
                            Color.FromArgb(63, 101, 126)
                        )
                )
                {
                    e.Graphics.FillRectangle(
                        fallback,
                        videoRect
                    );
                }
            }

            // Vse mere so podane na logični površini 1920x1080.
            // Ko se okno spremeni, se slika in podnapisi merijo z istim faktorjem.
            float scale =
                videoRect.Width / 1920F;

            float safeWidthPercent =
                numSubtitleStudioSafeWidth == null
                    ? 78F
                    : Convert.ToSingle(numSubtitleStudioSafeWidth.Value);
            float sidePercent =
                (100F - safeWidthPercent) / 2F;
            RectangleF safeArea =
                new RectangleF(
                    videoRect.Left + videoRect.Width * sidePercent / 100F,
                    videoRect.Top + 54F * scale,
                    videoRect.Width * safeWidthPercent / 100F,
                    972F * scale
                );

            using (
                Pen safePen =
                    new Pen(
                        Color.FromArgb(
                            175,
                            255,
                            235,
                            120
                        ),
                        Math.Max(1F, 2F * scale)
                    )
            )
            {
                safePen.DashStyle =
                    System.Drawing.Drawing2D.DashStyle.Dash;
                e.Graphics.DrawRectangle(
                    safePen,
                    safeArea.X,
                    safeArea.Y,
                    safeArea.Width,
                    safeArea.Height
                );
            }

            int fontSize =
                numSubtitleStudioFontSize == null
                    ? 48
                    : Convert.ToInt32(
                        numSubtitleStudioFontSize.Value
                    );

            int marginV =
                numSubtitleStudioMarginV == null
                    ? 120
                    : Convert.ToInt32(
                        numSubtitleStudioMarginV.Value
                    );

            int opacity =
                numSubtitleStudioOpacity == null
                    ? 50
                    : Convert.ToInt32(
                        numSubtitleStudioOpacity.Value
                    );

            float previewFontSize =
                Math.Max(7F, fontSize * scale);

            List<string> sampleSegments =
                WrapSubtitleTextToFortyTwoCharacters(
                    SubtitlePreviewComparisonText
                );

            string sample =
                sampleSegments.Count > 0
                    ? sampleSegments[0]
                    : SubtitlePreviewComparisonText;

            RectangleF subtitleArea =
                new RectangleF(
                    safeArea.Left,
                    safeArea.Top,
                    safeArea.Width,
                    safeArea.Height
                );

            using (
                Font font =
                    new Font(
                        "Arial",
                        previewFontSize,
                        FontStyle.Regular,
                        GraphicsUnit.Pixel
                    )
            )
            using (
                StringFormat format =
                    new StringFormat()
            )
            {
                format.Alignment =
                    StringAlignment.Center;
                format.LineAlignment =
                    StringAlignment.Near;
                format.Trimming =
                    StringTrimming.Word;
                format.FormatFlags =
                    StringFormatFlags.LineLimit;

                SizeF measured =
                    e.Graphics.MeasureString(
                        sample,
                        font,
                        new SizeF(
                            subtitleArea.Width,
                            subtitleArea.Height
                        ),
                        format
                    );

                float y =
                    videoRect.Bottom -
                    marginV * scale -
                    measured.Height;

                y = Math.Max(
                    safeArea.Top,
                    Math.Min(
                        safeArea.Bottom -
                        measured.Height,
                        y
                    )
                );

                RectangleF textRect =
                    new RectangleF(
                        subtitleArea.Left,
                        y,
                        subtitleArea.Width,
                        measured.Height +
                        5F * scale
                    );

                int edgeAlpha =
                    Convert.ToInt32(
                        Math.Round(
                            opacity / 100.0 * 255.0
                        )
                    );

                float outlineRadius =
                    Math.Max(
                        1F,
                        2F * scale
                    );

                using (
                    SolidBrush outlineBrush =
                        new SolidBrush(
                            Color.FromArgb(
                                edgeAlpha,
                                0,
                                0,
                                0
                            )
                        )
                )
                {
                    for (
                        int horizontal = -2;
                        horizontal <= 2;
                        horizontal++
                    )
                    {
                        for (
                            int vertical = -2;
                            vertical <= 2;
                            vertical++
                        )
                        {
                            if (
                                horizontal == 0 &&
                                vertical == 0
                            )
                            {
                                continue;
                            }

                            RectangleF outlineRect =
                                textRect;
                            outlineRect.Offset(
                                horizontal *
                                outlineRadius /
                                2F,
                                vertical *
                                outlineRadius /
                                2F
                            );

                            e.Graphics.DrawString(
                                sample,
                                font,
                                outlineBrush,
                                outlineRect,
                                format
                            );
                        }
                    }
                }

                using (
                    SolidBrush shadowBrush =
                        new SolidBrush(
                            Color.FromArgb(
                                Math.Min(
                                    220,
                                    edgeAlpha
                                ),
                                0,
                                0,
                                0
                            )
                        )
                )
                {
                    RectangleF shadowRect =
                        textRect;
                    shadowRect.Offset(
                        Math.Max(
                            1F,
                            2.5F * scale
                        ),
                        Math.Max(
                            1F,
                            2.5F * scale
                        )
                    );

                    e.Graphics.DrawString(
                        sample,
                        font,
                        shadowBrush,
                        shadowRect,
                        format
                    );
                }

                using (
                    SolidBrush textBrush =
                        new SolidBrush(
                            subtitleStudioTextColor
                        )
                )
                {
                    e.Graphics.DrawString(
                        sample,
                        font,
                        textBrush,
                        textRect,
                        format
                    );
                }
            }

            using (
                Pen border =
                    new Pen(
                        preview.Enabled
                            ? Color.FromArgb(130, 155, 180)
                            : Color.LightGray
                    )
            )
            {
                e.Graphics.DrawRectangle(
                    border,
                    videoRect.X,
                    videoRect.Y,
                    Math.Max(0F, videoRect.Width - 1F),
                    Math.Max(0F, videoRect.Height - 1F)
                );
            }
        }

        private int GetSubtitleStudioPowerPercent()
        {
            if (cmbSubtitleStudioPower == null)
            {
                return 50;
            }

            switch (
                cmbSubtitleStudioPower.SelectedIndex
            )
            {
                case 0:
                    return 100;
                case 2:
                    return 25;
                default:
                    return 50;
            }
        }

        private int GetSubtitleStudioThreadCount()
        {
            int percent =
                GetSubtitleStudioPowerPercent();
            return Math.Max(
                1,
                Convert.ToInt32(
                    Math.Ceiling(
                        Environment.ProcessorCount *
                        percent /
                        100.0
                    )
                )
            );
        }

        private string GetSubtitleStudioPreset()
        {
            int power =
                GetSubtitleStudioPowerPercent();

            if (power >= 100)
            {
                return "veryfast";
            }

            if (power >= 50)
            {
                return "fast";
            }

            return "medium";
        }

        private ProcessPriorityClass
            GetSubtitleStudioPriority()
        {
            int power =
                GetSubtitleStudioPowerPercent();

            if (power >= 100)
            {
                return ProcessPriorityClass.Normal;
            }

            if (power >= 50)
            {
                return ProcessPriorityClass.BelowNormal;
            }

            return ProcessPriorityClass.Idle;
        }

        private void ResetSubtitleStudioProgress(
            string message
        )
        {
            subtitleStudioLastElapsed =
                TimeSpan.Zero;

            if (subtitleStudioProgress != null)
            {
                subtitleStudioProgress.Value = 0;
            }
            if (lblSubtitleStudioProgress != null)
            {
                lblSubtitleStudioProgress.Text =
                    "0,0 %  |  Preteklo: 00:00  |  Preostalo: --:--";
            }
            if (lblSubtitleStudioStatus != null)
            {
                lblSubtitleStudioStatus.Text =
                    message;
            }
        }

        private void UpdateSubtitleStudioProgress(
            double percent,
            TimeSpan elapsed,
            TimeSpan remaining,
            string speed
        )
        {
            subtitleStudioLastElapsed =
                elapsed;

            SafeUi(delegate
            {
                if (subtitleStudioProgress != null)
                {
                    int value =
                        Convert.ToInt32(
                            Math.Round(
                                Math.Max(
                                    0.0,
                                    Math.Min(
                                        100.0,
                                        percent
                                    )
                                ) * 10.0
                            )
                        );
                    subtitleStudioProgress.Value =
                        Math.Max(
                            subtitleStudioProgress.Minimum,
                            Math.Min(
                                subtitleStudioProgress.Maximum,
                                value
                            )
                        );
                }

                if (lblSubtitleStudioProgress != null)
                {
                    lblSubtitleStudioProgress.Text =
                        percent.ToString("0.0") +
                        " %  |  Preteklo: " +
                        FormatSubtitleStudioTime(elapsed) +
                        "  |  Preostalo: " +
                        (
                            remaining == TimeSpan.MaxValue
                                ? "--:--"
                                : FormatSubtitleStudioTime(
                                    remaining
                                )
                        ) +
                        (
                            string.IsNullOrWhiteSpace(speed)
                                ? ""
                                : "  |  Hitrost: " + speed
                        );
                }
            });
        }

        private string FormatSubtitleStudioTime(
            TimeSpan value
        )
        {
            if (value < TimeSpan.Zero)
            {
                value = TimeSpan.Zero;
            }

            if (value.TotalHours >= 1.0)
            {
                return
                    Convert.ToInt32(
                        Math.Floor(
                            value.TotalHours
                        )
                    ).ToString("00") +
                    ":" +
                    value.Minutes.ToString("00") +
                    ":" +
                    value.Seconds.ToString("00");
            }

            return
                Convert.ToInt32(
                    Math.Floor(
                        value.TotalMinutes
                    )
                ).ToString("00") +
                ":" +
                value.Seconds.ToString("00");
        }

