        private void UpdateLowerAreaForSelectedTab()
        {
            if (
                mainTabs == null ||
                mainRootLayout == null ||
                lowerLayout == null ||
                sharedQueuePanel == null ||
                sharedLogPanel == null
            )
            {
                return;
            }

            bool downloadTabSelected =
                mainTabs.SelectedIndex == 0;

            lowerLayout.SuspendLayout();

            if (subtitleQuickHelpPanel != null)
            {
                subtitleQuickHelpPanel.Visible = false;
            }
            if (editorQuickHelpPanel != null)
            {
                editorQuickHelpPanel.Visible = false;
            }

            mainRootLayout.RowStyles[0].SizeType =
                SizeType.Percent;
            mainRootLayout.RowStyles[0].Height = 100F;
            mainRootLayout.RowStyles[1].SizeType =
                SizeType.Absolute;
            mainRootLayout.RowStyles[1].Height =
                downloadTabSelected ? 318F : 132F;

            lowerLayout.SetRowSpan(sharedLogPanel, 1);
            sharedLogPanel.Margin = new Padding(0);

            if (downloadTabSelected)
            {
                sharedQueuePanel.Visible = true;
                sharedLogPanel.Visible = true;
                lowerLayout.RowStyles[0].SizeType = SizeType.Absolute;
                lowerLayout.RowStyles[0].Height = 184F;
                lowerLayout.RowStyles[1].SizeType = SizeType.Absolute;
                lowerLayout.RowStyles[1].Height = 132F;
                lowerLayout.SetCellPosition(
                    sharedQueuePanel,
                    new TableLayoutPanelCellPosition(0, 0)
                );
                lowerLayout.SetCellPosition(
                    sharedLogPanel,
                    new TableLayoutPanelCellPosition(0, 1)
                );
                sharedQueuePanel.Margin = new Padding(0, 2, 0, 1);
                sharedLogPanel.Margin = new Padding(0, 1, 0, 0);
                sharedQueuePanel.BringToFront();
                sharedLogPanel.BringToFront();
            }
            else
            {
                sharedQueuePanel.Visible = false;
                sharedLogPanel.Visible = true;
                lowerLayout.RowStyles[0].SizeType = SizeType.Absolute;
                lowerLayout.RowStyles[0].Height = 0F;
                lowerLayout.RowStyles[1].SizeType = SizeType.Absolute;
                lowerLayout.RowStyles[1].Height = 132F;
                lowerLayout.SetCellPosition(
                    sharedLogPanel,
                    new TableLayoutPanelCellPosition(0, 0)
                );
                lowerLayout.SetRowSpan(sharedLogPanel, 2);
                sharedLogPanel.BringToFront();
            }

            lowerLayout.ResumeLayout(true);
        }

