        private void DrawConverterFormatItem(
            object sender,
            DrawItemEventArgs e
        )
        {
            e.DrawBackground();

            if (e.Index < 0)
            {
                return;
            }

            ComboBox combo =
                sender as ComboBox;

            if (combo == null)
            {
                return;
            }

            ConverterFormatOption option =
                combo.Items[e.Index]
                as ConverterFormatOption;

            if (option == null)
            {
                return;
            }

            string supportReason;
            bool supported =
                IsConverterFormatSupported(
                    option,
                    out supportReason
                );

            bool selected =
                (
                    e.State &
                    DrawItemState.Selected
                ) ==
                DrawItemState.Selected;

            Color normalText =
                selected
                    ? SystemColors.HighlightText
                    : (
                        supported
                            ? Color.FromArgb(32, 38, 46)
                            : Color.Gray
                    );

            Color extensionColor =
                selected
                    ? Color.FromArgb(255, 228, 198)
                    : Color.FromArgb(220, 86, 38);

            using (Brush extensionBrush = new SolidBrush(extensionColor))
            using (Brush textBrush = new SolidBrush(normalText))
            using (Brush secondaryBrush = new SolidBrush(
                selected
                    ? SystemColors.HighlightText
                    : Color.DimGray
            ))
            using (Font bold = new Font(e.Font, FontStyle.Bold))
            using (Font small = new Font(e.Font.FontFamily, 8F))
            {
                e.Graphics.DrawString(
                    option.Extension,
                    bold,
                    extensionBrush,
                    e.Bounds.Left + 6,
                    e.Bounds.Top + 3
                );

                e.Graphics.DrawString(
                    option.Name,
                    e.Font,
                    textBrush,
                    e.Bounds.Left + 82,
                    e.Bounds.Top + 3
                );

                string right =
                    option.Category;
                SizeF rightSize =
                    e.Graphics.MeasureString(
                        right,
                        e.Font
                    );
                e.Graphics.DrawString(
                    right,
                    e.Font,
                    secondaryBrush,
                    e.Bounds.Right - rightSize.Width - 8,
                    e.Bounds.Top + 3
                );

                e.Graphics.DrawString(
                    option.Usage,
                    small,
                    secondaryBrush,
                    e.Bounds.Left + 82,
                    e.Bounds.Top + 21
                );
            }

            e.DrawFocusRectangle();
        }


        private ConverterFormatOption
            GetSelectedConverterFormat()
        {
            if (
                cmbConverterFormat == null ||
                cmbConverterFormat.SelectedIndex < 0
            )
            {
                return null;
            }

            return
                cmbConverterFormat.SelectedItem
                as ConverterFormatOption;
        }

        private void UpdateConverterFormatInfo()
        {
            ConverterFormatOption option =
                GetSelectedConverterFormat();

            if (option == null)
            {
                return;
            }

            if (
                lblConverterFormatName != null
            )
            {
                lblConverterFormatName.Text =
                    option.Extension +
                    "  —  " +
                    option.Name;
            }

            if (
                lblConverterFormatUsage != null
            )
            {
                lblConverterFormatUsage.Text =
                    option.Usage;
            }

            if (
                lblConverterFormatNote != null
            )
            {
                lblConverterFormatNote.Text =
                    option.Note;
            }

            if (
                lblConverterFormatSupport != null
            )
            {
                string reason;
                bool supported =
                    IsConverterFormatSupported(
                        option,
                        out reason
                    );

                lblConverterFormatSupport.Text =
                    supported
                        ? "Podprto in pripravljeno"
                        : reason;

                lblConverterFormatSupport.ForeColor =
                    supported
                        ? Color.DarkGreen
                        : Color.DarkRed;
            }

            if (
                lblConverterCompatibleInputs != null
            )
            {
                lblConverterCompatibleInputs.Text =
                    BuildConverterCompatibilitySummary(
                        option
                    );
            }
        }

        private string BuildConverterCompatibilitySummary(
            ConverterFormatOption option
        )
        {
            string generic;

            if (
                string.Equals(
                    option.OutputKind,
                    "remux",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                generic =
                    "✓ Video datoteke z že združljivimi video/zvočnimi kodeki.\r\n" +
                    "✓ Tokovi se samo prekopirajo: brez ponovnega kodiranja in brez izgube kakovosti.\r\n" +
                    "✗ Filtri, vrtenje, sprememba hitrosti in drugi posegi niso mogoči.";
            }
            else if (
                string.Equals(
                    option.OutputKind,
                    "lottiejson",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                generic = "✓ .lottie → .json ali veljaven Lottie .json → .json.\r\n✗ Navaden poljuben JSON ni nujno Lottie animacija.";
            }
            else if (
                string.Equals(
                    option.OutputKind,
                    "dotlottie",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                generic = "✓ Veljaven Lottie .json → .lottie paket z manifestom.\r\n✗ Video, GIF, SVG in RIV niso Lottie JSON.";
            }
            else if (
                string.Equals(
                    option.OutputKind,
                    "svgcopy",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                generic = "✓ .svg → .svg brez izgube vektorske kakovosti.\r\n✗ Raster slike ni mogoče verodostojno samodejno pretvoriti v pravi vektor.";
            }
            else if (
                string.Equals(
                    option.OutputKind,
                    "rivecopy",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                generic = "✓ .riv → .riv brez spremembe.\r\n✗ Ustvarjanje ali renderiranje RIV zahteva uradni Rive runtime oziroma Rive Editor.";
            }
            else if (
                string.Equals(
                    option.OutputKind,
                    "video",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                generic =
                    "✓ Video: .mp4, .mkv, .webm, .mov, .avi, .m4v, .ts/.mts/.m2ts, .mxf, .wmv, .flv, .vob, .3gp/.3g2, .ogv, .rm/.rmvb, .r3d, .braw, .lrv.\r\n" +
                    "✓ Animacije: .gif in .apng se lahko pretvorijo v video.\r\n" +
                    "✗ Samostojen zvok ali statična slika se ne pretvorita v video.";
            }
            else if (
                string.Equals(
                    option.OutputKind,
                    "audio",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                generic =
                    "✓ Zvok: .mp3, .m4a, .aac, .wav, .flac, .ogg, .opus, .aiff/.aif, .wv, .ape, .tta, .tak, .wma, .ac3, .eac3, .mp2 in drugi zvočni vhodi.\r\n" +
                    "✓ Video: iz videa se izloči zvočna sled.\r\n" +
                    "✗ Slike in animacije brez zvoka niso združljive.";
            }
            else if (
                string.Equals(
                    option.OutputKind,
                    "image",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                generic =
                    "✓ Slike: .jpg/.jpeg, .png, .webp, .avif, .jxl, .heic/.heif, .bmp, .tif/.tiff, .ico, .dds, .tga, .qoi, .jp2/.j2k, .exr, .hdr, .pcx, .dpx.\r\n" +
                    "✓ Video ali animacija: izvozi se prvi kader.\r\n" +
                    "✓ RAW/vektor le, kadar jih trenutni FFmpeg zna prebrati.\r\n" +
                    "✗ Zvok ni združljiv s slikovnim izhodom.";
            }
            else
            {
                generic =
                    "✓ Video in animirane slike (.gif, .apng).\r\n" +
                    "✗ Zvok in posamezne statične slike se ne pretvorijo v animacijo.";
            }

            if (
                txtConverterFiles == null ||
                string.IsNullOrWhiteSpace(
                    txtConverterFiles.Text
                )
            )
            {
                return generic;
            }

            string[] files =
                txtConverterFiles.Text
                .Split(
                    new string[]
                    {
                        "\r\n",
                        "\n"
                    },
                    StringSplitOptions.RemoveEmptyEntries
                )
                .Select(
                    delegate(string value)
                    {
                        return value.Trim();
                    }
                )
                .Where(
                    delegate(string value)
                    {
                        return File.Exists(value);
                    }
                )
                .ToArray();

            if (files.Length == 0)
            {
                return generic;
            }

            int compatible = 0;
            List<string> incompatible =
                new List<string>();

            foreach (string file in files)
            {
                string reason;

                if (
                    IsConverterCombinationAllowed(
                        file,
                        option,
                        out reason
                    )
                )
                {
                    compatible++;
                }
                else
                {
                    incompatible.Add(
                        Path.GetFileName(file) +
                        ": " + reason
                    );
                }
            }

            string selectedSummary =
                "\r\n\r\nIzbrane datoteke: " +
                compatible +
                "/" +
                files.Length +
                " združljivih.";

            if (incompatible.Count > 0)
            {
                selectedSummary +=
                    " Nezdružljivo: " +
                    string.Join(
                        " | ",
                        incompatible.Take(3)
                        .ToArray()
                    );
            }

            return generic + selectedSummary;
        }

