            footer.Controls.Add(
                select
            );

            Action refreshRows =
                delegate
                {
                    formatGrid.Rows.Clear();

                    string selectedCategory =
                        category.SelectedIndex <= 0
                            ? ""
                            : category.SelectedItem
                                .ToString();

                    string query =
                        search.Text.Trim();

                    IEnumerable<ConverterFormatOption>
                        filtered =
                            ConverterFormats;

                    if (
                        !string.IsNullOrWhiteSpace(
                            selectedCategory
                        )
                    )
                    {
                        filtered =
                            filtered.Where(
                                delegate(
                                    ConverterFormatOption option
                                )
                                {
                                    return string.Equals(
                                        option.Category,
                                        selectedCategory,
                                        StringComparison.OrdinalIgnoreCase
                                    );
                                }
                            );
                    }

                    if (
                        !string.IsNullOrWhiteSpace(
                            query
                        )
                    )
                    {
                        filtered =
                            filtered.Where(
                                delegate(
                                    ConverterFormatOption option
                                )
                                {
                                    string combined =
                                        option.Extension +
                                        " " +
                                        option.Name +
                                        " " +
                                        option.Usage +
                                        " " +
                                        option.Note;

                                    return combined.IndexOf(
                                        query,
                                        StringComparison.OrdinalIgnoreCase
                                    ) >= 0;
                                }
                            );
                    }

                    foreach (
                        ConverterFormatOption option in
                        filtered
                        .OrderBy(
                            delegate(
                                ConverterFormatOption value
                            )
                            {
                                return value.Category;
                            }
                        )
                        .ThenBy(
                            delegate(
                                ConverterFormatOption value
                            )
                            {
                                return value.Extension;
                            }
                        )
                    )
                    {
                        string reason;
                        bool supported =
                            IsConverterFormatSupported(
                                option,
                                out reason
                            );

                        string status =
                            option.Selectable
                                ? (
                                    supported
                                        ? "Podprto"
                                        : reason
                                )
                                : "Vhodno / informativno";

                        int rowIndex =
                            formatGrid.Rows.Add(
                                option.Extension,
                                option.Name,
                                option.Category,
                                option.Usage,
                                option.Note,
                                status
                            );

                        DataGridViewRow row =
                            formatGrid.Rows[
                                rowIndex
                            ];
                        row.Tag = option;
                        row.Cells[0].Style.ForeColor =
                            Color.FromArgb(
                                220,
                                86,
                                38
                            );
                        row.Cells[0].Style.Font =
                            new Font(
                                formatGrid.Font,
                                FontStyle.Bold
                            );

                        if (!option.Selectable)
                        {
                            row.DefaultCellStyle.ForeColor =
                                Color.Gray;
                            row.Cells[0].Style.ForeColor =
                                Color.FromArgb(
                                    170,
                                    95,
                                    65
                                );
                        }
                        else if (supported)
                        {
                            row.Cells[5].Style.ForeColor =
                                Color.DarkGreen;
                            row.Cells[5].Style.Font =
                                new Font(
                                    formatGrid.Font,
                                    FontStyle.Bold
                                );
                        }
                        else
                        {
                            row.Cells[5].Style.ForeColor =
                                Color.DarkRed;
                        }
                    }

                    select.Enabled = false;
                };

            Action selectCurrent =
                delegate
                {
                    if (
                        formatGrid.SelectedRows.Count == 0
                    )
                    {
                        return;
                    }

                    ConverterFormatOption option =
                        formatGrid.SelectedRows[0].Tag
                        as ConverterFormatOption;

                    if (option == null)
                    {
                        return;
                    }

                    string reason;

                    if (
                        !IsConverterFormatSupported(
                            option,
                            out reason
                        )
                    )
                    {
                        MessageBox.Show(
                            popup,
                            option.Selectable
                                ? reason
                                : "Ta format je prikazan kot vhodni ali informativni format in ga program ne ponuja kot izhod.",
                            "Format ni na voljo za izvoz",
                            MessageBoxButtons.OK,
                            MessageBoxIcon.Information
                        );
                        return;
                    }

                    for (
                        int index = 0;
                        index <
                        ConverterOutputFormats.Length;
                        index++
                    )
                    {
                        if (
                            string.Equals(
                                ConverterOutputFormats[
                                    index
                                ].Id,
                                option.Id,
                                StringComparison.OrdinalIgnoreCase
                            )
                        )
                        {
                            cmbConverterFormat.SelectedIndex =
                                index;
                            break;
                        }
                    }

                    popup.Close();
                };

            formatGrid.SelectionChanged += delegate
            {
                if (
                    formatGrid.SelectedRows.Count == 0
                )
                {
                    select.Enabled = false;
                    return;
                }

                ConverterFormatOption option =
                    formatGrid.SelectedRows[0].Tag
                    as ConverterFormatOption;

                string reason;
                select.Enabled =
                    option != null &&
                    IsConverterFormatSupported(
                        option,
                        out reason
                    );
            };

            formatGrid.CellDoubleClick += delegate(
                object sender,
                DataGridViewCellEventArgs e
            )
            {
                if (e.RowIndex >= 0)
                {
                    selectCurrent();
                }
            };

            select.Click += delegate
            {
                selectCurrent();
            };

            category.SelectedIndexChanged +=
                delegate
                {
                    refreshRows();
                };

            search.TextChanged += delegate
            {
                refreshRows();
            };

            popup.KeyDown += delegate(
                object sender,
                KeyEventArgs e
            )
            {
                if (e.KeyCode == Keys.Escape)
                {
                    popup.Close();
                }
            };

            refreshRows();
            popup.ShowDialog(this);
        }

        private Label CreateSectionLabel(string text)
        {
            Label label =
                new Label();
            label.Text = text;
            label.AutoSize = true;
            label.Anchor =
                AnchorStyles.Left;
            return label;
        }

        private void ConfigureFileDrop(
            Control control,
            Action<string[]> handler
        )
        {
            if (
                control == null ||
                handler == null
            )
            {
                return;
            }

            control.AllowDrop = true;

            control.DragEnter += delegate(
                object sender,
                DragEventArgs e
            )
            {
                if (
                    e.Data != null &&
                    e.Data.GetDataPresent(
                        DataFormats.FileDrop
                    )
                )
                {
                    e.Effect =
                        DragDropEffects.Copy;
                }
                else
                {
                    e.Effect =
                        DragDropEffects.None;
                }
            };

            control.DragDrop += delegate(
                object sender,
                DragEventArgs e
            )
            {
                if (
                    e.Data == null ||
                    !e.Data.GetDataPresent(
                        DataFormats.FileDrop
                    )
                )
                {
                    return;
                }

                string[] files =
                    e.Data.GetData(
                        DataFormats.FileDrop
                    ) as string[];

                if (
                    files != null &&
                    files.Length > 0
                )
                {
                    handler(files);
                }
            };
        }

        private bool IsVideoFile(
            string fileName
        )
        {
            string extension =
                Path.GetExtension(
                    fileName ?? ""
                ).ToLowerInvariant();

            return
                new string[]
                {
                    ".mp4", ".mkv", ".webm", ".mov",
                    ".avi", ".m4v", ".ts", ".mts",
                    ".m2ts", ".wmv", ".flv", ".mpg",
                    ".mpeg", ".ogv", ".vob", ".3gp",
                    ".3g2", ".mxf"
                }.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                );
        }

        private bool IsAudioFile(
            string fileName
        )
        {
            string extension =
                Path.GetExtension(
                    fileName ?? ""
                ).ToLowerInvariant();

            return
                new string[]
                {
                    ".mp3", ".m4a", ".aac", ".wav",
                    ".flac", ".ogg", ".opus", ".aiff",
                    ".aif", ".wma", ".ac3", ".eac3",
                    ".dts", ".mp2"
                }.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                );
        }

        private bool IsSubtitleFile(
            string fileName
        )
        {
            string extension =
                Path.GetExtension(
                    fileName ?? ""
                ).ToLowerInvariant();

            return
                new string[]
                {
                    ".srt", ".vtt", ".ass", ".ssa"
                }.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                );
        }

        private void HandleDownloaderDroppedFiles(
            string[] files
        )
        {
            AddLocalFilesFromDroppedPaths(files);
        }

        private void AddLocalFilesFromDroppedPaths(
            IEnumerable<string> filePaths
        )
        {
            string[] files =
                (filePaths ??
                 Enumerable.Empty<string>())
                .Where(
                    delegate(string file)
                    {
                        return
                            File.Exists(file) &&
                            (
                                IsVideoFile(file) ||
                                IsAudioFile(file)
                            );
                    }
                )
                .Distinct(
                    StringComparer.OrdinalIgnoreCase
                )
                .ToArray();

            if (files.Length == 0)
            {
                MessageBox.Show(
                    this,
                    "V ta del lahko spustiš video ali zvočne datoteke.",
                    "Ni podprtih datotek",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
                return;
            }

            if (cmbOutput.SelectedIndex == 0)
            {
                cmbOutput.SelectedIndex = 1;
                Log(
                    "Za lokalne datoteke je bil samodejno izbran MP4 – H.264 + AAC.",
                    "VRSTA"
                );
            }

            string folder =
                EnsureOutputFolder();

            foreach (string file in files)
            {
                DownloadJob job =
                    new DownloadJob();
                job.Kind =
                    JobKind.LocalConversion;
                job.LocalFile = file;
                job.SourceName = "lokalno";
                job.DisplayTitle =
                    Path.GetFileName(file);
                job.OutputFolder = folder;
                job.QualityIndex =
                    cmbQuality.SelectedIndex;
                job.OutputIndex =
                    cmbSubtitles.SelectedIndex == 3
                        ? 1
                        : cmbOutput.SelectedIndex;
                job.SubtitleModeIndex =
                    cmbSubtitles.SelectedIndex;
                job.SubtitleLanguages =
                    txtSubtitleLanguages.Text.Trim();
                job.IncludeAutoSubtitles =
                    chkAutoSubtitles.Checked;
                job.StyledEmbeddedSubtitles =
                    chkStyledEmbeddedSubtitles.Checked;
                job.SubtitleBackgroundOpacity =
                    Convert.ToInt32(
                        numSubtitleBackgroundOpacity.Value
                    );
                job.ConcurrentFragments =
                    Convert.ToInt32(
                        numFragments.Value
                    );
                AddJob(job);
            }

            Log(
                "Dodane lokalne datoteke: " +
                files.Length,
                "VRSTA"
            );
        }

        private void HandleSubtitleTabDroppedFiles(
            string[] files
        )
        {
            string video =
                files.FirstOrDefault(
                    delegate(string file)
                    {
                        return
                            File.Exists(file) &&
                            IsVideoFile(file);
                    }
                );

            string subtitle =
                files.FirstOrDefault(
                    delegate(string file)
                    {
                        return
                            File.Exists(file) &&
                            IsSubtitleFile(file);
                    }
                );

            string text =
                files.FirstOrDefault(
                    delegate(string file)
                    {
                        return
                            File.Exists(file) &&
                            string.Equals(
                                Path.GetExtension(file),
                                ".txt",
                                StringComparison.OrdinalIgnoreCase
                            );
                    }
                );

            if (!string.IsNullOrWhiteSpace(video))
            {
                txtSubtitleStudioVideo.Text = video;
            }
            if (!string.IsNullOrWhiteSpace(subtitle))
            {
                txtSubtitleStudioFile.Text = subtitle;
            }
            if (!string.IsNullOrWhiteSpace(text))
            {
                LoadTimedSubtitleFile(text);
            }

            if (
                !string.IsNullOrWhiteSpace(video) ||
                !string.IsNullOrWhiteSpace(subtitle)
            )
            {
                UpdateSubtitleStudioSuggestedOutput();
            }
        }

