        private void AddConverterFilesFromPaths(
            string[] filePaths
        )
        {
            string[] files =
                (filePaths ?? new string[0])
                .Where(
                    delegate(string file)
                    {
                        return File.Exists(file);
                    }
                )
                .Distinct(
                    StringComparer.OrdinalIgnoreCase
                )
                .ToArray();

            if (files.Length == 0)
            {
                return;
            }

            HashSet<string> combined =
                new HashSet<string>(
                    StringComparer.OrdinalIgnoreCase
                );

            foreach (
                string existing in
                (txtConverterFiles.Text ?? "")
                .Split(
                    new string[] { "\r\n", "\n" },
                    StringSplitOptions.RemoveEmptyEntries
                )
            )
            {
                if (File.Exists(existing.Trim()))
                {
                    combined.Add(existing.Trim());
                }
            }

            foreach (string file in files)
            {
                combined.Add(file);
            }

            txtConverterFiles.Text =
                string.Join(
                    Environment.NewLine,
                    combined
                );

            if (
                string.IsNullOrWhiteSpace(
                    txtConverterFolder.Text
                )
            )
            {
                txtConverterFolder.Text =
                    Path.GetDirectoryName(files[0]);
            }

            lblConverterStatus.Text =
                "Izbranih datotek: " +
                combined.Count;
            UpdateConverterFormatInfo();
        }

        private void HandleEditorTabDroppedFiles(
            string[] files
        )
        {
            string[] videos =
                files.Where(
                    delegate(string file)
                    {
                        return
                            File.Exists(file) &&
                            IsVideoFile(file);
                    }
                )
                .Distinct(
                    StringComparer.OrdinalIgnoreCase
                )
                .ToArray();

            if (videos.Length == 1)
            {
                HandleEditorInputDrop(videos);
            }
            else if (videos.Length > 1)
            {
                AddEditorMergeFilesFromPaths(videos);
            }
        }

        private async void HandleEditorInputDrop(
            string[] files
        )
        {
            string file =
                files.FirstOrDefault(
                    delegate(string value)
                    {
                        return
                            File.Exists(value) &&
                            IsVideoFile(value);
                    }
                );

            if (!string.IsNullOrWhiteSpace(file))
            {
                await LoadEditorInputAsync(file);
            }
        }

        private void AddEditorMergeFilesFromPaths(
            string[] files
        )
        {
            if (files == null)
            {
                return;
            }

            foreach (
                string file in files.Where(
                    delegate(string value)
                    {
                        return
                            File.Exists(value) &&
                            IsVideoFile(value);
                    }
                )
                .Distinct(
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                if (
                    !lstEditorMergeFiles.Items
                    .Cast<object>()
                    .Any(
                        delegate(object item)
                        {
                            return string.Equals(
                                Convert.ToString(item),
                                file,
                                StringComparison.OrdinalIgnoreCase
                            );
                        }
                    )
                )
                {
                    lstEditorMergeFiles.Items.Add(file);
                }
            }

            UpdateEditorMergeSuggestedOutput();

            if (lblEditorMergeStatus != null)
            {
                lblEditorMergeStatus.Text =
                    "Na seznamu je " +
                    lstEditorMergeFiles.Items.Count +
                    " posnetkov. Vrstni red spremeni s puščicama.";
            }
        }

