        private void UpdateSubtitleStudioSuggestedOutput()
        {
            if (
                txtSubtitleStudioVideo == null ||
                string.IsNullOrWhiteSpace(
                    txtSubtitleStudioVideo.Text
                )
            )
            {
                return;
            }

            string video =
                txtSubtitleStudioVideo.Text.Trim();
            string folder =
                Path.GetDirectoryName(video);
            string name =
                Path.GetFileNameWithoutExtension(video);
            string extension =
                cmbSubtitleStudioMode != null &&
                cmbSubtitleStudioMode.SelectedIndex == 1
                    ? ".mp4"
                    : ".mkv";
            string suffix =
                cmbSubtitleStudioMode != null &&
                cmbSubtitleStudioMode.SelectedIndex == 1
                    ? " - zapečeni podnapisi"
                    : " - izbirni podnapisi";

            txtSubtitleStudioOutput.Text =
                Path.Combine(
                    folder,
                    name + suffix + extension
                );
        }

        private void ChooseSubtitleStudioOutput()
        {
            SaveFileDialog dialog =
                new SaveFileDialog();

            bool burn =
                cmbSubtitleStudioMode != null &&
                cmbSubtitleStudioMode.SelectedIndex == 1;

            dialog.Title =
                "Izberi končno video datoteko";
            dialog.Filter =
                burn
                    ? "MP4 video|*.mp4"
                    : "MKV video|*.mkv";
            dialog.DefaultExt =
                burn
                    ? "mp4"
                    : "mkv";

            if (
                !string.IsNullOrWhiteSpace(
                    txtSubtitleStudioOutput.Text
                )
            )
            {
                dialog.FileName =
                    Path.GetFileName(
                        txtSubtitleStudioOutput.Text
                    );
                dialog.InitialDirectory =
                    Path.GetDirectoryName(
                        txtSubtitleStudioOutput.Text
                    );
            }

            if (
                dialog.ShowDialog(this) ==
                DialogResult.OK
            )
            {
                txtSubtitleStudioOutput.Text =
                    dialog.FileName;
            }
        }

        private async Task<string> CreateNormalizedStandaloneSrtAsync(
            string ffmpeg,
            string subtitleFile,
            string temporaryFolder
        )
        {
            string rawSrt = Path.Combine(
                temporaryFolder,
                "podnapisi_raw.srt"
            );
            string normalizedSrt = Path.Combine(
                temporaryFolder,
                "podnapisi_42x2.srt"
            );

            if (
                string.Equals(
                    Path.GetExtension(subtitleFile),
                    ".srt",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                File.Copy(
                    subtitleFile,
                    rawSrt,
                    true
                );
            }
            else
            {
                List<string> arguments =
                    new List<string>();
                arguments.Add("-y");
                arguments.Add("-hide_banner");
                arguments.Add("-loglevel");
                arguments.Add("warning");
                arguments.Add("-i");
                arguments.Add(subtitleFile);
                arguments.Add("-c:s");
                arguments.Add("srt");
                arguments.Add(rawSrt);

                int result =
                    await RunStandaloneProcessAsync(
                        ffmpeg,
                        arguments,
                        "PODNAPISI 42"
                    );

                if (
                    result != 0 ||
                    !File.Exists(rawSrt)
                )
                {
                    throw new InvalidOperationException(
                        "Podnapisov ni bilo mogoče pretvoriti v SRT za omejitev 42 znakov na vrstico."
                    );
                }
            }

            NormalizeSrtFileToFortyTwoCharacters(
                rawSrt,
                normalizedSrt
            );

            return normalizedSrt;
        }

        private async Task RunSubtitleStudioAsync(
            Button actionButton
        )
        {
            string video =
                txtSubtitleStudioVideo.Text.Trim();
            string subtitle =
                txtSubtitleStudioFile.Text.Trim();

            if (!File.Exists(video))
            {
                MessageBox.Show(
                    this,
                    "Najprej izberi veljavno video datoteko.",
                    "Video ni izbran",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            if (!File.Exists(subtitle))
            {
                MessageBox.Show(
                    this,
                    "Najprej izberi veljavno datoteko s podnapisi.",
                    "Podnapisi niso izbrani",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            string ffmpeg =
                ToolLocator.FindFfmpeg();
            string ffprobe =
                ToolLocator.FindFfprobe();

            if (string.IsNullOrWhiteSpace(ffmpeg))
            {
                MessageBox.Show(
                    this,
                    "FFmpeg ni najden. Odpri »Orodja in nastavitve« in namesti orodja.",
                    "FFmpeg ni nameščen",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            bool burn =
                cmbSubtitleStudioMode.SelectedIndex == 1;

            string output =
                txtSubtitleStudioOutput.Text.Trim();

            if (string.IsNullOrWhiteSpace(output))
            {
                UpdateSubtitleStudioSuggestedOutput();
                output =
                    txtSubtitleStudioOutput.Text.Trim();
            }

            output =
                Path.ChangeExtension(
                    output,
                    burn
                        ? ".mp4"
                        : ".mkv"
                );
            output =
                GetUniquePath(output);
            txtSubtitleStudioOutput.Text =
                output;

            actionButton.Enabled = false;
            ResetSubtitleStudioProgress(
                burn
                    ? "Pripravljam zapečenje podnapisov …"
                    : "Pripravljam vgradnjo izbirnih podnapisov …"
            );

            Log(
                "Začenjam obdelavo podnapisov: " +
                Path.GetFileName(video),
                "PODNAPISI"
            );

            string temporaryFolder =
                Path.Combine(
                    AppPaths.WorkFolder,
                    "SubtitleStudio_" +
                    Guid.NewGuid().ToString("N")
                );

            try
            {
                Directory.CreateDirectory(
                    temporaryFolder
                );

                double duration =
                    string.IsNullOrWhiteSpace(ffprobe)
                        ? 0.0
                        : await ReadStandaloneDurationAsync(
                            ffprobe,
                            video
                        );

                string normalizedSubtitle =
                    await CreateNormalizedStandaloneSrtAsync(
                        ffmpeg,
                        subtitle,
                        temporaryFolder
                    );

                if (!burn)
                {
                    string subtitleCodec =
                        "srt";

                    List<string> arguments =
                        new List<string>();
                    arguments.Add("-y");
                    arguments.Add("-hide_banner");
                    arguments.Add("-loglevel");
                    arguments.Add("warning");
                    arguments.Add("-i");
                    arguments.Add(video);
                    arguments.Add("-i");
                    arguments.Add(normalizedSubtitle);
                    arguments.Add("-map");
                    arguments.Add("0");
                    arguments.Add("-map");
                    arguments.Add("1:0");
                    arguments.Add("-c");
                    arguments.Add("copy");
                    arguments.Add("-c:s");
                    arguments.Add(subtitleCodec);
                    arguments.Add("-metadata:s:s:0");
                    arguments.Add("language=slv");
                    arguments.Add("-disposition:s:0");
                    arguments.Add("default");
                    arguments.Add("-progress");
                    arguments.Add("pipe:1");
                    arguments.Add("-nostats");
                    arguments.Add(output);

                    lblSubtitleStudioStatus.Text =
                        "Vgrajujem izbirne podnapise brez ponovnega kodiranja slike …";

                    int result =
                        await RunStandaloneProgressProcessAsync(
                            ffmpeg,
                            arguments,
                            "PODNAPISI",
                            duration,
                            ProcessPriorityClass.BelowNormal
                        );

                    if (
                        result != 0 ||
                        !File.Exists(output)
                    )
                    {
                        throw new InvalidOperationException(
                            "Vgrajevanje podnapisov v MKV ni uspelo."
                        );
                    }
                }
                else
                {
                    string assFile =
                        Path.Combine(
                            temporaryFolder,
                            "podnapisi.ass"
                        );

                    lblSubtitleStudioStatus.Text =
                        "Pripravljam videz podnapisov …";

                    List<string> subtitleArguments =
                        new List<string>();
                    subtitleArguments.Add("-y");
                    subtitleArguments.Add("-hide_banner");
                    subtitleArguments.Add("-loglevel");
                    subtitleArguments.Add("warning");
                    subtitleArguments.Add("-i");
                    subtitleArguments.Add(normalizedSubtitle);
                    subtitleArguments.Add("-c:s");
                    subtitleArguments.Add("ass");
                    subtitleArguments.Add(assFile);

                    int subtitleResult =
                        await RunStandaloneProcessAsync(
                            ffmpeg,
                            subtitleArguments,
                            "PODNAPISI"
                        );

                    if (
                        subtitleResult != 0 ||
                        !File.Exists(assFile)
                    )
                    {
                        throw new InvalidOperationException(
                            "Pretvorba podnapisov v ASS ni uspela."
                        );
                    }

                    ApplyTransparentAssBackground(
                        assFile,
                        Convert.ToInt32(
                            numSubtitleStudioOpacity.Value
                        ),
                        Convert.ToInt32(
                            numSubtitleStudioFontSize.Value
                        ),
                        Convert.ToInt32(
                            numSubtitleStudioMarginV.Value
                        ),
                        subtitleStudioTextColor,
                        Convert.ToInt32(numSubtitleStudioSafeWidth.Value)
                    );

                    int threads =
                        GetSubtitleStudioThreadCount();

                    List<string> burnArguments =
                        new List<string>();
                    burnArguments.Add("-y");
                    burnArguments.Add("-hide_banner");
                    burnArguments.Add("-loglevel");
                    burnArguments.Add("warning");
                    burnArguments.Add("-filter_threads");
                    burnArguments.Add(threads.ToString());
                    burnArguments.Add("-fflags");
                    burnArguments.Add("+genpts");
                    burnArguments.Add("-i");
                    burnArguments.Add(video);
                    burnArguments.Add("-map");
                    burnArguments.Add("0:v:0");
                    burnArguments.Add("-map");
                    burnArguments.Add("0:a:0?");
                    burnArguments.Add("-vf");
                    burnArguments.Add(
                        "ass='" +
                        EscapeSubtitleFilterPath(
                            assFile
                        ) +
                        "'"
                    );
                    burnArguments.Add("-c:v");
                    burnArguments.Add("libx264");
                    burnArguments.Add("-preset");
                    burnArguments.Add(
                        GetSubtitleStudioPreset()
                    );
                    burnArguments.Add("-threads");
                    burnArguments.Add(
                        threads.ToString()
                    );
                    burnArguments.Add("-crf");
                    burnArguments.Add("20");
                    burnArguments.Add("-pix_fmt");
                    burnArguments.Add("yuv420p");
                    burnArguments.Add("-c:a");
                    burnArguments.Add("aac");
                    burnArguments.Add("-b:a");
                    burnArguments.Add("160k");
                    burnArguments.Add("-movflags");
                    burnArguments.Add("+faststart");
                    burnArguments.Add("-progress");
                    burnArguments.Add("pipe:1");
                    burnArguments.Add("-nostats");
                    burnArguments.Add(output);

                    lblSubtitleStudioStatus.Text =
                        "Zapečenje poteka z " +
                        GetSubtitleStudioPowerPercent() +
                        " % moči in " +
                        threads +
                        " procesorskimi nitmi …";

                    Log(
                        "Zapečenje uporablja " +
                        GetSubtitleStudioPowerPercent() +
                        " % moči, " +
                        threads +
                        " niti in nastavitev " +
                        GetSubtitleStudioPreset() +
                        ".",
                        "PODNAPISI"
                    );

                    int burnResult =
                        await RunStandaloneProgressProcessAsync(
                            ffmpeg,
                            burnArguments,
                            "PODNAPISI",
                            duration,
                            GetSubtitleStudioPriority()
                        );

                    if (
                        burnResult != 0 ||
                        !File.Exists(output)
                    )
                    {
                        throw new InvalidOperationException(
                            "Zapečenje podnapisov v MP4 ni uspelo."
                        );
                    }
                }

                UpdateSubtitleStudioProgress(
                    100.0,
                    subtitleStudioLastElapsed,
                    TimeSpan.Zero,
                    ""
                );
                lblSubtitleStudioStatus.Text =
                    "Končano: " + output;
                Log(
                    "Končna datoteka: " + output,
                    "PODNAPISI"
                );

                MessageBox.Show(
                    this,
                    "Obdelava podnapisov je končana.\r\n\r\n" +
                    output,
                    "Končano",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
            }
            catch (Exception e)
            {
                lblSubtitleStudioStatus.Text =
                    "Napaka: " + e.Message;
                ShowError(
                    "Obdelava podnapisov ni uspela.",
                    e
                );
            }
            finally
            {
                actionButton.Enabled = true;

                try
                {
                    if (
                        Directory.Exists(
                            temporaryFolder
                        )
                    )
                    {
                        Directory.Delete(
                            temporaryFolder,
                            true
                        );
                    }
                }
                catch
                {
                }
            }
        }

        private async Task<double>
            ReadStandaloneDurationAsync(
                string ffprobe,
                string input
            )
        {
            return await Task.Run(
                delegate
                {
                    try
                    {
                        ProcessStartInfo info =
                            new ProcessStartInfo();
                        info.FileName = ffprobe;
                        info.Arguments =
                            ToolLocator.JoinArguments(
                                new string[]
                                {
                                    "-v",
                                    "error",
                                    "-show_entries",
                                    "format=duration",
                                    "-of",
                                    "default=noprint_wrappers=1:nokey=1",
                                    input
                                }
                            );
                        info.UseShellExecute = false;
                        ToolLocator.ConfigureUtf8Process(info);
                        info.CreateNoWindow = true;
                        info.RedirectStandardOutput = true;
                        info.RedirectStandardError = true;
                        info.StandardOutputEncoding =
                            Encoding.UTF8;

                        using (
                            Process process =
                                Process.Start(info)
                        )
                        {
                            string outputText =
                                process.StandardOutput.ReadToEnd();
                            process.WaitForExit();

                            double duration;
                            if (
                                double.TryParse(
                                    outputText.Trim(),
                                    System.Globalization.NumberStyles.Float,
                                    System.Globalization.CultureInfo.InvariantCulture,
                                    out duration
                                )
                            )
                            {
                                return duration;
                            }
                        }
                    }
                    catch
                    {
                    }

                    return 0.0;
                }
            );
        }

        private Task<int>
            RunStandaloneProgressProcessAsync(
                string executable,
                IEnumerable<string> arguments,
                string prefix,
                double duration,
                ProcessPriorityClass priority
            )
        {
            TaskCompletionSource<int> completion =
                new TaskCompletionSource<int>();

            ProcessStartInfo info =
                new ProcessStartInfo();
            info.FileName = executable;
            info.Arguments =
                ToolLocator.JoinArguments(arguments);
            info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
            // FFplay je SDL grafični program. Skrit zagon lahko na nekaterih
            // sistemih povzroči, da se njegovo okno takoj zapre. Zato ga
            // zaženemo normalno, nato pa ga brez roba vgradimo v predogled.
            info.CreateNoWindow = false;
            info.WindowStyle =
                ProcessWindowStyle.Normal;
            info.RedirectStandardOutput = true;
            info.RedirectStandardError = true;
            info.StandardOutputEncoding =
                Encoding.UTF8;
            info.StandardErrorEncoding =
                Encoding.UTF8;

            Process process =
                new Process();
            process.StartInfo = info;
            process.EnableRaisingEvents = true;

            Stopwatch stopwatch =
                Stopwatch.StartNew();
            string speed = "";
            int processExited = 0;
            int outputClosed = 0;
            int errorClosed = 0;
            int exitCode = -1;

            Action tryComplete = delegate
            {
                if (
                    Interlocked.CompareExchange(
                        ref processExited,
                        0,
                        0
                    ) == 1 &&
                    Interlocked.CompareExchange(
                        ref outputClosed,
                        0,
                        0
                    ) == 1 &&
                    Interlocked.CompareExchange(
                        ref errorClosed,
                        0,
                        0
                    ) == 1
                )
                {
                    stopwatch.Stop();
                    completion.TrySetResult(
                        exitCode
                    );
                }
            };

            process.OutputDataReceived += delegate(
                object sender,
                DataReceivedEventArgs e
            )
            {
                if (e.Data == null)
                {
                    Interlocked.Exchange(
                        ref outputClosed,
                        1
                    );
                    tryComplete();
                    return;
                }

                string line = e.Data.Trim();

                if (
                    line.StartsWith(
                        "speed=",
                        StringComparison.Ordinal
                    )
                )
                {
                    speed = line.Substring(6);
                    return;
                }

                if (
                    line.StartsWith(
                        "out_time_us=",
                        StringComparison.Ordinal
                    ) ||
                    line.StartsWith(
                        "out_time_ms=",
                        StringComparison.Ordinal
                    )
                )
                {
                    int equals = line.IndexOf('=');
                    long value;

                    if (
                        equals >= 0 &&
                        long.TryParse(
                            line.Substring(equals + 1),
                            out value
                        )
                    )
                    {
                        double seconds =
                            value / 1000000.0;
                        double percent =
                            duration > 0.0
                                ? Math.Max(
                                    0.0,
                                    Math.Min(
                                        99.9,
                                        seconds /
                                        duration *
                                        100.0
                                    )
                                )
                                : 0.0;

                        TimeSpan remaining =
                            TimeSpan.MaxValue;

                        if (
                            percent > 0.2 &&
                            seconds > 0.0 &&
                            duration > seconds
                        )
                        {
                            double remainingSeconds =
                                stopwatch.Elapsed.TotalSeconds *
                                (duration - seconds) /
                                seconds;

                            if (
                                remainingSeconds >= 0.0 &&
                                remainingSeconds <
                                TimeSpan.MaxValue.TotalSeconds
                            )
                            {
                                remaining =
                                    TimeSpan.FromSeconds(
                                        remainingSeconds
                                    );
                            }
                        }

                        UpdateSubtitleStudioProgress(
                            percent,
                            stopwatch.Elapsed,
                            remaining,
                            speed
                        );
                    }

                    return;
                }

                if (
                    string.Equals(
                        line,
                        "progress=end",
                        StringComparison.Ordinal
                    )
                )
                {
                    UpdateSubtitleStudioProgress(
                        100.0,
                        stopwatch.Elapsed,
                        TimeSpan.Zero,
                        speed
                    );
                    return;
                }

                if (!IsFfmpegTechnicalLine(line))
                {
                    Log(line, prefix);
                }
            };

            process.ErrorDataReceived += delegate(
                object sender,
                DataReceivedEventArgs e
            )
            {
                if (e.Data == null)
                {
                    Interlocked.Exchange(
                        ref errorClosed,
                        1
                    );
                    tryComplete();
                    return;
                }

                if (
                    !string.IsNullOrWhiteSpace(
                        e.Data
                    ) &&
                    !IsFfmpegTechnicalLine(
                        e.Data
                    )
                )
                {
                    Log(e.Data, prefix);
                }
            };

            process.Exited += delegate
            {
                try
                {
                    exitCode =
                        process.ExitCode;
                }
                catch
                {
                    exitCode = -1;
                }

                Interlocked.Exchange(
                    ref processExited,
                    1
                );
                tryComplete();
            };

            try
            {
                if (!process.Start())
                {
                    throw new InvalidOperationException(
                        "Procesa ni bilo mogoče zagnati."
                    );
                }

                try
                {
                    process.PriorityClass = priority;
                }
                catch
                {
                }

                process.BeginOutputReadLine();
                process.BeginErrorReadLine();
            }
            catch (Exception e)
            {
                stopwatch.Stop();
                completion.TrySetException(e);
            }

            return completion.Task.ContinueWith(
                delegate(Task<int> task)
                {
                    try
                    {
                        process.Dispose();
                    }
                    catch
                    {
                    }

                    return task.GetAwaiter().GetResult();
                }
            );
        }

        private void OpenTimedSubtitleText()
        {
            OpenFileDialog dialog = new OpenFileDialog();
            dialog.Title =
                "Odpri besedilo ali podnapisno datoteko";
            dialog.Filter =
                "Podnapisi in besedilo|*.txt;*.srt;*.vtt;*.ass;*.ssa|Besedilo|*.txt|Podnapisi|*.srt;*.vtt;*.ass;*.ssa|Vse datoteke|*.*";

            if (dialog.ShowDialog(this) != DialogResult.OK)
            {
                return;
            }

            LoadTimedSubtitleFile(dialog.FileName);
        }

        private void LoadTimedSubtitleFile(
            string fileName
        )
        {
            if (
                string.IsNullOrWhiteSpace(fileName) ||
                !File.Exists(fileName)
            )
            {
                return;
            }

            string extension =
                Path.GetExtension(fileName)
                .ToLowerInvariant();

            string[] supported =
                new string[]
                {
                    ".txt",
                    ".srt",
                    ".vtt",
                    ".ass",
                    ".ssa"
                };

            if (
                !supported.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                MessageBox.Show(
                    this,
                    "Podprte so datoteke TXT, SRT, VTT, ASS in SSA.",
                    "Nepodprta datoteka",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            timedSubtitleLoadedPath = fileName;
            txtTimedSubtitleSource.Text =
                File.ReadAllText(
                    fileName,
                    Encoding.UTF8
                );

            txtTimedSubtitleOutput.Text =
                Path.Combine(
                    Path.GetDirectoryName(fileName),
                    Path.GetFileNameWithoutExtension(fileName) +
                    " - pretvorjeno" +
                    GetTimedSubtitleExtension()
                );

            lblTimedSubtitleStatus.Text =
                "Naloženo: " +
                Path.GetFileName(fileName);
        }

        private void TimedSubtitleSourceDragEnter(
            object sender,
            DragEventArgs e
        )
        {
            if (
                e.Data != null &&
                e.Data.GetDataPresent(
                    DataFormats.FileDrop
                )
            )
            {
                e.Effect = DragDropEffects.Copy;
            }
            else
            {
                e.Effect = DragDropEffects.None;
            }
        }

        private void TimedSubtitleSourceDragDrop(
            object sender,
            DragEventArgs e
        )
        {
            if (
                e.Data == null ||
                !e.Data.GetDataPresent(
                    DataFormats.FileDrop
                )
            )
            {
                return;
            }

            string[] files =
                e.Data.GetData(
                    DataFormats.FileDrop
                ) as string[];

            if (files != null && files.Length > 0)
            {
                LoadTimedSubtitleFile(files[0]);
            }
        }

        private string GetTimedSubtitleExtension()
        {
            if (cmbTimedSubtitleFormat == null)
            {
                return ".srt";
            }

            switch (cmbTimedSubtitleFormat.SelectedIndex)
            {
                case 1:
                    return ".vtt";
                case 2:
                    return ".ass";
                case 3:
                    return ".ssa";
                default:
                    return ".srt";
            }
        }

        private string GetTimedSubtitleCodec()
        {
            if (cmbTimedSubtitleFormat == null)
            {
                return "subrip";
            }

            switch (cmbTimedSubtitleFormat.SelectedIndex)
            {
                case 1:
                    return "webvtt";
                case 2:
                    return "ass";
                case 3:
                    return "ssa";
                default:
                    return "subrip";
            }
        }

        private void UpdateTimedSubtitleOutputExtension()
        {
            if (
                txtTimedSubtitleOutput == null ||
                string.IsNullOrWhiteSpace(
                    txtTimedSubtitleOutput.Text
                )
            )
            {
                return;
            }

            txtTimedSubtitleOutput.Text =
                Path.ChangeExtension(
                    txtTimedSubtitleOutput.Text,
                    GetTimedSubtitleExtension()
                );
        }

        private void ChooseTimedSubtitleOutput()
        {
            SaveFileDialog dialog =
                new SaveFileDialog();

            string extension =
                GetTimedSubtitleExtension();

            dialog.Title = "Shrani podnapise";
            dialog.DefaultExt =
                extension.TrimStart('.');
            dialog.Filter =
                "Izbrani podnapisi|*" +
                extension +
                "|Vse datoteke|*.*";

            if (
                !string.IsNullOrWhiteSpace(
                    txtTimedSubtitleOutput.Text
                )
            )
            {
                dialog.FileName =
                    Path.GetFileName(
                        txtTimedSubtitleOutput.Text
                    );

                string folder =
                    Path.GetDirectoryName(
                        txtTimedSubtitleOutput.Text
                    );

                if (
                    !string.IsNullOrWhiteSpace(folder) &&
                    Directory.Exists(folder)
                )
                {
                    dialog.InitialDirectory = folder;
                }
            }

            if (dialog.ShowDialog(this) == DialogResult.OK)
            {
                txtTimedSubtitleOutput.Text =
                    Path.ChangeExtension(
                        dialog.FileName,
                        extension
                    );
            }
        }

        private string DetectTimedSubtitleSourceExtension(
            string source
        )
        {
            string text =
                (source ?? "")
                .TrimStart(
                    '\uFEFF',
                    ' ',
                    '\t',
                    '\r',
                    '\n'
                );

            if (
                text.StartsWith(
                    "WEBVTT",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                return ".vtt";
            }

            if (
                text.IndexOf(
                    "[V4+ Styles]",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0
            )
            {
                return ".ass";
            }

            if (
                text.IndexOf(
                    "[V4 Styles]",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0
            )
            {
                return ".ssa";
            }

            if (
                Regex.IsMatch(
                    text,
                    @"(?m)^\s*(?:\d+\s*[\r\n]+\s*)?\d{2}:\d{2}:\d{2}[,.]\d{3}\s+-->"
                )
            )
            {
                return ".srt";
            }

            return ".txt";
        }

        private async Task ConvertTimedSubtitleAsync(
            Button actionButton
        )
        {
            string sourceText =
                txtTimedSubtitleSource.Text;

            if (string.IsNullOrWhiteSpace(sourceText))
            {
                MessageBox.Show(
                    this,
                    "Najprej prilepi besedilo ali odpri oziroma spusti podnapisno datoteko.",
                    "Ni vsebine",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            string output =
                txtTimedSubtitleOutput.Text.Trim();

            if (string.IsNullOrWhiteSpace(output))
            {
                ChooseTimedSubtitleOutput();
                output =
                    txtTimedSubtitleOutput.Text.Trim();

                if (string.IsNullOrWhiteSpace(output))
                {
                    return;
                }
            }

            string targetExtension =
                GetTimedSubtitleExtension();

            output =
                Path.ChangeExtension(
                    output,
                    targetExtension
                );
            output = GetUniquePath(output);
            txtTimedSubtitleOutput.Text = output;

            actionButton.Enabled = false;
            lblTimedSubtitleStatus.Text =
                "Pretvarjanje poteka …";

            string temporaryFolder =
                Path.Combine(
                    AppPaths.WorkFolder,
                    "TimedSubtitle_" +
                    Guid.NewGuid().ToString("N")
                );

            try
            {
                Directory.CreateDirectory(
                    temporaryFolder
                );

                string sourceExtension =
                    DetectTimedSubtitleSourceExtension(
                        sourceText
                    );

                if (sourceExtension == ".txt")
                {
                    List<Tuple<TimeSpan, string>> captions =
                        ParseTimedSubtitleText(
                            sourceText
                        );

                    if (captions.Count == 0)
                    {
                        throw new InvalidOperationException(
                            "Nobena vrstica ni bila prepoznana. Uporabi obliko 00:38 - Besedilo ali odpri veljavno SRT, VTT, ASS oziroma SSA datoteko."
                        );
                    }

                    captions =
                        captions.OrderBy(
                            delegate(
                                Tuple<TimeSpan, string> caption
                            )
                            {
                                return caption.Item1;
                            }
                        ).ToList();

                    File.WriteAllText(
                        output,
                        BuildTimedSubtitleContent(
                            captions,
                            targetExtension
                        ),
                        new UTF8Encoding(true)
                    );
                }
                else
                {
                    string ffmpeg =
                        ToolLocator.FindFfmpeg();

                    if (string.IsNullOrWhiteSpace(ffmpeg))
                    {
                        throw new InvalidOperationException(
                            "Za urejanje obstoječe podnapisne datoteke na 42 znakov na vrstico je potreben FFmpeg."
                        );
                    }

                    string temporaryInput =
                        Path.Combine(
                            temporaryFolder,
                            "vhod" +
                            sourceExtension
                        );
                    string rawSrt =
                        Path.Combine(
                            temporaryFolder,
                            "vhod_raw.srt"
                        );
                    string normalizedSrt =
                        Path.Combine(
                            temporaryFolder,
                            "vhod_42x2.srt"
                        );

                    File.WriteAllText(
                        temporaryInput,
                        sourceText,
                        new UTF8Encoding(true)
                    );

                    if (
                        string.Equals(
                            sourceExtension,
                            ".srt",
                            StringComparison.OrdinalIgnoreCase
                        )
                    )
                    {
                        File.Copy(
                            temporaryInput,
                            rawSrt,
                            true
                        );
                    }
                    else
                    {
                        List<string> toSrtArguments =
                            new List<string>();
                        toSrtArguments.Add("-y");
                        toSrtArguments.Add("-hide_banner");
                        toSrtArguments.Add("-loglevel");
                        toSrtArguments.Add("warning");
                        toSrtArguments.Add("-i");
                        toSrtArguments.Add(temporaryInput);
                        toSrtArguments.Add("-map");
                        toSrtArguments.Add("0:0");
                        toSrtArguments.Add("-c:s");
                        toSrtArguments.Add("srt");
                        toSrtArguments.Add(rawSrt);

                        int toSrtExit =
                            await RunStandaloneProcessAsync(
                                ffmpeg,
                                toSrtArguments,
                                "PODNAPISI 42"
                            );

                        if (
                            toSrtExit != 0 ||
                            !File.Exists(rawSrt)
                        )
                        {
                            throw new InvalidOperationException(
                                "Podnapisov ni bilo mogoče pripraviti za omejitev 42 znakov na vrstico."
                            );
                        }
                    }

                    NormalizeSrtFileToFortyTwoCharacters(
                        rawSrt,
                        normalizedSrt
                    );

                    if (
                        string.Equals(
                            targetExtension,
                            ".srt",
                            StringComparison.OrdinalIgnoreCase
                        )
                    )
                    {
                        File.Copy(
                            normalizedSrt,
                            output,
                            true
                        );
                    }
                    else
                    {
                        List<string> arguments =
                            new List<string>();
                        arguments.Add("-y");
                        arguments.Add("-hide_banner");
                        arguments.Add("-loglevel");
                        arguments.Add("warning");
                        arguments.Add("-i");
                        arguments.Add(normalizedSrt);
                        arguments.Add("-map");
                        arguments.Add("0:0");
                        arguments.Add("-c:s");
                        arguments.Add(
                            GetTimedSubtitleCodec()
                        );
                        arguments.Add(output);

                        int exitCode =
                            await RunStandaloneProcessAsync(
                                ffmpeg,
                                arguments,
                                "PODNAPISI FORMAT"
                            );

                        if (
                            exitCode != 0 ||
                            !File.Exists(output)
                        )
                        {
                            throw new InvalidOperationException(
                                "FFmpeg ni mogel pretvoriti podnapisov v izbrani format."
                            );
                        }
                    }
                }
                lblTimedSubtitleStatus.Text =
                    "Končano: " + output;

                Log(
                    "Podnapisi so shranjeni: " +
                    output,
                    "PODNAPISI FORMAT"
                );

                MessageBox.Show(
                    this,
                    "Podnapisi so uspešno ustvarjeni oziroma pretvorjeni.\r\n\r\n" +
                    output,
                    "Končano",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
            }
            catch (Exception e)
            {
                lblTimedSubtitleStatus.Text =
                    "Napaka: " + e.Message;

                ShowError(
                    "Pretvorba podnapisov ni uspela.",
                    e
                );
            }
            finally
            {
                actionButton.Enabled = true;

                try
                {
                    if (Directory.Exists(temporaryFolder))
                    {
                        Directory.Delete(
                            temporaryFolder,
                            true
                        );
                    }
                }
                catch
                {
                }
            }
        }

        private string CleanSubtitleTextForWrapping(
            string text
        )
        {
            string clean = text ?? "";

            clean = clean
                .Replace("\\N", " ")
                .Replace("\\n", " ")
                .Replace("\r\n", " ")
                .Replace("\r", " ")
                .Replace("\n", " ");

            clean = Regex.Replace(
                clean,
                @"\{\\[^}]*\}",
                ""
            );
            clean = Regex.Replace(
                clean,
                @"<[^>]+>",
                ""
            );

            try
            {
                clean =
                    System.Net.WebUtility.HtmlDecode(
                        clean
                    );
            }
            catch
            {
            }

            clean = Regex.Replace(
                clean,
                @"\s+",
                " "
            ).Trim();

            return clean;
        }

        private List<string> WrapSubtitleTextToFortyTwoCharacters(
            string text
        )
        {
            string clean =
                CleanSubtitleTextForWrapping(
                    text
                );

            List<string> segments =
                new List<string>();

            if (clean.Length == 0)
            {
                return segments;
            }

            List<string> lines =
                new List<string>();
            string currentLine = "";

            string[] words = Regex.Split(
                clean,
                @"\s+"
            );

            foreach (string originalWord in words)
            {
                string word = originalWord.Trim();

                if (word.Length == 0)
                {
                    continue;
                }

                if (word.Length > SubtitleMaxCharactersPerLine)
                {
                    if (currentLine.Length > 0)
                    {
                        lines.Add(currentLine);
                        currentLine = "";
                    }

                    string remaining = word;

                    while (
                        remaining.Length >
                        SubtitleMaxCharactersPerLine
                    )
                    {
                        lines.Add(
                            remaining.Substring(
                                0,
                                SubtitleMaxCharactersPerLine
                            )
                        );
                        remaining =
                            remaining.Substring(
                                SubtitleMaxCharactersPerLine
                            );
                    }

                    currentLine = remaining;
                    continue;
                }

                string candidate =
                    currentLine.Length == 0
                        ? word
                        : currentLine + " " + word;

                if (
                    candidate.Length <=
                    SubtitleMaxCharactersPerLine
                )
                {
                    currentLine = candidate;
                }
                else
                {
                    if (currentLine.Length > 0)
                    {
                        lines.Add(currentLine);
                    }

                    currentLine = word;
                }
            }

            if (currentLine.Length > 0)
            {
                lines.Add(currentLine);
            }

            int linesPerCue = Math.Max(
                1,
                SubtitleMaxCharactersPerCue /
                SubtitleMaxCharactersPerLine
            );

            for (
                int index = 0;
                index < lines.Count;
                index += linesPerCue
            )
            {
                List<string> cueLines =
                    lines.Skip(index)
                    .Take(linesPerCue)
                    .ToList();

                segments.Add(
                    string.Join(
                        Environment.NewLine,
                        cueLines.ToArray()
                    )
                );
            }

            return segments;
        }

        private List<Tuple<TimeSpan, TimeSpan, string>>
            NormalizeSubtitleCuesToFortyTwoCharacters(
                List<Tuple<TimeSpan, TimeSpan, string>> cues
            )
        {
            List<Tuple<TimeSpan, TimeSpan, string>> result =
                new List<Tuple<TimeSpan, TimeSpan, string>>();

            foreach (
                Tuple<TimeSpan, TimeSpan, string> cue
                in cues
            )
            {
                List<string> segments =
                    WrapSubtitleTextToFortyTwoCharacters(
                        cue.Item3
                    );

                if (segments.Count == 0)
                {
                    continue;
                }

                TimeSpan start = cue.Item1;
                TimeSpan end = cue.Item2;

                if (end <= start)
                {
                    end =
                        start +
                        TimeSpan.FromSeconds(2);
                }

                long durationTicks =
                    (end - start).Ticks;

                for (
                    int index = 0;
                    index < segments.Count;
                    index++
                )
                {
                    TimeSpan segmentStart =
                        start +
                        TimeSpan.FromTicks(
                            durationTicks *
                            index /
                            segments.Count
                        );

                    TimeSpan segmentEnd =
                        start +
                        TimeSpan.FromTicks(
                            durationTicks *
                            (index + 1) /
                            segments.Count
                        );

                    if (segmentEnd <= segmentStart)
                    {
                        segmentEnd =
                            segmentStart +
                            TimeSpan.FromMilliseconds(1);
                    }

                    result.Add(
                        Tuple.Create(
                            segmentStart,
                            segmentEnd,
                            segments[index]
                        )
                    );
                }
            }

            return result;
        }

        private bool TryParseSrtTimestamp(
            string value,
            out TimeSpan result
        )
        {
            result = TimeSpan.Zero;

            Match match = Regex.Match(
                value ?? "",
                @"^\s*(?<h>\d{1,3}):(?<m>\d{2}):(?<s>\d{2})[,.](?<ms>\d{3})\s*$"
            );

            if (!match.Success)
            {
                return false;
            }

            int hours;
            int minutes;
            int seconds;
            int milliseconds;

            if (
                !int.TryParse(
                    match.Groups["h"].Value,
                    out hours
                ) ||
                !int.TryParse(
                    match.Groups["m"].Value,
                    out minutes
                ) ||
                !int.TryParse(
                    match.Groups["s"].Value,
                    out seconds
                ) ||
                !int.TryParse(
                    match.Groups["ms"].Value,
                    out milliseconds
                )
            )
            {
                return false;
            }

            result = new TimeSpan(
                0,
                hours,
                minutes,
                seconds,
                milliseconds
            );

            return true;
        }

        private List<Tuple<TimeSpan, TimeSpan, string>>
            ParseSrtCues(
                string content
            )
        {
            List<Tuple<TimeSpan, TimeSpan, string>> cues =
                new List<Tuple<TimeSpan, TimeSpan, string>>();

            string normalized =
                (content ?? "")
                .Replace("\r\n", "\n")
                .Replace('\r', '\n')
                .Trim();

            if (normalized.Length == 0)
            {
                return cues;
            }

            string[] blocks = Regex.Split(
                normalized,
                @"\n\s*\n"
            );

            foreach (string block in blocks)
            {
                string[] lines =
                    block.Split('\n');
                int timingIndex = -1;
                Match timingMatch = null;

                for (
                    int index = 0;
                    index < lines.Length;
                    index++
                )
                {
                    Match candidate = Regex.Match(
                        lines[index],
                        @"^\s*(?<start>\d{1,3}:\d{2}:\d{2}[,.]\d{3})\s*-->\s*(?<end>\d{1,3}:\d{2}:\d{2}[,.]\d{3})"
                    );

                    if (candidate.Success)
                    {
                        timingIndex = index;
                        timingMatch = candidate;
                        break;
                    }
                }

                if (
                    timingIndex < 0 ||
                    timingMatch == null
                )
                {
                    continue;
                }

                TimeSpan start;
                TimeSpan end;

                if (
                    !TryParseSrtTimestamp(
                        timingMatch.Groups["start"].Value,
                        out start
                    ) ||
                    !TryParseSrtTimestamp(
                        timingMatch.Groups["end"].Value,
                        out end
                    )
                )
                {
                    continue;
                }

                string text = string.Join(
                    Environment.NewLine,
                    lines.Skip(timingIndex + 1).ToArray()
                );

                cues.Add(
                    Tuple.Create(
                        start,
                        end,
                        text
                    )
                );
            }

            return cues;
        }

        private void NormalizeSrtFileToFortyTwoCharacters(
            string inputFile,
            string outputFile
        )
        {
            List<Tuple<TimeSpan, TimeSpan, string>> cues =
                ParseSrtCues(
                    File.ReadAllText(
                        inputFile,
                        Encoding.UTF8
                    )
                );

            cues =
                NormalizeSubtitleCuesToFortyTwoCharacters(
                    cues
                );

            if (cues.Count == 0)
            {
                throw new InvalidDataException(
                    "Podnapisov ni bilo mogoče prepoznati za omejitev 42 znakov na vrstico."
                );
            }

            File.WriteAllText(
                outputFile,
                BuildSrtContent(cues),
                new UTF8Encoding(true)
            );
        }

        private string BuildTimedSubtitleContent(
            List<Tuple<TimeSpan, string>> captions,
            string extension
        )
        {
            List<Tuple<TimeSpan, TimeSpan, string>> cues =
                BuildTimedSubtitleCues(captions);

            switch (extension.ToLowerInvariant())
            {
                case ".vtt":
                    return BuildVttContent(cues);
                case ".ass":
                    return BuildAssContent(cues, true);
                case ".ssa":
                    return BuildAssContent(cues, false);
                default:
                    return BuildSrtContent(cues);
            }
        }

        private List<Tuple<TimeSpan, TimeSpan, string>>
            BuildTimedSubtitleCues(
                List<Tuple<TimeSpan, string>> captions
            )
        {
            List<Tuple<TimeSpan, TimeSpan, string>> cues =
                new List<Tuple<TimeSpan, TimeSpan, string>>();

            for (int index = 0; index < captions.Count; index++)
            {
                TimeSpan start =
                    captions[index].Item1;
                TimeSpan end;

                if (index + 1 < captions.Count)
                {
                    end =
                        captions[index + 1].Item1 -
                        TimeSpan.FromMilliseconds(100);

                    if (
                        end <=
                        start +
                        TimeSpan.FromMilliseconds(400)
                    )
                    {
                        end =
                            start +
                            TimeSpan.FromSeconds(2);
                    }
                }
                else
                {
                    end =
                        start +
                        TimeSpan.FromSeconds(
                            Convert.ToDouble(
                                numLastSubtitleSeconds.Value
                            )
                        );
                }

                cues.Add(
                    Tuple.Create(
                        start,
                        end,
                        captions[index].Item2
                    )
                );
            }

            return
                NormalizeSubtitleCuesToFortyTwoCharacters(
                    cues
                );
        }

        private string BuildSrtContent(
            List<Tuple<TimeSpan, TimeSpan, string>> cues
        )
        {
            StringBuilder result = new StringBuilder();

            for (int index = 0; index < cues.Count; index++)
            {
                result.AppendLine(
                    (index + 1).ToString()
                );
                result.AppendLine(
                    FormatSrtTime(cues[index].Item1) +
                    " --> " +
                    FormatSrtTime(cues[index].Item2)
                );
                result.AppendLine(cues[index].Item3);
                result.AppendLine();
            }

            return result.ToString();
        }

        private string BuildVttContent(
            List<Tuple<TimeSpan, TimeSpan, string>> cues
        )
        {
            StringBuilder result = new StringBuilder();
            result.AppendLine("WEBVTT");
            result.AppendLine();

            for (int index = 0; index < cues.Count; index++)
            {
                result.AppendLine(
                    (index + 1).ToString()
                );
                result.AppendLine(
                    FormatVttTime(cues[index].Item1) +
                    " --> " +
                    FormatVttTime(cues[index].Item2)
                );
                result.AppendLine(cues[index].Item3);
                result.AppendLine();
            }

            return result.ToString();
        }

        private string BuildAssContent(
            List<Tuple<TimeSpan, TimeSpan, string>> cues,
            bool advanced
        )
        {
            StringBuilder result = new StringBuilder();

            result.AppendLine("[Script Info]");
            result.AppendLine(
                advanced
                    ? "ScriptType: v4.00+"
                    : "ScriptType: v4.00"
            );
            result.AppendLine("PlayResX: 1920");
            result.AppendLine("PlayResY: 1080");
            result.AppendLine("ScaledBorderAndShadow: yes");
            result.AppendLine("WrapStyle: 0");
            result.AppendLine();

            if (advanced)
            {
                result.AppendLine("[V4+ Styles]");
                result.AppendLine(
                    "Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding"
                );
                result.AppendLine(
                    "Style: Default,Arial,46,&H00FFFFFF,&H00FFFFFF,&H20000000,&H60000000,0,0,0,0,100,100,0,0,1,2,1,2,170,170,120,1"
                );
                result.AppendLine();
                result.AppendLine("[Events]");
                result.AppendLine(
                    "Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text"
                );

                foreach (
                    Tuple<TimeSpan, TimeSpan, string> cue
                    in cues
                )
                {
                    result.AppendLine(
                        "Dialogue: 0," +
                        FormatAssTime(cue.Item1) +
                        "," +
                        FormatAssTime(cue.Item2) +
                        ",Default,,0,0,0,," +
                        EscapeAssText(cue.Item3)
                    );
                }
            }
            else
            {
                result.AppendLine("[V4 Styles]");
                result.AppendLine(
                    "Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, TertiaryColour, BackColour, Bold, Italic, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, AlphaLevel, Encoding"
                );
                result.AppendLine(
                    "Style: Default,Arial,46,16777215,16777215,0,0,0,0,1,2,1,2,170,170,120,0,1"
                );
                result.AppendLine();
                result.AppendLine("[Events]");
                result.AppendLine(
                    "Format: Marked, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text"
                );

                foreach (
                    Tuple<TimeSpan, TimeSpan, string> cue
                    in cues
                )
                {
                    result.AppendLine(
                        "Dialogue: Marked=0," +
                        FormatAssTime(cue.Item1) +
                        "," +
                        FormatAssTime(cue.Item2) +
                        ",Default,,0,0,0,," +
                        EscapeAssText(cue.Item3)
                    );
                }
            }

            return result.ToString();
        }

        private string FormatVttTime(
            TimeSpan time
        )
        {
            return
                Convert.ToInt32(
                    Math.Floor(time.TotalHours)
                ).ToString("00") +
                ":" +
                time.Minutes.ToString("00") +
                ":" +
                time.Seconds.ToString("00") +
                "." +
                time.Milliseconds.ToString("000");
        }

        private string FormatAssTime(
            TimeSpan time
        )
        {
            int hundredths =
                Convert.ToInt32(
                    Math.Round(
                        time.Milliseconds / 10.0
                    )
                );

            if (hundredths >= 100)
            {
                time =
                    time.Add(
                        TimeSpan.FromSeconds(1)
                    );
                hundredths = 0;
            }

            return
                Convert.ToInt32(
                    Math.Floor(time.TotalHours)
                ).ToString("0") +
                ":" +
                time.Minutes.ToString("00") +
                ":" +
                time.Seconds.ToString("00") +
                "." +
                hundredths.ToString("00");
        }

        private string EscapeAssText(
            string text
        )
        {
            return
                (text ?? "")
                .Replace("\\", "\\\\")
                .Replace("{", "\\{")
                .Replace("}", "\\}")
                .Replace("\r\n", "\\N")
                .Replace("\n", "\\N")
                .Replace("\r", "\\N");
        }

        private List<Tuple<TimeSpan, string>>
            ParseTimedSubtitleText(
                string source
            )
        {
            List<Tuple<TimeSpan, string>> result =
                new List<Tuple<TimeSpan, string>>();

            string[] lines =
                (source ?? "")
                .Replace("\r\n", "\n")
                .Replace('\r', '\n')
                .Split('\n');

            Match currentMatch = null;

            foreach (string rawLine in lines)
            {
                string line =
                    rawLine.Trim();

                if (line.Length == 0)
                {
                    continue;
                }

                Match match =
                    Regex.Match(
                        line,
                        @"^\s*(?:(?<h>\d{1,3}):)?(?<m>\d{1,2}):(?<s>\d{2})(?:[,.](?<ms>\d{1,3}))?\s*(?:-|–|—)\s*(?<text>.+?)\s*$"
                    );

                if (match.Success)
                {
                    int hours =
                        match.Groups["h"].Success
                            ? int.Parse(
                                match.Groups["h"].Value
                            )
                            : 0;
                    int minutes =
                        int.Parse(
                            match.Groups["m"].Value
                        );
                    int seconds =
                        int.Parse(
                            match.Groups["s"].Value
                        );
                    int milliseconds = 0;

                    if (
                        match.Groups["ms"].Success
                    )
                    {
                        string ms =
                            match.Groups["ms"].Value
                            .PadRight(3, '0')
                            .Substring(0, 3);
                        milliseconds =
                            int.Parse(ms);
                    }

                    TimeSpan start =
                        new TimeSpan(
                            0,
                            hours,
                            minutes,
                            seconds,
                            milliseconds
                        );

                    result.Add(
                        Tuple.Create(
                            start,
                            match.Groups["text"].Value.Trim()
                        )
                    );

                    currentMatch = match;
                }
                else if (
                    result.Count > 0 &&
                    currentMatch != null
                )
                {
                    Tuple<TimeSpan, string> previous =
                        result[result.Count - 1];

                    result[result.Count - 1] =
                        Tuple.Create(
                            previous.Item1,
                            previous.Item2 +
                            Environment.NewLine +
                            line
                        );
                }
            }

            return result;
        }

        private string FormatSrtTime(
            TimeSpan time
        )
        {
            if (time < TimeSpan.Zero)
            {
                time = TimeSpan.Zero;
            }

            int totalHours =
                Convert.ToInt32(
                    Math.Floor(
                        time.TotalHours
                    )
                );

            return
                totalHours.ToString("00") +
                ":" +
                time.Minutes.ToString("00") +
                ":" +
                time.Seconds.ToString("00") +
                "," +
                time.Milliseconds.ToString("000");
        }

