        private async Task RunConverterAsync(
            Button actionButton
        )
        {
            string[] files =
                txtConverterFiles.Text
                .Split(
                    new string[]
                    {
                        "\r\n",
                        "\n"
                    },
                    StringSplitOptions.RemoveEmptyEntries
                )
                .Select(
                    delegate(string value)
                    {
                        return value.Trim();
                    }
                )
                .Where(
                    delegate(string value)
                    {
                        return File.Exists(value);
                    }
                )
                .ToArray();

            if (files.Length == 0)
            {
                MessageBox.Show(
                    this,
                    "Najprej izberi najmanj eno veljavno datoteko.",
                    "Ni datotek",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            ConverterFormatOption option =
                GetSelectedConverterFormat();

            if (option == null)
            {
                MessageBox.Show(
                    this,
                    "Najprej izberi ciljni format.",
                    "Format ni izbran",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            string supportReason;

            if (
                !IsConverterFormatSupported(
                    option,
                    out supportReason
                )
            )
            {
                MessageBox.Show(
                    this,
                    supportReason,
                    "Format ni podprt",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            foreach (string input in files)
            {
                string compatibilityReason;

                if (
                    !IsConverterCombinationAllowed(
                        input,
                        option,
                        out compatibilityReason
                    )
                )
                {
                    MessageBox.Show(
                        this,
                        Path.GetFileName(input) +
                        "\r\n\r\n" +
                        compatibilityReason,
                        "Pretvorba ni smiselna",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Warning
                    );
                    return;
                }
            }

            string outputFolder =
                txtConverterFolder.Text.Trim();

            if (
                string.IsNullOrWhiteSpace(
                    outputFolder
                )
            )
            {
                outputFolder =
                    Path.GetDirectoryName(
                        files[0]
                    );
                txtConverterFolder.Text =
                    outputFolder;
            }

            Directory.CreateDirectory(
                outputFolder
            );

            bool specialConversion =
                IsSpecialConverterOption(option);

            string ffmpeg =
                specialConversion
                    ? ""
                    : ToolLocator.FindFfmpeg();

            if (!specialConversion && string.IsNullOrWhiteSpace(ffmpeg))
            {
                MessageBox.Show(
                    this,
                    "FFmpeg ni najden. Odpri »Orodja in nastavitve« in namesti orodja.",
                    "FFmpeg ni nameščen",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            actionButton.Enabled = false;
            btnConverterFormatCatalog.Enabled =
                false;
            cmbConverterFormat.Enabled =
                false;
            int successful = 0;

            try
            {
                for (
                    int index = 0;
                    index < files.Length;
                    index++
                )
                {
                    string input =
                        files[index];

                    lblConverterStatus.Text =
                        "Pretvarjam " +
                        (index + 1) +
                        "/" +
                        files.Length +
                        ": " +
                        Path.GetFileName(input);

                    string output =
                        GetUniquePath(
                            Path.Combine(
                                outputFolder,
                                SanitizeFileName(
                                    Path.GetFileNameWithoutExtension(
                                        input
                                    )
                                ) +
                                " - " +
                                SanitizeFileName(
                                    option.Id
                                ) +
                                option.Extension
                            )
                        );

                    List<string> arguments =
                        specialConversion
                            ? new List<string>()
                            : BuildConverterArguments(
                                input,
                                output,
                                option
                            );

                    Log(
                        "Pretvarjam: " +
                        Path.GetFileName(input) +
                        " → " +
                        Path.GetFileName(output) +
                        " (" +
                        option.Extension +
                        " " +
                        option.Name +
                        ")",
                        "PRETVORNIK"
                    );

                    int result =
                        specialConversion
                            ? await RunSpecialConverterAsync(
                                input,
                                output,
                                option
                            )
                            : await RunStandaloneProcessAsync(
                                ffmpeg,
                                arguments,
                                "PRETVORNIK"
                            );

                    if (
                        result != 0 ||
                        !File.Exists(output)
                    )
                    {
                        throw new InvalidOperationException(
                            "Pretvorba ni uspela za datoteko:\r\n" +
                            input +
                            "\r\n\r\nCiljni format: " +
                            option.Extension +
                            " " +
                            option.Name +
                            "\r\nKoda FFmpeg: " +
                            result
                        );
                    }

                    successful++;
                    Log(
                        "Končano: " +
                        output,
                        "PRETVORNIK"
                    );
                }

                lblConverterStatus.Text =
                    "Končano: " +
                    successful +
                    "/" +
                    files.Length +
                    " datotek.";

                MessageBox.Show(
                    this,
                    "Pretvorba je končana.\r\n\r\n" +
                    "Uspešno: " +
                    successful +
                    " od " +
                    files.Length,
                    "Pretvorba končana",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
            }
            catch (Exception e)
            {
                lblConverterStatus.Text =
                    "Napaka: " + e.Message;
                ShowError(
                    "Pretvorba datoteke ni uspela.",
                    e
                );
            }
            finally
            {
                actionButton.Enabled = true;
                btnConverterFormatCatalog.Enabled =
                    true;
                cmbConverterFormat.Enabled =
                    true;
            }
        }

        private void RefreshConverterCapabilities(
            bool force
        )
        {
            if (
                !force &&
                DateTime.Now -
                converterCapabilitiesReadAt <
                TimeSpan.FromMinutes(10) &&
                (
                    !string.IsNullOrWhiteSpace(
                        converterEncodersCache
                    ) ||
                    !string.IsNullOrWhiteSpace(
                        converterMuxersCache
                    )
                )
            )
            {
                return;
            }

            converterCapabilitiesReadAt =
                DateTime.Now;
            converterEncodersCache = "";
            converterMuxersCache = "";

            string ffmpeg =
                ToolLocator.FindFfmpeg();

            if (string.IsNullOrWhiteSpace(ffmpeg))
            {
                return;
            }

            converterEncodersCache =
                CaptureToolOutput(
                    ffmpeg,
                    "-hide_banner -encoders"
                );

            converterMuxersCache =
                CaptureToolOutput(
                    ffmpeg,
                    "-hide_banner -muxers"
                );
        }

        private string CaptureToolOutput(
            string executable,
            string arguments
        )
        {
            ProcessStartInfo info =
                new ProcessStartInfo();
            info.FileName =
                executable;
            info.Arguments =
                arguments;
            info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
            info.CreateNoWindow = true;
            info.WindowStyle =
                ProcessWindowStyle.Hidden;
            info.RedirectStandardOutput = true;
            info.RedirectStandardError = true;
            info.StandardOutputEncoding =
                Encoding.UTF8;
            info.StandardErrorEncoding =
                Encoding.UTF8;

            using (
                Process process =
                    new Process()
            )
            {
                process.StartInfo =
                    info;
                process.Start();

                string output =
                    process.StandardOutput
                    .ReadToEnd();
                string error =
                    process.StandardError
                    .ReadToEnd();

                if (
                    !process.WaitForExit(
                        15000
                    )
                )
                {
                    try
                    {
                        process.Kill();
                    }
                    catch
                    {
                    }
                }

                return
                    output +
                    Environment.NewLine +
                    error;
            }
        }

        private bool IsConverterFormatSupported(
            ConverterFormatOption option,
            out string reason
        )
        {
            reason = "";

            if (option == null)
            {
                reason =
                    "Format ni izbran.";
                return false;
            }

            if (!option.Selectable)
            {
                reason =
                    "Samo vhodno ali informativno – izvoz ni na voljo.";
                return false;
            }

            if (IsSpecialConverterOption(option))
            {
                reason = "Podprto z vgrajenim pretvornikom";
                return true;
            }

            string ffmpeg =
                ToolLocator.FindFfmpeg();

            if (string.IsNullOrWhiteSpace(ffmpeg))
            {
                reason =
                    "FFmpeg ni nameščen.";
                return false;
            }

            RefreshConverterCapabilities(
                false
            );

            if (
                string.IsNullOrWhiteSpace(
                    converterEncodersCache
                ) ||
                string.IsNullOrWhiteSpace(
                    converterMuxersCache
                )
            )
            {
                reason =
                    "Podpore trenutnega FFmpeg ni bilo mogoče preveriti.";
                return false;
            }

            if (
                !CapabilityRequirementsAvailable(
                    converterEncodersCache,
                    option.RequiredEncoders
                )
            )
            {
                reason =
                    "Manjka encoder: " +
                    option.RequiredEncoders;
                return false;
            }

            if (
                !CapabilityRequirementsAvailable(
                    converterMuxersCache,
                    option.RequiredMuxers
                )
            )
            {
                reason =
                    "Manjka muxer: " +
                    option.RequiredMuxers;
                return false;
            }

            reason =
                "Podprto";
            return true;
        }

        private bool CapabilityRequirementsAvailable(
            string capabilityText,
            string requirements
        )
        {
            if (
                string.IsNullOrWhiteSpace(
                    requirements
                )
            )
            {
                return true;
            }

            string[] groups =
                requirements.Split(
                    new char[]
                    {
                        ','
                    },
                    StringSplitOptions.RemoveEmptyEntries
                );

            foreach (string group in groups)
            {
                bool groupAvailable = false;

                foreach (
                    string alternative in
                    group.Split(
                        new char[]
                        {
                            '|'
                        },
                        StringSplitOptions.RemoveEmptyEntries
                    )
                )
                {
                    if (
                        ContainsCapabilityToken(
                            capabilityText,
                            alternative.Trim()
                        )
                    )
                    {
                        groupAvailable = true;
                        break;
                    }
                }

                if (!groupAvailable)
                {
                    return false;
                }
            }

            return true;
        }

        private bool ContainsCapabilityToken(
            string capabilityText,
            string token
        )
        {
            if (
                string.IsNullOrWhiteSpace(
                    capabilityText
                ) ||
                string.IsNullOrWhiteSpace(
                    token
                )
            )
            {
                return false;
            }

            return Regex.IsMatch(
                capabilityText,
                @"(?m)(?:^|\s)" +
                Regex.Escape(token) +
                @"(?:\s|$)",
                RegexOptions.IgnoreCase
            );
        }

        private string ChooseFirstAvailableEncoder(
            string alternatives
        )
        {
            RefreshConverterCapabilities(
                false
            );

            foreach (
                string alternative in
                alternatives.Split(
                    new char[]
                    {
                        '|'
                    },
                    StringSplitOptions.RemoveEmptyEntries
                )
            )
            {
                string encoder =
                    alternative.Trim();

                if (
                    ContainsCapabilityToken(
                        converterEncodersCache,
                        encoder
                    )
                )
                {
                    return encoder;
                }
            }

            return
                alternatives.Split('|')[0];
        }

        private string GetConverterInputKind(
            string inputFile
        )
        {
            string extension =
                Path.GetExtension(
                    inputFile
                )
                .ToLowerInvariant();

            string[] audio =
                new string[]
            {
                ".mp3", ".m4a", ".aac",
                ".wav", ".flac", ".ogg",
                ".opus", ".aiff", ".aif",
                ".wv", ".ape", ".tta",
                ".tak", ".wma", ".au",
                ".voc", ".ac3", ".eac3",
                ".truehd", ".dts", ".mp2",
                ".ra", ".amr", ".gsm",
                ".pcm", ".mid", ".midi",
                ".mod", ".xm", ".it",
                ".s3m", ".mpc", ".dsf",
                ".dff", ".rf64", ".bwf"
            };

            string[] animation =
                new string[]
            {
                ".gif", ".apng"
            };

            string[] image =
                new string[]
            {
                ".jpg", ".jpeg", ".png",
                ".webp", ".avif", ".jxl",
                ".heic", ".heif", ".bmp",
                ".tif", ".tiff", ".ico",
                ".cur", ".dds", ".tga",
                ".qoi", ".jp2", ".j2k",
                ".exr", ".hdr", ".psd",
                ".pcx", ".dpx", ".bpg",
                ".flif", ".iff"
            };

            if (extension == ".json") return "lottiejson";
            if (extension == ".lottie") return "dotlottie";
            if (extension == ".riv") return "rive";

            string[] vector =
                new string[]
            {
                ".svg", ".eps", ".ai",
                ".pdf", ".cdr"
            };

            string[] raw =
                new string[]
            {
                ".raw", ".cr2", ".cr3",
                ".nef", ".arw", ".dng"
            };

            string[] video =
                new string[]
            {
                ".mp4", ".mkv", ".webm",
                ".mov", ".avi", ".m4v",
                ".ts", ".mts", ".m2ts",
                ".mxf", ".wmv", ".flv",
                ".vob", ".3gp", ".3g2",
                ".ogv", ".rm", ".rmvb",
                ".r3d", ".braw", ".lrv"
            };

            if (
                audio.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                return "audio";
            }

            if (
                animation.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                return "animation";
            }

            if (
                image.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                return "image";
            }

            if (
                vector.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                return "vector";
            }

            if (
                raw.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                return "raw";
            }

            if (
                video.Contains(
                    extension,
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                return "video";
            }

            return "unknown";
        }

        private bool IsConverterCombinationAllowed(
            string inputFile,
            ConverterFormatOption option,
            out string reason
        )
        {
            reason = "";

            string inputKind =
                GetConverterInputKind(
                    inputFile
                );

            if (
                string.Equals(
                    inputKind,
                    "unknown",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                reason =
                    "Vrsta vhodne datoteke ni prepoznana.";
                return false;
            }

            if (IsSpecialConverterOption(option))
            {
                string extension = Path.GetExtension(inputFile).ToLowerInvariant();

                if (option.Id == "dotlottie")
                {
                    if (extension == ".json") return true;
                    reason = "V .lottie je mogoče zapakirati samo veljaven Lottie JSON (.json).";
                    return false;
                }

                if (option.Id == "lottie_json")
                {
                    if (extension == ".json" || extension == ".lottie") return true;
                    reason = "Ciljni Lottie JSON sprejme samo .json ali .lottie.";
                    return false;
                }

                if (option.Id == "svg_preserve")
                {
                    if (extension == ".svg") return true;
                    reason = "Pravi SVG se brez specializiranega vektorizatorja lahko ohrani samo iz datoteke .svg.";
                    return false;
                }

                if (option.Id == "rive_preserve")
                {
                    if (extension == ".riv") return true;
                    reason = "RIV je lastni binarni runtime format; program lahko brez spremembe ohrani samo obstoječo .riv datoteko.";
                    return false;
                }
            }

            if (
                string.Equals(
                    option.OutputKind,
                    "remux",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                if (string.Equals(inputKind, "video", StringComparison.OrdinalIgnoreCase)) return true;
                reason = "Remux brez ponovnega kodiranja je namenjen video datotekam.";
                return false;
            }

            if (
                string.Equals(
                    inputKind,
                    "audio",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                if (
                    !string.Equals(
                        option.OutputKind,
                        "audio",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    reason =
                        "Zvočno datoteko je mogoče pretvoriti samo v drug zvočni format.";
                    return false;
                }

                return true;
            }

            if (
                string.Equals(
                    inputKind,
                    "image",
                    StringComparison.OrdinalIgnoreCase
                ) ||
                string.Equals(
                    inputKind,
                    "vector",
                    StringComparison.OrdinalIgnoreCase
                ) ||
                string.Equals(
                    inputKind,
                    "raw",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                if (
                    !string.Equals(
                        option.OutputKind,
                        "image",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    reason =
                        "Posamezne statične slike ni mogoče pretvoriti v video, zvok ali animacijo. Izberi drug slikovni format.";
                    return false;
                }

                return true;
            }

            if (
                string.Equals(
                    inputKind,
                    "animation",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                if (
                    string.Equals(
                        option.OutputKind,
                        "audio",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    reason =
                        "Animirana slika nima zvočne sledi.";
                    return false;
                }

                return true;
            }

            if (
                string.Equals(
                    inputKind,
                    "video",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                return true;
            }

            reason =
                "Ta kombinacija ni podprta.";
            return false;
        }

        private bool IsSpecialConverterOption(
            ConverterFormatOption option
        )
        {
            if (option == null) return false;
            return
                option.Id == "lottie_json" ||
                option.Id == "dotlottie" ||
                option.Id == "svg_preserve" ||
                option.Id == "rive_preserve";
        }

        private Task<int> RunSpecialConverterAsync(
            string input,
            string output,
            ConverterFormatOption option
        )
        {
            return Task.Run<int>(
                delegate
                {
                    try
                    {
                        if (option.Id == "dotlottie")
                        {
                            string json = File.ReadAllText(input, Encoding.UTF8);
                            JavaScriptSerializer serializer = new JavaScriptSerializer();
                            object parsed = serializer.DeserializeObject(json);
                            Dictionary<string, object> dictionary = parsed as Dictionary<string, object>;
                            if (dictionary == null || !dictionary.ContainsKey("layers"))
                            {
                                throw new InvalidDataException("Datoteka ni prepoznana kot Lottie JSON (manjka polje layers). ");
                            }

                            if (File.Exists(output)) File.Delete(output);
                            using (FileStream stream = new FileStream(output, FileMode.CreateNew, FileAccess.ReadWrite, FileShare.None))
                            using (ZipArchive archive = new ZipArchive(stream, ZipArchiveMode.Create))
                            {
                                ZipArchiveEntry animation = archive.CreateEntry("animations/animation.json", CompressionLevel.Optimal);
                                using (StreamWriter writer = new StreamWriter(animation.Open(), new UTF8Encoding(false)))
                                {
                                    writer.Write(json);
                                }

                                Dictionary<string, object> manifest = new Dictionary<string, object>();
                                manifest["version"] = "1.0";
                                manifest["generator"] = "Video Downloader 10.0.5";
                                List<object> animations = new List<object>();
                                Dictionary<string, object> animationInfo = new Dictionary<string, object>();
                                animationInfo["id"] = "animation";
                                animations.Add(animationInfo);
                                manifest["animations"] = animations;

                                ZipArchiveEntry manifestEntry = archive.CreateEntry("manifest.json", CompressionLevel.Optimal);
                                using (StreamWriter writer = new StreamWriter(manifestEntry.Open(), new UTF8Encoding(false)))
                                {
                                    writer.Write(serializer.Serialize(manifest));
                                }
                            }
                            return 0;
                        }

                        if (option.Id == "lottie_json")
                        {
                            string extension = Path.GetExtension(input).ToLowerInvariant();
                            if (extension == ".json")
                            {
                                string json = File.ReadAllText(input, Encoding.UTF8);
                                JavaScriptSerializer serializer = new JavaScriptSerializer();
                                Dictionary<string, object> dictionary = serializer.DeserializeObject(json) as Dictionary<string, object>;
                                if (dictionary == null || !dictionary.ContainsKey("layers"))
                                {
                                    throw new InvalidDataException("Datoteka ni prepoznana kot Lottie JSON.");
                                }
                                File.WriteAllText(output, json, new UTF8Encoding(false));
                                return 0;
                            }

                            using (ZipArchive archive = ZipFile.OpenRead(input))
                            {
                                ZipArchiveEntry entry = archive.Entries.FirstOrDefault(
                                    delegate(ZipArchiveEntry value)
                                    {
                                        string path = value.FullName.Replace('\\', '/');
                                        return path.StartsWith("animations/", StringComparison.OrdinalIgnoreCase) &&
                                               path.EndsWith(".json", StringComparison.OrdinalIgnoreCase);
                                    }
                                );
                                if (entry == null) throw new InvalidDataException("V .lottie paketu ni animacijske JSON datoteke.");
                                using (StreamReader reader = new StreamReader(entry.Open(), Encoding.UTF8))
                                {
                                    string extractedJson = reader.ReadToEnd();
                                    JavaScriptSerializer serializer = new JavaScriptSerializer();
                                    Dictionary<string, object> dictionary = serializer.DeserializeObject(extractedJson) as Dictionary<string, object>;
                                    if (dictionary == null || !dictionary.ContainsKey("layers"))
                                    {
                                        throw new InvalidDataException("Animacija v .lottie paketu ni veljaven Lottie JSON.");
                                    }
                                    File.WriteAllText(output, extractedJson, new UTF8Encoding(false));
                                }
                            }
                            return 0;
                        }

                        if (option.Id == "svg_preserve" || option.Id == "rive_preserve")
                        {
                            File.Copy(input, output, true);
                            return 0;
                        }

                        return 1;
                    }
                    catch (Exception e)
                    {
                        Log("Napaka specializirane pretvorbe: " + e.Message, "PRETVORNIK");
                        return 1;
                    }
                }
            );
        }

        private List<string> BuildConverterArguments(
            string input,
            string output,
            ConverterFormatOption option
        )
        {
            List<string> arguments =
                new List<string>();
            arguments.Add("-y");
            arguments.Add("-hide_banner");
            arguments.Add("-loglevel");
            arguments.Add("warning");
            arguments.Add("-i");
            arguments.Add(input);

            string id =
                option.Id;
            string av1Encoder =
                ChooseFirstAvailableEncoder(
                    "libsvtav1|libaom-av1|librav1e"
                );

            switch (id)
            {
                case "copy_mkv":
                case "copy_mp4":
                    arguments.Add("-map");
                    arguments.Add("0");
                    arguments.Add("-c");
                    arguments.Add("copy");
                    if (id == "copy_mp4")
                    {
                        arguments.Add("-movflags");
                        arguments.Add("+faststart");
                    }
                    break;

                case "mkv_ffv1":
                    arguments.Add("-map");
                    arguments.Add("0:v:0");
                    arguments.Add("-map");
                    arguments.Add("0:a?");
                    arguments.Add("-c:v");
                    arguments.Add("ffv1");
                    arguments.Add("-level");
                    arguments.Add("3");
                    arguments.Add("-g");
                    arguments.Add("1");
                    arguments.Add("-slicecrc");
                    arguments.Add("1");
                    arguments.Add("-c:a");
                    arguments.Add("copy");
                    break;

                case "mp4_h264":
                    arguments.Add("-c:v");
                    arguments.Add("libx264");
                    arguments.Add("-preset");
                    arguments.Add("medium");
                    arguments.Add("-crf");
                    arguments.Add("16");
                    arguments.Add("-pix_fmt");
                    arguments.Add("yuv420p");
                    arguments.Add("-c:a");
                    arguments.Add("aac");
                    arguments.Add("-b:a");
                    arguments.Add("320k");
                    arguments.Add("-movflags");
                    arguments.Add("+faststart");
                    break;

                case "mp4_h265":
                    arguments.Add("-c:v");
                    arguments.Add("libx265");
                    arguments.Add("-preset");
                    arguments.Add("medium");
                    arguments.Add("-crf");
                    arguments.Add("18");
                    arguments.Add("-tag:v");
                    arguments.Add("hvc1");
                    arguments.Add("-c:a");
                    arguments.Add("aac");
                    arguments.Add("-b:a");
                    arguments.Add("320k");
                    arguments.Add("-movflags");
                    arguments.Add("+faststart");
                    break;

                case "mp4_av1":
                    arguments.Add("-c:v");
                    arguments.Add(av1Encoder);
                    arguments.Add("-crf");
                    arguments.Add("24");
                    arguments.Add("-b:v");
                    arguments.Add("0");
                    arguments.Add("-pix_fmt");
                    arguments.Add("yuv420p");
                    arguments.Add("-c:a");
                    arguments.Add("aac");
                    arguments.Add("-b:a");
                    arguments.Add("320k");
                    arguments.Add("-movflags");
                    arguments.Add("+faststart");
                    break;

                case "webm_vp9":
                    arguments.Add("-c:v");
                    arguments.Add("libvpx-vp9");
                    arguments.Add("-crf");
                    arguments.Add("24");
                    arguments.Add("-b:v");
                    arguments.Add("0");
                    arguments.Add("-c:a");
                    arguments.Add("libopus");
                    arguments.Add("-b:a");
                    arguments.Add("160k");
                    break;

                case "webm_av1":
                    arguments.Add("-c:v");
                    arguments.Add(av1Encoder);
                    arguments.Add("-crf");
                    arguments.Add("26");
                    arguments.Add("-b:v");
                    arguments.Add("0");
                    arguments.Add("-c:a");
                    arguments.Add("libopus");
                    arguments.Add("-b:a");
                    arguments.Add("160k");
                    break;

                case "mkv_h264":
                    arguments.Add("-c:v");
                    arguments.Add("libx264");
                    arguments.Add("-preset");
                    arguments.Add("medium");
                    arguments.Add("-crf");
                    arguments.Add("16");
                    arguments.Add("-c:a");
                    arguments.Add("aac");
                    arguments.Add("-b:a");
                    arguments.Add("320k");
                    break;

                case "mkv_h265":
                    arguments.Add("-c:v");
                    arguments.Add("libx265");
                    arguments.Add("-preset");
                    arguments.Add("medium");
                    arguments.Add("-crf");
                    arguments.Add("18");
                    arguments.Add("-c:a");
                    arguments.Add("aac");
                    arguments.Add("-b:a");
                    arguments.Add("320k");
                    break;

                case "mkv_av1":
                    arguments.Add("-c:v");
                    arguments.Add(av1Encoder);
                    arguments.Add("-crf");
                    arguments.Add("24");
                    arguments.Add("-b:v");
                    arguments.Add("0");
                    arguments.Add("-c:a");
                    arguments.Add("libopus");
                    arguments.Add("-b:a");
                    arguments.Add("160k");
                    break;

                case "mov_h264":
                    arguments.Add("-c:v");
                    arguments.Add("libx264");
                    arguments.Add("-preset");
                    arguments.Add("medium");
                    arguments.Add("-crf");
                    arguments.Add("16");
                    arguments.Add("-c:a");
                    arguments.Add("aac");
                    arguments.Add("-b:a");
                    arguments.Add("320k");
                    break;

                case "mov_prores":
                    arguments.Add("-c:v");
                    arguments.Add("prores_ks");
                    arguments.Add("-profile:v");
                    arguments.Add("3");
                    arguments.Add("-pix_fmt");
                    arguments.Add("yuv422p10le");
                    arguments.Add("-c:a");
                    arguments.Add("pcm_s16le");
