                    );
            }

            arguments.Add(output);
            return arguments;
        }

        private Task<int> RunStandaloneProcessAsync(
            string executable,
            IEnumerable<string> arguments,
            string prefix
        )
        {
            TaskCompletionSource<int> completion =
                new TaskCompletionSource<int>();

            ProcessStartInfo info =
                new ProcessStartInfo();
            info.FileName =
                executable;
            info.Arguments =
                ToolLocator.JoinArguments(
                    arguments
                );
            info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
            info.CreateNoWindow = true;
            info.WindowStyle =
                ProcessWindowStyle.Hidden;
            info.RedirectStandardOutput = true;
            info.RedirectStandardError = true;
            info.StandardOutputEncoding =
                Encoding.UTF8;
            info.StandardErrorEncoding =
                Encoding.UTF8;

            Process process =
                new Process();
            process.StartInfo =
                info;
            process.EnableRaisingEvents = true;

            DataReceivedEventHandler handler =
                delegate(
                    object sender,
                    DataReceivedEventArgs e
                )
                {
                    if (
                        !string.IsNullOrWhiteSpace(
                            e.Data
                        ) &&
                        !IsFfmpegTechnicalLine(
                            e.Data
                        )
                    )
                    {
                        Log(
                            e.Data,
                            prefix
                        );
                    }
                };

            process.OutputDataReceived +=
                handler;
            process.ErrorDataReceived +=
                handler;

            process.Exited += delegate
            {
                try
                {
                    completion.TrySetResult(
                        process.ExitCode
                    );
                }
                catch (Exception e)
                {
                    completion.TrySetException(e);
                }
            };

            try
            {
                if (!process.Start())
                {
                    throw new InvalidOperationException(
                        "Procesa ni bilo mogoče zagnati."
                    );
                }

                process.BeginOutputReadLine();
                process.BeginErrorReadLine();
            }
            catch (Exception e)
            {
                completion.TrySetException(e);
            }

            return completion.Task.ContinueWith(
                delegate(Task<int> task)
                {
                    try
                    {
                        process.Dispose();
                    }
                    catch
                    {
                    }

                    return task.GetAwaiter().GetResult();
                }
            );
        }

        private Panel BuildEditorQuickHelpPanel()
        {
            Panel panel =
                new Panel();
            panel.Dock =
                DockStyle.Fill;
            panel.BackColor =
                Color.FromArgb(239, 246, 253);
            panel.Padding =
                new Padding(12, 8, 12, 7);

            TableLayoutPanel layout =
                new TableLayoutPanel();
            layout.Dock =
                DockStyle.Fill;
            layout.ColumnCount = 4;
            layout.RowCount = 1;
            layout.Margin =
                new Padding(0);

            for (int index = 0; index < 4; index++)
            {
                layout.ColumnStyles.Add(
                    new ColumnStyle(
                        SizeType.Percent,
                        25F
                    )
                );
            }

            panel.Controls.Add(layout);

            string[] texts =
                new string[]
                {
                    "1  Povleci ali izberi video\r\nDatoteko spusti v polje »Vhodni video« ali na prazni del zavihka.",
                    "2  Določi izrez\r\nVpiši čas ali premakni drsnika. »Celoten video« ponastavi čas.",
                    "3  Izberi spremembe\r\nVrtenje, zrcaljenje, hitrost, zvok, format in moč so na enem mestu.",
                    "4  Združi posnetke\r\nVeč videov spusti na seznam desno. Vrstni red spremeni s puščicama."
                };

            for (
                int index = 0;
                index < texts.Length;
                index++
            )
            {
                Label card =
                    new Label();
                card.Text =
                    texts[index];
                card.Dock =
                    DockStyle.Fill;
                card.BackColor =
                    Color.White;
                card.ForeColor =
                    Color.FromArgb(42, 57, 75);
                card.Font =
                    new Font("Segoe UI", 9.5F);
                card.BorderStyle =
                    BorderStyle.FixedSingle;
                card.Padding =
                    new Padding(10, 6, 10, 5);
                card.Margin =
                    new Padding(4, 2, 4, 2);
                layout.Controls.Add(
                    card,
                    index,
                    0
                );
            }

            return panel;
        }

