        private void ShowEditorInformation()
        {
            ShowSubtitleInformation(
                "Urejevalnik – podrobna navodila",
                "PREDOGLED VIDEA IN ZVOKA\r\n\r\n" +
                "• Ko izbereš video, program z FFmpeg prikaže trenutno sličico.\r\n" +
                "• Gumb »Predvajaj« uporablja FFplay in predvaja sliko skupaj z zvokom.\r\n" +
                "• Če FFplay ni nameščen, še vedno delujejo mirujoče sličice in premikanje po času. Orodja posodobi v zavihku »Orodja in nastavitve«.\r\n" +
                "• Predogled se poskuša vgraditi v program. Na nekaterih računalnikih se lahko FFplay odpre v ločenem oknu; funkcije so enake.\r\n\r\n" +

                "PREMIKANJE PO VIDEU\r\n\r\n" +
                "• −10 s / +10 s: večji skok po videu.\r\n" +
                "• −1 s / +1 s: natančnejši skok po sekundah.\r\n" +
                "• −1 kader / +1 kader: premik za eno sličico glede na zaznani FPS videa.\r\n" +
                "• Drsnik pod sliko: hitro premikanje po celotnem videu.\r\n" +
                "• Drsnik »Začetek«: med vlečenjem pokaže kader; po spustu miške se video samodejno začne od novega začetka.\r\n" +
                "• Drsnik »Konec«: med vlečenjem pokaže končni kader; po spustu miške program predvaja približno zadnje tri sekunde do novega konca.\r\n" +
                "• ⏮: skoči na izbrani začetek.\r\n" +
                "• ⏹: ustavi predogled in se vrne na izbrani začetek.\r\n\r\n" +

                "IZREZ\r\n\r\n" +
                "Začetek in konec lahko določiš na tri načine:\r\n" +
                "1. ročno napišeš čas HH:MM:SS.000;\r\n" +
                "2. uporabiš drsnika Začetek in Konec;\r\n" +
                "3. v predogledu se premakneš na želeno mesto in klikneš »Trenutni položaj → začetek« ali »Trenutni položaj → konec«.\r\n\r\n" +

                "SPREMEMBE\r\n\r\n" +
                "• Vrtenje: obrne sliko za 90° ali 180°.\r\n" +
                "• Zrcaljenje: vodoravno ali navpično.\r\n" +
                "• Hitrost: spremeni hitrost videa; zvok se po potrebi samodejno prilagodi.\r\n" +
                "• Zvok: ga ohrani ali odstrani iz končnega videa.\r\n" +
                "• Format: MP4 je najbolj združljiv, MKV pa bolj prilagodljiv.\r\n" +
                "• Moč: 100 % je najhitreje, 50 % je priporočeno, 25 % manj obremeni računalnik.\r\n\r\n" +

                "ZVOK PREDOGLEDA\r\n\r\n" +
                "Drsnik »Glasnost predogleda« vpliva samo na predvajanje v Urejevalniku, ne pa na glasnost končne datoteke. »Brez zvoka« začasno utiša predogled.\r\n\r\n" +

                "ZDRUŽEVANJE POSNETKOV\r\n\r\n" +
                "V podzavihku »Združi posnetke« lahko dodaš ali povlečeš več videov, spremeniš vrstni red in jih hitro združiš brez ponovnega kodiranja. Za to morajo imeti enake kodeke, ločljivost, FPS in zvočne lastnosti. Če niso združljivi, jih najprej pretvori v isti profil.\r\n\r\n" +

                "POMEMBNO\r\n\r\n" +
                "Predogled prikazuje izvorni video in upošteva vrtenje ter zrcaljenje pri mirujoči sličici. Končno kakovost in vse spremembe določi šele postopek »Začni urejanje«."
            );
        }

        private double GetEditorFrameStep()
        {
            return
                editorPreviewFps > 0.1
                    ? 1.0 / editorPreviewFps
                    : 1.0 / 25.0;
        }

        private void HandleEditorPreviewTrackChanged()
        {
            if (
                editorPreviewTrackUpdating ||
                trkEditorPreview == null ||
                editorDurationSeconds <= 0.0
            )
            {
                return;
            }

            if (editorPreviewPlaying)
            {
                StopEditorPreview(
                    false
                );
            }

            editorPreviewPositionSeconds =
                editorDurationSeconds *
                trkEditorPreview.Value /
                (double)trkEditorPreview.Maximum;

            UpdateEditorPreviewUi();

            if (editorPreviewSeekTimer != null)
            {
                editorPreviewSeekTimer.Stop();
                editorPreviewSeekTimer.Start();
            }
        }

        private void QueueEditorPreviewFrameRefresh()
        {
            if (editorPreviewSeekTimer == null)
            {
                return;
            }

            editorPreviewSeekTimer.Stop();
            editorPreviewSeekTimer.Start();
        }

        private async Task StepEditorPreviewAsync(
            double deltaSeconds
        )
        {
            double target =
                GetCurrentEditorPreviewPosition() +
                deltaSeconds;

            await SeekEditorPreviewAsync(
                target,
                true
            );
        }

        private async Task SeekEditorPreviewAsync(
            double seconds,
            bool refreshFrame
        )
        {
            StopEditorPreview(
                false
            );

            editorPreviewPositionSeconds =
                Math.Max(
                    0.0,
                    Math.Min(
                        editorDurationSeconds,
                        seconds
                    )
                );

            UpdateEditorPreviewUi();

            if (refreshFrame)
            {
                await RefreshEditorPreviewFrameAsync();
            }
        }

        private async Task ToggleEditorPreviewAsync()
        {
            if (editorPreviewPlaying)
            {
                double current =
                    GetCurrentEditorPreviewPosition();

                StopEditorPreview(
                    false
                );
                editorPreviewPositionSeconds =
                    current;
                UpdateEditorPreviewUi();
                await RefreshEditorPreviewFrameAsync();
                return;
            }

            await StartEditorPreviewAsync();
        }

        private async Task RefreshEditorPreviewAfterSettingChangeAsync(
            bool refreshFrame
        )
        {
            double position = GetCurrentEditorPreviewPosition();
            bool wasPlaying = editorPreviewPlaying;

            if (wasPlaying)
            {
                StopEditorPreview(false);
                editorPreviewPositionSeconds = position;
                UpdateEditorPreviewUi();
                await StartEditorPreviewAsync();
            }
            else if (refreshFrame)
            {
                await RefreshEditorPreviewFrameAsync();
            }

            UpdateEditorSelectionUi();
        }

        private async Task StartEditorPreviewAsync()
        {
            string input =
                txtEditorInput == null
                    ? ""
                    : txtEditorInput.Text.Trim();

            if (
                !File.Exists(
                    input
                )
            )
            {
                MessageBox.Show(
                    this,
                    "Najprej izberi video za predogled.",
                    "Video ni izbran",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
                return;
            }

            string ffplay =
                ToolLocator.FindFfplay();

            if (
                string.IsNullOrWhiteSpace(
                    ffplay
                ) ||
                !File.Exists(
                    ffplay
                )
            )
            {
                MessageBox.Show(
                    this,
                    "FFplay ni najden. Mirujoče sličice in premikanje po času še vedno delujejo. V »Orodja in nastavitve« posodobi ali namesti FFmpeg, ki običajno vključuje tudi FFplay.",
                    "FFplay ni nameščen",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
                await RefreshEditorPreviewFrameAsync();
                return;
            }

            StopEditorPreview(
                false
            );

            double start =
                Math.Max(
                    0.0,
                    Math.Min(
                        editorDurationSeconds,
                        editorPreviewPositionSeconds
                    )
                );

            if (
                editorEndSeconds >
                editorStartSeconds &&
                (
                    start <
                    editorStartSeconds ||
                    start >=
                    editorEndSeconds -
                    0.03
                )
            )
            {
                start =
                    editorStartSeconds;
            }

            editorPreviewPositionSeconds =
                start;
            editorPreviewStartPositionSeconds =
                start;
            editorPreviewStopwatch =
                Stopwatch.StartNew();
            editorPreviewPlaying = true;

            int session =
                Interlocked.Increment(
                    ref editorPreviewSessionId
                );

            string title =
                "VideoDownloaderPreview_" +
                Guid.NewGuid()
                .ToString("N");

            List<string> arguments =
                new List<string>();
            arguments.Add("-hide_banner");
            arguments.Add("-loglevel");
            arguments.Add("quiet");
            arguments.Add("-window_title");
            arguments.Add(title);
            arguments.Add("-ss");
            arguments.Add(
                start.ToString(
                    "0.###",
                    System.Globalization.CultureInfo.InvariantCulture
                )
            );
            arguments.Add("-i");
            arguments.Add(input);
            arguments.Add("-autoexit");
            arguments.Add("-noborder");

            // Delujoča izvedba iz različice 9.9.x je ohranjena.
            // Za preprečitev prevelike oziroma odrezane slike FFplay
            // že ob zagonu dobi velikost predoglednega panela.
            int previewWidth =
                editorPreviewHost == null
                    ? 960
                    : Math.Max(
                        320,
                        editorPreviewHost.ClientSize.Width
                    );
            int previewHeight =
                editorPreviewHost == null
                    ? 540
                    : Math.Max(
                        180,
                        editorPreviewHost.ClientSize.Height
                    );

            arguments.Add("-x");
            arguments.Add(
                previewWidth.ToString()
            );
            arguments.Add("-y");
            arguments.Add(
                previewHeight.ToString()
            );

            int volume =
                chkEditorPreviewMute != null &&
                chkEditorPreviewMute.Checked
                    ? 0
                    : (
                        trkEditorPreviewVolume == null
                            ? 80
                            : trkEditorPreviewVolume.Value
                    );

            arguments.Add("-volume");
            arguments.Add(
                volume.ToString()
            );

            double speed =
                GetEditorSpeed();

            List<string> videoFilters =
                BuildEditorVideoFilters(
                    speed
                );

            if (videoFilters.Count > 0)
            {
                arguments.Add("-vf");
                arguments.Add(
                    string.Join(
                        ",",
                        videoFilters.ToArray()
                    )
                );
            }

            if (
                editorInputHasAudio &&
                cmbEditorAudio != null &&
                cmbEditorAudio.SelectedIndex == 0
            )
            {
                if (
                    Math.Abs(
                        speed - 1.0
                    ) > 0.0001
                )
                {
                    arguments.Add("-af");
                    arguments.Add(
                        "atempo=" +
                        speed.ToString(
                            "0.###",
                            System.Globalization.CultureInfo.InvariantCulture
                        )
                    );
                }
            }
            else
            {
                arguments.Add("-an");
            }

            ProcessStartInfo info =
                new ProcessStartInfo();
            info.FileName =
                ffplay;
            info.Arguments =
                ToolLocator.JoinArguments(
                    arguments
                );
            info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
            info.CreateNoWindow = true;
            info.WindowStyle =
                ProcessWindowStyle.Hidden;

            Process process =
                new Process();
            process.StartInfo =
                info;
            process.EnableRaisingEvents = true;

            process.Exited += delegate
            {
                try
                {
                    BeginInvoke(
                        new Action(
                            delegate
                            {
                                if (
                                    session !=
                                    editorPreviewSessionId
                                )
                                {
                                    return;
                                }

                                double current =
                                    GetCurrentEditorPreviewPosition();

                                editorPreviewPlaying = false;
                                editorPreviewWindowHandle =
                                    IntPtr.Zero;
                                editorPreviewProcess = null;

                                try
                                {
                                    process.Dispose();
                                }
                                catch
                                {
                                }

                                if (
                                    editorPreviewTimer != null
                                )
                                {
                                    editorPreviewTimer.Stop();
                                }

                                editorPreviewPositionSeconds =
                                    Math.Min(
                                        editorDurationSeconds,
                                        current
                                    );

                                if (
                                    editorEndSeconds >
                                    editorStartSeconds
                                )
                                {
                                    editorPreviewPositionSeconds =
                                        Math.Min(
                                            editorEndSeconds,
                                            editorPreviewPositionSeconds
                                        );
                                }

                                if (
                                    btnEditorPreviewPlay != null
                                )
                                {
                                    btnEditorPreviewPlay.Text =
                                        "▶ Predvajaj";
                                }

                                if (
                                    editorPreviewPicture != null
                                )
                                {
                                    editorPreviewPicture.Visible =
                                        true;
                                    editorPreviewPicture.BringToFront();
                                }

                                UpdateEditorPreviewUi();
                                RefreshEditorPreviewFrameSafe();
                            }
                        )
                    );
                }
                catch
                {
                }
            };

            try
            {
                if (!process.Start())
                {
                    throw new InvalidOperationException(
                        "FFplay se ni zagnal."
                    );
                }

                editorPreviewProcess =
                    process;

                if (
                    btnEditorPreviewPlay != null
                )
                {
                    btnEditorPreviewPlay.Text =
                        "⏸ Premor";
                }

                if (
                    lblEditorStatus != null
                )
                {
                    lblEditorStatus.Text =
                        "Predogled se predvaja z zvokom. Klikni »Premor« za natančno premikanje po sličicah.";
                }

                if (
                    editorPreviewTimer != null
                )
                {
                    editorPreviewTimer.Start();
                }

                bool embedded =
                    await EmbedEditorPreviewWindowAsync(
                        process,
                        session
                    );

                if (
                    embedded &&
                    editorPreviewPicture != null
                )
                {
                    editorPreviewPicture.Visible =
                        false;
                }
                else if (
                    lblEditorStatus != null &&
                    !process.HasExited
                )
                {
                    lblEditorStatus.Text =
                        "FFplay se je odprl v ločenem oknu. Predvajanje in zvok delujeta, mirujoči kader pa ostane v programu.";
                }
            }
            catch (Exception e)
            {
                StopEditorPreview(
                    false
                );

                MessageBox.Show(
                    this,
                    "Predogleda z zvokom ni bilo mogoče zagnati.\r\n\r\n" +
                    e.Message,
                    "Predogled",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );

                RefreshEditorPreviewFrameSafe();
            }
        }

        private bool IsEditorPreviewProcessRunning(
            Process process
        )
        {
            if (process == null)
            {
                return false;
            }

            try
            {
                return !process.HasExited;
            }
            catch
            {
                return false;
            }
        }

        private async Task<bool> EmbedEditorPreviewWindowAsync(
            Process process,
            int session
        )
        {
            for (
                int attempt = 0;
                attempt < 50;
                attempt++
            )
            {
                if (
                    process == null ||
                    process.HasExited ||
                    session !=
                    editorPreviewSessionId
                )
                {
                    return false;
                }

                process.Refresh();

                IntPtr handle =
                    process.MainWindowHandle;

                if (
                    handle != IntPtr.Zero &&
                    editorPreviewHost != null &&
                    editorPreviewHost.IsHandleCreated
                )
                {
                    try
                    {
                        SetParent(
                            handle,
                            editorPreviewHost.Handle
                        );

                        int style =
                            GetWindowLong(
                                handle,
                                GWL_STYLE
                            );

                        style &=
                            ~(
                                WS_CAPTION |
                                WS_THICKFRAME |
                                WS_POPUP
                            );
                        style |=
                            WS_CHILD |
                            WS_VISIBLE;

                        SetWindowLong(
                            handle,
                            GWL_STYLE,
                            style
                        );

                        editorPreviewWindowHandle =
                            handle;
                        ResizeEditorPreviewWindow();
                        return true;
                    }
                    catch
                    {
                        return false;
                    }
                }

                await Task.Delay(
                    80
                );
            }

            return false;
        }

        private void ResizeEditorPreviewWindow()
        {
            if (
                editorPreviewWindowHandle ==
                IntPtr.Zero ||
                editorPreviewHost == null
            )
            {
                return;
            }

            try
            {
                MoveWindow(
                    editorPreviewWindowHandle,
                    0,
                    0,
                    Math.Max(
                        1,
                        editorPreviewHost.ClientSize.Width
                    ),
                    Math.Max(
                        1,
                        editorPreviewHost.ClientSize.Height
                    ),
                    true
                );
            }
            catch
            {
            }
        }

        private double GetCurrentEditorPreviewPosition()
        {
            double position =
                editorPreviewPositionSeconds;

            if (
                editorPreviewPlaying &&
                editorPreviewStopwatch != null
            )
            {
                position =
                    editorPreviewStartPositionSeconds +
                    editorPreviewStopwatch.Elapsed.TotalSeconds *
                    GetEditorSpeed();
            }

            return
                Math.Max(
                    0.0,
                    Math.Min(
                        editorDurationSeconds,
                        position
                    )
                );
        }

        private void UpdateEditorPreviewPlaybackClock()
        {
            if (!editorPreviewPlaying)
            {
                return;
            }

            double position =
                GetCurrentEditorPreviewPosition();

            double endLimit =
                editorDurationSeconds;

            if (
                editorEndSeconds >
                editorStartSeconds
            )
            {
                endLimit =
                    Math.Min(
                        endLimit,
                        editorEndSeconds
                    );
            }

            if (
                position >=
                endLimit -
                0.02
            )
            {
                StopEditorPreview(
                    false
                );
                editorPreviewPositionSeconds =
                    endLimit;
                UpdateEditorPreviewUi();
                RefreshEditorPreviewFrameSafe();
                return;
            }

            editorPreviewPositionSeconds =
                position;
            UpdateEditorPreviewUi();
        }

        private void StopEditorPreview(
            bool refreshFrame
        )
        {
            Interlocked.Increment(
                ref editorPreviewSessionId
            );

            editorPreviewPlaying = false;

            if (
                editorPreviewTimer != null
            )
            {
                editorPreviewTimer.Stop();
            }

            if (
                editorPreviewStopwatch != null
            )
            {
                try
                {
                    editorPreviewStopwatch.Stop();
                }
                catch
                {
                }
            }

            Process process =
                editorPreviewProcess;
            editorPreviewProcess = null;
            editorPreviewWindowHandle =
                IntPtr.Zero;

            if (
                process != null
            )
            {
                try
                {
                    if (!process.HasExited)
                    {
                        KillProcessTree(
                            process.Id
                        );
                    }
                }
                catch
                {
                    try
                    {
                        process.Kill();
                    }
                    catch
                    {
                    }
                }

                try
                {
                    process.Dispose();
                }
                catch
                {
                }
            }

            if (
                btnEditorPreviewPlay != null
            )
            {
                btnEditorPreviewPlay.Text =
                    "▶ Predvajaj";
            }

            if (
                editorPreviewPicture != null
            )
            {
                editorPreviewPicture.Visible =
                    true;
                editorPreviewPicture.BringToFront();
            }

            if (refreshFrame)
            {
                RefreshEditorPreviewFrameSafe();
            }
        }

        private void UpdateEditorPreviewUi()
        {
            if (
                lblEditorPreviewTime != null
            )
            {
                lblEditorPreviewTime.Text =
                    FormatEditorTime(
                        editorPreviewPositionSeconds
                    ) +
                    " / " +
                    (
                        editorDurationSeconds > 0.0
                            ? FormatEditorTime(
                                editorDurationSeconds
                            )
                            : "--:--"
                    );
            }

            if (
                trkEditorPreview != null &&
                editorDurationSeconds > 0.0
            )
            {
                editorPreviewTrackUpdating =
                    true;

                try
                {
                    trkEditorPreview.Value =
                        Math.Max(
                            trkEditorPreview.Minimum,
                            Math.Min(
                                trkEditorPreview.Maximum,
                                Convert.ToInt32(
                                    Math.Round(
                                        editorPreviewPositionSeconds /
                                        editorDurationSeconds *
                                        trkEditorPreview.Maximum
                                    )
                                )
                            )
                        );
                }
                finally
                {
                    editorPreviewTrackUpdating =
                        false;
                }
            }
        }

        private async void RefreshEditorPreviewFrameSafe()
        {
            try
            {
                await RefreshEditorPreviewFrameAsync();
            }
            catch (Exception e)
            {
                if (
                    lblEditorStatus != null
                )
                {
                    lblEditorStatus.Text =
                        "Predogled sličice ni uspel: " +
                        e.Message;
                }
            }
        }

        private async Task RefreshEditorPreviewFrameAsync()
        {
            if (
                editorPreviewPicture == null ||
                editorPreviewPlaying
            )
            {
                return;
            }

            string input =
                txtEditorInput == null
                    ? ""
                    : txtEditorInput.Text.Trim();

            if (
                !File.Exists(
                    input
                )
            )
            {
                return;
            }

            int request =
                Interlocked.Increment(
                    ref editorPreviewFrameRequestVersion
                );

            double position =
                Math.Max(
                    0.0,
                    Math.Min(
                        editorDurationSeconds,
                        editorPreviewPositionSeconds
                    )
                );

            Image image =
                await ExtractEditorPreviewFrameAsync(
                    input,
                    position
                );

            if (
                request !=
                editorPreviewFrameRequestVersion
            )
            {
                if (image != null)
                {
                    image.Dispose();
                }
                return;
            }

            if (image == null)
            {
                return;
            }

            Image previous =
                editorPreviewPicture.Image;

            editorPreviewPicture.Image =
                image;
            editorPreviewPicture.Visible =
                true;
            editorPreviewPicture.BringToFront();

            if (previous != null)
            {
                previous.Dispose();
            }
        }

        private Task<Image> ExtractEditorPreviewFrameAsync(
            string input,
            double position
        )
        {
            List<string> filters =
                BuildEditorVideoFilters(
                    1.0
                );

            filters.Add(
                "scale=1280:-2"
            );

            string filter =
                string.Join(
                    ",",
                    filters.ToArray()
                );

            return Task.Run<Image>(
                delegate
                {
                    string ffmpeg =
                        ToolLocator.FindFfmpeg();

                    if (
                        string.IsNullOrWhiteSpace(
                            ffmpeg
                        ) ||
                        !File.Exists(
                            ffmpeg
                        )
                    )
                    {
                        return null;
                    }

                    ProcessStartInfo info =
                        new ProcessStartInfo();
                    info.FileName =
                        ffmpeg;
                    info.Arguments =
                        ToolLocator.JoinArguments(
                            new string[]
                            {
                                "-hide_banner",
                                "-loglevel",
                                "error",
                                "-ss",
                                position.ToString(
                                    "0.###",
                                    System.Globalization.CultureInfo.InvariantCulture
                                ),
                                "-i",
                                input,
                                "-frames:v",
                                "1",
                                "-an",
                                "-sn",
                                "-vf",
                                filter,
                                "-f",
                                "image2pipe",
                                "-vcodec",
                                "mjpeg",
                                "pipe:1"
                            }
                        );
                    info.UseShellExecute = false;
                    ToolLocator.ConfigureUtf8Process(info);
                    info.CreateNoWindow = true;
                    info.WindowStyle =
                        ProcessWindowStyle.Hidden;
                    info.RedirectStandardOutput = true;
                    info.RedirectStandardError = true;

                    try
                    {
                        using (
                            Process process =
                                Process.Start(
                                    info
                                )
                        )
                        {
                            if (process == null)
                            {
                                return null;
                            }

                            Task<string> errorTask =
                                process.StandardError
                                .ReadToEndAsync();

                            using (
                                MemoryStream stream =
                                    new MemoryStream()
                            )
                            {
                                process.StandardOutput
                                    .BaseStream
                                    .CopyTo(
                                        stream
                                    );

                                process.WaitForExit();

                                try
                                {
                                    errorTask.Wait(
                                        1000
                                    );
                                }
                                catch
                                {
                                }

                                if (
                                    process.ExitCode != 0 ||
                                    stream.Length == 0
                                )
                                {
                                    return null;
                                }

                                stream.Position = 0;

                                using (
                                    Image loaded =
                                        Image.FromStream(
                                            stream
                                        )
                                )
                                {
                                    return
                                        new Bitmap(
                                            loaded
                                        );
                                }
                            }
                        }
                    }
                    catch
                    {
                        return null;
                    }
                }
            );
        }

        private Task<double> ReadEditorFrameRateAsync(
            string ffprobe,
            string input
        )
        {
            return Task.Run(
                delegate
                {
                    try
                    {
                        ProcessStartInfo info =
                            new ProcessStartInfo();
                        info.FileName =
                            ffprobe;
                        info.Arguments =
                            ToolLocator.JoinArguments(
                                new string[]
                                {
                                    "-v",
                                    "error",
                                    "-select_streams",
                                    "v:0",
                                    "-show_entries",
                                    "stream=avg_frame_rate",
                                    "-of",
                                    "default=noprint_wrappers=1:nokey=1",
                                    input
                                }
                            );
                        info.UseShellExecute = false;
                        ToolLocator.ConfigureUtf8Process(info);
                        info.CreateNoWindow = true;
                        info.RedirectStandardOutput = true;
                        info.RedirectStandardError = true;

                        using (
                            Process process =
                                Process.Start(
                                    info
                                )
                        )
                        {
                            if (process == null)
                            {
                                return 25.0;
                            }

                            string value =
                                process.StandardOutput
                                .ReadToEnd()
                                .Trim();

                            process.WaitForExit();

                            string[] parts =
                                value.Split('/');

                            if (parts.Length == 2)
                            {
                                double numerator;
                                double denominator;

                                if (
                                    double.TryParse(
                                        parts[0],
                                        System.Globalization.NumberStyles.Float,
                                        System.Globalization.CultureInfo.InvariantCulture,
                                        out numerator
                                    ) &&
                                    double.TryParse(
                                        parts[1],
                                        System.Globalization.NumberStyles.Float,
                                        System.Globalization.CultureInfo.InvariantCulture,
                                        out denominator
                                    ) &&
                                    denominator > 0.0
                                )
                                {
                                    return
                                        Math.Max(
                                            1.0,
                                            Math.Min(
                                                240.0,
                                                numerator /
                                                denominator
                                            )
                                        );
                                }
                            }

                            double fps;

                            if (
                                double.TryParse(
                                    value,
                                    System.Globalization.NumberStyles.Float,
                                    System.Globalization.CultureInfo.InvariantCulture,
                                    out fps
                                )
                            )
                            {
                                return
                                    Math.Max(
                                        1.0,
                                        Math.Min(
                                            240.0,
                                            fps
                                        )
                                    );
                            }
                        }
                    }
                    catch
                    {
                    }

                    return 25.0;
                }
            );
        }

        private ComboBox NewEditorCombo(
            object[] items,
            int selectedIndex
        )
        {
            ComboBox combo =
                new ComboBox();
            combo.DropDownStyle =
                ComboBoxStyle.DropDownList;
            combo.Dock =
                DockStyle.Fill;
            combo.Margin =
                new Padding(0, 3, 6, 3);
            combo.Items.AddRange(items);
            combo.SelectedIndex =
                Math.Max(
                    0,
                    Math.Min(
                        items.Length - 1,
                        selectedIndex
                    )
                );
            return combo;
        }

        private async void OpenEditorInput()
        {
            OpenFileDialog dialog =
                new OpenFileDialog();
            dialog.Title =
                "Izberi video za urejanje";
            dialog.Filter =
                "Video datoteke|*.mp4;*.mkv;*.webm;*.mov;*.avi;*.m4v;*.ts;*.mts;*.m2ts;*.wmv;*.flv|Vse datoteke|*.*";

            if (
                dialog.ShowDialog(this) !=
                DialogResult.OK
            )
            {
                return;
            }

            await LoadEditorInputAsync(
                dialog.FileName
            );
        }

        private async Task LoadEditorInputAsync(
            string fileName
        )
        {
            if (!File.Exists(fileName))
            {
                return;
            }

            StopEditorPreview(
                false
            );

            Interlocked.Increment(
                ref editorPreviewFrameRequestVersion
            );

            txtEditorInput.Text =
                fileName;
            lblEditorStatus.Text =
                "Berem trajanje, FPS in zvočne steze …";

            string ffprobe =
                ToolLocator.FindFfprobe();

            if (
                string.IsNullOrWhiteSpace(
                    ffprobe
                )
            )
            {
                editorDurationSeconds = 0.0;
                editorInputHasAudio = false;
                lblEditorStatus.Text =
                    "ffprobe ni najden. Namesti orodja v »Orodja in nastavitve«.";
                return;
            }

            editorDurationSeconds =
                await ReadStandaloneDurationAsync(
                    ffprobe,
                    fileName
                );
            editorInputHasAudio =
                await ReadEditorHasAudioAsync(
                    ffprobe,
                    fileName
                );
            editorPreviewFps =
                await ReadEditorFrameRateAsync(
                    ffprobe,
                    fileName
                );

            editorStartSeconds = 0.0;
            editorEndSeconds =
                Math.Max(
                    0.0,
                    editorDurationSeconds
                );

            editorPreviewPositionSeconds =
                0.0;

            UpdateEditorTracksFromTimes();
            UpdateEditorSuggestedOutput();
            UpdateEditorPreviewUi();

            if (
                lblEditorPreviewAudio != null
            )
            {
                lblEditorPreviewAudio.Text =
                    editorInputHasAudio
                        ? "Zvok: najden  |  FPS: " +
                          editorPreviewFps.ToString(
                              "0.###",
                              System.Globalization.CultureInfo.InvariantCulture
                          )
                        : "Zvok: ni zvočne steze  |  FPS: " +
                          editorPreviewFps.ToString(
                              "0.###",
                              System.Globalization.CultureInfo.InvariantCulture
                          );
            }

            lblEditorStatus.Text =
                editorDurationSeconds > 0.0
                    ? "Video je pripravljen. Uporabi Predvajaj ali se premikaj po sekundah in sličicah."
                    : "Trajanja videa ni bilo mogoče prebrati.";

            await RefreshEditorPreviewFrameAsync();
            Image storyboard = await CreateEditorStoryboardAsync(fileName, editorDurationSeconds);
            if (editorStoryboardImage != null)
            {
                editorStoryboardImage.Dispose();
            }
            editorStoryboardImage = storyboard;
            if (editorTimelinePanel != null)
            {
                editorTimelinePanel.Invalidate();
            }
        }

        private Task<Image> CreateEditorStoryboardAsync(
            string input,
            double duration
        )
        {
            return Task.Run<Image>(delegate
            {
                if (duration <= 0.0) return null;
                string ffmpeg = ToolLocator.FindFfmpeg();
                if (string.IsNullOrWhiteSpace(ffmpeg) || !File.Exists(ffmpeg)) return null;
                double interval = Math.Max(0.2, duration / 10.0);
                string filter =
                    "fps=1/" + interval.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture) +
                    ",scale=150:84:force_original_aspect_ratio=decrease," +
                    "pad=150:84:(ow-iw)/2:(oh-ih)/2:color=black,tile=10x1:padding=2:margin=2";
                ProcessStartInfo info = new ProcessStartInfo();
                info.FileName = ffmpeg;
                info.Arguments = ToolLocator.JoinArguments(new string[]
                {
                    "-hide_banner", "-loglevel", "error", "-i", input,
                    "-vf", filter, "-frames:v", "1", "-f", "image2pipe",
                    "-vcodec", "mjpeg", "pipe:1"
                });
                info.UseShellExecute = false;
                ToolLocator.ConfigureUtf8Process(info);
                info.CreateNoWindow = true;
                info.RedirectStandardOutput = true;
                info.RedirectStandardError = true;
                try
                {
                    using (Process process = Process.Start(info))
                    {
                        if (process == null) return null;
                        process.StandardError.ReadToEndAsync();
                        using (MemoryStream stream = new MemoryStream())
                        {
                            process.StandardOutput.BaseStream.CopyTo(stream);
                            process.WaitForExit();
                            if (process.ExitCode != 0 || stream.Length == 0) return null;
                            stream.Position = 0;
                            using (Image loaded = Image.FromStream(stream))
                            {
                                return new Bitmap(loaded);
                            }
                        }
                    }
                }
                catch
                {
                    return null;
                }
            });
        }

        private Task<bool> ReadEditorHasAudioAsync(
            string ffprobe,
            string input
        )
        {
            return Task.Run(
                delegate
                {
                    try
                    {
                        ProcessStartInfo info =
                            new ProcessStartInfo();
                        info.FileName = ffprobe;
                        info.Arguments =
                            ToolLocator.JoinArguments(
                                new string[]
                                {
                                    "-v",
                                    "error",
                                    "-select_streams",
                                    "a:0",
                                    "-show_entries",
                                    "stream=index",
                                    "-of",
                                    "csv=p=0",
                                    input
                                }
                            );
                        info.UseShellExecute = false;
                        ToolLocator.ConfigureUtf8Process(info);
                        info.CreateNoWindow = true;
                        info.RedirectStandardOutput = true;
                        info.RedirectStandardError = true;

                        using (
                            Process process =
                                Process.Start(info)
                        )
                        {
                            if (process == null)
                            {
                                return false;
                            }

                            string output =
                                process.StandardOutput.ReadToEnd();
                            process.WaitForExit();
                            return
                                process.ExitCode == 0 &&
                                !string.IsNullOrWhiteSpace(
                                    output
                                );
                        }
                    }
                    catch
                    {
                        return false;
                    }
                }
            );
        }

        private void ChooseEditorOutput()
        {
            SaveFileDialog dialog =
                new SaveFileDialog();
            string extension =
                GetEditorOutputExtension();
            dialog.Title =
                "Izberi končno video datoteko";
            dialog.DefaultExt =
                extension.TrimStart('.');
            dialog.Filter =
                extension == ".mkv" ? "Matroska video|*.mkv" :
                extension == ".webm" ? "WebM video|*.webm" :
                extension == ".mov" ? "QuickTime video|*.mov" :
                extension == ".avi" ? "AVI video|*.avi" :
                "MP4 video|*.mp4";

            if (
                !string.IsNullOrWhiteSpace(
                    txtEditorOutput.Text
                )
            )
            {
                dialog.FileName =
                    Path.GetFileName(
                        txtEditorOutput.Text
                    );
                string folder =
                    Path.GetDirectoryName(
                        txtEditorOutput.Text
                    );
                if (
                    !string.IsNullOrWhiteSpace(
                        folder
                    ) &&
                    Directory.Exists(folder)
                )
                {
                    dialog.InitialDirectory =
                        folder;
                }
            }

            if (
                dialog.ShowDialog(this) ==
                DialogResult.OK
            )
            {
                txtEditorOutput.Text =
                    Path.ChangeExtension(
                        dialog.FileName,
                        extension
                    );
            }
        }

        private string GetEditorOutputExtension()
        {
            if (cmbEditorOutputFormat == null)
            {
                return ".mp4";
            }
            switch (cmbEditorOutputFormat.SelectedIndex)
            {
                case 1: return ".mkv";
                case 3: return ".webm";
                case 4: return ".mov";
                case 5: return ".avi";
                case 7: return ".mkv";
                case 6:
                    if (txtEditorInput != null && !string.IsNullOrWhiteSpace(txtEditorInput.Text))
                    {
                        string originalExtension = Path.GetExtension(txtEditorInput.Text.Trim());
                        if (!string.IsNullOrWhiteSpace(originalExtension)) return originalExtension;
                    }
                    return ".mkv";
                default: return ".mp4";
            }
        }

        private void UpdateEditorSuggestedOutput()
        {
            if (
                txtEditorInput == null ||
                txtEditorOutput == null ||
                string.IsNullOrWhiteSpace(
                    txtEditorInput.Text
                )
            )
            {
                return;
            }

            string input =
                txtEditorInput.Text.Trim();
            string folder =
                Path.GetDirectoryName(input);
            string name =
                Path.GetFileNameWithoutExtension(
                    input
                );

            txtEditorOutput.Text =
                Path.Combine(
                    folder,
                    name +
                    " - urejeno" +
                    GetEditorOutputExtension()
                );
        }

        private bool TryParseEditorTime(
            string text,
            out double seconds
        )
        {
            seconds = 0.0;
            string value =
                (text ?? "")
                .Trim()
                .Replace(',', '.');

            if (value.Length == 0)
            {
                return false;
            }

            string[] parts =
                value.Split(':');

            try
            {
                if (parts.Length == 1)
                {
                    return double.TryParse(
                        parts[0],
                        System.Globalization.NumberStyles.Float,
                        System.Globalization.CultureInfo.InvariantCulture,
                        out seconds
                    );
                }

                if (parts.Length == 2)
                {
                    double minutes;
                    double lastSeconds;
                    if (
                        !double.TryParse(
                            parts[0],
                            System.Globalization.NumberStyles.Float,
                            System.Globalization.CultureInfo.InvariantCulture,
                            out minutes
                        ) ||
                        !double.TryParse(
                            parts[1],
                            System.Globalization.NumberStyles.Float,
                            System.Globalization.CultureInfo.InvariantCulture,
                            out lastSeconds
                        )
                    )
                    {
                        return false;
                    }

                    seconds =
                        minutes * 60.0 +
                        lastSeconds;
                    return true;
                }

                if (parts.Length == 3)
                {
                    double hours;
                    double minutes;
                    double lastSeconds;
                    if (
                        !double.TryParse(
                            parts[0],
                            System.Globalization.NumberStyles.Float,
                            System.Globalization.CultureInfo.InvariantCulture,
                            out hours
                        ) ||
                        !double.TryParse(
                            parts[1],
                            System.Globalization.NumberStyles.Float,
                            System.Globalization.CultureInfo.InvariantCulture,
                            out minutes
                        ) ||
                        !double.TryParse(
                            parts[2],
                            System.Globalization.NumberStyles.Float,
                            System.Globalization.CultureInfo.InvariantCulture,
                            out lastSeconds
                        )
                    )
                    {
                        return false;
                    }

                    seconds =
                        hours * 3600.0 +
                        minutes * 60.0 +
                        lastSeconds;
                    return true;
                }
            }
            catch
            {
            }

            return false;
        }

        private string FormatEditorTime(
            double seconds
        )
        {
            seconds =
                Math.Max(
                    0.0,
                    seconds
                );
            TimeSpan value =
                TimeSpan.FromSeconds(
                    seconds
                );
            int hours =
                Convert.ToInt32(
                    Math.Floor(
                        value.TotalHours
                    )
                );

            return
                hours.ToString("00") +
                ":" +
                value.Minutes.ToString("00") +
                ":" +
                value.Seconds.ToString("00") +
                "." +
                value.Milliseconds.ToString("000");
        }

        private void ApplyEditorTimeText()
        {
            if (editorDurationSeconds <= 0.0)
            {
                return;
            }

            double start;
            double end;

            if (
                !TryParseEditorTime(
                    txtEditorStart.Text,
                    out start
                ) ||
                !TryParseEditorTime(
                    txtEditorEnd.Text,
                    out end
                )
            )
            {
                MessageBox.Show(
                    this,
                    "Čas napiši kot HH:MM:SS.000, na primer 00:01:25.500.",
                    "Neveljaven čas",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                UpdateEditorTracksFromTimes();
                return;
            }

            start =
                Math.Max(
                    0.0,
                    Math.Min(
                        editorDurationSeconds,
                        start
                    )
                );
            end =
                Math.Max(
                    0.0,
                    Math.Min(
                        editorDurationSeconds,
                        end
                    )
                );

            if (end <= start + 0.05)
            {
                MessageBox.Show(
                    this,
                    "Konec mora biti pozneje od začetka.",
                    "Neveljaven izrez",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                UpdateEditorTracksFromTimes();
                return;
            }

            editorStartSeconds = start;
            editorEndSeconds = end;
            UpdateEditorTracksFromTimes();
        }

        private void ShowEditorTrimBoundaryFrame(
            bool startBoundary
        )
        {
            if (
                editorDurationSeconds <= 0.0 ||
                editorTimeUpdating
            )
            {
                return;
            }

            if (editorPreviewPlaying)
            {
                StopEditorPreview(
                    false
                );
            }

            double target =
                startBoundary
                    ? editorStartSeconds
                    : Math.Max(
                        editorStartSeconds,
                        editorEndSeconds -
                        GetEditorFrameStep()
                    );

            editorPreviewPositionSeconds =
                Math.Max(
                    0.0,
                    Math.Min(
                        editorDurationSeconds,
                        target
                    )
                );

            UpdateEditorPreviewUi();
            QueueEditorPreviewFrameRefresh();

            if (lblEditorStatus != null)
            {
                lblEditorStatus.Text =
                    startBoundary
                        ? "Začetek izreza je premaknjen. Po spustu miške se predogled samodejno začne na tej točki."
                        : "Konec izreza je premaknjen. Po spustu miške se predvajajo zadnje tri sekunde do izbranega konca.";
            }
        }

        private async Task PlayEditorTrimBoundaryAsync(
            bool startBoundary
        )
        {
            if (
                editorDurationSeconds <= 0.0 ||
                txtEditorInput == null ||
                !File.Exists(
                    txtEditorInput.Text.Trim()
                )
            )
            {
                return;
            }

            StopEditorPreview(
                false
            );

            double target;

            if (startBoundary)
            {
                target =
                    editorStartSeconds;
            }
            else
            {
                double selectedLength =
                    Math.Max(
                        0.0,
                        editorEndSeconds -
                        editorStartSeconds
                    );

                double leadSeconds =
                    Math.Min(
                        3.0,
                        Math.Max(
                            0.5,
                            selectedLength
                        )
                    );

                target =
                    Math.Max(
                        editorStartSeconds,
                        editorEndSeconds -
                        leadSeconds
                    );
            }

            editorPreviewPositionSeconds =
                Math.Max(
                    0.0,
                    Math.Min(
                        editorDurationSeconds,
                        target
                    )
                );

            UpdateEditorPreviewUi();
            await StartEditorPreviewAsync();
        }

