        private void UpdateEditorTimesFromTracks(
            bool changedStart
        )
        {
            if (
                editorTimeUpdating ||
                editorDurationSeconds <= 0.0
            )
            {
                return;
            }

            editorTimeUpdating = true;

            try
            {
                int startValue =
                    trkEditorStart.Value;
                int endValue =
                    trkEditorEnd.Value;

                if (
                    changedStart &&
                    startValue >= endValue
                )
                {
                    startValue =
                        Math.Max(
                            0,
                            endValue - 1
                        );
                    trkEditorStart.Value =
                        startValue;
                }
                else if (
                    !changedStart &&
                    endValue <= startValue
                )
                {
                    endValue =
                        Math.Min(
                            1000,
                            startValue + 1
                        );
                    trkEditorEnd.Value =
                        endValue;
                }

                editorStartSeconds =
                    editorDurationSeconds *
                    startValue /
                    1000.0;
                editorEndSeconds =
                    editorDurationSeconds *
                    endValue /
                    1000.0;

                txtEditorStart.Text =
                    FormatEditorTime(
                        editorStartSeconds
                    );
                txtEditorEnd.Text =
                    FormatEditorTime(
                        editorEndSeconds
                    );
            }
            finally
            {
                editorTimeUpdating = false;
            }

            UpdateEditorSelectionUi();
        }

        private void UpdateEditorTracksFromTimes()
        {
            if (
                trkEditorStart == null ||
                trkEditorEnd == null
            )
            {
                return;
            }

            editorTimeUpdating = true;

            try
            {
                if (editorDurationSeconds > 0.0)
                {
                    trkEditorStart.Value =
                        Math.Max(
                            0,
                            Math.Min(
                                1000,
                                Convert.ToInt32(
                                    Math.Round(
                                        editorStartSeconds /
                                        editorDurationSeconds *
                                        1000.0
                                    )
                                )
                            )
                        );
                    trkEditorEnd.Value =
                        Math.Max(
                            trkEditorStart.Value + 1,
                            Math.Min(
                                1000,
                                Convert.ToInt32(
                                    Math.Round(
                                        editorEndSeconds /
                                        editorDurationSeconds *
                                        1000.0
                                    )
                                )
                            )
                        );
                }
                else
                {
                    trkEditorStart.Value = 0;
                    trkEditorEnd.Value = 1000;
                }

                if (txtEditorStart != null)
                {
                    txtEditorStart.Text =
                        FormatEditorTime(
                            editorStartSeconds
                        );
                }
                if (txtEditorEnd != null)
                {
                    txtEditorEnd.Text =
                        FormatEditorTime(
                            editorEndSeconds
                        );
                }
            }
            finally
            {
                editorTimeUpdating = false;
            }

            UpdateEditorSelectionUi();
        }

        private double GetEditorSpeed()
        {
            if (cmbEditorSpeed == null)
            {
                return 1.0;
            }

            switch (
                cmbEditorSpeed.SelectedIndex
            )
            {
                case 0:
                    return 0.5;
                case 1:
                    return 0.75;
                case 3:
                    return 1.25;
                case 4:
                    return 1.5;
                case 5:
                    return 2.0;
                default:
                    return 1.0;
            }
        }

        private void UpdateEditorSelectionUi()
        {
            if (lblEditorDuration != null)
            {
                lblEditorDuration.Text =
                    editorDurationSeconds > 0.0
                        ? "Trajanje: " +
                          FormatEditorTime(
                              editorDurationSeconds
                          ) +
                          "  |  Začetek: " +
                          FormatEditorTime(
                              editorStartSeconds
                          ) +
                          "  |  Konec: " +
                          FormatEditorTime(
                              editorEndSeconds
                          )
                        : "Trajanje: --:--  |  Začetek: --:--  |  Konec: --:--";
            }

            double selected =
                Math.Max(
                    0.0,
                    editorEndSeconds -
                    editorStartSeconds
                );
            double outputDuration =
                GetEditorSpeed() > 0.0
                    ? selected /
                      GetEditorSpeed()
                    : selected;

            if (lblEditorSelection != null)
            {
                lblEditorSelection.Text =
                    selected > 0.0
                        ? "Izbrani del: " +
                          FormatEditorTime(selected) +
                          "  |  Končni video: približno " +
                          FormatEditorTime(
                              outputDuration
                          )
                        : "Izbrani del: --:--";
            }

            if (editorTimelinePanel != null)
            {
                editorTimelinePanel.Invalidate();
            }
        }

        private void DrawEditorTimeline(
            object sender,
            PaintEventArgs e
        )
        {
            Panel panel = sender as Panel;
            if (panel == null) return;

            Rectangle bounds = panel.ClientRectangle;
            e.Graphics.Clear(Color.FromArgb(25, 29, 35));

            if (editorStoryboardImage != null)
            {
                e.Graphics.InterpolationMode =
                    System.Drawing.Drawing2D.InterpolationMode.HighQualityBicubic;
                e.Graphics.DrawImage(editorStoryboardImage, bounds);
            }
            else
            {
                using (Brush empty = new SolidBrush(Color.FromArgb(43, 51, 62)))
                {
                    e.Graphics.FillRectangle(empty, bounds);
                }
                using (Brush text = new SolidBrush(Color.LightGray))
                {
                    e.Graphics.DrawString(
                        "Po izbiri videa se tukaj ustvari časovnica iz desetih sličic.",
                        Font,
                        text,
                        new RectangleF(8, 8, Math.Max(1, bounds.Width - 16), Math.Max(1, bounds.Height - 16))
                    );
                }
            }

            if (editorDurationSeconds > 0.0)
            {
                float startX = Convert.ToSingle(bounds.Width * editorStartSeconds / editorDurationSeconds);
                float endX = Convert.ToSingle(bounds.Width * editorEndSeconds / editorDurationSeconds);
                float currentX = Convert.ToSingle(bounds.Width * editorPreviewPositionSeconds / editorDurationSeconds);

                using (Brush shade = new SolidBrush(Color.FromArgb(145, 0, 0, 0)))
                {
                    if (startX > 0) e.Graphics.FillRectangle(shade, 0, 0, startX, bounds.Height);
                    if (endX < bounds.Width) e.Graphics.FillRectangle(shade, endX, 0, bounds.Width - endX, bounds.Height);
                }
                using (Pen selection = new Pen(Color.FromArgb(50, 190, 255), 3F))
                {
                    e.Graphics.DrawRectangle(selection, startX, 1, Math.Max(1, endX - startX), Math.Max(1, bounds.Height - 3));
                }
                using (Pen marker = new Pen(Color.FromArgb(255, 190, 45), 3F))
                {
                    e.Graphics.DrawLine(marker, currentX, 0, currentX, bounds.Height);
                }
            }
        }

        private int GetEditorPowerPercent()
        {
            if (cmbEditorPower == null)
            {
                return 50;
            }

            if (cmbEditorPower.SelectedIndex == 0)
            {
                return 100;
            }
            if (cmbEditorPower.SelectedIndex == 2)
            {
                return 25;
            }
            return 50;
        }

        private int GetEditorThreadCount()
        {
            return Math.Max(
                1,
                Convert.ToInt32(
                    Math.Ceiling(
                        Environment.ProcessorCount *
                        GetEditorPowerPercent() /
                        100.0
                    )
                )
            );
        }

        private string GetEditorPreset()
        {
            int power =
                GetEditorPowerPercent();
            if (power >= 100)
            {
                return "veryfast";
            }
            if (power >= 50)
            {
                return "fast";
            }
            return "medium";
        }

        private ProcessPriorityClass GetEditorPriority()
        {
            int power =
                GetEditorPowerPercent();
            if (power >= 100)
            {
                return ProcessPriorityClass.Normal;
            }
            if (power >= 50)
            {
                return ProcessPriorityClass.BelowNormal;
            }
            return ProcessPriorityClass.Idle;
        }

        private List<string> BuildEditorVideoFilters(
            double speed
        )
        {
            List<string> filters =
                new List<string>();

            if (cmbEditorRotate != null)
            {
                switch (
                    cmbEditorRotate.SelectedIndex
                )
                {
                    case 1:
                        filters.Add("transpose=1");
                        break;
                    case 2:
                        filters.Add("hflip");
                        filters.Add("vflip");
                        break;
                    case 3:
                        filters.Add("transpose=2");
                        break;
                }
            }

            if (cmbEditorMirror != null)
            {
                if (
                    cmbEditorMirror.SelectedIndex == 1
                )
                {
                    filters.Add("hflip");
                }
                else if (
                    cmbEditorMirror.SelectedIndex == 2
                )
                {
                    filters.Add("vflip");
                }
            }

            if (
                Math.Abs(
                    speed - 1.0
                ) > 0.0001
            )
            {
                filters.Add(
                    "setpts=PTS/" +
                    speed.ToString(
                        "0.###",
                        System.Globalization.CultureInfo.InvariantCulture
                    )
                );
            }

            return filters;
        }

        private async Task RunEditorAsync(
            Button actionButton
        )
        {
            string input =
                txtEditorInput.Text.Trim();

            if (!File.Exists(input))
            {
                MessageBox.Show(
                    this,
                    "Najprej izberi veljaven video.",
                    "Video ni izbran",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            ApplyEditorTimeText();

            if (
                editorDurationSeconds <= 0.0 ||
                editorEndSeconds <=
                editorStartSeconds + 0.05
            )
            {
                MessageBox.Show(
                    this,
                    "Izbrani časovni del ni veljaven.",
                    "Neveljaven izrez",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            string ffmpeg =
                ToolLocator.FindFfmpeg();
            if (
                string.IsNullOrWhiteSpace(
                    ffmpeg
                )
            )
            {
                MessageBox.Show(
                    this,
                    "FFmpeg ni najden. Namesti ga v »Orodja in nastavitve«.",
                    "FFmpeg ni nameščen",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            string output =
                txtEditorOutput.Text.Trim();
            if (
                string.IsNullOrWhiteSpace(
                    output
                )
            )
            {
                UpdateEditorSuggestedOutput();
                output =
                    txtEditorOutput.Text.Trim();
            }

            output =
                Path.ChangeExtension(
                    output,
                    GetEditorOutputExtension()
                );
            output =
                GetUniquePath(output);
            txtEditorOutput.Text =
                output;

            double selectedDuration =
                editorEndSeconds -
                editorStartSeconds;
            double speed =
                GetEditorSpeed();
            double outputDuration =
                selectedDuration /
                speed;
            int threads =
                GetEditorThreadCount();

            List<string> arguments =
                new List<string>();
            arguments.Add("-y");
            arguments.Add("-hide_banner");
            arguments.Add("-loglevel");
            arguments.Add("warning");
            arguments.Add("-ss");
            arguments.Add(
                editorStartSeconds.ToString(
                    "0.###",
                    System.Globalization.CultureInfo.InvariantCulture
                )
            );
            arguments.Add("-i");
            arguments.Add(input);
            arguments.Add("-t");
            arguments.Add(
                selectedDuration.ToString(
                    "0.###",
                    System.Globalization.CultureInfo.InvariantCulture
                )
            );
            arguments.Add("-map");
            arguments.Add("0:v:0");

            bool removeAudio =
                cmbEditorAudio.SelectedIndex == 1;

            if (removeAudio)
            {
                arguments.Add("-an");
            }
            else
            {
                arguments.Add("-map");
                arguments.Add("0:a:0?");
            }

            List<string> videoFilters =
                BuildEditorVideoFilters(
                    speed
                );

            if (videoFilters.Count > 0)
            {
                arguments.Add("-vf");
                arguments.Add(
                    string.Join(
                        ",",
                        videoFilters.ToArray()
                    )
                );
            }

            if (
                !removeAudio &&
                editorInputHasAudio &&
                Math.Abs(
                    speed - 1.0
                ) > 0.0001
            )
            {
                arguments.Add("-af");
                arguments.Add(
                    "atempo=" +
                    speed.ToString(
                        "0.###",
                        System.Globalization.CultureInfo.InvariantCulture
                    )
                );
            }

            arguments.Add("-filter_threads");
            arguments.Add(
                threads.ToString()
            );
            arguments.Add("-threads");
            arguments.Add(
                threads.ToString()
            );
            int editorFormatIndex = cmbEditorOutputFormat.SelectedIndex;
            bool streamCopyMode = editorFormatIndex == 6;
            bool losslessRenderMode = editorFormatIndex == 7;

            if (streamCopyMode)
            {
                if (videoFilters.Count > 0 || Math.Abs(speed - 1.0) > 0.0001)
                {
                    MessageBox.Show(
                        this,
                        "Način brez ponovnega kodiranja podpira samo izrez in po želji odstranitev zvoka. Vrtenje, zrcaljenje, sprememba hitrosti in filtri zahtevajo ponovno kodiranje.",
                        "Brezizgubni način",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information
                    );
                    actionButton.Enabled = true;
                    return;
                }

                arguments.Add("-c");
                arguments.Add("copy");
            }
            else if (losslessRenderMode)
            {
                arguments.Add("-c:v");
                arguments.Add("ffv1");
                arguments.Add("-level");
                arguments.Add("3");
                arguments.Add("-g");
                arguments.Add("1");
                arguments.Add("-slicecrc");
                arguments.Add("1");

                if (!removeAudio)
                {
                    arguments.Add("-c:a");
                    if (Math.Abs(speed - 1.0) > 0.0001)
                    {
                        arguments.Add("flac");
                    }
                    else
                    {
                        arguments.Add("copy");
                    }
                }
            }
            else
            {
                arguments.Add("-c:v");
                if (editorFormatIndex == 2)
                {
                    arguments.Add("libx265");
                    arguments.Add("-preset");
                    arguments.Add(GetEditorPreset());
                    arguments.Add("-crf");
                    arguments.Add("18");
                    arguments.Add("-tag:v");
                    arguments.Add("hvc1");
                }
                else if (editorFormatIndex == 3)
                {
                    arguments.Add("libvpx-vp9");
                    arguments.Add("-crf");
                    arguments.Add("24");
                    arguments.Add("-b:v");
                    arguments.Add("0");
                }
                else if (editorFormatIndex == 5)
                {
                    arguments.Add("mpeg4");
                    arguments.Add("-q:v");
                    arguments.Add("2");
                }
                else
                {
                    arguments.Add("libx264");
                    arguments.Add("-preset");
                    arguments.Add(GetEditorPreset());
                    arguments.Add("-crf");
                    arguments.Add("16");
                }
                arguments.Add("-pix_fmt");
                arguments.Add("yuv420p");

                if (!removeAudio)
                {
                    arguments.Add("-c:a");
                    arguments.Add(editorFormatIndex == 3 ? "libopus" : (editorFormatIndex == 5 ? "libmp3lame" : "aac"));
                    arguments.Add("-b:a");
                    arguments.Add(editorFormatIndex == 3 ? "256k" : "320k");
                }
            }

            arguments.Add("-avoid_negative_ts");
            arguments.Add("make_zero");

            if (
                GetEditorOutputExtension() == ".mp4" ||
                GetEditorOutputExtension() == ".mov"
            )
            {
                arguments.Add("-movflags");
                arguments.Add("+faststart");
            }

            arguments.Add("-progress");
            arguments.Add("pipe:1");
            arguments.Add("-nostats");
            arguments.Add(output);

            actionButton.Enabled = false;
            ResetEditorProgress(
                "Urejanje videa poteka …"
            );

            Log(
                "Urejevalnik: izrez " +
                FormatEditorTime(
                    editorStartSeconds
                ) +
                "–" +
                FormatEditorTime(
                    editorEndSeconds
                ) +
                ", hitrost " +
                speed.ToString(
                    "0.##",
                    System.Globalization.CultureInfo.InvariantCulture
                ) +
                "×, moč " +
                GetEditorPowerPercent() +
                " %.",
                "UREJEVALNIK"
            );

            try
            {
                int exitCode =
                    await RunEditorProgressProcessAsync(
                        ffmpeg,
                        arguments,
                        "UREJEVALNIK",
                        outputDuration,
                        GetEditorPriority()
                    );

                if (
                    exitCode != 0 ||
                    !File.Exists(output)
                )
                {
                    throw new InvalidOperationException(
                        "Urejanje videa ni uspelo. Podrobnosti so v spodnjem dnevniku."
                    );
                }

                UpdateEditorProgress(
                    100.0,
                    editorLastElapsed,
                    TimeSpan.Zero,
                    ""
                );
                lblEditorStatus.Text =
                    "Končano: " +
                    output;
                Log(
                    "Končna datoteka: " +
                    output,
                    "UREJEVALNIK"
                );

                MessageBox.Show(
                    this,
                    "Urejanje videa je končano.\r\n\r\n" +
                    output,
                    "Končano",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
            }
            catch (Exception e)
            {
                lblEditorStatus.Text =
                    "Napaka: " +
                    e.Message;
                ShowError(
                    "Urejanje videa ni uspelo.",
                    e
                );
            }
            finally
            {
                actionButton.Enabled = true;
            }
        }

        private void AddEditorMergeFiles()
        {
            OpenFileDialog dialog =
                new OpenFileDialog();
            dialog.Title =
                "Izberi posnetke v želenem vrstnem redu";
            dialog.Multiselect = true;
            dialog.Filter =
                "Video datoteke|*.mp4;*.mkv;*.mov;*.m4v;*.ts;*.mts;*.m2ts;*.webm;*.avi|Vse datoteke|*.*";

            if (
                dialog.ShowDialog(this) !=
                DialogResult.OK
            )
            {
                return;
            }

            AddEditorMergeFilesFromPaths(
                dialog.FileNames
            );
        }

        private void RemoveEditorMergeFile()
        {
            int index =
                lstEditorMergeFiles.SelectedIndex;
            if (index >= 0)
            {
                lstEditorMergeFiles.Items.RemoveAt(
                    index
                );
            }
        }

        private void MoveEditorMergeFile(
            int direction
        )
        {
            int index =
                lstEditorMergeFiles.SelectedIndex;
            int target =
                index + direction;

            if (
                index < 0 ||
                target < 0 ||
                target >=
                lstEditorMergeFiles.Items.Count
            )
            {
                return;
            }

            object item =
                lstEditorMergeFiles.Items[index];
            lstEditorMergeFiles.Items.RemoveAt(
                index
            );
            lstEditorMergeFiles.Items.Insert(
                target,
                item
            );
            lstEditorMergeFiles.SelectedIndex =
                target;
        }

        private string GetEditorMergeExtension()
        {
            return
                cmbEditorMergeFormat != null &&
                cmbEditorMergeFormat.SelectedIndex == 1
                    ? ".mp4"
                    : ".mkv";
        }

        private void UpdateEditorMergeSuggestedOutput()
        {
            if (
                txtEditorMergeOutput == null ||
                lstEditorMergeFiles == null ||
                lstEditorMergeFiles.Items.Count == 0
            )
            {
                return;
            }

            string first =
                Convert.ToString(
                    lstEditorMergeFiles.Items[0]
                );
            string folder =
                Path.GetDirectoryName(first);
            txtEditorMergeOutput.Text =
                Path.Combine(
                    folder,
                    "Združeni posnetki" +
                    GetEditorMergeExtension()
                );
        }

        private void ChooseEditorMergeOutput()
        {
            SaveFileDialog dialog =
                new SaveFileDialog();
            string extension =
                GetEditorMergeExtension();
            dialog.Title =
                "Izberi združeno video datoteko";
            dialog.DefaultExt =
                extension.TrimStart('.');
            dialog.Filter =
                extension == ".mp4"
                    ? "MP4 video|*.mp4"
                    : "Matroska video|*.mkv";

            if (
                !string.IsNullOrWhiteSpace(
                    txtEditorMergeOutput.Text
                )
            )
            {
                dialog.FileName =
                    Path.GetFileName(
                        txtEditorMergeOutput.Text
                    );
            }

            if (
                dialog.ShowDialog(this) ==
                DialogResult.OK
            )
            {
                txtEditorMergeOutput.Text =
                    Path.ChangeExtension(
                        dialog.FileName,
                        extension
                    );
            }
        }

        private Task<string>
            ReadEditorMergeSignatureAsync(
                string ffprobe,
                string input
            )
        {
            return Task.Run(
                delegate
                {
                    ProcessStartInfo info =
                        new ProcessStartInfo();
                    info.FileName = ffprobe;
                    info.Arguments =
                        ToolLocator.JoinArguments(
                            new string[]
                            {
                                "-v",
                                "error",
                                "-show_entries",
                                "stream=codec_type,codec_name,width,height,pix_fmt,r_frame_rate,sample_rate,channels,channel_layout",
                                "-of",
                                "json",
                                input
                            }
                        );
                    info.UseShellExecute = false;
                    ToolLocator.ConfigureUtf8Process(info);
                    info.CreateNoWindow = true;
                    info.RedirectStandardOutput = true;
                    info.RedirectStandardError = true;
                    info.StandardOutputEncoding =
                        Encoding.UTF8;

                    using (
                        Process process =
                            Process.Start(info)
                    )
                    {
                        if (process == null)
                        {
                            return "";
                        }

                        string output =
                            process.StandardOutput.ReadToEnd();
                        process.WaitForExit();

                        if (process.ExitCode != 0)
                        {
                            return "";
                        }

                        return Regex.Replace(
                            output,
                            @"\s+",
                            ""
                        );
                    }
                }
            );
        }

        private string EscapeConcatPath(
            string path
        )
        {
            return
                (path ?? "")
                .Replace(
                    "'",
                    "'\\''"
                );
        }

        private async Task RunEditorMergeAsync(
            Button actionButton
        )
        {
            List<string> files =
                lstEditorMergeFiles.Items
                .Cast<object>()
                .Select(
                    delegate(object item)
                    {
                        return Convert.ToString(
                            item
                        );
                    }
                )
                .Where(
                    delegate(string file)
                    {
                        return File.Exists(file);
                    }
                )
                .ToList();

            if (files.Count < 2)
            {
                MessageBox.Show(
                    this,
                    "Za združevanje izberi najmanj dva posnetka.",
                    "Premalo posnetkov",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            string ffmpeg =
                ToolLocator.FindFfmpeg();
            string ffprobe =
                ToolLocator.FindFfprobe();

            if (
                string.IsNullOrWhiteSpace(ffmpeg) ||
                string.IsNullOrWhiteSpace(ffprobe)
            )
            {
                MessageBox.Show(
                    this,
                    "FFmpeg ali ffprobe ni najden. Namesti orodja v »Orodja in nastavitve«.",
                    "Orodja niso nameščena",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            string firstExtension =
                Path.GetExtension(
                    files[0]
                );
            bool sameExtension =
                files.All(
                    delegate(string file)
                    {
                        return string.Equals(
                            Path.GetExtension(file),
                            firstExtension,
                            StringComparison.OrdinalIgnoreCase
                        );
                    }
                );

            if (!sameExtension)
            {
                MessageBox.Show(
                    this,
                    "Hitro združevanje brez kodiranja zahteva enako vrsto vhodne datoteke. Najprej jih v zavihku Pretvornik pretvori v enak format.",
                    "Različne vrste datotek",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            lblEditorMergeStatus.Text =
                "Preverjam kodeke, ločljivost, FPS in zvok …";

            string referenceSignature =
                await ReadEditorMergeSignatureAsync(
                    ffprobe,
                    files[0]
                );

            if (
                string.IsNullOrWhiteSpace(
                    referenceSignature
                )
            )
            {
                MessageBox.Show(
                    this,
                    "Lastnosti prvega posnetka ni bilo mogoče prebrati.",
                    "Preverjanje ni uspelo",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            for (
                int index = 1;
                index < files.Count;
                index++
            )
            {
                string signature =
                    await ReadEditorMergeSignatureAsync(
                        ffprobe,
                        files[index]
                    );

                if (
                    !string.Equals(
                        referenceSignature,
                        signature,
                        StringComparison.Ordinal
                    )
                )
                {
                    MessageBox.Show(
                        this,
                        "Posnetki nimajo popolnoma enakih kodekov, ločljivosti, FPS ali zvočnih lastnosti.\r\n\r\nNezdružljiv posnetek:\r\n" +
                        files[index] +
                        "\r\n\r\nNajprej vse posnetke v Pretvorniku pretvori v isti profil, nato ponovi združevanje.",
                        "Posnetki niso združljivi",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Warning
                    );
                    lblEditorMergeStatus.Text =
                        "Združevanje ustavljeno zaradi različnih lastnosti posnetkov.";
                    return;
                }
            }

            string output =
                txtEditorMergeOutput.Text.Trim();
            if (
                string.IsNullOrWhiteSpace(
                    output
                )
            )
            {
                UpdateEditorMergeSuggestedOutput();
                output =
                    txtEditorMergeOutput.Text.Trim();
            }

            output =
                Path.ChangeExtension(
                    output,
                    GetEditorMergeExtension()
                );
            output =
                GetUniquePath(output);
            txtEditorMergeOutput.Text =
                output;

            string workFolder =
                Path.Combine(
                    AppPaths.WorkFolder,
                    "EditorMerge_" +
                    Guid.NewGuid().ToString("N")
                );
            Directory.CreateDirectory(
                workFolder
            );

            string listFile =
                Path.Combine(
                    workFolder,
                    "seznam.txt"
                );
            StringBuilder listContent =
                new StringBuilder();

            foreach (string file in files)
            {
                listContent.AppendLine(
                    "file '" +
                    EscapeConcatPath(file) +
                    "'"
                );
            }

            File.WriteAllText(
                listFile,
                listContent.ToString(),
                new UTF8Encoding(false)
            );

            double totalDuration = 0.0;
            foreach (string file in files)
            {
                totalDuration +=
                    await ReadStandaloneDurationAsync(
                        ffprobe,
                        file
                    );
            }

            List<string> arguments =
                new List<string>();
            arguments.Add("-y");
            arguments.Add("-hide_banner");
            arguments.Add("-loglevel");
            arguments.Add("warning");
            arguments.Add("-f");
            arguments.Add("concat");
            arguments.Add("-safe");
            arguments.Add("0");
            arguments.Add("-i");
            arguments.Add(listFile);
            arguments.Add("-map");
            arguments.Add("0");
            arguments.Add("-c");
            arguments.Add("copy");
            arguments.Add("-avoid_negative_ts");
            arguments.Add("make_zero");
            arguments.Add("-progress");
            arguments.Add("pipe:1");
            arguments.Add("-nostats");
            arguments.Add(output);

            actionButton.Enabled = false;
            ResetEditorProgress(
                "Združevanje posnetkov poteka …"
            );
            lblEditorMergeStatus.Text =
                "Združujem " +
                files.Count +
                " posnetkov brez ponovnega kodiranja …";

            try
            {
                int exitCode =
                    await RunEditorProgressProcessAsync(
                        ffmpeg,
                        arguments,
                        "ZDRUŽEVANJE",
                        totalDuration,
                        ProcessPriorityClass.BelowNormal
                    );

                if (
                    exitCode != 0 ||
                    !File.Exists(output)
                )
                {
                    throw new InvalidOperationException(
                        "FFmpeg posnetkov ni mogel združiti. Čeprav imajo podobne lastnosti, se lahko razlikujejo časovna osnova ali drugi notranji parametri."
                    );
                }

                UpdateEditorProgress(
                    100.0,
                    editorLastElapsed,
                    TimeSpan.Zero,
                    ""
                );
                lblEditorMergeStatus.Text =
                    "Končano: " +
                    output;
                lblEditorStatus.Text =
                    "Združevanje je končano.";
                Log(
                    "Združena datoteka: " +
                    output,
                    "ZDRUŽEVANJE"
                );

                MessageBox.Show(
                    this,
                    "Posnetki so uspešno združeni.\r\n\r\n" +
                    output,
                    "Končano",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
            }
            catch (Exception e)
            {
                lblEditorMergeStatus.Text =
                    "Napaka: " +
                    e.Message;
                ShowError(
                    "Združevanje posnetkov ni uspelo.",
                    e
                );
            }
            finally
            {
                actionButton.Enabled = true;
                try
                {
                    if (Directory.Exists(workFolder))
                    {
                        Directory.Delete(
                            workFolder,
                            true
                        );
                    }
                }
                catch
                {
                }
            }
        }

        private void ResetEditorProgress(
            string message
        )
        {
            editorLastElapsed =
                TimeSpan.Zero;

            if (editorProgress != null)
            {
                editorProgress.Value = 0;
            }
            if (lblEditorProgress != null)
            {
                lblEditorProgress.Text =
                    "0,0 %  |  Preteklo: 00:00  |  Preostalo: --:--";
            }
            if (lblEditorStatus != null)
            {
                lblEditorStatus.Text =
                    message;
            }
        }

        private void UpdateEditorProgress(
            double percent,
            TimeSpan elapsed,
            TimeSpan remaining,
            string speed
        )
        {
            editorLastElapsed =
                elapsed;

            SafeUi(
                delegate
                {
                    if (editorProgress != null)
                    {
                        int value =
                            Convert.ToInt32(
                                Math.Round(
                                    Math.Max(
                                        0.0,
                                        Math.Min(
                                            100.0,
                                            percent
                                        )
                                    ) *
                                    10.0
                                )
                            );
                        editorProgress.Value =
                            Math.Max(
                                editorProgress.Minimum,
                                Math.Min(
                                    editorProgress.Maximum,
                                    value
                                )
                            );
                    }

                    if (lblEditorProgress != null)
                    {
                        lblEditorProgress.Text =
                            percent.ToString("0.0") +
                            " %  |  Preteklo: " +
                            FormatSubtitleStudioTime(
                                elapsed
                            ) +
                            "  |  Preostalo: " +
                            (
                                remaining ==
                                TimeSpan.MaxValue
                                    ? "--:--"
                                    : FormatSubtitleStudioTime(
                                        remaining
                                    )
                            ) +
                            (
                                string.IsNullOrWhiteSpace(
                                    speed
                                )
                                    ? ""
                                    : "  |  Hitrost: " +
                                      speed
                            );
                    }
                }
            );
        }

        private Task<int> RunEditorProgressProcessAsync(
            string executable,
            IEnumerable<string> arguments,
            string prefix,
            double duration,
            ProcessPriorityClass priority
        )
        {
            TaskCompletionSource<int> completion =
                new TaskCompletionSource<int>();

            ProcessStartInfo info =
                new ProcessStartInfo();
            info.FileName =
                executable;
            info.Arguments =
                ToolLocator.JoinArguments(
                    arguments
                );
            info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
            info.CreateNoWindow = true;
            info.WindowStyle =
                ProcessWindowStyle.Hidden;
            info.RedirectStandardOutput = true;
            info.RedirectStandardError = true;
            info.StandardOutputEncoding =
                Encoding.UTF8;
            info.StandardErrorEncoding =
                Encoding.UTF8;

            Process process =
                new Process();
            process.StartInfo =
                info;
            process.EnableRaisingEvents = true;

            Stopwatch stopwatch =
                Stopwatch.StartNew();
            string speed = "";
            int processExited = 0;
            int outputClosed = 0;
            int errorClosed = 0;
            int exitCode = -1;

            Action tryComplete = delegate
            {
                if (
                    Interlocked.CompareExchange(
                        ref processExited,
                        0,
                        0
                    ) == 1 &&
                    Interlocked.CompareExchange(
                        ref outputClosed,
                        0,
                        0
                    ) == 1 &&
                    Interlocked.CompareExchange(
                        ref errorClosed,
                        0,
                        0
                    ) == 1
                )
                {
                    stopwatch.Stop();
                    completion.TrySetResult(
                        exitCode
                    );
                }
            };

            process.OutputDataReceived += delegate(
                object sender,
                DataReceivedEventArgs e
            )
            {
                if (e.Data == null)
                {
                    Interlocked.Exchange(
                        ref outputClosed,
                        1
                    );
                    tryComplete();
                    return;
                }

                string line =
                    e.Data.Trim();

                if (
                    line.StartsWith(
                        "speed=",
                        StringComparison.Ordinal
                    )
                )
                {
                    speed =
                        line.Substring(6);
                    return;
                }

                if (
                    line.StartsWith(
                        "out_time_us=",
                        StringComparison.Ordinal
                    ) ||
                    line.StartsWith(
                        "out_time_ms=",
                        StringComparison.Ordinal
                    )
                )
                {
                    int equals =
                        line.IndexOf('=');
                    long value;

                    if (
                        equals >= 0 &&
                        long.TryParse(
                            line.Substring(
                                equals + 1
                            ),
                            out value
                        )
                    )
                    {
                        double seconds =
                            value /
                            1000000.0;
                        double percent =
                            duration > 0.0
                                ? Math.Max(
                                    0.0,
                                    Math.Min(
                                        99.9,
                                        seconds /
                                        duration *
                                        100.0
                                    )
                                )
                                : 0.0;

                        TimeSpan remaining =
                            TimeSpan.MaxValue;

                        if (
                            percent > 0.2 &&
                            seconds > 0.0 &&
                            duration > seconds
                        )
                        {
                            double remainingSeconds =
                                stopwatch.Elapsed.TotalSeconds *
                                (duration - seconds) /
                                seconds;

                            if (
                                remainingSeconds >= 0.0 &&
                                remainingSeconds <
                                TimeSpan.MaxValue.TotalSeconds
                            )
                            {
                                remaining =
                                    TimeSpan.FromSeconds(
                                        remainingSeconds
                                    );
                            }
                        }

                        UpdateEditorProgress(
                            percent,
                            stopwatch.Elapsed,
                            remaining,
                            speed
                        );
                    }

                    return;
                }

                if (
                    string.Equals(
                        line,
                        "progress=end",
                        StringComparison.Ordinal
                    )
                )
                {
                    UpdateEditorProgress(
                        100.0,
                        stopwatch.Elapsed,
                        TimeSpan.Zero,
                        speed
                    );
                    return;
                }

                if (
                    !IsFfmpegTechnicalLine(
                        line
                    )
                )
                {
                    Log(
                        line,
                        prefix
                    );
                }
            };

            process.ErrorDataReceived += delegate(
                object sender,
                DataReceivedEventArgs e
            )
            {
                if (e.Data == null)
                {
                    Interlocked.Exchange(
                        ref errorClosed,
                        1
                    );
                    tryComplete();
                    return;
                }

                if (
                    !string.IsNullOrWhiteSpace(
                        e.Data
                    ) &&
                    !IsFfmpegTechnicalLine(
                        e.Data
                    )
                )
                {
                    Log(
                        e.Data,
                        prefix
                    );
                }
            };

            process.Exited += delegate
            {
                try
                {
                    exitCode =
                        process.ExitCode;
                }
                catch
                {
                    exitCode = -1;
                }

                Interlocked.Exchange(
                    ref processExited,
                    1
                );
                tryComplete();
            };

            try
            {
                if (!process.Start())
                {
                    throw new InvalidOperationException(
                        "Procesa ni bilo mogoče zagnati."
                    );
                }

                try
                {
                    process.PriorityClass =
                        priority;
                }
                catch
                {
                }

                process.BeginOutputReadLine();
                process.BeginErrorReadLine();
            }
            catch (Exception e)
            {
                stopwatch.Stop();
                completion.TrySetException(e);
            }

            return completion.Task.ContinueWith(
                delegate(Task<int> task)
                {
                    try
                    {
                        process.Dispose();
                    }
                    catch
                    {
                    }

                    return task.GetAwaiter().GetResult();
                }
            );
        }

        private Panel BuildQueuePanel()
        {
            Panel panel = new Panel();
            panel.Dock = DockStyle.Fill;
            panel.BackColor = Color.White;

            FlowLayoutPanel toolbar = new FlowLayoutPanel();
            toolbar.Dock = DockStyle.Top;
            toolbar.Height = 44;
            toolbar.Padding = new Padding(8, 5, 8, 4);
            toolbar.WrapContents = false;
            panel.Controls.Add(toolbar);

            btnStartQueue = NewButton("ZAČNI VRSTO", 125);
            btnStartQueue.Font = new Font("Segoe UI Semibold", 9.5F);
            btnStartQueue.Click += delegate { StartQueue(); };
            toolbar.Controls.Add(btnStartQueue);

            btnStopQueue = NewButton("Ustavi po aktivnih", 128);
            btnStopQueue.Click += delegate
            {
                queueRunning = false;
                Log("Vrsta je ustavljena. Aktivni prenosi se bodo dokončali.", "VRSTA");
                RefreshQueueStatus();
            };
            toolbar.Controls.Add(btnStopQueue);

            btnCancelSelected = NewButton("Prekliči izbrano", 120);
            btnCancelSelected.Click += delegate { CancelSelected(); };
            toolbar.Controls.Add(btnCancelSelected);

            btnRemoveFinished = NewButton("Odstrani končane", 128);
            btnRemoveFinished.Click += delegate { RemoveFinished(); };
            toolbar.Controls.Add(btnRemoveFinished);

            btnOpenFolder = NewButton("Odpri mapo", 100);
            btnOpenFolder.Click += delegate { OpenOutputFolder(); };
            toolbar.Controls.Add(btnOpenFolder);

            lblQueueStatus = new Label();
            lblQueueStatus.Text = "Čaka: 0   Aktivni: 0   Končani: 0   Napake: 0";
            lblQueueStatus.AutoSize = true;
            lblQueueStatus.Margin = new Padding(18, 8, 0, 0);
            toolbar.Controls.Add(lblQueueStatus);

            grid = new DataGridView();
            grid.Dock = DockStyle.Fill;
            grid.AllowUserToAddRows = false;
            grid.AllowUserToDeleteRows = false;
            grid.AllowUserToResizeRows = false;
            grid.ReadOnly = true;
            grid.MultiSelect = true;
            grid.SelectionMode = DataGridViewSelectionMode.FullRowSelect;
            grid.AutoGenerateColumns = false;
            grid.RowHeadersVisible = false;
            grid.BackgroundColor = Color.White;
            grid.BorderStyle = BorderStyle.None;
            grid.AutoSizeRowsMode = DataGridViewAutoSizeRowsMode.AllCells;
            grid.CellDoubleClick += delegate(object sender, DataGridViewCellEventArgs e)
            {
                if (e.RowIndex >= 0)
                {
                    DownloadJob job = grid.Rows[e.RowIndex].Tag as DownloadJob;
                    if (job != null && !string.IsNullOrWhiteSpace(job.FinalFile) && File.Exists(job.FinalFile))
                    {
                        Process.Start("explorer.exe", "/select," + ToolLocator.Quote(job.FinalFile));
                    }
                }
            };

            AddGridColumn("Stanje", 105);
            AddGridColumn("Napredek", 75);
            AddGridColumn("Hitrost", 95);
            AddGridColumn("ETA", 60);
            AddGridColumn("Vir", 115);
            AddGridColumn("Kakovost", 115);
            AddGridColumn("Format", 170);

            DataGridViewTextBoxColumn titleColumn = new DataGridViewTextBoxColumn();
            titleColumn.Name = "Naslov";
            titleColumn.HeaderText = "Naslov / povezava / datoteka";
            titleColumn.AutoSizeMode = DataGridViewAutoSizeColumnMode.Fill;
            titleColumn.MinimumWidth = 260;
            grid.Columns.Add(titleColumn);

            panel.Controls.Add(grid);
            grid.BringToFront();
            return panel;
        }

