        private void ShowEffectsInformation()
        {
            ShowSubtitleInformation(
                "Učinki, prekrivanje in filtri – podrobna pomoč",
                "IZBIRA OBMOČJA Z MIŠKO\r\n\r\n" +
                "Na predogledu pritisni levi gumb miške, povleci pravokotnik in spusti. Program sam izračuna X, Y, širino in višino v odstotkih, zato se območje prilagodi tudi drugi ločljivosti.\r\n\r\n" +
                "VEČ ZAMEGLITEV ALI MOZAIKOV\r\n\r\n" +
                "Za vsako osebo, logotip ali napis označi novo območje in klikni »Dodaj območje«. V seznam lahko dodaš več plasti. Močan mozaik je namenjen popolni neprepoznavnosti; zameglitev je mehkejša.\r\n\r\n" +
                "ČAS PRIKAZA\r\n\r\n" +
                "Čas vpiši kot HH:MM:SS.000. Označi »Cel video«, kadar naj plast velja od začetka do konca. Primer: 00:00:05.000–00:00:12.500 pokaže plast samo v tem delu.\r\n\r\n" +
                "SLIKA, ANIMACIJA ALI GIF\r\n\r\n" +
                "Podprti so PNG, JPG, BMP, WebP, GIF in APNG, če jih zna prebrati trenutni FFmpeg. Prosojni PNG je najboljši za logotip. Animirani GIF/WebP se ponavlja v izbranem časovnem obdobju.\r\n\r\n" +
                "EMOJI IN BESEDILO\r\n\r\n" +
                "V polje lahko vstaviš emoji z Win + . ali navadno besedilo. FFmpeg uporabi Windowsovo pisavo Segoe UI Emoji; nekateri FFmpeg paketi barvne emoji izrišejo enobarvno. Za popolnoma enak videz uporabi PNG ali animirani GIF.\r\n\r\n" +
                "KAKOVOST\r\n\r\nUčinki, filtri, zameglitev, vrtenje in sprememba hitrosti zahtevajo ponovno kodiranje. Privzeto je označen »Brezizgubni MKV«: spremenjene sličice se zapišejo s kodekom FFV1, zvočna sled pa se prekopira brez spremembe. Datoteka je lahko zelo velika. Manjši MP4 uporablja H.264 CRF 16 in zato ni matematično povsem enak izvirniku. Popolnoma enak izvirni tok brez sprememb je mogoč samo z načinom brez ponovnega kodiranja.\r\n\r\n" +
                "FILTRI\r\n\r\n" +
                "Filmski, vintage, črno-beli, sepia, živahni, mehki, risani, ostri in vignette filtri uporabljajo standardne FFmpeg filtre. Risani videz je stilizacija, ne generativna AI pretvorba.\r\n\r\n" +
                "AI ODSTRANJEVANJE LOGOTIPA\r\n\r\n" +
                "Samodejno ustvarjanje manjkajočega ozadja ni vključeno. Zanesljiv video-inpainting zahteva ločen velik model, veliko grafičnega pomnilnika in časovno stabilizacijo med sličicami. Program zato ponuja predvidljive mozaike, zameglitve, prekrivanja in lastne slike."
            );
        }

        private void ClampEffectsRegion()
        {
            if (numEffectsX == null || numEffectsY == null || numEffectsWidth == null || numEffectsHeight == null) return;
            decimal maxWidth = 100M - numEffectsX.Value;
            decimal maxHeight = 100M - numEffectsY.Value;
            if (numEffectsWidth.Value > maxWidth) numEffectsWidth.Value = Math.Max(numEffectsWidth.Minimum, maxWidth);
            if (numEffectsHeight.Value > maxHeight) numEffectsHeight.Value = Math.Max(numEffectsHeight.Minimum, maxHeight);
        }

        private void UpdateEffectsControls()
        {
            if (effectsPreviewPanel != null) effectsPreviewPanel.Invalidate();
        }

        private async void OpenEffectsInput()
        {
            OpenFileDialog dialog = new OpenFileDialog();
            dialog.Title = "Izberi video za učinke";
            dialog.Filter = "Video datoteke|*.mp4;*.mkv;*.webm;*.mov;*.avi;*.m4v;*.ts;*.mts;*.m2ts;*.wmv;*.flv|Vse datoteke|*.*";
            if (dialog.ShowDialog(this) == DialogResult.OK) await LoadEffectsInputAsync(dialog.FileName);
        }

        private async void HandleEffectsInputDrop(string[] files)
        {
            string file = files.FirstOrDefault(delegate(string value) { return File.Exists(value) && IsVideoFile(value); });
            if (!string.IsNullOrWhiteSpace(file)) await LoadEffectsInputAsync(file);
        }

        private async Task LoadEffectsInputAsync(string fileName)
        {
            if (!File.Exists(fileName)) return;
            txtEffectsInput.Text = fileName;
            string ffprobe = ToolLocator.FindFfprobe();
            effectsDurationSeconds = string.IsNullOrWhiteSpace(ffprobe)
                ? 0.0
                : await ReadStandaloneDurationAsync(ffprobe, fileName);
            if (chkEffectsWholeVideo != null) chkEffectsWholeVideo.Checked = true;
            if (txtEffectsStartTime != null) txtEffectsStartTime.Text = "00:00:00.000";
            if (txtEffectsEndTime != null) txtEffectsEndTime.Text = FormatEditorTime(effectsDurationSeconds);
            UpdateEffectsTimeControls();
            UpdateEffectsSuggestedOutput();
            await RefreshEffectsPreviewFrameAsync();
            lblEffectsStatus.Text = "Video je pripravljen. Povleci območje ali dodaj sliko/emoji.";
        }

        private async Task RefreshEffectsPreviewFrameAsync()
        {
            if (txtEffectsInput == null || !File.Exists(txtEffectsInput.Text)) return;
            Image image = await ExtractPlainVideoFrameAsync(txtEffectsInput.Text, 0.0);
            if (image == null) return;
            if (effectsPreviewImage != null) effectsPreviewImage.Dispose();
            effectsPreviewImage = image;
            if (effectsPreviewPanel != null) effectsPreviewPanel.Invalidate();
        }

        private Task<Image> ExtractPlainVideoFrameAsync(string input, double position)
        {
            return Task.Run<Image>(delegate
            {
                string ffmpeg = ToolLocator.FindFfmpeg();
                if (string.IsNullOrWhiteSpace(ffmpeg) || !File.Exists(ffmpeg)) return null;
                ProcessStartInfo info = new ProcessStartInfo();
                info.FileName = ffmpeg;
                info.Arguments = ToolLocator.JoinArguments(new string[]
                {
                    "-hide_banner", "-loglevel", "error", "-ss",
                    position.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture),
                    "-i", input, "-frames:v", "1", "-an", "-sn", "-vf", "scale=1280:-2",
                    "-f", "image2pipe", "-vcodec", "mjpeg", "pipe:1"
                });
                info.UseShellExecute = false;
                ToolLocator.ConfigureUtf8Process(info);
                info.CreateNoWindow = true;
                info.RedirectStandardOutput = true;
                info.RedirectStandardError = true;
                try
                {
                    using (Process process = Process.Start(info))
                    {
                        if (process == null) return null;
                        process.StandardError.ReadToEndAsync();
                        using (MemoryStream stream = new MemoryStream())
                        {
                            process.StandardOutput.BaseStream.CopyTo(stream);
                            process.WaitForExit();
                            if (process.ExitCode != 0 || stream.Length == 0) return null;
                            stream.Position = 0;
                            using (Image loaded = Image.FromStream(stream)) return new Bitmap(loaded);
                        }
                    }
                }
                catch { return null; }
            });
        }

        private void OpenEffectsOverlay()
        {
            OpenFileDialog dialog = new OpenFileDialog();
            dialog.Title = "Izberi sliko, animacijo ali GIF";
            dialog.Filter = "Slike in animacije|*.png;*.webp;*.jpg;*.jpeg;*.bmp;*.gif;*.apng|Vse datoteke|*.*";
            if (dialog.ShowDialog(this) == DialogResult.OK) txtEffectsOverlay.Text = dialog.FileName;
        }

        private void HandleEffectsOverlayDrop(string[] files)
        {
            string file = files.FirstOrDefault(delegate(string value)
            {
                string extension = Path.GetExtension(value).ToLowerInvariant();
                return File.Exists(value) && new string[] { ".png", ".webp", ".jpg", ".jpeg", ".bmp", ".gif", ".apng" }.Contains(extension, StringComparer.OrdinalIgnoreCase);
            });
            if (!string.IsNullOrWhiteSpace(file)) txtEffectsOverlay.Text = file;
        }

        private void ChooseEffectsOutput()
        {
            bool lossless = chkEffectsLosslessOutput != null && chkEffectsLosslessOutput.Checked;
            SaveFileDialog dialog = new SaveFileDialog();
            dialog.Title = "Izberi končno datoteko";
            dialog.Filter = lossless
                ? "Brezizgubni MKV video|*.mkv"
                : "MP4 video visoke kakovosti|*.mp4";
            dialog.DefaultExt = lossless ? "mkv" : "mp4";
            if (!string.IsNullOrWhiteSpace(txtEffectsOutput.Text)) dialog.FileName = Path.GetFileName(txtEffectsOutput.Text);
            if (dialog.ShowDialog(this) == DialogResult.OK)
            {
                txtEffectsOutput.Text = Path.ChangeExtension(dialog.FileName, lossless ? ".mkv" : ".mp4");
            }
        }

        private void UpdateEffectsSuggestedOutput()
        {
            if (txtEffectsInput == null || txtEffectsOutput == null || string.IsNullOrWhiteSpace(txtEffectsInput.Text)) return;
            bool lossless = chkEffectsLosslessOutput != null && chkEffectsLosslessOutput.Checked;
            txtEffectsOutput.Text = Path.Combine(
                Path.GetDirectoryName(txtEffectsInput.Text),
                Path.GetFileNameWithoutExtension(txtEffectsInput.Text) +
                (lossless ? " - učinki brezizgubno.mkv" : " - učinki.mp4")
            );
        }

        private double GetEffectsStartSeconds()
        {
            if (chkEffectsWholeVideo != null && chkEffectsWholeVideo.Checked) return 0.0;
            double seconds;
            if (txtEffectsStartTime != null && TryParseEditorTime(txtEffectsStartTime.Text, out seconds))
            {
                return Math.Max(0.0, Math.Min(effectsDurationSeconds, seconds));
            }
            return 0.0;
        }

        private double GetEffectsLayerEnd()
        {
            if (chkEffectsWholeVideo != null && chkEffectsWholeVideo.Checked)
            {
                return effectsDurationSeconds > 0.0 ? effectsDurationSeconds : 86400.0;
            }

            double seconds;
            if (txtEffectsEndTime != null && TryParseEditorTime(txtEffectsEndTime.Text, out seconds))
            {
                return Math.Max(0.0, Math.Min(effectsDurationSeconds > 0.0 ? effectsDurationSeconds : 86400.0, seconds));
            }
            return effectsDurationSeconds > 0.0 ? effectsDurationSeconds : 86400.0;
        }

        private void ApplyEffectsTimeText()
        {
            if (effectsUpdatingTimeControls) return;
            double start = GetEffectsStartSeconds();
            double end = GetEffectsLayerEnd();
            if (end <= start)
            {
                end = effectsDurationSeconds > start ? effectsDurationSeconds : start + 1.0;
            }
            if (txtEffectsStartTime != null) txtEffectsStartTime.Text = FormatEditorTime(start);
            if (txtEffectsEndTime != null) txtEffectsEndTime.Text = FormatEditorTime(end);
        }

        private void UpdateEffectsTimeControls()
        {
            if (effectsUpdatingTimeControls) return;
            effectsUpdatingTimeControls = true;
            try
            {
                bool whole = chkEffectsWholeVideo != null && chkEffectsWholeVideo.Checked;
                if (txtEffectsStartTime != null)
                {
                    txtEffectsStartTime.Enabled = !whole;
                    if (whole) txtEffectsStartTime.Text = "00:00:00.000";
                }
                if (txtEffectsEndTime != null)
                {
                    txtEffectsEndTime.Enabled = !whole;
                    if (whole) txtEffectsEndTime.Text = FormatEditorTime(effectsDurationSeconds);
                }
            }
            finally
            {
                effectsUpdatingTimeControls = false;
            }
        }

        private EffectLayerItem CreateCurrentEffectsLayer(string kind)
        {
            EffectLayerItem item = new EffectLayerItem();
            item.Kind = kind;
            item.Mode = cmbEffectsMode == null || cmbEffectsMode.SelectedItem == null ? "Močan mozaik" : cmbEffectsMode.SelectedItem.ToString();
            item.X = numEffectsX.Value;
            item.Y = numEffectsY.Value;
            item.Width = numEffectsWidth.Value;
            item.Height = numEffectsHeight.Value;
            item.Strength = numEffectsStrength == null ? 32 : Convert.ToInt32(numEffectsStrength.Value);
            item.StartSeconds = GetEffectsStartSeconds();
            item.EndSeconds = GetEffectsLayerEnd();
            item.Opacity = numEffectsOpacity == null ? 100 : Convert.ToInt32(numEffectsOpacity.Value);
            return item;
        }

        private void AddEffectsRegionLayer()
        {
            EffectLayerItem item = CreateCurrentEffectsLayer("region");
            effectsLayers.Add(item);
            RefreshEffectsLayerList();
            lstEffectsLayers.SelectedIndex = effectsLayers.Count - 1;
        }

        private void AddEffectsImageLayer()
        {
            string file = txtEffectsOverlay == null ? "" : txtEffectsOverlay.Text.Trim();
            if (!File.Exists(file))
            {
                MessageBox.Show(this, "Izberi veljavno sliko, GIF, WebP ali APNG.", "Manjka slika", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            EffectLayerItem item = CreateCurrentEffectsLayer("image");
            item.FilePath = file;
            item.Mode = "Slika / animacija";
            effectsLayers.Add(item);
            RefreshEffectsLayerList();
            lstEffectsLayers.SelectedIndex = effectsLayers.Count - 1;
        }

        private void AddEffectsEmojiLayer()
        {
            string text = txtEffectsEmoji == null ? "" : txtEffectsEmoji.Text;
            if (string.IsNullOrWhiteSpace(text))
            {
                MessageBox.Show(this, "Vpiši emoji ali besedilo.", "Manjka besedilo", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            EffectLayerItem item = CreateCurrentEffectsLayer("text");
            item.Text = text;
            item.Mode = "Emoji / besedilo";
            effectsLayers.Add(item);
            RefreshEffectsLayerList();
            lstEffectsLayers.SelectedIndex = effectsLayers.Count - 1;
        }

        private void UpdateSelectedEffectsLayer()
        {
            int index = lstEffectsLayers == null ? -1 : lstEffectsLayers.SelectedIndex;
            if (index < 0 || index >= effectsLayers.Count) return;
            EffectLayerItem old = effectsLayers[index];
            EffectLayerItem item = CreateCurrentEffectsLayer(old.Kind);
            item.FilePath = old.Kind == "image" && txtEffectsOverlay != null && File.Exists(txtEffectsOverlay.Text.Trim())
                ? txtEffectsOverlay.Text.Trim()
                : old.FilePath;
            item.Text = old.Kind == "text" && txtEffectsEmoji != null && !string.IsNullOrWhiteSpace(txtEffectsEmoji.Text)
                ? txtEffectsEmoji.Text
                : old.Text;
            item.Mode = old.Kind == "region" ? item.Mode : old.Mode;
            effectsLayers[index] = item;
            RefreshEffectsLayerList();
            lstEffectsLayers.SelectedIndex = index;
        }

        private void RemoveSelectedEffectsLayer()
        {
            int index = lstEffectsLayers == null ? -1 : lstEffectsLayers.SelectedIndex;
            if (index < 0 || index >= effectsLayers.Count) return;
            effectsLayers.RemoveAt(index);
            RefreshEffectsLayerList();
            effectsPreviewPanel.Invalidate();
        }

        private void RefreshEffectsLayerList()
        {
            if (lstEffectsLayers == null) return;
            lstEffectsLayers.BeginUpdate();
            lstEffectsLayers.Items.Clear();
            foreach (EffectLayerItem item in effectsLayers) lstEffectsLayers.Items.Add(item);
            lstEffectsLayers.EndUpdate();
            lblEffectsStatus.Text = "Plasti: " + effectsLayers.Count + ". Uporabijo se po vrstnem redu seznama.";
        }

        private void LoadSelectedEffectsLayerToControls()
        {
            int index = lstEffectsLayers == null ? -1 : lstEffectsLayers.SelectedIndex;
            if (index < 0 || index >= effectsLayers.Count) return;
            EffectLayerItem item = effectsLayers[index];
            SetEffectsNumeric(numEffectsX, item.X);
            SetEffectsNumeric(numEffectsY, item.Y);
            SetEffectsNumeric(numEffectsWidth, item.Width);
            SetEffectsNumeric(numEffectsHeight, item.Height);
            SetEffectsNumeric(numEffectsStrength, item.Strength);
            bool wholeVideo = item.StartSeconds <= 0.001 && effectsDurationSeconds > 0.0 && item.EndSeconds >= effectsDurationSeconds - 0.05;
            effectsUpdatingTimeControls = true;
            try
            {
                if (chkEffectsWholeVideo != null) chkEffectsWholeVideo.Checked = wholeVideo;
                if (txtEffectsStartTime != null) txtEffectsStartTime.Text = FormatEditorTime(item.StartSeconds);
                if (txtEffectsEndTime != null) txtEffectsEndTime.Text = FormatEditorTime(item.EndSeconds);
            }
            finally
            {
                effectsUpdatingTimeControls = false;
            }
            UpdateEffectsTimeControls();
            SetEffectsNumeric(numEffectsOpacity, item.Opacity);
            if (item.Kind == "region" && cmbEffectsMode != null)
            {
                int mode = cmbEffectsMode.FindStringExact(item.Mode);
                if (mode >= 0) cmbEffectsMode.SelectedIndex = mode;
            }
            if (item.Kind == "image" && txtEffectsOverlay != null) txtEffectsOverlay.Text = item.FilePath;
            if (item.Kind == "text" && txtEffectsEmoji != null) txtEffectsEmoji.Text = item.Text;
        }

        private void SetEffectsNumeric(NumericUpDown control, decimal value)
        {
            if (control == null) return;
            control.Value = Math.Max(control.Minimum, Math.Min(control.Maximum, value));
        }

        private void EffectsPreviewMouseDown(object sender, MouseEventArgs e)
        {
            if (e.Button != MouseButtons.Left) return;
            effectsMouseSelecting = true;
            effectsPreviewPanel.Capture = true;
            effectsMouseStart = e.Location;
            effectsCurrentSelection = new RectangleF(e.X, e.Y, 1, 1);
            effectsPreviewPanel.Invalidate();
        }

        private void EffectsPreviewMouseMove(object sender, MouseEventArgs e)
        {
            if (!effectsMouseSelecting) return;
            float left = Math.Min(effectsMouseStart.X, e.X);
            float top = Math.Min(effectsMouseStart.Y, e.Y);
            float right = Math.Max(effectsMouseStart.X, e.X);
            float bottom = Math.Max(effectsMouseStart.Y, e.Y);
            effectsCurrentSelection = RectangleF.FromLTRB(left, top, right, bottom);
            effectsPreviewPanel.Invalidate();
        }

        private void EffectsPreviewMouseUp(object sender, MouseEventArgs e)
        {
            if (!effectsMouseSelecting) return;
            effectsMouseSelecting = false;
            effectsPreviewPanel.Capture = false;
            RectangleF videoRect = GetFittedVideoRectangle(effectsPreviewPanel.ClientRectangle);
            RectangleF selection = RectangleF.Intersect(effectsCurrentSelection, videoRect);
            if (selection.Width < 3 || selection.Height < 3) return;
            SetEffectsNumeric(numEffectsX, Convert.ToDecimal((selection.Left - videoRect.Left) * 100.0 / videoRect.Width));
            SetEffectsNumeric(numEffectsY, Convert.ToDecimal((selection.Top - videoRect.Top) * 100.0 / videoRect.Height));
            SetEffectsNumeric(numEffectsWidth, Convert.ToDecimal(selection.Width * 100.0 / videoRect.Width));
            SetEffectsNumeric(numEffectsHeight, Convert.ToDecimal(selection.Height * 100.0 / videoRect.Height));
            ClampEffectsRegion();
            effectsPreviewPanel.Invalidate();
        }

        private RectangleF GetEffectsLayerRectangle(RectangleF videoRect, EffectLayerItem item)
        {
            return new RectangleF(
                videoRect.Left + videoRect.Width * Convert.ToSingle(item.X) / 100F,
                videoRect.Top + videoRect.Height * Convert.ToSingle(item.Y) / 100F,
                videoRect.Width * Convert.ToSingle(item.Width) / 100F,
                videoRect.Height * Convert.ToSingle(item.Height) / 100F
            );
        }

        private RectangleF GetEffectsImageSourceRectangle(
            Image image,
            RectangleF videoRect,
            RectangleF targetRect
        )
        {
            if (image == null || videoRect.Width <= 0F || videoRect.Height <= 0F) return RectangleF.Empty;
            return new RectangleF(
                (targetRect.Left - videoRect.Left) / videoRect.Width * image.Width,
                (targetRect.Top - videoRect.Top) / videoRect.Height * image.Height,
                targetRect.Width / videoRect.Width * image.Width,
                targetRect.Height / videoRect.Height * image.Height
            );
        }

        private Bitmap CreateEffectsRegionBitmap(
            Image background,
            RectangleF source,
            int width,
            int height
        )
        {
            Bitmap bitmap = new Bitmap(
                Math.Max(2, width),
                Math.Max(2, height),
                PixelFormat.Format32bppArgb
            );

            using (Graphics graphics = Graphics.FromImage(bitmap))
            {
                graphics.CompositingMode =
                    System.Drawing.Drawing2D.CompositingMode.SourceCopy;
                graphics.CompositingQuality =
                    System.Drawing.Drawing2D.CompositingQuality.HighQuality;
                graphics.InterpolationMode =
                    System.Drawing.Drawing2D.InterpolationMode.HighQualityBicubic;
                graphics.PixelOffsetMode =
                    System.Drawing.Drawing2D.PixelOffsetMode.HighQuality;
                graphics.DrawImage(
                    background,
                    new RectangleF(0, 0, bitmap.Width, bitmap.Height),
                    source,
                    GraphicsUnit.Pixel
                );
            }

            return bitmap;
        }

        private void ApplyEffectsBoxBlur(
            Bitmap bitmap,
            int radius,
            int passes
        )
        {
            if (bitmap == null || radius < 1 || passes < 1)
            {
                return;
            }

            Rectangle rectangle = new Rectangle(
                0,
                0,
                bitmap.Width,
                bitmap.Height
            );
            BitmapData data = bitmap.LockBits(
                rectangle,
                ImageLockMode.ReadWrite,
                PixelFormat.Format32bppArgb
            );

            try
            {
                int stride = data.Stride;
                int length = Math.Abs(stride) * bitmap.Height;
                byte[] pixels = new byte[length];
                byte[] temporary = new byte[length];
                Marshal.Copy(data.Scan0, pixels, 0, length);

                for (int pass = 0; pass < passes; pass++)
                {
                    ApplyEffectsBlurDirection(
                        pixels,
                        temporary,
                        bitmap.Width,
                        bitmap.Height,
                        stride,
                        radius,
                        true
                    );
                    ApplyEffectsBlurDirection(
                        temporary,
                        pixels,
                        bitmap.Width,
                        bitmap.Height,
                        stride,
                        radius,
                        false
                    );
                }

                Marshal.Copy(pixels, 0, data.Scan0, length);
            }
            finally
            {
                bitmap.UnlockBits(data);
            }
        }

        private void ApplyEffectsBlurDirection(
            byte[] source,
            byte[] target,
            int width,
            int height,
            int stride,
            int radius,
            bool horizontal
        )
        {
            int window = radius * 2 + 1;

            if (horizontal)
            {
                for (int y = 0; y < height; y++)
                {
                    int row = y * stride;
                    for (int channel = 0; channel < 3; channel++)
                    {
                        int sum = 0;
                        for (int offset = -radius; offset <= radius; offset++)
                        {
                            int sampleX = Math.Max(0, Math.Min(width - 1, offset));
                            sum += source[row + sampleX * 4 + channel];
                        }

                        for (int x = 0; x < width; x++)
                        {
                            int index = row + x * 4 + channel;
                            target[index] = Convert.ToByte(sum / window);

                            int removeX = Math.Max(0, Math.Min(width - 1, x - radius));
                            int addX = Math.Max(0, Math.Min(width - 1, x + radius + 1));
                            sum -= source[row + removeX * 4 + channel];
                            sum += source[row + addX * 4 + channel];
                        }
                    }

                    for (int x = 0; x < width; x++)
                    {
                        target[row + x * 4 + 3] = 255;
                    }
                }
            }
            else
            {
                for (int x = 0; x < width; x++)
                {
                    for (int channel = 0; channel < 3; channel++)
                    {
                        int sum = 0;
                        for (int offset = -radius; offset <= radius; offset++)
                        {
                            int sampleY = Math.Max(0, Math.Min(height - 1, offset));
                            sum += source[sampleY * stride + x * 4 + channel];
                        }

                        for (int y = 0; y < height; y++)
                        {
                            int index = y * stride + x * 4 + channel;
                            target[index] = Convert.ToByte(sum / window);

                            int removeY = Math.Max(0, Math.Min(height - 1, y - radius));
                            int addY = Math.Max(0, Math.Min(height - 1, y + radius + 1));
                            sum -= source[removeY * stride + x * 4 + channel];
                            sum += source[addY * stride + x * 4 + channel];
                        }
                    }

                    for (int y = 0; y < height; y++)
                    {
                        target[y * stride + x * 4 + 3] = 255;
                    }
                }
            }
        }

        private void DrawEffectsRegionVisual(
            Graphics graphics,
            Image background,
            RectangleF videoRect,
            RectangleF targetRect,
            string mode,
            int strength
        )
        {
            RectangleF clipped = RectangleF.Intersect(videoRect, targetRect);
            if (clipped.Width < 2F || clipped.Height < 2F)
            {
                return;
            }

            strength = Math.Max(1, Math.Min(100, strength));

            if (mode.IndexOf("Temno", StringComparison.OrdinalIgnoreCase) >= 0)
            {
                int alpha = Math.Max(
                    4,
                    Math.Min(
                        245,
                        Convert.ToInt32(
                            Math.Round(4.0 + strength * 2.41)
                        )
                    )
                );
                using (Brush brush = new SolidBrush(Color.FromArgb(alpha, 0, 0, 0)))
                {
                    graphics.FillRectangle(brush, clipped);
                }
                return;
            }

            if (background == null)
            {
                return;
            }

            RectangleF source = GetEffectsImageSourceRectangle(
                background,
                videoRect,
                clipped
            );
            if (source.Width < 1F || source.Height < 1F)
            {
                return;
            }

            int targetWidth = Math.Max(2, Convert.ToInt32(Math.Ceiling(clipped.Width)));
            int targetHeight = Math.Max(2, Convert.ToInt32(Math.Ceiling(clipped.Height)));
            bool mosaic = mode.IndexOf("mozaik", StringComparison.OrdinalIgnoreCase) >= 0;

            if (mosaic)
            {
                int blockSize = Math.Max(
                    2,
                    Math.Min(
                        52,
                        2 + Convert.ToInt32(Math.Round(strength * 0.50))
                    )
                );
                int smallWidth = Math.Max(1, targetWidth / blockSize);
                int smallHeight = Math.Max(1, targetHeight / blockSize);

                using (Bitmap small = new Bitmap(smallWidth, smallHeight))
                {
                    using (Graphics smallGraphics = Graphics.FromImage(small))
                    {
                        smallGraphics.CompositingMode =
                            System.Drawing.Drawing2D.CompositingMode.SourceCopy;
                        smallGraphics.InterpolationMode =
                            System.Drawing.Drawing2D.InterpolationMode.NearestNeighbor;
                        smallGraphics.PixelOffsetMode =
                            System.Drawing.Drawing2D.PixelOffsetMode.Half;
                        smallGraphics.DrawImage(
                            background,
                            new RectangleF(0, 0, smallWidth, smallHeight),
                            source,
                            GraphicsUnit.Pixel
                        );
                    }

                    System.Drawing.Drawing2D.InterpolationMode oldInterpolation =
                        graphics.InterpolationMode;
                    System.Drawing.Drawing2D.PixelOffsetMode oldPixel =
                        graphics.PixelOffsetMode;
                    graphics.InterpolationMode =
                        System.Drawing.Drawing2D.InterpolationMode.NearestNeighbor;
                    graphics.PixelOffsetMode =
                        System.Drawing.Drawing2D.PixelOffsetMode.Half;
                    graphics.DrawImage(small, clipped);
                    graphics.InterpolationMode = oldInterpolation;
                    graphics.PixelOffsetMode = oldPixel;
                }
                return;
            }

            using (Bitmap blurred = CreateEffectsRegionBitmap(
                background,
                source,
                targetWidth,
                targetHeight
            ))
            {
                int radius = Math.Max(
                    1,
                    Math.Min(
                        42,
                        1 + Convert.ToInt32(Math.Round(strength * 0.41))
                    )
                );
                int passes = strength >= 70 ? 4 : (strength >= 35 ? 3 : 2);
                ApplyEffectsBoxBlur(blurred, radius, passes);

                System.Drawing.Drawing2D.InterpolationMode oldInterpolation =
                    graphics.InterpolationMode;
                graphics.InterpolationMode =
                    System.Drawing.Drawing2D.InterpolationMode.HighQualityBicubic;
                graphics.DrawImage(blurred, clipped);
                graphics.InterpolationMode = oldInterpolation;
            }
        }

        private void DrawEffectsOverlayVisual(
            Graphics graphics,
            RectangleF rect,
            EffectLayerItem item
        )
        {
            if (item.Kind == "image" && File.Exists(item.FilePath))
            {
                try
                {
                    using (Image image = Image.FromFile(item.FilePath))
                    {
                        ColorMatrix matrix = new ColorMatrix();
                        matrix.Matrix33 = Math.Max(0.1F, Math.Min(1F, item.Opacity / 100F));
                        using (ImageAttributes attributes = new ImageAttributes())
                        {
                            attributes.SetColorMatrix(matrix);
                            graphics.DrawImage(
                                image,
                                Rectangle.Round(rect),
                                0,
                                0,
                                image.Width,
                                image.Height,
                                GraphicsUnit.Pixel,
                                attributes
                            );
                        }
                    }
                }
                catch
                {
                }
                return;
            }

            if (item.Kind == "text")
            {
                float fontSize = Math.Max(12F, rect.Height * 0.72F);
                using (Font font = new Font("Segoe UI Emoji", fontSize, FontStyle.Regular, GraphicsUnit.Pixel))
                using (StringFormat format = new StringFormat())
                using (Brush shadow = new SolidBrush(Color.FromArgb(190, 0, 0, 0)))
                using (Brush text = new SolidBrush(Color.FromArgb(Math.Max(25, item.Opacity * 255 / 100), 255, 255, 255)))
                {
                    format.Alignment = StringAlignment.Center;
                    format.LineAlignment = StringAlignment.Center;
                    RectangleF shadowRect = rect;
                    shadowRect.Offset(2F, 2F);
                    graphics.DrawString(item.Text ?? "", font, shadow, shadowRect, format);
                    graphics.DrawString(item.Text ?? "", font, text, rect, format);
                }
            }
        }

        private void DrawEffectsLayerVisual(
            Graphics graphics,
            Image background,
            RectangleF videoRect,
            RectangleF rect,
            EffectLayerItem item
        )
        {
            if (item.Kind == "region")
            {
                DrawEffectsRegionVisual(graphics, background, videoRect, rect, item.Mode ?? "Močan mozaik", item.Strength);
            }
            else
            {
                DrawEffectsOverlayVisual(graphics, rect, item);
            }
        }

        private void DrawEffectsPreview(object sender, PaintEventArgs e)
        {
            Panel preview = sender as Panel;
            if (preview == null) return;

            e.Graphics.Clear(Color.FromArgb(27, 30, 35));
            e.Graphics.SmoothingMode = System.Drawing.Drawing2D.SmoothingMode.AntiAlias;
            e.Graphics.InterpolationMode = System.Drawing.Drawing2D.InterpolationMode.HighQualityBicubic;
            e.Graphics.PixelOffsetMode = System.Drawing.Drawing2D.PixelOffsetMode.HighQuality;
            e.Graphics.CompositingQuality = effectsMouseSelecting
                ? System.Drawing.Drawing2D.CompositingQuality.HighSpeed
                : System.Drawing.Drawing2D.CompositingQuality.HighQuality;

            RectangleF videoRect = GetFittedVideoRectangle(preview.ClientRectangle);
            if (videoRect.Width <= 1F || videoRect.Height <= 1F) return;

            Image background = effectsPreviewImage ?? GetSubtitlePreviewImage();
            if (background != null)
            {
                e.Graphics.DrawImage(background, videoRect);
            }
            else
            {
                using (Brush fill = new SolidBrush(Color.FromArgb(63, 101, 126))) e.Graphics.FillRectangle(fill, videoRect);
            }

            for (int i = 0; i < effectsLayers.Count; i++)
            {
                EffectLayerItem item = effectsLayers[i];
                RectangleF rect = GetEffectsLayerRectangle(videoRect, item);
                DrawEffectsLayerVisual(e.Graphics, background, videoRect, rect, item);

                Color color = item.Kind == "image" ? Color.DeepSkyBlue : (item.Kind == "text" ? Color.LimeGreen : Color.OrangeRed);
                using (Pen pen = new Pen(color, i == lstEffectsLayers.SelectedIndex ? 3F : 2F))
                {
                    e.Graphics.DrawRectangle(pen, rect.X, rect.Y, rect.Width, rect.Height);
                }
                string label = (i + 1) + ". " + item.Mode;
                using (Font labelFont = new Font("Segoe UI", 8F))
                {
                    SizeF labelSize = e.Graphics.MeasureString(label, labelFont);
                    using (Brush labelBack = new SolidBrush(Color.FromArgb(195, 0, 0, 0)))
                    {
                        e.Graphics.FillRectangle(labelBack, rect.X, rect.Y, Math.Min(rect.Width, labelSize.Width + 8F), 20F);
                    }
                    using (Brush labelText = new SolidBrush(Color.White))
                    {
                        e.Graphics.DrawString(label, labelFont, labelText, rect.X + 3F, rect.Y + 2F);
                    }
                }
            }

            RectangleF current;
            if (effectsMouseSelecting)
            {
                current = RectangleF.Intersect(effectsCurrentSelection, videoRect);
            }
            else
            {
                current = new RectangleF(
                    videoRect.Left + videoRect.Width * Convert.ToSingle(numEffectsX.Value) / 100F,
                    videoRect.Top + videoRect.Height * Convert.ToSingle(numEffectsY.Value) / 100F,
                    videoRect.Width * Convert.ToSingle(numEffectsWidth.Value) / 100F,
                    videoRect.Height * Convert.ToSingle(numEffectsHeight.Value) / 100F
                );
            }

            if (current.Width > 2F && current.Height > 2F)
            {
                string mode = cmbEffectsMode == null || cmbEffectsMode.SelectedItem == null
                    ? "Močan mozaik"
                    : cmbEffectsMode.SelectedItem.ToString();
                int strength = numEffectsStrength == null ? 32 : Convert.ToInt32(numEffectsStrength.Value);
                if (effectsMouseSelecting)
                {
                    using (Brush selectionBrush = new SolidBrush(Color.FromArgb(42, 255, 80, 30)))
                    {
                        e.Graphics.FillRectangle(selectionBrush, current);
                    }
                }
                else
                {
                    DrawEffectsRegionVisual(e.Graphics, background, videoRect, current, mode, strength);
                }

                using (Pen currentPen = new Pen(Color.Red, 2.5F))
                {
                    currentPen.DashStyle = System.Drawing.Drawing2D.DashStyle.Dash;
                    e.Graphics.DrawRectangle(currentPen, current.X, current.Y, current.Width, current.Height);
                }
            }

            using (Pen border = new Pen(Color.FromArgb(130, 155, 180)))
            {
                e.Graphics.DrawRectangle(border, videoRect.X, videoRect.Y, videoRect.Width - 1, videoRect.Height - 1);
            }
        }

        private int GetEffectsThreadCount()
        {
            int processors = Math.Max(1, Environment.ProcessorCount);
            if (cmbEffectsPower != null && cmbEffectsPower.SelectedIndex == 0) return processors;
            if (cmbEffectsPower != null && cmbEffectsPower.SelectedIndex == 2) return Math.Max(1, processors / 4);
            return Math.Max(1, processors / 2);
        }

        private string GetEffectsPreset()
        {
            if (cmbEffectsPower != null && cmbEffectsPower.SelectedIndex == 0) return "veryfast";
            if (cmbEffectsPower != null && cmbEffectsPower.SelectedIndex == 2) return "slow";
            return "medium";
        }

        private string EffectsPercent(decimal value, string dimension)
        {
            return "trunc(" + dimension + "*" + value.ToString("0.####", System.Globalization.CultureInfo.InvariantCulture) + "/100/2)*2";
        }

        private string EffectsEnable(EffectLayerItem item)
        {
            double start = Math.Max(0.0, item.StartSeconds);
            double end = item.EndSeconds > start ? item.EndSeconds : Math.Max(start + 0.01, effectsDurationSeconds);
            return "between(t\\," + start.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture) + "\\," + end.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture) + ")";
        }

        private string EscapeDrawText(string value)
        {
            return (value ?? "")
                .Replace("\\", "\\\\")
                .Replace("'", "\\'")
                .Replace(":", "\\:")
                .Replace("%", "\\%")
                .Replace("\r", " ")
                .Replace("\n", "\\n");
        }

        private string GetEffectsGlobalFilter()
        {
            int index = cmbEffectsGlobalFilter == null ? 0 : cmbEffectsGlobalFilter.SelectedIndex;
            switch (index)
            {
                case 1: return "eq=contrast=1.08:brightness=-0.015:saturation=1.10,colorbalance=rs=.06:gs=.015:bs=-.045,vignette=PI/5";
                case 2: return "eq=contrast=1.08:brightness=-0.02:saturation=1.02,colorbalance=rs=-.04:gs=.01:bs=.07,vignette=PI/5";
                case 3: return "curves=preset=vintage,eq=saturation=.82,noise=alls=5:allf=t+u,vignette=PI/4";
                case 4: return "hue=s=0,eq=contrast=1.10";
                case 5: return "colorchannelmixer=.393:.769:.189:0:.349:.686:.168:0:.272:.534:.131";
                case 6: return "eq=contrast=1.12:saturation=1.35:gamma=1.02,unsharp=5:5:.55";
                case 7: return "hqdn3d=1.4:1.4:5:5,eq=contrast=1.05:saturation=.94,vignette=PI/5";
                case 8: return "smartblur=lr=2.0:ls=-0.7,eq=contrast=1.20:saturation=1.40,unsharp=5:5:.8";
                case 9: return "unsharp=7:7:1.0:5:5:0.0";
                case 10: return "vignette=PI/4";
                default: return "";
            }
        }

        private async Task RunEffectsAsync()
        {
            string input = txtEffectsInput == null ? "" : txtEffectsInput.Text.Trim();
            string output = txtEffectsOutput == null ? "" : txtEffectsOutput.Text.Trim();
            if (!File.Exists(input))
            {
                MessageBox.Show(this, "Najprej izberi veljaven vhodni video.", "Manjka video", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            if (effectsLayers.Count == 0 && (cmbEffectsGlobalFilter == null || cmbEffectsGlobalFilter.SelectedIndex == 0) && (chkEffectsFade == null || !chkEffectsFade.Checked))
            {
                MessageBox.Show(this, "Dodaj vsaj eno plast, filter ali fade.", "Ni učinkov", MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }
            if (string.IsNullOrWhiteSpace(output)) { UpdateEffectsSuggestedOutput(); output = txtEffectsOutput.Text.Trim(); }
            string ffmpeg = ToolLocator.FindFfmpeg();
            if (string.IsNullOrWhiteSpace(ffmpeg))
            {
                MessageBox.Show(this, "FFmpeg ni najden. Namesti ga v Orodja in nastavitve.", "Manjka FFmpeg", MessageBoxButtons.OK, MessageBoxIcon.Warning);
                return;
            }
            bool losslessOutput = chkEffectsLosslessOutput != null && chkEffectsLosslessOutput.Checked;
            output = GetUniquePath(Path.ChangeExtension(output, losslessOutput ? ".mkv" : ".mp4"));
            txtEffectsOutput.Text = output;
            string outputDirectory = Path.GetDirectoryName(output);
            if (!string.IsNullOrWhiteSpace(outputDirectory)) Directory.CreateDirectory(outputDirectory);

            btnEffectsRun.Enabled = false;
            effectsProgress.Style = ProgressBarStyle.Marquee;
            effectsProgress.MarqueeAnimationSpeed = 28;
            lblEffectsStatus.Text = "Obdelava vseh plasti poteka …";
            Log("Začenjam večplastno obdelavo: " + effectsLayers.Count + " plasti.", "UČINKI");

            try
            {
                List<string> arguments = new List<string>();
                arguments.Add("-y"); arguments.Add("-hide_banner"); arguments.Add("-loglevel"); arguments.Add("warning");
                arguments.Add("-i"); arguments.Add(input);

                Dictionary<EffectLayerItem, int> imageInputIndices = new Dictionary<EffectLayerItem, int>();
                int nextInput = 1;
                foreach (EffectLayerItem item in effectsLayers)
                {
                    if (item.Kind != "image") continue;
                    string ext = Path.GetExtension(item.FilePath).ToLowerInvariant();
                    if (ext == ".gif" || ext == ".webp" || ext == ".apng")
                    {
                        arguments.Add("-stream_loop"); arguments.Add("-1");
                    }
                    else
                    {
                        arguments.Add("-loop"); arguments.Add("1");
                    }
                    arguments.Add("-i"); arguments.Add(item.FilePath);
                    imageInputIndices[item] = nextInput++;
                }

                List<string> graph = new List<string>();
                string current = "v0";
                graph.Add("[0:v]setpts=PTS-STARTPTS[" + current + "]");
                int layerNumber = 0;

                foreach (EffectLayerItem item in effectsLayers)
                {
                    string next = "v" + (layerNumber + 1);
                    string x = EffectsPercent(item.X, "iw");
                    string y = EffectsPercent(item.Y, "ih");
                    string w = EffectsPercent(item.Width, "iw");
                    string h = EffectsPercent(item.Height, "ih");
                    string ox = EffectsPercent(item.X, "main_w");
                    string oy = EffectsPercent(item.Y, "main_h");
                    string enable = EffectsEnable(item);

                    if (item.Kind == "region")
                    {
                        if (item.Mode.IndexOf("Temno", StringComparison.OrdinalIgnoreCase) >= 0)
                        {
                            double alpha = Math.Max(0.15, Math.Min(0.98, item.Strength / 80.0));
                            graph.Add("[" + current + "]drawbox=x=" + x + ":y=" + y + ":w=" + w + ":h=" + h + ":color=black@" + alpha.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture) + ":t=fill:enable='" + enable + "'[" + next + "]");
                        }
                        else
                        {
                            string baseLabel = "base" + layerNumber;
                            string tmpLabel = "tmp" + layerNumber;
                            string fxLabel = "fx" + layerNumber;
                            graph.Add("[" + current + "]split=2[" + baseLabel + "][" + tmpLabel + "]");
                            if (item.Mode.IndexOf("zamegl", StringComparison.OrdinalIgnoreCase) >= 0)
                            {
                                double sigma = 0.75 + Math.Max(1, Math.Min(100, item.Strength)) * 0.58;
                                int steps = item.Strength >= 75 ? 6 : (item.Strength >= 40 ? 4 : 2);
                                graph.Add(
                                    "[" + tmpLabel + "]crop=w=" + w + ":h=" + h + ":x=" + x + ":y=" + y +
                                    ",gblur=sigma=" + sigma.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture) +
                                    ":steps=" + steps + "[" + fxLabel + "]"
                                );
                            }
                            else
                            {
                                int block = Math.Max(8, item.Strength * 2);
                                graph.Add("[" + tmpLabel + "]crop=w=" + w + ":h=" + h + ":x=" + x + ":y=" + y + ",scale=max(2\\,iw/" + block + "):max(2\\,ih/" + block + "):flags=neighbor,scale=iw*" + block + ":ih*" + block + ":flags=neighbor[" + fxLabel + "]");
                            }
                            graph.Add("[" + baseLabel + "][" + fxLabel + "]overlay=x=" + ox + ":y=" + oy + ":enable='" + enable + "'[" + next + "]");
                        }
                    }
                    else if (item.Kind == "image")
                    {
                        int inputIndex = imageInputIndices[item];
                        string imageLabel = "img" + layerNumber;
                        string overlayLabel = "ov" + layerNumber;
                        string baseLabel = "base" + layerNumber;
                        double alpha = Math.Max(0.1, Math.Min(1.0, item.Opacity / 100.0));
                        graph.Add("[" + inputIndex + ":v]setpts=PTS-STARTPTS,format=rgba,colorchannelmixer=aa=" + alpha.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture) + "[" + imageLabel + "]");
                        graph.Add("[" + imageLabel + "][" + current + "]scale2ref=w=main_w*" + (item.Width / 100M).ToString("0.####", System.Globalization.CultureInfo.InvariantCulture) + ":h=main_h*" + (item.Height / 100M).ToString("0.####", System.Globalization.CultureInfo.InvariantCulture) + "[" + overlayLabel + "][" + baseLabel + "]");
                        graph.Add("[" + baseLabel + "][" + overlayLabel + "]overlay=x=main_w*" + (item.X / 100M).ToString("0.####", System.Globalization.CultureInfo.InvariantCulture) + ":y=main_h*" + (item.Y / 100M).ToString("0.####", System.Globalization.CultureInfo.InvariantCulture) + ":enable='" + enable + "':eof_action=repeat:shortest=0[" + next + "]");
                    }
                    else
                    {
                        double alpha = Math.Max(0.1, Math.Min(1.0, item.Opacity / 100.0));
                        string fontFile = "C\\:/Windows/Fonts/seguiemj.ttf";
                        graph.Add("[" + current + "]drawtext=fontfile='" + fontFile + "':text='" + EscapeDrawText(item.Text) + "':fontcolor=white@" + alpha.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture) + ":fontsize=h*" + (item.Height / 100M).ToString("0.####", System.Globalization.CultureInfo.InvariantCulture) + ":borderw=3:bordercolor=black@0.75:x=w*" + (item.X / 100M).ToString("0.####", System.Globalization.CultureInfo.InvariantCulture) + ":y=h*" + (item.Y / 100M).ToString("0.####", System.Globalization.CultureInfo.InvariantCulture) + ":enable='" + enable + "'[" + next + "]");
                    }
                    current = next;
                    layerNumber++;
                }

                string globalFilter = GetEffectsGlobalFilter();
                if (!string.IsNullOrWhiteSpace(globalFilter))
                {
                    string next = "vfilter";
                    graph.Add("[" + current + "]" + globalFilter + "[" + next + "]");
                    current = next;
                }

                if (chkEffectsFade != null && chkEffectsFade.Checked)
                {
                    double fadeSeconds = Convert.ToDouble(numEffectsFadeSeconds.Value);
                    double fadeOut = Math.Max(0.0, effectsDurationSeconds - fadeSeconds);
                    string filter = "fade=t=in:st=0:d=" + fadeSeconds.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture);
                    if (effectsDurationSeconds > fadeSeconds) filter += ",fade=t=out:st=" + fadeOut.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture) + ":d=" + fadeSeconds.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture);
                    graph.Add("[" + current + "]" + filter + "[vout]");
                    current = "vout";
                }

                arguments.Add("-filter_complex");
                arguments.Add(string.Join(";", graph.ToArray()));
                arguments.Add("-map"); arguments.Add("[" + current + "]");
                arguments.Add("-map"); arguments.Add("0:a?");
                if (effectsDurationSeconds > 0.0)
                {
                    arguments.Add("-t"); arguments.Add(effectsDurationSeconds.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture));
                }
                if (losslessOutput)
                {
                    arguments.Add("-c:v"); arguments.Add("ffv1");
                    arguments.Add("-level"); arguments.Add("3");
                    arguments.Add("-g"); arguments.Add("1");
                    arguments.Add("-slicecrc"); arguments.Add("1");
                    arguments.Add("-threads"); arguments.Add(GetEffectsThreadCount().ToString());
                    arguments.Add("-c:a"); arguments.Add("copy");
                }
                else
                {
                    arguments.Add("-c:v"); arguments.Add("libx264");
                    arguments.Add("-preset"); arguments.Add(GetEffectsPreset());
                    arguments.Add("-crf"); arguments.Add("16");
                    arguments.Add("-threads"); arguments.Add(GetEffectsThreadCount().ToString());
                    arguments.Add("-pix_fmt"); arguments.Add("yuv420p");
                    arguments.Add("-c:a"); arguments.Add("aac");
                    arguments.Add("-b:a"); arguments.Add("320k");
                    arguments.Add("-movflags"); arguments.Add("+faststart");
                }
                arguments.Add(output);

                int exitCode = await RunStandaloneProcessAsync(ffmpeg, arguments, "UČINKI");
                if (exitCode != 0 || !File.Exists(output)) throw new InvalidOperationException("FFmpeg ni mogel dokončati vseh plasti. Preveri rdeče vrstice v zapisu.");
                effectsProgress.Style = ProgressBarStyle.Blocks;
                effectsProgress.Value = 100;
                lblEffectsStatus.Text = "Končano: " + output;
                Log("KONČANO: " + output, "UČINKI");
                MessageBox.Show(this, "Obdelava je končana.\r\n\r\n" + output, "Končano", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            catch (Exception e)
            {
                effectsProgress.Style = ProgressBarStyle.Blocks;
                effectsProgress.Value = 0;
                lblEffectsStatus.Text = "Napaka: " + e.Message;
                ShowError("Obdelava učinkov ni uspela.", e);
            }
            finally
            {
                btnEffectsRun.Enabled = true;
                effectsProgress.MarqueeAnimationSpeed = 0;
            }
        }

