        private void ApplySettings()
        {
            txtFolder.Text = string.IsNullOrWhiteSpace(settings.OutputFolder)
                ? new AppSettings().OutputFolder
                : settings.OutputFolder;

            if (txtConverterFolder != null)
            {
                txtConverterFolder.Text =
                    txtFolder.Text;
            }

            cmbQuality.SelectedIndex = Clamp(settings.QualityIndex, 0, QualityNames.Length - 1);
            cmbOutput.SelectedIndex = Clamp(settings.OutputIndex, 0, OutputNames.Length - 1);
            chkCookies.Checked = settings.UseEdgeCookies;
            if (cmbCookieBrowser != null)
            {
                string savedBrowser = (settings.CookieBrowser ?? "firefox").ToLowerInvariant();
                cmbCookieBrowser.SelectedIndex =
                    savedBrowser == "edge" ? 1 : (savedBrowser == "chrome" ? 2 : 0);
                cmbCookieBrowser.Enabled = chkCookies.Checked;
            }
            chkDirectMedia.Checked = settings.DirectMediaMode;
            txtReferer.Text = settings.Referer ?? "";
            txtReferer.Enabled = chkDirectMedia.Checked;

            cmbSubtitles.SelectedIndex = Clamp(
                settings.SubtitleModeIndex,
                0,
                SubtitleNames.Length - 1
            );

            cmbSubtitleLanguagePreset.SelectedIndex = Clamp(
                settings.SubtitleLanguagePresetIndex,
                0,
                SubtitleLanguagePresetNames.Length - 1
            );

            txtSubtitleLanguages.Text =
                string.IsNullOrWhiteSpace(settings.SubtitleLanguages)
                    ? GetSubtitleLanguagePattern(
                        cmbSubtitleLanguagePreset.SelectedIndex
                    )
                    : settings.SubtitleLanguages;

            chkAutoSubtitles.Checked = settings.IncludeAutoSubtitles;

            if (
                cmbSubtitleLanguagePreset.SelectedIndex == 5
            )
            {
                chkAutoSubtitles.Checked = true;
                chkCookies.Checked = true;

                if (cmbSubtitles.SelectedIndex == 0)
                {
                    cmbSubtitles.SelectedIndex = 3;
                }
            }

            chkStyledEmbeddedSubtitles.Checked =
                settings.StyledEmbeddedSubtitles;
            numSubtitleBackgroundOpacity.Value = Clamp(
                settings.SubtitleBackgroundOpacity,
                20,
                90
            );
            ApplySubtitleLanguagePreset();
            UpdateSubtitleLanguageControls();

            numConcurrent.Value = Clamp(settings.MaxConcurrent, 1, 8);
            numFragments.Value = Clamp(settings.ConcurrentFragments, 1, 16);
            cmbUpdateChannel.SelectedIndex = Clamp(settings.UpdateChannelIndex, 0, 1);
            chkUpdateFfmpeg.Checked = settings.UpdateFfmpeg;
        }

        private string GetSubtitleLanguagePattern(
            int presetIndex
        )
        {
            switch (presetIndex)
            {
                case 0:
                    return "sl.*,slv,slo,slovenian,si";

                case 1:
                    return "en.*";

                case 2:
                    return "sl.*,slv,slo,slovenian,si,en.*";

                case 3:
                    return "all,-live_chat";

                case 4:
                    return txtSubtitleLanguages == null
                        ? ""
                        : txtSubtitleLanguages.Text.Trim();

                case 5:
                    return "sl-en.*";

                default:
                    return "sl.*,slv,slo,slovenian,si";
            }
        }

        private bool IsYouTubeSlovenianAutoTranslation(
            DownloadJob job
        )
        {
            if (
                job == null ||
                string.IsNullOrWhiteSpace(job.Url) ||
                string.IsNullOrWhiteSpace(job.SubtitleLanguages)
            )
            {
                return false;
            }

            bool isYouTube =
                Regex.IsMatch(
                    job.Url,
                    @"https?://(?:www\.)?(?:youtube\.com|youtu\.be)/",
                    RegexOptions.IgnoreCase
                );

            bool wantsTranslation =
                Regex.IsMatch(
                    job.SubtitleLanguages,
                    @"(?:^|,)\s*sl-en(?:\.\*)?(?:,|$)",
                    RegexOptions.IgnoreCase
                );

            return isYouTube && wantsTranslation;
        }

        private void ApplySubtitleLanguagePreset()
        {
            if (cmbSubtitleLanguagePreset == null ||
                txtSubtitleLanguages == null)
            {
                return;
            }

            if (cmbSubtitleLanguagePreset.SelectedIndex != 4)
            {
                txtSubtitleLanguages.Text =
                    GetSubtitleLanguagePattern(
                        cmbSubtitleLanguagePreset.SelectedIndex
                    );
            }

            UpdateSubtitleLanguageControls();
        }

        private void UpdateSubtitleLanguageControls()
        {
            if (cmbSubtitles == null ||
                cmbSubtitleLanguagePreset == null ||
                txtSubtitleLanguages == null ||
                chkAutoSubtitles == null)
            {
                return;
            }

            bool subtitlesEnabled =
                cmbSubtitles.SelectedIndex > 0;

            cmbSubtitleLanguagePreset.Enabled =
                subtitlesEnabled;

            txtSubtitleLanguages.Enabled =
                subtitlesEnabled &&
                cmbSubtitleLanguagePreset.SelectedIndex == 4;

            chkAutoSubtitles.Enabled =
                subtitlesEnabled;

            if (chkStyledEmbeddedSubtitles != null)
            {
                bool burnInEnabled =
                    cmbSubtitles.SelectedIndex == 3;

                chkStyledEmbeddedSubtitles.Enabled =
                    burnInEnabled;

                if (numSubtitleBackgroundOpacity != null)
                {
                    numSubtitleBackgroundOpacity.Enabled =
                        burnInEnabled &&
                        chkStyledEmbeddedSubtitles.Checked;
                }
            }
        }

        private int Clamp(int value, int minimum, int maximum)
        {
            if (value < minimum)
            {
                return minimum;
            }

            if (value > maximum)
            {
                return maximum;
            }

            return value;
        }

        private string GetSelectedCookieBrowser()
        {
            if (cmbCookieBrowser == null)
            {
                return "firefox";
            }
            if (cmbCookieBrowser.SelectedIndex == 1)
            {
                return "edge";
            }
            if (cmbCookieBrowser.SelectedIndex == 2)
            {
                return "chrome";
            }
            return "firefox";
        }

        private string GetCookieBrowserDisplayName(
            string browser
        )
        {
            string value = (browser ?? "firefox").ToLowerInvariant();
            if (value == "edge") return "Microsoft Edge";
            if (value == "chrome") return "Google Chrome";
            return "Firefox";
        }

        private void SaveCurrentSettings()
        {
            if (txtFolder == null)
            {
                return;
            }

            settings.OutputFolder = txtFolder.Text.Trim();
            settings.QualityIndex = cmbQuality.SelectedIndex;
            settings.OutputIndex = cmbOutput.SelectedIndex;
            settings.UseEdgeCookies = chkCookies.Checked;
            settings.CookieBrowser = GetSelectedCookieBrowser();
            settings.DirectMediaMode = chkDirectMedia.Checked;
            settings.Referer = txtReferer.Text.Trim();
            settings.SubtitleModeIndex = cmbSubtitles.SelectedIndex;
            settings.SubtitleLanguagePresetIndex =
                cmbSubtitleLanguagePreset.SelectedIndex;
            settings.SubtitleLanguages =
                txtSubtitleLanguages.Text.Trim();
            settings.IncludeAutoSubtitles = chkAutoSubtitles.Checked;
            settings.StyledEmbeddedSubtitles =
                chkStyledEmbeddedSubtitles.Checked;
            settings.SubtitleBackgroundOpacity =
                Convert.ToInt32(
                    numSubtitleBackgroundOpacity.Value
                );
            settings.MaxConcurrent = Convert.ToInt32(numConcurrent.Value);
            settings.ConcurrentFragments = Convert.ToInt32(numFragments.Value);
            settings.UpdateChannelIndex = cmbUpdateChannel.SelectedIndex;
            settings.UpdateFfmpeg = chkUpdateFfmpeg.Checked;
            SettingsStore.Save(settings);
        }

        private void PasteClipboard()
        {
            try
            {
                if (!Clipboard.ContainsText())
                {
                    return;
                }

                string text = Clipboard.GetText().Trim();
                if (txtUrls.TextLength > 0)
                {
                    txtUrls.AppendText(Environment.NewLine);
                }

                txtUrls.AppendText(text);
            }
            catch (Exception e)
            {
                ShowError("Odložišča ni bilo mogoče prebrati.", e);
            }
        }

        private void PasteVeeVeeMediaUrl()
        {
            try
            {
                string existingVoyoPage =
                    ExtractUrls(
                        txtUrls.Text
                    )
                    .FirstOrDefault(
                        delegate(string value)
                        {
                            return IsVoyoUrl(value);
                        }
                    );

                if (!Clipboard.ContainsText())
                {
                    Log(
                        "V odložišču ni besedila. V VeeVee klikni majhno ikono verige ob vrstici M3U8, ne zelenega gumba »Prenesi«, nato ponovno klikni »M3U8«.",
                        "M3U8"
                    );
                    System.Media.SystemSounds.Exclamation.Play();
                    return;
                }

                string clipboardText =
                    Clipboard.GetText();

                List<string> mediaUrls =
                    ExtractDirectMediaCandidates(
                        clipboardText
                    );

                if (mediaUrls.Count == 0)
                {
                    List<string> clipboardUrls =
                        ExtractUrls(
                            DecodeMediaText(
                                clipboardText
                            )
                        );

                    bool containsOrdinaryVoyoPage =
                        clipboardUrls.Any(
                            delegate(string value)
                            {
                                return IsVoyoUrl(value);
                            }
                        );

                    if (containsOrdinaryVoyoPage)
                    {
                        Log(
                            "Kopirana je bila navadna stran Voyo, ne tok M3U8. V VeeVee klikni MAJHNO IKONO VERIGE ob vrstici »1080p … M3U8«. Zeleni gumb »Prenesi« povezave ne kopira v ta program.",
                            "M3U8"
                        );
                    }
                    else
                    {
                        Log(
                            "V odložišču ni bilo mogoče najti uporabnega medijskega URL-ja. Po kliku ikone verige v VeeVee mora biti v odložišču povezava, ki se začne s https:// in običajno vsebuje m3u8, manifest, playlist ali naslov CDN.",
                            "M3U8"
                        );
                    }

                    System.Media.SystemSounds.Exclamation.Play();
                    return;
                }

                txtUrls.Text =
                    string.Join(
                        Environment.NewLine,
                        mediaUrls.ToArray()
                    );

                chkDirectMedia.Checked = true;
                chkCookies.Checked = true;

                if (!string.IsNullOrWhiteSpace(existingVoyoPage))
                {
                    txtReferer.Text =
                        existingVoyoPage;
                }
                else if (string.IsNullOrWhiteSpace(txtReferer.Text))
                {
                    txtReferer.Text =
                        "https://voyo.si/";
                }

                txtUrls.SelectionStart =
                    txtUrls.TextLength;
                txtUrls.ScrollToCaret();

                SaveCurrentSettings();

                Log(
                    "Neposredni medijski URL je bil prebran iz odložišča. Vključen je neposredni način, Firefoxovi piškotki in referer Voyo. Preveri, da se zgornja povezava začne s https://, nato klikni »Dodaj in začni«.",
                    "M3U8"
                );
            }
            catch (Exception e)
            {
                ShowError(
                    "Povezave M3U8 iz odložišča ni bilo mogoče prebrati.",
                    e
                );
            }
        }

        private bool IsDrmProtectedMediaUrl(string url)
        {
            try
            {
                Uri uri;

                if (
                    !Uri.TryCreate(
                        url,
                        UriKind.Absolute,
                        out uri
                    )
                )
                {
                    return false;
                }

                string[] segments =
                    uri.AbsolutePath.Split(
                        new char[]
                        {
                            '/'
                        },
                        StringSplitOptions.RemoveEmptyEntries
                    );

                foreach (string segment in segments)
                {
                    string[] parts =
                        segment.Split('.');

                    if (parts.Length != 3)
                    {
                        continue;
                    }

                    string payload =
                        parts[1]
                        .Replace('-', '+')
                        .Replace('_', '/');

                    int remainder =
                        payload.Length % 4;

                    if (remainder == 2)
                    {
                        payload += "==";
                    }
                    else if (remainder == 3)
                    {
                        payload += "=";
                    }
                    else if (remainder == 1)
                    {
                        continue;
                    }

                    string json =
                        Encoding.UTF8.GetString(
                            Convert.FromBase64String(
                                payload
                            )
                        );

                    if (
                        Regex.IsMatch(
                            json,
                            "\"drmProtected\"\\s*:\\s*1",
                            RegexOptions.IgnoreCase
                        )
                    )
                    {
                        return true;
                    }
                }
            }
            catch
            {
            }

            return false;
        }

        private string GetSafeDisplayUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
            {
                return "";
            }

            try
            {
                Uri uri;

                if (
                    !Uri.TryCreate(
                        url,
                        UriKind.Absolute,
                        out uri
                    )
                )
                {
                    return url;
                }

                if (
                    string.Equals(
                        uri.Host,
                        "vod.api.24ur.si",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    string fileName =
                        Path.GetFileName(
                            uri.AbsolutePath
                        );

                    return
                        uri.Scheme +
                        "://" +
                        uri.Host +
                        "/vod/[začasni-žeton]/…/" +
                        (
                            string.IsNullOrWhiteSpace(fileName)
                                ? "medijski-tok"
                                : fileName
                        );
                }

                if (!string.IsNullOrWhiteSpace(uri.Query))
                {
                    return
                        uri.GetLeftPart(
                            UriPartial.Path
                        ) +
                        "?[začasni-parametri]";
                }
            }
            catch
            {
            }

            return url;
        }

        private string SanitizeSensitiveText(string text)
        {
            if (string.IsNullOrEmpty(text))
            {
                return text;
            }

            string sanitized =
                Regex.Replace(
                    text,
                    @"https?://vod\.api\.24ur\.si/vod/[^\s]+",
                    "https://vod.api.24ur.si/vod/[ZAČASNA-POVEZAVA]",
                    RegexOptions.IgnoreCase
                );

            sanitized =
                Regex.Replace(
                    sanitized,
                    @"([?&](?:token|signature|sig|auth|jwt|key)=)[^&\s]+",
                    "$1[SKRITO]",
                    RegexOptions.IgnoreCase
                );

            return sanitized;
        }

        private string DecodeMediaText(string text)
        {
            string value =
                text ?? "";

            value = value
                .Replace("\\/", "/")
                .Replace("\\u0026", "&")
                .Replace("\\u003D", "=")
                .Replace("\\u003d", "=")
                .Replace("\\u002F", "/")
                .Replace("\\u002f", "/")
                .Replace("\\u003A", ":")
                .Replace("\\u003a", ":");

            value =
                WebUtility.HtmlDecode(
                    value
                );

            for (int attempt = 0; attempt < 3; attempt++)
            {
                try
                {
                    string decoded =
                        Uri.UnescapeDataString(
                            value
                        );

                    if (string.Equals(
                        decoded,
                        value,
                        StringComparison.Ordinal
                    ))
                    {
                        break;
                    }

                    value = decoded;
                }
                catch
                {
                    break;
                }
            }

            return value;
        }

        private List<string> ExtractDirectMediaCandidates(string text)
        {
            List<string> variants =
                new List<string>();

            string original =
                text ?? "";
            string decoded =
                DecodeMediaText(
                    original
                );

            variants.Add(original);

            if (!string.Equals(
                decoded,
                original,
                StringComparison.Ordinal
            ))
            {
                variants.Add(decoded);
            }

            List<string> candidates =
                new List<string>();

            foreach (string variant in variants)
            {
                foreach (string extracted in ExtractUrls(variant))
                {
                    string url =
                        DecodeMediaText(
                            extracted
                        )
                        .Trim()
                        .TrimEnd(
                            '.',
                            ',',
                            ';',
                            ')',
                            ']',
                            '}'
                        );

                    if (
                        IsDirectMediaUrl(url) &&
                        !candidates.Contains(
                            url,
                            StringComparer.OrdinalIgnoreCase
                        )
                    )
                    {
                        candidates.Add(url);
                    }
                }
            }

            if (candidates.Count > 0)
            {
                return candidates;
            }

            // Nekateri podpisani CDN naslovi nimajo vidne končnice .m3u8.
            // Če je VeeVee kopiral zunanji HTTP(S) naslov in to ni navadna
            // stran predvajalnika Voyo, ga sprejmemo kot neposredni kandidat.
            foreach (string variant in variants)
            {
                foreach (string extracted in ExtractUrls(variant))
                {
                    string url =
                        DecodeMediaText(
                            extracted
                        )
                        .Trim()
                        .TrimEnd(
                            '.',
                            ',',
                            ';',
                            ')',
                            ']',
                            '}'
                        );

                    if (
                        IsPossibleDirectMediaEndpoint(url) &&
                        !candidates.Contains(
                            url,
                            StringComparer.OrdinalIgnoreCase
                        )
                    )
                    {
                        candidates.Add(url);
                    }
                }
            }

            return candidates
                .Take(10)
                .ToList();
        }

        private bool IsDirectMediaUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
            {
                return false;
            }

            if (!Regex.IsMatch(
                url,
                @"^https?://",
                RegexOptions.IgnoreCase
            ))
            {
                return false;
            }

            if (Regex.IsMatch(
                url,
                @"\.(?:m3u8|mpd|mp4|m4v|webm)(?:[?#]|$)",
                RegexOptions.IgnoreCase
            ))
            {
                return true;
            }

            return Regex.IsMatch(
                url,
                @"(?:m3u8|manifest|playlist|master|index\.m3u|format=hls|type=hls)",
                RegexOptions.IgnoreCase
            );
        }

        private bool IsPossibleDirectMediaEndpoint(string url)
        {
            Uri uri;

            if (
                !Uri.TryCreate(
                    url,
                    UriKind.Absolute,
                    out uri
                ) ||
                (
                    uri.Scheme != Uri.UriSchemeHttp &&
                    uri.Scheme != Uri.UriSchemeHttps
                )
            )
            {
                return false;
            }

            if (IsVoyoUrl(url))
            {
                return false;
            }

            string path =
                (uri.AbsolutePath ?? "")
                .ToLowerInvariant();

            if (Regex.IsMatch(
                path,
                @"\.(?:jpg|jpeg|png|gif|webp|svg|css|js|json|woff2?|ttf|ico)$",
                RegexOptions.IgnoreCase
            ))
            {
                return false;
            }

            string host =
                (uri.Host ?? "")
                .ToLowerInvariant();

            if (
                host.Contains("veevee.app") ||
                host.Contains("chromewebstore.google.com") ||
                host.Contains("addons.mozilla.org")
            )
            {
                return false;
            }

            return true;
        }

        private void BrowseFolder()
        {
            using (FolderBrowserDialog dialog = new FolderBrowserDialog())
            {
                dialog.Description = "Izberi mapo za končne video in zvočne datoteke";
                dialog.SelectedPath = txtFolder.Text;

                if (dialog.ShowDialog(this) == DialogResult.OK)
                {
                    txtFolder.Text = dialog.SelectedPath;
                    SaveCurrentSettings();
                }
            }
        }

        private List<string> ExtractUrls(string text)
        {
            List<string> urls = new List<string>();
            MatchCollection matches = Regex.Matches(
                text ?? "",
                @"https?://[^\s<>""']+",
                RegexOptions.IgnoreCase
            );

            foreach (Match match in matches)
            {
                string url = match.Value.Trim().TrimEnd('.', ',', ';', ')', ']');
                if (!urls.Contains(url, StringComparer.OrdinalIgnoreCase))
                {
                    urls.Add(url);
                }
            }

            return urls;
        }

        private void AddUrlsToQueue(bool startAfter)
        {
            List<string> urls = ExtractUrls(txtUrls.Text);

            if (urls.Count == 0)
            {
                MessageBox.Show(
                    this,
                    "Prilepi najmanj eno veljavno povezavo, ki se začne z http:// ali https://.",
                    "Ni povezav",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Warning
                );
                return;
            }

            string folder = EnsureOutputFolder();
            int added = 0;
            List<string> unsupportedUrls =
                new List<string>();

            foreach (string originalUrl in urls)
            {
                string url = NormalizeInputUrl(originalUrl);

                if (!string.Equals(
                    originalUrl,
                    url,
                    StringComparison.OrdinalIgnoreCase
                ))
                {
                    Log(
                        "RTV 365 povezava »Kratki« je bila samodejno pretvorjena v podprto arhivsko povezavo: " +
                        url,
                        "RTV 365"
                    );
                }

                if (IsVoyoUrl(url))
                {
                    unsupportedUrls.Add(
                        originalUrl
                    );

                    Log(
                        "Navadna stran predvajalnika Voyo ni neposredni M3U8. Povezava ni bila dodana. Neposredni M3U8/MPD/MP4 prilepi v isto polje in klikni »Dodaj v vrsto« ali »Dodaj in začni«.",
                        "VOYO"
                    );

                    continue;
                }

                if (
                    chkDirectMedia.Checked &&
                    IsDrmProtectedMediaUrl(url)
                )
                {
                    unsupportedUrls.Add(
                        originalUrl
                    );

                    Log(
                        "Medijski URL je zaščiten in ni bil dodan v vrsto. Uporabi uradno možnost ogleda brez povezave.",
                        "M3U8"
                    );

                    continue;
                }

                if (
                    chkDirectMedia.Checked &&
                    !IsDirectMediaUrl(url) &&
                    !IsPossibleDirectMediaEndpoint(url)
                )
                {
                    unsupportedUrls.Add(
                        originalUrl
                    );

                    Log(
                        "Neposredni način je vključen, vendar vneseni naslov ni prepoznan kot M3U8, MPD, MP4 ali podpisani medijski naslov.",
                        "M3U8"
                    );

                    continue;
                }

                bool directMedia =
                    chkDirectMedia.Checked ||
                    IsDirectMediaUrl(url);

                DownloadJob job = new DownloadJob();
                job.Kind = JobKind.Download;
                job.Url = url;
                job.SourceName =
                    directMedia
                        ? "HLS/FFmpeg"
                        : GetSiteName(url);
                job.DisplayTitle = GetSafeDisplayUrl(url);
                job.OutputFolder = folder;
                job.QualityIndex = cmbQuality.SelectedIndex;
                job.OutputIndex =
                    cmbSubtitles.SelectedIndex == 3
                        ? 1
                        : cmbOutput.SelectedIndex;
                job.UseEdgeCookies = chkCookies.Checked;
                job.CookieBrowser = GetSelectedCookieBrowser();
                job.DirectMediaMode = directMedia;
                job.Referer = txtReferer.Text.Trim();
                job.SubtitleModeIndex = cmbSubtitles.SelectedIndex;
                job.SubtitleLanguages = txtSubtitleLanguages.Text.Trim();
                job.IncludeAutoSubtitles = chkAutoSubtitles.Checked;
                job.StyledEmbeddedSubtitles =
                    chkStyledEmbeddedSubtitles.Checked;
                job.SubtitleBackgroundOpacity =
                    Convert.ToInt32(
                        numSubtitleBackgroundOpacity.Value
                    );
                job.ConcurrentFragments = Convert.ToInt32(numFragments.Value);

                AddJob(job);
                added++;
            }

            if (unsupportedUrls.Count > 0)
            {
                txtUrls.Text =
                    string.Join(
                        Environment.NewLine,
                        unsupportedUrls.ToArray()
                    );

                txtUrls.SelectionStart =
                    txtUrls.TextLength;
                txtUrls.ScrollToCaret();

                Log(
                    "Nepodprte povezave so ostale v vnosnem polju: " +
                    unsupportedUrls.Count,
                    "VRSTA"
                );
            }
            else
            {
                txtUrls.Clear();
            }

            SaveCurrentSettings();
            Log(
                "V vrsto je bilo dodanih povezav: " +
                added,
                "VRSTA"
            );

            if (startAfter && added > 0)
            {
                lock (queueLock)
                {
                    queueRunning = true;
                }

                Log(
                    "Čakalna vrsta je zagnana.",
                    "VRSTA"
                );
                PumpQueue();
            }
        }

        private void AddLocalFiles()
        {
            if (cmbOutput.SelectedIndex == 0)
            {
                MessageBox.Show(
                    this,
                    "Za lokalno datoteko izberi končni format, ki zahteva pretvorbo. Možnost »Original – brez ponovnega kodiranja« pri lokalni pretvorbi nima smisla.",
                    "Izberi format",
                    MessageBoxButtons.OK,
                    MessageBoxIcon.Information
                );
                return;
            }

            using (OpenFileDialog dialog = new OpenFileDialog())
            {
                dialog.Title = "Izberi video ali zvočne datoteke za pretvorbo";
                dialog.Multiselect = true;
                dialog.Filter =
                    "Video in zvok|*.mp4;*.mkv;*.webm;*.mov;*.avi;*.m4v;*.ts;*.m2ts;*.mpg;*.mpeg;*.wmv;*.flv;*.mp3;*.m4a;*.aac;*.flac;*.wav;*.ogg;*.opus|" +
                    "Vse datoteke|*.*";

                if (dialog.ShowDialog(this) != DialogResult.OK)
                {
                    return;
                }

                string folder = EnsureOutputFolder();

                foreach (string file in dialog.FileNames)
                {
                    DownloadJob job = new DownloadJob();
                    job.Kind = JobKind.LocalConversion;
                    job.LocalFile = file;
                    job.SourceName = "lokalno";
                    job.DisplayTitle = Path.GetFileName(file);
                    job.OutputFolder = folder;
                    job.QualityIndex = cmbQuality.SelectedIndex;
                    job.OutputIndex =
                        cmbSubtitles.SelectedIndex == 3
                            ? 1
                            : cmbOutput.SelectedIndex;
                    job.SubtitleModeIndex =
                        cmbSubtitles.SelectedIndex;
                    job.SubtitleLanguages =
                        txtSubtitleLanguages.Text.Trim();
                    job.IncludeAutoSubtitles =
                        chkAutoSubtitles.Checked;
                    job.StyledEmbeddedSubtitles =
                        chkStyledEmbeddedSubtitles.Checked;
                    job.SubtitleBackgroundOpacity =
                        Convert.ToInt32(
                            numSubtitleBackgroundOpacity.Value
                        );
                    job.ConcurrentFragments =
                        Convert.ToInt32(numFragments.Value);
                    AddJob(job);
                }

                Log("Dodane lokalne datoteke: " + dialog.FileNames.Length, "VRSTA");
            }
        }

        private void AddJob(DownloadJob job)
        {
            DataGridViewRow row = new DataGridViewRow();
            row.CreateCells(grid);
            row.Cells[0].Value = StatusText(JobStatus.Waiting);
            row.Cells[1].Value = "0 %";
            row.Cells[2].Value = "";
            row.Cells[3].Value = "";
            row.Cells[4].Value = job.SourceName;
            row.Cells[5].Value = QualityNames[job.QualityIndex];
            row.Cells[6].Value =
                job.SubtitleModeIndex == 3 &&
                job.OutputIndex < 7
                    ? "MP4 – H.264 + AAC (zapečeni podnapisi)"
                    : OutputNames[job.OutputIndex];
            row.Cells[7].Value = job.DisplayTitle;
            row.Cells[7].ToolTipText =
                job.Kind == JobKind.Download
                    ? job.DisplayTitle
                    : job.LocalFile;
            row.Tag = job;
            job.Row = row;

            grid.Rows.Add(row);

            lock (queueLock)
            {
                allJobs.Add(job);
                pendingJobs.Enqueue(job);
            }

            RefreshQueueStatus();
        }

        private void StartQueue()
        {
            if (txtUrls.Text.Trim().Length > 0)
            {
                AddUrlsToQueue(false);
            }

            lock (queueLock)
            {
                if (pendingJobs.Count == 0 && activeJobs.Count == 0)
                {
                    MessageBox.Show(
                        this,
                        "Čakalna vrsta je prazna.",
                        "Ni videov",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information
                    );
                    return;
                }

                queueRunning = true;
            }

            Log("Čakalna vrsta je zagnana.", "VRSTA");
            PumpQueue();
        }

        private void PumpQueue()
        {
            if (InvokeRequired)
            {
                BeginInvoke(new Action(PumpQueue));
                return;
            }

            List<DownloadJob> toStart = new List<DownloadJob>();

            lock (queueLock)
            {
                if (!queueRunning)
                {
                    RefreshQueueStatus();
                    return;
                }

                int limit = Convert.ToInt32(numConcurrent.Value);

                while (activeJobs.Count < limit && pendingJobs.Count > 0)
                {
                    DownloadJob job = pendingJobs.Dequeue();
                    if (job.Status == JobStatus.Cancelled)
                    {
                        continue;
                    }

                    activeJobs[job.Id] = job;
                    toStart.Add(job);
                }

                if (activeJobs.Count == 0 && pendingJobs.Count == 0)
                {
                    queueRunning = false;
                }
            }

            foreach (DownloadJob job in toStart)
            {
                RunJobOnQueueAsync(job);
            }

            RefreshQueueStatus();
        }

        private async void RunJobOnQueueAsync(DownloadJob job)
        {
            try
            {
                await RunJobAsync(job);
            }
            catch (OperationCanceledException)
            {
                SetJobStatus(job, JobStatus.Cancelled);
                Log("Opravilo je bilo preklicano.", JobPrefix(job));
            }
            catch (Exception e)
            {
                job.Error = e.Message;
                SetJobStatus(job, JobStatus.Failed);
                SetRowColor(job, Color.MistyRose);
                Log(e.Message, JobPrefix(job) + " NAPAKA");
                ErrorLogger.Write("Opravilo " + job.Id, e);
            }
            finally
            {
                lock (queueLock)
                {
                    activeJobs.Remove(job.Id);
                    job.CurrentProcess = null;

                    if (activeJobs.Count == 0 && pendingJobs.Count == 0)
                    {
                        queueRunning = false;
                    }
                }

                RefreshQueueStatus();
                PumpQueue();
            }
        }

        private async Task RunJobAsync(DownloadJob job)
        {
            string ytDlp = ToolLocator.FindYtDlp();
            string ffmpeg = ToolLocator.FindFfmpeg();
            string ffprobe = ToolLocator.FindFfprobe();

            if (job.Kind == JobKind.Download && string.IsNullOrWhiteSpace(ytDlp))
            {
                throw new InvalidOperationException(
                    "yt-dlp ni najden. Klikni »Namesti/posodobi orodja in seznam«."
                );
            }

            if (job.OutputIndex != 0 && (string.IsNullOrWhiteSpace(ffmpeg) || string.IsNullOrWhiteSpace(ffprobe)))
            {
                throw new InvalidOperationException(
                    "FFmpeg ali ffprobe ni najden. Klikni »Namesti/posodobi orodja in seznam«."
                );
            }

            string workFolder = Path.Combine(AppPaths.WorkFolder, job.Id.ToString("N"));
            Directory.CreateDirectory(workFolder);
            TryHideFolder(workFolder);

            string sourceFile = "";

            try
            {
                if (job.Kind == JobKind.Download)
                {
                    SetJobStatus(job, JobStatus.Downloading);
                    SetRowColor(job, Color.FromArgb(235, 247, 255));

                    Log("Uporabljam yt-dlp: " + ytDlp, JobPrefix(job));

                    if (Regex.IsMatch(
                        job.Url ?? "",
                        @"https?://(?:www\.)?(?:365\.)?rtvslo\.si/",
                        RegexOptions.IgnoreCase
                    ))
                    {
                        Log(
                            "RTV 365 se pripravlja. Povezave oblike /kratki#ID-0 program samodejno pretvori v podprto obliko /arhiv/kratki/ID. Pri HLS oddajah lahko nekaj časa ni znan odstotek.",
                            JobPrefix(job)
                        );
                    }

                    sourceFile = await DownloadSourceAsync(job, ytDlp, workFolder);

                    if (string.IsNullOrWhiteSpace(sourceFile) || !File.Exists(sourceFile))
                    {
                        sourceFile = FindLargestMediaFile(workFolder);
                    }

                    if (string.IsNullOrWhiteSpace(sourceFile) || !File.Exists(sourceFile))
                    {
                        throw new FileNotFoundException(
                            "Prenos se je zaključil, vendar končne izvorne datoteke ni bilo mogoče najti."
                        );
                    }
                }
                else
                {
                    sourceFile = job.LocalFile;
                    if (!File.Exists(sourceFile))
                    {
                        throw new FileNotFoundException(
                            "Lokalna datoteka ne obstaja.",
                            sourceFile
                        );
                    }
                }

                job.Cancellation.Token.ThrowIfCancellationRequested();

                List<string> subtitleFiles = FindSubtitleFiles(workFolder);

                if (
                    job.Kind == JobKind.Download &&
                    job.SubtitleModeIndex > 0 &&
                    IsYouTubeSlovenianAutoTranslation(job) &&
                    subtitleFiles.Count == 0
                )
                {
                    throw new InvalidOperationException(
                        "YouTube ni vrnil samodejno prevedenih slovenskih podnapisov. Preveri, da video omogoča angleške podnapise in možnost Samodejni prevod → Slovenščina. Nato v izbranem brskalniku osveži sejo, brskalnik popolnoma zapri in ponovi."
                    );
                }

                if (
                    job.Kind == JobKind.Download &&
                    job.SubtitleModeIndex > 0 &&
                    subtitleFiles.Count == 0
                )
                {
                    Log(
                        "Običajni izvlečevalnik ni ustvaril datoteke s podnapisi. Preverjam podnapisne steze neposredno v HLS manifestu.",
                        JobPrefix(job)
                    );

                    List<string> recoveredSubtitles =
                        await TryRecoverHlsSubtitlesAsync(
                            job,
                            ytDlp,
                            ffmpeg,
                            workFolder
                        );

                    if (recoveredSubtitles.Count > 0)
                    {
                        subtitleFiles = recoveredSubtitles;
                        Log(
                            "HLS rezervni način je našel podnapisnih stez: " +
                            recoveredSubtitles.Count,
                            JobPrefix(job)
                        );
                    }
                }

                bool burnStyledSubtitles =
                    job.SubtitleModeIndex == 3 &&
                    subtitleFiles.Count > 0 &&
                    job.OutputIndex < 7;

                string finalCandidate;

                // Pri zapečenih podnapisih vedno uporabimo izvorni video in
                // izdelamo enoten MP4 H.264/AAC. Tako se izognemo dvojnemu
                // kodiranju in popravimo časovne žige ter iskanje po videu.
                if (burnStyledSubtitles)
                {
                    finalCandidate = sourceFile;
                }
                else if (job.OutputIndex == 0)
                {
                    finalCandidate = sourceFile;
                }
                else
                {
                    SetJobStatus(job, JobStatus.Converting);
                    SetRowColor(job, Color.FromArgb(245, 238, 255));

                    finalCandidate = await ConvertFileAsync(
                        job,
                        sourceFile,
                        workFolder,
                        ffmpeg,
                        ffprobe
                    );
                }

                bool embedSelectableSubtitles =
                    job.SubtitleModeIndex == 2 &&
                    subtitleFiles.Count > 0 &&
                    job.OutputIndex < 7;

                if (embedSelectableSubtitles)
                {
                    if (string.IsNullOrWhiteSpace(ffmpeg) ||
                        string.IsNullOrWhiteSpace(ffprobe))
                    {
                        throw new InvalidOperationException(
                            "Za vgradnjo podnapisov sta potrebna FFmpeg in ffprobe."
                        );
                    }

                    SetJobStatus(job, JobStatus.Converting);
                    finalCandidate =
                        await EmbedSelectableSubtitlesInMkvAsync(
                            job,
                            finalCandidate,
                            subtitleFiles,
                            workFolder,
                            ffmpeg,
                            ffprobe
                        );
                }
                else if (burnStyledSubtitles)
                {
                    if (string.IsNullOrWhiteSpace(ffmpeg) ||
                        string.IsNullOrWhiteSpace(ffprobe))
                    {
                        throw new InvalidOperationException(
                            "Za zapečene podnapise sta potrebna FFmpeg in ffprobe."
                        );
                    }

                    SetJobStatus(job, JobStatus.Converting);
                    SetRowColor(
                        job,
                        Color.FromArgb(
                            245,
                            238,
                            255
                        )
                    );

                    job.Progress = "0 %";
                    job.Speed = "";
                    job.Eta = "";
                    UpdateJobRow(job);

                    Log(
                        "Prenos videa je končan. Zdaj zapečem podnapise v MP4. To zahteva ponovno kodiranje in lahko traja nekaj minut.",
                        JobPrefix(job)
                    );

                    finalCandidate =
                        await BurnStyledSubtitleIntoMp4Async(
                            job,
                            sourceFile,
                            subtitleFiles,
                            workFolder,
                            ffmpeg,
                            ffprobe
                        );
                }
                else if (
                    (job.SubtitleModeIndex == 2 ||
                     job.SubtitleModeIndex == 3) &&
                    subtitleFiles.Count == 0
                )
                {
                    Log(
                        "Spletna stran ni ponudila podnapisov za zahtevane jezike; video bo shranjen brez njih.",
                        JobPrefix(job)
                    );
                }
                else if (
                    (job.SubtitleModeIndex == 2 ||
                     job.SubtitleModeIndex == 3) &&
                    job.OutputIndex >= 7
                )
                {
                    Log(
                        "Podnapisov ni mogoče vgraditi ali zapeči v zvočno datoteko; shranjeni bodo ločeno.",
                        JobPrefix(job)
                    );
                }

                SetJobStatus(job, JobStatus.Finalizing);
                string completedFile = await PublishFinalFileAsync(
                    finalCandidate,
                    job.OutputFolder,
                    Path.GetFileName(finalCandidate),
                    job.Kind == JobKind.LocalConversion &&
                    string.Equals(
                        finalCandidate,
                        sourceFile,
                        StringComparison.OrdinalIgnoreCase
                    ),
                    job.Cancellation.Token
                );

                if (IsOneDrivePath(completedFile))
                {
                    Log(
                        "Ciljna mapa je v OneDrive. Končno datoteko označujem kot »Vedno obdrži v tej napravi« in preverjam lokalno dostopnost.",
                        JobPrefix(job)
                    );

                    bool oneDriveReady =
                        await EnsureOneDriveFileAvailableLocallyAsync(
                            completedFile,
                            job.Cancellation.Token
                        );

                    Log(
                        oneDriveReady
                            ? "OneDrive datoteka je lokalno pripravljena. Zdaj jo lahko odpreš."
                            : "Datoteka je shranjena, vendar OneDrive še ni potrdil stabilne lokalne dostopnosti. Počakaj na zeleno kljukico ali uporabi mapo zunaj OneDrive.",
                        JobPrefix(job)
                    );
                }

                bool publishSeparateSubtitles =
                    job.SubtitleModeIndex == 1 ||
                    (
                        (
                            job.SubtitleModeIndex == 2 ||
                            job.SubtitleModeIndex == 3
                        ) &&
                        job.OutputIndex >= 7
                    );

                if (publishSeparateSubtitles &&
                    subtitleFiles.Count > 0)
                {
                    await PublishSubtitleFilesAsync(
                        job,
                        subtitleFiles,
                        completedFile
                    );
                }

                job.FinalFile = completedFile;
                job.Progress = "100 %";
                job.Speed = "";
                job.Eta = "";
                SetJobStatus(job, JobStatus.Completed);
                UpdateJobRow(job);
                SetRowColor(job, Color.Honeydew);
                Log("KONČANO: " + completedFile, JobPrefix(job));
            }
            finally
            {
                try
                {
                    if (Directory.Exists(workFolder))
                    {
                        Directory.Delete(workFolder, true);
                    }
                }
                catch (Exception cleanupError)
                {
                    ErrorLogger.Write("Čiščenje začasne mape", cleanupError);
                }
            }
        }

        private string NormalizeUnicodeDisplayText(
            string value
        )
        {
            if (string.IsNullOrEmpty(value))
            {
                return value ?? "";
            }

            string result =
                value.Normalize(
                    NormalizationForm.FormC
                );

            result =
                result.Replace(
                    "\u0000",
                    ""
                );

            return result;
        }

        private async Task<string> DownloadSourceAsync(
            DownloadJob job,
            string ytDlp,
            string workFolder
        )
        {
            job.Url = NormalizeInputUrl(job.Url);
            string downloadedFile = "";

            bool youtubeSlovenianAutoTranslation =
                IsYouTubeSlovenianAutoTranslation(job);

            bool translatedSubtitleRateLimited = false;

            bool directCandidate =
                job.DirectMediaMode &&
                !IsVoyoUrl(job.Url);

            if (
                directCandidate &&
                !job.UseEdgeCookies
            )
            {
                string directFfmpeg =
                    ToolLocator.FindFfmpeg();

                if (!string.IsNullOrWhiteSpace(directFfmpeg))
                {
                    Log(
                        "Neposredni način brez brskalniških piškotkov: najprej poskuša FFmpeg.",
                        JobPrefix(job)
                    );

                    string directResult =
                        await DownloadDirectMediaWithFfmpegAsync(
                            job,
                            directFfmpeg,
                            workFolder
                        );

                    if (
                        !string.IsNullOrWhiteSpace(directResult) &&
                        File.Exists(directResult)
                    )
                    {
                        return directResult;
                    }

                    Log(
                        "FFmpeg neposrednega toka ni dokončal. Poskušam še z yt-dlp.",
                        JobPrefix(job)
                    );
                }
            }
            else if (
                directCandidate &&
                job.UseEdgeCookies
            )
            {
                Log(
                    "Neposredni M3U8/HLS način: najprej poskuša yt-dlp z brskalniškimi piškotki in refererjem; ob neuspehu sledi FFmpeg.",
                    JobPrefix(job)
                );
            }

            if (string.IsNullOrWhiteSpace(ytDlp))
            {
                if (directCandidate)
                {
                    string directFfmpeg =
                        ToolLocator.FindFfmpeg();

                    if (!string.IsNullOrWhiteSpace(directFfmpeg))
                    {
                        string directResult =
                            await DownloadDirectMediaWithFfmpegAsync(
                                job,
                                directFfmpeg,
                                workFolder
                            );

                        if (
                            !string.IsNullOrWhiteSpace(directResult) &&
                            File.Exists(directResult)
                        )
                        {
                            return directResult;
                        }
                    }
                }

                throw new InvalidOperationException(
                    "yt-dlp ni nameščen, FFmpeg pa neposrednega toka ni dokončal."
                );
            }

            List<string> arguments = new List<string>();
            arguments.Add("--ignore-config");
            arguments.Add("--encoding");
            arguments.Add("utf-8");
            arguments.Add("--plugin-dirs");
            arguments.Add(AppPaths.PluginFolder);
            arguments.Add("--no-simulate");
            arguments.Add("--progress");
            arguments.Add("--no-playlist");
            arguments.Add("--windows-filenames");
            arguments.Add("--trim-filenames");
            arguments.Add("170");
            arguments.Add("--no-color");
            arguments.Add("--newline");
            arguments.Add("--progress-delta");
            arguments.Add("0.5");
            arguments.Add("--retries");
            arguments.Add("10");
            arguments.Add("--fragment-retries");
            arguments.Add("10");
            arguments.Add("--concurrent-fragments");
            arguments.Add(job.ConcurrentFragments.ToString());
            arguments.Add("--progress-template");
            arguments.Add("download:PROGRESS|%(progress._percent_str)s|%(progress._speed_str)s|%(progress._eta_str)s|%(progress._downloaded_bytes_str)s|%(progress._total_bytes_str)s|%(progress.fragment_index)s|%(progress.fragment_count)s");
            arguments.Add("--print");
            arguments.Add("before_dl:TITLE|%(title)s");
            arguments.Add("--print");
            arguments.Add("after_move:FILE|%(filepath)s");

            if (job.UseEdgeCookies)
            {
                arguments.Add("--cookies-from-browser");
                arguments.Add(string.IsNullOrWhiteSpace(job.CookieBrowser) ? "firefox" : job.CookieBrowser);
            }

            if (job.DirectMediaMode)
            {
                arguments.Add("--force-generic-extractor");

                if (!string.IsNullOrWhiteSpace(job.Referer))
                {
                    arguments.Add("--referer");
                    arguments.Add(job.Referer);

                    if (
                        job.Referer.IndexOf(
                            "voyo.si",
                            StringComparison.OrdinalIgnoreCase
                        ) >= 0
                    )
                    {
                        arguments.Add("--add-headers");
                        arguments.Add(
                            "Origin:https://voyo.si"
                        );
                    }
                }

                Log(
                    "Uporabljen je neposredni medijski URL. Program ga obdeluje kot HLS/DASH tok; navadna stran predvajalnika mora biti prej pretvorjena v neposredni URL, na primer z ikono verige v VeeVee.",
                    JobPrefix(job)
                );
            }

            if (Regex.IsMatch(
                job.Url ?? "",
                @"https?://(?:www\.)?(?:365\.)?rtvslo\.si/",
                RegexOptions.IgnoreCase
            ))
            {
                arguments.Add("--geo-bypass-country");
                arguments.Add("SI");
            }

            if (job.SubtitleModeIndex > 0)
            {
                arguments.Add("--write-subs");

                if (
                    job.IncludeAutoSubtitles ||
                    youtubeSlovenianAutoTranslation
                )
                {
                    arguments.Add("--write-auto-subs");
                }

                if (youtubeSlovenianAutoTranslation)
                {
                    arguments.Add("--sleep-subtitles");
                    arguments.Add("1");
                    arguments.Add("--sleep-requests");
                    arguments.Add("0.5");

                    Log(
                        "YouTube samodejni prevod: zahtevam slovenske podnapise iz angleškega vira z vzorcem sl-en.*. Izbrani brskalnik (Firefox, Edge ali Chrome) mora biti popolnoma zaprt, da lahko yt-dlp prebere sveže piškotke.",
                        JobPrefix(job)
                    );
                }

                arguments.Add("--sub-langs");
                arguments.Add(
                    string.IsNullOrWhiteSpace(job.SubtitleLanguages)
                        ? "sl.*,slv,slo,slovenian,si,en.*"
                        : job.SubtitleLanguages
                );
                arguments.Add("--sub-format");
                arguments.Add("srt/best");
                arguments.Add("--convert-subs");
                arguments.Add("srt");

                Log(
                    "Zahtevani podnapisi: " +
                    (
                        string.IsNullOrWhiteSpace(job.SubtitleLanguages)
                            ? "sl.*,slv,slo,slovenian,si,en.*"
                            : job.SubtitleLanguages
                    ) +
                    (
                        job.IncludeAutoSubtitles
                            ? " + samodejni"
                            : ""
                    ),
                    JobPrefix(job)
                );
            }

            arguments.Add("-f");
            arguments.Add(GetYtDlpFormat(job.QualityIndex, job.OutputIndex));

            if (job.OutputIndex < 7)
            {
                arguments.Add("--merge-output-format");
                arguments.Add("mp4");
            }

            arguments.Add("-o");
            arguments.Add(
                Path.Combine(
                    workFolder,
                    "%(uploader,channel,creator,unknown)s - %(title).120s [%(id)s].%(ext)s"
                )
            );
            arguments.Add(job.Url);

            Action<string> handleYtDlpLine = delegate(string line)
            {
                if (string.IsNullOrWhiteSpace(line))
                {
                    return;
                }

                if (
                    youtubeSlovenianAutoTranslation &&
                    line.IndexOf(
                        "HTTP Error 429",
                        StringComparison.OrdinalIgnoreCase
                    ) >= 0
                )
                {
                    translatedSubtitleRateLimited = true;
                }

                if (line.StartsWith("TITLE|", StringComparison.Ordinal))
                {
                    string title =
                        NormalizeUnicodeDisplayText(
                            line.Substring(6)
                        );
                    if (!string.IsNullOrWhiteSpace(title))
                    {
                        job.DisplayTitle = title;
                        SafeUi(delegate
                        {
                            job.Row.Cells[7].Value = title;
                            job.Row.Cells[7].ToolTipText = job.Url;
                        });
                    }
                    return;
                }

                if (line.StartsWith("PROGRESS|", StringComparison.Ordinal))
                {
                    string[] parts = line.Split(new char[] { '|' });

                    if (parts.Length > 1 &&
                        !string.IsNullOrWhiteSpace(parts[1]) &&
                        !parts[1].Contains("NA"))
                    {
                        job.Progress = parts[1].Trim();
                    }
                    else
                    {
                        job.Progress = "aktivno";
                    }

                    if (parts.Length > 2 &&
                        !string.IsNullOrWhiteSpace(parts[2]) &&
                        !parts[2].Contains("NA"))
                    {
                        job.Speed = parts[2].Trim();
                    }

                    if (parts.Length > 3 &&
                        !string.IsNullOrWhiteSpace(parts[3]) &&
                        !parts[3].Contains("NA"))
                    {
                        job.Eta = parts[3].Trim();
                    }

                    string detail = "";

                    if (parts.Length > 4 &&
                        !string.IsNullOrWhiteSpace(parts[4]) &&
                        !parts[4].Contains("NA"))
                    {
                        detail = parts[4].Trim();
                    }

                    if (parts.Length > 5 &&
                        !string.IsNullOrWhiteSpace(parts[5]) &&
                        !parts[5].Contains("NA"))
                    {
                        detail += " / " + parts[5].Trim();
                    }

                    if (parts.Length > 7 &&
                        !string.IsNullOrWhiteSpace(parts[6]) &&
                        !string.IsNullOrWhiteSpace(parts[7]) &&
                        !parts[6].Contains("NA") &&
                        !parts[7].Contains("NA"))
                    {
                        detail += "  del " + parts[6].Trim() +
                                  "/" + parts[7].Trim();
                    }

                    if (!string.IsNullOrWhiteSpace(detail))
                    {
                        SafeUi(delegate
                        {
                            job.Row.Cells[1].ToolTipText = detail;
                        });
                    }

                    UpdateJobRow(job);
                    return;
                }

                if (line.StartsWith("FILE|", StringComparison.Ordinal))
                {
                    downloadedFile =
                        NormalizeUnicodeDisplayText(
                            line.Substring(5)
                        );
                    return;
                }

                Log(line, JobPrefix(job));
            };

            int exitCode = await RunProcessAsync(
                job,
                ytDlp,
                arguments,
                handleYtDlpLine,
                handleYtDlpLine,
                job.Cancellation.Token
            );

            if (exitCode != 0)
            {
                if (
                    youtubeSlovenianAutoTranslation &&
                    translatedSubtitleRateLimited
                )
                {
                    throw new InvalidOperationException(
                        "YouTube je začasno zavrnil samodejno prevedene podnapise (HTTP 429). V izbranem brskalniku odpri isti video, izberi Podnapisi → Samodejni prevod → Slovenščina, predvajaj nekaj sekund, nato brskalnik popolnoma zapri in ponovi prenos."
                    );
                }

                if (job.DirectMediaMode)
                {
                    string ffmpeg = ToolLocator.FindFfmpeg();

                    if (!string.IsNullOrWhiteSpace(ffmpeg))
                    {
                        Log(
                            "yt-dlp neposrednega toka ni prenesel. Poskušam še neposredno z FFmpeg.",
                            JobPrefix(job)
                        );

                        string directFile = await DownloadDirectMediaWithFfmpegAsync(
                            job,
                            ffmpeg,
                            workFolder
                        );

                        if (!string.IsNullOrWhiteSpace(directFile) &&
                            File.Exists(directFile))
                        {
                            return directFile;
                        }
                    }
                }

                throw new InvalidOperationException(
                    "yt-dlp je prenos končal z napako " + exitCode +
                    ". Dodajanje domene na seznam samo po sebi ne ustvari podpore. Potreben je izvlečevalni vtičnik ali neposredni medijski URL."
                );
            }

            if (
                string.IsNullOrWhiteSpace(downloadedFile) ||
                !File.Exists(downloadedFile)
            )
            {
                string discovered = FindLargestMediaFile(workFolder);
                if (!string.IsNullOrWhiteSpace(discovered))
                {
                    downloadedFile = discovered;
                }
            }

            // Rezervni način je čim bolj podoben delujoči različici 5.2:
            // brez --print, z običajnim napredkom yt-dlp.
            if (
                string.IsNullOrWhiteSpace(downloadedFile) ||
                !File.Exists(downloadedFile)
            )
            {
                Log(
                    "Prvi način ni ustvaril datoteke. Samodejno ponavljam v združljivostnem načinu 5.2.",
                    JobPrefix(job)
                );

                List<string> fallback = new List<string>();
                fallback.Add("--ignore-config");
                fallback.Add("--plugin-dirs");
                fallback.Add(AppPaths.PluginFolder);
                fallback.Add("--no-simulate");
                fallback.Add("--progress");
                fallback.Add("--newline");
                fallback.Add("--no-playlist");
                fallback.Add("--windows-filenames");
                fallback.Add("--trim-filenames");
                fallback.Add("170");
                fallback.Add("--retries");
                fallback.Add("10");
                fallback.Add("--fragment-retries");
                fallback.Add("10");
                fallback.Add("--concurrent-fragments");
                fallback.Add(job.ConcurrentFragments.ToString());

                if (job.UseEdgeCookies)
                {
                    fallback.Add("--cookies-from-browser");
                    fallback.Add(string.IsNullOrWhiteSpace(job.CookieBrowser) ? "firefox" : job.CookieBrowser);
                }

                if (job.DirectMediaMode)
                {
                    fallback.Add("--force-generic-extractor");

                    if (!string.IsNullOrWhiteSpace(job.Referer))
                    {
                        fallback.Add("--referer");
                        fallback.Add(job.Referer);

                        if (
                            job.Referer.IndexOf(
                                "voyo.si",
                                StringComparison.OrdinalIgnoreCase
                            ) >= 0
                        )
                        {
                            fallback.Add("--add-headers");
                            fallback.Add(
                                "Origin:https://voyo.si"
                            );
                        }
                    }
                }

                if (Regex.IsMatch(
                    job.Url ?? "",
                    @"https?://(?:www\.)?(?:365\.)?rtvslo\.si/",
                    RegexOptions.IgnoreCase
                ))
                {
                    fallback.Add("--geo-bypass-country");
                    fallback.Add("SI");
                }

                if (job.SubtitleModeIndex > 0)
                {
                    fallback.Add("--write-subs");

                    if (
                        job.IncludeAutoSubtitles ||
                        youtubeSlovenianAutoTranslation
                    )
                    {
                        fallback.Add("--write-auto-subs");
                    }

                    if (youtubeSlovenianAutoTranslation)
                    {
                        fallback.Add("--sleep-subtitles");
                        fallback.Add("1");
                        fallback.Add("--sleep-requests");
                        fallback.Add("0.5");
                    }

                    fallback.Add("--sub-langs");
                    fallback.Add(
                        string.IsNullOrWhiteSpace(job.SubtitleLanguages)
                            ? "sl.*,slv,slo,slovenian,si,en.*"
                            : job.SubtitleLanguages
                    );
                    fallback.Add("--sub-format");
                    fallback.Add("srt/best");
                    fallback.Add("--convert-subs");
                    fallback.Add("srt");
                }

                fallback.Add("-f");
                fallback.Add(
                    GetYtDlpFormat(
                        job.QualityIndex,
                        job.OutputIndex
                    )
                );

                if (job.OutputIndex < 7)
                {
                    fallback.Add("--merge-output-format");
                    fallback.Add("mp4");
                }

                fallback.Add("-o");
                fallback.Add(
                    Path.Combine(
                        workFolder,
                        "%(uploader,channel,creator,unknown)s - %(title).120s [%(id)s].%(ext)s"
                    )
                );
                fallback.Add(job.Url);

                int fallbackExit = await RunProcessAsync(
                    job,
                    ytDlp,
                    fallback,
                    delegate(string line)
                    {
                        ParseNormalYtDlpProgress(job, line);
                    },
                    delegate(string line)
                    {
                        ParseNormalYtDlpProgress(job, line);
                    },
                    job.Cancellation.Token
                );

                if (fallbackExit != 0)
                {
                    throw new InvalidOperationException(
                        "Tudi združljivostni način 5.2 ni uspel. Koda yt-dlp: " +
                        fallbackExit
                    );
                }

                downloadedFile = FindLargestMediaFile(workFolder);
            }

            return downloadedFile;
        }

        private void ParseNormalYtDlpProgress(
            DownloadJob job,
            string line
        )
        {
            if (string.IsNullOrWhiteSpace(line))
            {
                return;
            }

            Match progressMatch = Regex.Match(
                line,
                @"\[download\]\s+(?<percent>\d+(?:\.\d+)?)%\s+of.*?(?:at\s+(?<speed>\S+))?(?:\s+ETA\s+(?<eta>\S+))?",
                RegexOptions.IgnoreCase
            );

            if (progressMatch.Success)
            {
                job.Progress =
                    progressMatch.Groups["percent"].Value + " %";

                if (progressMatch.Groups["speed"].Success)
                {
                    job.Speed =
                        progressMatch.Groups["speed"].Value;
                }

                if (progressMatch.Groups["eta"].Success)
                {
                    job.Eta =
                        progressMatch.Groups["eta"].Value;
                }

                UpdateJobRow(job);
                return;
            }

            Match fragmentMatch = Regex.Match(
                line,
                @"\[download\]\s+Downloading\s+fragment\s+(?<current>\d+)\s+of\s+(?<total>\d+)",
                RegexOptions.IgnoreCase
            );

            if (fragmentMatch.Success)
            {
                int current;
                int total;

                if (
                    int.TryParse(
                        fragmentMatch.Groups["current"].Value,
                        out current
                    ) &&
                    int.TryParse(
                        fragmentMatch.Groups["total"].Value,
                        out total
                    ) &&
                    total > 0
                )
                {
                    job.Progress =
                        ((double)current / total * 100.0)
                        .ToString("0.0") + " %";
                    job.Eta =
                        "del " + current + "/" + total;
                    UpdateJobRow(job);
                }

                return;
            }

            if (
                line.IndexOf(
                    "Downloading webpage",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0 ||
                line.IndexOf(
                    "Downloading m3u8",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0 ||
                line.IndexOf(
                    "Downloading manifest",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0
            )
            {
                job.Progress = "priprava";
                UpdateJobRow(job);
            }

            Log(line, JobPrefix(job));
        }

        private async Task<string> DownloadDirectMediaWithFfmpegAsync(
            DownloadJob job,
            string ffmpeg,
            string workFolder
        )
        {
            string outputFile = Path.Combine(
                workFolder,
                "Neposredni_tok_" + job.Id.ToString("N") + ".mkv"
            );

            List<string> arguments = new List<string>();
            arguments.Add("-y");
            arguments.Add("-hide_banner");
            arguments.Add("-loglevel");
            arguments.Add("warning");
            arguments.Add("-progress");
            arguments.Add("pipe:1");
            arguments.Add("-nostats");

            StringBuilder requestHeaders =
                new StringBuilder();

            requestHeaders.Append(
                "User-Agent: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/142 Safari/537.36\r\n"
            );

            if (!string.IsNullOrWhiteSpace(job.Referer))
            {
                requestHeaders.Append(
                    "Referer: " +
                    job.Referer +
                    "\r\n"
                );

                if (
                    job.Referer.IndexOf(
                        "voyo.si",
                        StringComparison.OrdinalIgnoreCase
                    ) >= 0
                )
                {
                    requestHeaders.Append(
                        "Origin: https://voyo.si\r\n"
                    );
                }
            }

            arguments.Add("-headers");
            arguments.Add(
                requestHeaders.ToString()
            );

            arguments.Add("-i");
            arguments.Add(job.Url);
            arguments.Add("-map");
            arguments.Add("0:v:0?");
            arguments.Add("-map");
            arguments.Add("0:a:0?");
            arguments.Add("-c");
            arguments.Add("copy");
            arguments.Add(outputFile);

            int exitCode = await RunProcessAsync(
                job,
                ffmpeg,
                arguments,
                delegate(string line)
                {
                    if (line.StartsWith("out_time=", StringComparison.Ordinal) ||
                        line.StartsWith("out_time_ms=", StringComparison.Ordinal) ||
                        line.StartsWith("out_time_us=", StringComparison.Ordinal))
                    {
                        job.Progress = "aktivno";
                        UpdateJobRow(job);
                        return;
                    }

                    if (line == "progress=end")
                    {
                        job.Progress = "100 %";
                        UpdateJobRow(job);
                        return;
                    }

                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(line, JobPrefix(job) + " FFMPEG");
                    }
                },
                delegate(string line)
                {
                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(line, JobPrefix(job) + " FFMPEG");
                    }
                },
                job.Cancellation.Token
            );

            if (exitCode == 0 && File.Exists(outputFile))
            {
                return outputFile;
            }

            return "";
        }

        private async Task<List<string>> TryRecoverHlsSubtitlesAsync(
            DownloadJob job,
            string ytDlp,
            string ffmpeg,
            string workFolder
        )
        {
            List<string> results = new List<string>();

            if (string.IsNullOrWhiteSpace(ytDlp) ||
                string.IsNullOrWhiteSpace(ffmpeg))
            {
                Log(
                    "HLS rezervni način potrebuje yt-dlp in FFmpeg.",
                    JobPrefix(job)
                );
                return results;
            }

            StringBuilder jsonOutput = new StringBuilder();

            List<string> infoArguments = new List<string>();
            infoArguments.Add("--ignore-config");
            infoArguments.Add("--plugin-dirs");
            infoArguments.Add(AppPaths.PluginFolder);
            infoArguments.Add("--dump-single-json");
            infoArguments.Add("--skip-download");
            infoArguments.Add("--no-playlist");
            infoArguments.Add("--no-warnings");

            if (job.UseEdgeCookies)
            {
                infoArguments.Add("--cookies-from-browser");
                infoArguments.Add(string.IsNullOrWhiteSpace(job.CookieBrowser) ? "firefox" : job.CookieBrowser);
            }

            if (Regex.IsMatch(
                job.Url ?? "",
                @"https?://(?:www\.)?(?:365\.)?rtvslo\.si/",
                RegexOptions.IgnoreCase
            ))
            {
                infoArguments.Add("--geo-bypass-country");
                infoArguments.Add("SI");
            }

            infoArguments.Add(job.Url);

            int metadataExit = await RunProcessAsync(
                job,
                ytDlp,
                infoArguments,
                delegate(string line)
                {
                    jsonOutput.AppendLine(line);
                },
                delegate(string line)
                {
                    if (!string.IsNullOrWhiteSpace(line))
                    {
                        Log(
                            line,
                            JobPrefix(job) + " HLS-PREGLED"
                        );
                    }
                },
                job.Cancellation.Token
            );

            if (metadataExit != 0 ||
                jsonOutput.Length == 0)
            {
                Log(
                    "Podatkov o HLS manifestu ni bilo mogoče pridobiti.",
                    JobPrefix(job)
                );
                return results;
            }

            List<string> manifestUrls = new List<string>();

            try
            {
                JavaScriptSerializer serializer =
                    new JavaScriptSerializer();
                serializer.MaxJsonLength = int.MaxValue;

                object metadata = serializer.DeserializeObject(
                    jsonOutput.ToString()
                );

                CollectManifestUrls(
                    metadata,
                    manifestUrls
                );
            }
            catch (Exception exception)
            {
                ErrorLogger.Write(
                    "Razčlenjevanje yt-dlp JSON za HLS podnapise",
                    exception
                );
                Log(
                    "Metapodatkov HLS ni bilo mogoče razčleniti: " +
                    exception.Message,
                    JobPrefix(job)
                );
                return results;
            }

            manifestUrls = manifestUrls
                .Where(
                    delegate(string value)
                    {
                        return !string.IsNullOrWhiteSpace(value);
                    }
                )
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .Take(30)
                .ToList();

            if (manifestUrls.Count == 0)
            {
                Log(
                    "yt-dlp ni vrnil nobenega HLS manifesta.",
                    JobPrefix(job)
                );
                return results;
            }

            foreach (string manifestUrl in manifestUrls)
            {
                job.Cancellation.Token.ThrowIfCancellationRequested();

                string manifestText;

                try
                {
                    manifestText = await DownloadTextAsync(
                        manifestUrl,
                        GetEffectiveReferer(job),
                        job.Cancellation.Token
                    );
                }
                catch
                {
                    continue;
                }

                if (string.IsNullOrWhiteSpace(manifestText) ||
                    manifestText.IndexOf(
                        "#EXT-X-MEDIA",
                        StringComparison.OrdinalIgnoreCase
                    ) < 0 ||
                    manifestText.IndexOf(
                        "TYPE=SUBTITLES",
                        StringComparison.OrdinalIgnoreCase
                    ) < 0)
                {
                    continue;
                }

                List<HlsSubtitleTrack> allTracks =
                    ParseHlsSubtitleTracks(
                        manifestText,
                        manifestUrl
                    );

                foreach (HlsSubtitleTrack availableTrack in allTracks)
                {
                    Log(
                        "Najdena HLS podnapisna steza: LANGUAGE='" +
                        availableTrack.Language +
                        "', NAME='" +
                        availableTrack.Name +
                        "', DEFAULT='" +
                        availableTrack.DefaultValue +
                        "', AUTOSELECT='" +
                        availableTrack.AutoSelectValue +
                        "', FORCED='" +
                        availableTrack.ForcedValue +
                        "'.",
                        JobPrefix(job)
                    );
                }

                List<HlsSubtitleTrack> tracks = FilterSubtitleTracks(
                    allTracks,
                    job.SubtitleLanguages
                );

                if (tracks.Count == 0)
                {
                    List<HlsSubtitleTrack> unlabeledDefaults = allTracks
                        .Where(
                            delegate(HlsSubtitleTrack track)
                            {
                                bool hasNoUsefulLabel =
                                    string.IsNullOrWhiteSpace(track.Language) &&
                                    string.IsNullOrWhiteSpace(track.Name);
                                bool isDefault =
                                    string.Equals(
                                        track.DefaultValue,
                                        "YES",
                                        StringComparison.OrdinalIgnoreCase
                                    ) ||
                                    string.Equals(
                                        track.AutoSelectValue,
                                        "YES",
                                        StringComparison.OrdinalIgnoreCase
                                    );

                                return hasNoUsefulLabel &&
                                    (isDefault || allTracks.Count == 1);
                            }
                        )
                        .ToList();

                    if (unlabeledDefaults.Count > 0)
                    {
                        tracks = unlabeledDefaults;
                        Log(
                            "Jezikovna oznaka manjka; uporabljam edino oziroma privzeto HLS podnapisno stezo.",
                            JobPrefix(job)
                        );
                    }
                }

                if (tracks.Count == 0)
                {
                    string available = string.Join(
                        "; ",
                        allTracks.Select(
                            delegate(HlsSubtitleTrack track)
                            {
                                return "LANGUAGE='" + track.Language +
                                    "', NAME='" + track.Name + "'";
                            }
                        ).ToArray()
                    );

                    Log(
                        "HLS manifest vsebuje podnapise, vendar nobena steza ne ustreza izbranim jezikom: " +
                        (
                            string.IsNullOrWhiteSpace(job.SubtitleLanguages)
                                ? "sl.*,slv,slo,slovenian,si,en.*"
                                : job.SubtitleLanguages
                        ) +
                        ". Razpoložljivo: " + available,
                        JobPrefix(job)
                    );
                    continue;
                }

                int trackNumber = 0;

                foreach (HlsSubtitleTrack track in tracks)
                {
                    job.Cancellation.Token.ThrowIfCancellationRequested();
                    trackNumber++;

                    string language =
                        NormalizeLanguageCode(
                            string.IsNullOrWhiteSpace(track.Language)
                                ? track.Name
                                : track.Language
                        );

                    if (string.IsNullOrWhiteSpace(language))
                    {
                        language = "und";
                    }

                    string outputFile = Path.Combine(
                        workFolder,
                        "HLS-podnapisi." +
                        language +
                        "." +
                        trackNumber.ToString() +
                        ".srt"
                    );

                    bool success =
                        await DownloadHlsSubtitleTrackAsync(
                            job,
                            ffmpeg,
                            track.Url,
                            outputFile
                        );

                    if (success &&
                        File.Exists(outputFile) &&
                        new FileInfo(outputFile).Length > 0)
                    {
                        results.Add(outputFile);
                        Log(
                            "Prenesena HLS podnapisna steza: " +
                            language +
                            (
                                string.IsNullOrWhiteSpace(track.Name)
                                    ? ""
                                    : " – " + track.Name
                            ),
                            JobPrefix(job)
                        );
                    }
                }

                if (results.Count > 0)
                {
                    break;
                }
            }

            if (results.Count == 0)
            {
                Log(
                    "Podnapisi so v predvajalniku vidni, vendar jih trenutni HLS rezervni način ni mogel izvoziti.",
                    JobPrefix(job)
                );
            }

            return results;
        }

        private sealed class HlsSubtitleTrack
        {
            public string Language { get; set; }
            public string Name { get; set; }
            public string Url { get; set; }
            public string DefaultValue { get; set; }
            public string AutoSelectValue { get; set; }
            public string ForcedValue { get; set; }
            public string Characteristics { get; set; }

            public HlsSubtitleTrack()
            {
                Language = "";
                Name = "";
                Url = "";
                DefaultValue = "";
                AutoSelectValue = "";
                ForcedValue = "";
                Characteristics = "";
            }
        }

        private void CollectManifestUrls(
            object node,
            List<string> results
        )
        {
            if (node == null)
            {
                return;
            }

            string stringValue = node as string;

            if (stringValue != null)
            {
                if (
                    stringValue.IndexOf(
                        ".m3u8",
                        StringComparison.OrdinalIgnoreCase
                    ) >= 0
                )
                {
                    results.Add(stringValue);
                }

                return;
            }

            IDictionary<string, object> dictionary =
                node as IDictionary<string, object>;

            if (dictionary != null)
            {
                foreach (
                    KeyValuePair<string, object> item
                    in dictionary
                )
                {
                    if (
                        (
                            string.Equals(
                                item.Key,
                                "manifest_url",
                                StringComparison.OrdinalIgnoreCase
                            ) ||
                            string.Equals(
                                item.Key,
                                "url",
                                StringComparison.OrdinalIgnoreCase
                            )
                        ) &&
                        item.Value is string
                    )
                    {
                        string candidate =
                            Convert.ToString(item.Value);

                        if (
                            candidate.IndexOf(
                                ".m3u8",
                                StringComparison.OrdinalIgnoreCase
                            ) >= 0
                        )
                        {
                            results.Add(candidate);
                        }
                    }

                    CollectManifestUrls(
                        item.Value,
                        results
                    );
                }

                return;
            }

            IDictionary nonGenericDictionary =
                node as IDictionary;

            if (nonGenericDictionary != null)
            {
                foreach (
                    DictionaryEntry entry
                    in nonGenericDictionary
                )
                {
                    CollectManifestUrls(
                        entry.Value,
                        results
                    );
                }

                return;
            }

            IEnumerable enumerable =
                node as IEnumerable;

            if (enumerable != null)
            {
                foreach (object value in enumerable)
                {
                    CollectManifestUrls(
                        value,
                        results
                    );
                }
            }
        }

        private async Task<string> DownloadTextAsync(
            string url,
            string referer,
            CancellationToken cancellationToken
        )
        {
            return await Task.Run(
                delegate
                {
                    cancellationToken.ThrowIfCancellationRequested();

                    using (WebClient client = new WebClient())
                    {
                        client.Encoding = Encoding.UTF8;
                        client.Headers[
                            HttpRequestHeader.UserAgent
                        ] =
                            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) " +
                            "AppleWebKit/537.36 (KHTML, like Gecko) " +
                            "Chrome/142.0 Safari/537.36";

                        if (!string.IsNullOrWhiteSpace(referer))
                        {
                            client.Headers[
                                HttpRequestHeader.Referer
                            ] = referer;
                        }

                        return client.DownloadString(url);
                    }
                },
                cancellationToken
            );
        }

        private string GetEffectiveReferer(
            DownloadJob job
        )
        {
            if (!string.IsNullOrWhiteSpace(job.Referer))
            {
                return job.Referer;
            }

            return job.Url;
        }

        private List<HlsSubtitleTrack> ParseHlsSubtitleTracks(
            string manifestText,
            string manifestUrl
        )
        {
            List<HlsSubtitleTrack> tracks =
                new List<HlsSubtitleTrack>();

            string[] lines = manifestText.Split(
                new string[]
                {
                    "\r\n",
                    "\n"
                },
                StringSplitOptions.RemoveEmptyEntries
            );

            foreach (string rawLine in lines)
            {
                string line = rawLine.Trim();

                if (
                    !line.StartsWith(
                        "#EXT-X-MEDIA:",
                        StringComparison.OrdinalIgnoreCase
                    ) ||
                    line.IndexOf(
                        "TYPE=SUBTITLES",
                        StringComparison.OrdinalIgnoreCase
                    ) < 0
                )
                {
                    continue;
                }

                Dictionary<string, string> attributes =
                    ParseHlsAttributeList(
                        line.Substring(
                            line.IndexOf(':') + 1
                        )
                    );

                string uri;

                if (
                    !attributes.TryGetValue(
                        "URI",
                        out uri
                    ) ||
                    string.IsNullOrWhiteSpace(uri)
                )
                {
                    continue;
                }

                string absoluteUrl;

                try
                {
                    absoluteUrl = ResolveHlsUri(
                        manifestUrl,
                        uri
                    );
                }
                catch
                {
                    continue;
                }

                string language = "";
                string name = "";
                string defaultValue = "";
                string autoSelectValue = "";
                string forcedValue = "";
                string characteristics = "";

                attributes.TryGetValue(
                    "LANGUAGE",
                    out language
                );
                attributes.TryGetValue(
                    "NAME",
                    out name
                );
                attributes.TryGetValue(
                    "DEFAULT",
                    out defaultValue
                );
                attributes.TryGetValue(
                    "AUTOSELECT",
                    out autoSelectValue
                );
                attributes.TryGetValue(
                    "FORCED",
                    out forcedValue
                );
                attributes.TryGetValue(
                    "CHARACTERISTICS",
                    out characteristics
                );

                tracks.Add(
                    new HlsSubtitleTrack
                    {
                        Language = language ?? "",
                        Name = name ?? "",
                        Url = absoluteUrl,
                        DefaultValue = defaultValue ?? "",
                        AutoSelectValue = autoSelectValue ?? "",
                        ForcedValue = forcedValue ?? "",
                        Characteristics = characteristics ?? ""
                    }
                );
            }

            return tracks;
        }

        private string ResolveHlsUri(
            string baseManifestUrl,
            string relativeOrAbsoluteUrl
        )
        {
            Uri baseUri = new Uri(baseManifestUrl);
            Uri resolved = new Uri(baseUri, relativeOrAbsoluteUrl);

            if (
                string.IsNullOrWhiteSpace(resolved.Query) &&
                !string.IsNullOrWhiteSpace(baseUri.Query) &&
                !Uri.IsWellFormedUriString(
                    relativeOrAbsoluteUrl,
                    UriKind.Absolute
                )
            )
            {
                UriBuilder builder = new UriBuilder(resolved);
                builder.Query = baseUri.Query.TrimStart('?');
                return builder.Uri.AbsoluteUri;
            }

            return resolved.AbsoluteUri;
        }

        private Dictionary<string, string> ParseHlsAttributeList(
            string text
        )
        {
            Dictionary<string, string> result =
                new Dictionary<string, string>(
                    StringComparer.OrdinalIgnoreCase
                );

            MatchCollection matches = Regex.Matches(
                text,
                @"(?<key>[A-Z0-9-]+)=(?<value>""[^""]*""|[^,]*)",
                RegexOptions.IgnoreCase
            );

            foreach (Match match in matches)
            {
                string key =
                    match.Groups["key"].Value.Trim();
                string value =
                    match.Groups["value"].Value.Trim();

                if (
                    value.Length >= 2 &&
                    value.StartsWith("\"") &&
                    value.EndsWith("\"")
                )
                {
                    value = value.Substring(
                        1,
                        value.Length - 2
                    );
                }

                result[key] = value;
            }

            return result;
        }

        private List<HlsSubtitleTrack> FilterSubtitleTracks(
            List<HlsSubtitleTrack> tracks,
            string requestedLanguages
        )
        {
            if (tracks == null)
            {
                return new List<HlsSubtitleTrack>();
            }

            string requested =
                string.IsNullOrWhiteSpace(requestedLanguages)
                    ? "sl.*,slv,slo,slovenian,si,en.*"
                    : requestedLanguages;

            string[] rawPatterns = requested.Split(
                new char[] { ',', ';' },
                StringSplitOptions.RemoveEmptyEntries
            );

            List<string> includePatterns = rawPatterns
                .Select(delegate(string pattern) { return pattern.Trim(); })
                .Where(delegate(string pattern)
                {
                    return pattern.Length > 0 && !pattern.StartsWith("-");
                })
                .ToList();

            List<string> excludePatterns = rawPatterns
                .Select(delegate(string pattern) { return pattern.Trim(); })
                .Where(delegate(string pattern)
                {
                    return pattern.StartsWith("-") && pattern.Length > 1;
                })
                .Select(delegate(string pattern) { return pattern.Substring(1); })
                .ToList();

            bool includeAll = includePatterns.Any(delegate(string pattern)
            {
                return string.Equals(
                    pattern,
                    "all",
                    StringComparison.OrdinalIgnoreCase
                );
            });

            return tracks.Where(delegate(HlsSubtitleTrack track)
            {
                bool included = includeAll || includePatterns.Any(
                    delegate(string pattern)
                    {
                        return SubtitleTrackMatchesPattern(track, pattern);
                    }
                );

                if (!included)
                {
                    return false;
                }

                bool excluded = excludePatterns.Any(
                    delegate(string pattern)
                    {
                        return SubtitleTrackMatchesPattern(track, pattern);
                    }
                );

                return !excluded;
            }).ToList();
        }

        private bool SubtitleTrackMatchesPattern(
            HlsSubtitleTrack track,
            string requestedPattern
        )
        {
            if (track == null || string.IsNullOrWhiteSpace(requestedPattern))
            {
                return false;
            }

            string pattern = requestedPattern.Trim();

            if (string.Equals(pattern, "all", StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            string rawLanguage = (track.Language ?? "").Trim().ToLowerInvariant();
            string rawName = (track.Name ?? "").Trim().ToLowerInvariant();
            string normalizedLanguage = NormalizeLanguageCode(track.Language);
            string normalizedName = NormalizeLanguageCode(track.Name);
            string baseLanguage = GetBaseLanguageCode(normalizedLanguage);
            string baseName = GetBaseLanguageCode(normalizedName);

            string[] candidates = new string[]
            {
                rawLanguage,
                rawName,
                normalizedLanguage,
                normalizedName,
                baseLanguage,
                baseName
            };

            string canonicalPattern = NormalizeLanguageAlias(pattern);

            if (!string.IsNullOrWhiteSpace(canonicalPattern))
            {
                if (candidates.Any(delegate(string candidate)
                {
                    return string.Equals(
                        candidate,
                        canonicalPattern,
                        StringComparison.OrdinalIgnoreCase
                    ) || string.Equals(
                        GetBaseLanguageCode(candidate),
                        canonicalPattern,
                        StringComparison.OrdinalIgnoreCase
                    );
                }))
                {
                    return true;
                }
            }

            try
            {
                Regex regex = new Regex(
                    "^(?:" + pattern + ")$",
                    RegexOptions.IgnoreCase | RegexOptions.CultureInvariant
                );

                return candidates.Any(delegate(string candidate)
                {
                    return !string.IsNullOrWhiteSpace(candidate) &&
                        regex.IsMatch(candidate);
                });
            }
            catch (ArgumentException)
            {
                return candidates.Any(delegate(string candidate)
                {
                    return string.Equals(
                        candidate,
                        pattern,
                        StringComparison.OrdinalIgnoreCase
                    );
                });
            }
        }

        private string NormalizeLanguageAlias(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return "";
            }

            string normalized = value
                .Trim()
                .Trim('"')
                .ToLowerInvariant()
                .Replace('_', '-');

            if (normalized.IndexOfAny(new char[]
                {
                    '.', '*', '+', '?', '[', ']', '(', ')',
                    '{', '}', '|', '^', '$', '\\'
                }) >= 0)
            {
                return "";
            }

            if (normalized == "eng" || normalized == "english")
            {
                return "en";
            }

            if (normalized == "slv" || normalized == "slo" ||
                normalized == "si" || normalized == "sl-si" ||
                normalized == "slovenian" || normalized == "slovene" ||
                normalized == "slovenski")
            {
                return "sl";
            }

            return normalized;
        }

        private string GetBaseLanguageCode(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return "";
            }

            string normalized = value
                .Trim()
                .ToLowerInvariant()
                .Replace('_', '-');
            int separator = normalized.IndexOf('-');

            return separator > 0
                ? normalized.Substring(0, separator)
                : normalized;
        }

        private string NormalizeLanguageCode(string value)
        {
            if (string.IsNullOrWhiteSpace(value))
            {
                return "";
            }

            string normalized = value.Trim()
                .Trim('"')
                .ToLowerInvariant()
                .Replace('_', '-');

            if (normalized == "eng" || normalized.StartsWith("english"))
            {
                return "en";
            }

            if (normalized == "slv" || normalized == "slo" ||
                normalized == "si" || normalized == "sl-si" ||
                normalized.StartsWith("sloven"))
            {
                return "sl";
            }

            return normalized.Length >= 2 ? normalized : "";
        }

        private async Task<bool> DownloadHlsSubtitleTrackAsync(
            DownloadJob job,
            string ffmpeg,
            string subtitleUrl,
            string outputFile
        )
        {
            List<string> arguments = new List<string>();
            arguments.Add("-y");
            arguments.Add("-hide_banner");
            arguments.Add("-loglevel");
            arguments.Add("warning");

            string referer = GetEffectiveReferer(job);

            arguments.Add("-user_agent");
            arguments.Add(
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) " +
                "AppleWebKit/537.36 (KHTML, like Gecko) " +
                "Chrome/142.0 Safari/537.36"
            );

            if (!string.IsNullOrWhiteSpace(referer))
            {
                arguments.Add("-referer");
                arguments.Add(referer);
            }

            arguments.Add("-i");
            arguments.Add(subtitleUrl);
            arguments.Add("-map");
            arguments.Add("0:s:0?");
            arguments.Add("-c:s");
            arguments.Add(
                job.StyledEmbeddedSubtitles
                    ? "ass"
                    : "srt"
            );
            arguments.Add("-f");
            arguments.Add("srt");
            arguments.Add(outputFile);

            int exitCode = await RunProcessAsync(
                job,
                ffmpeg,
                arguments,
                delegate(string line)
                {
                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(
                            line,
                            JobPrefix(job) + " HLS-SUB"
                        );
                    }
                },
                delegate(string line)
                {
                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(
                            line,
                            JobPrefix(job) + " HLS-SUB"
                        );
                    }
                },
                job.Cancellation.Token
            );

            return
                exitCode == 0 &&
                File.Exists(outputFile) &&
                new FileInfo(outputFile).Length > 0;
        }

        private List<string> FindSubtitleFiles(string workFolder)
        {
            string[] supportedExtensions = new string[]
            {
                ".srt",
                ".vtt",
                ".ass",
                ".ssa"
            };

            try
            {
                return new DirectoryInfo(workFolder)
                    .GetFiles("*", SearchOption.AllDirectories)
                    .Where(
                        delegate(FileInfo file)
                        {
                            return supportedExtensions.Contains(
                                file.Extension,
                                StringComparer.OrdinalIgnoreCase
                            );
                        }
                    )
                    .OrderBy(
                        delegate(FileInfo file)
                        {
                            return file.FullName;
                        }
                    )
                    .Select(
                        delegate(FileInfo file)
                        {
                            return file.FullName;
                        }
                    )
                    .ToList();
            }
            catch
            {
                return new List<string>();
            }
        }

        private async Task<string> CreateStyledAssSubtitleAsync(
            DownloadJob job,
            string subtitleFile,
            string workFolder,
            string ffmpeg,
            int subtitleIndex
        )
        {
            string assFile = Path.Combine(
                workFolder,
                "Stilizirani_podnapisi_" +
                subtitleIndex.ToString() +
                ".ass"
            );

            string normalizedSrt =
                await EnsureSrtSubtitleAsync(
                    job,
                    subtitleFile,
                    workFolder,
                    ffmpeg,
                    subtitleIndex
                );

            List<string> conversionArguments =
                new List<string>();
            conversionArguments.Add("-y");
            conversionArguments.Add("-hide_banner");
            conversionArguments.Add("-loglevel");
            conversionArguments.Add("warning");
            conversionArguments.Add("-i");
            conversionArguments.Add(normalizedSrt);
            conversionArguments.Add("-c:s");
            conversionArguments.Add("ass");
            conversionArguments.Add(assFile);

            int conversionExit = await RunProcessAsync(
                job,
                ffmpeg,
                conversionArguments,
                delegate(string line)
                {
                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(
                            line,
                            JobPrefix(job) + " ASS"
                        );
                    }
                },
                delegate(string line)
                {
                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(
                            line,
                            JobPrefix(job) + " ASS"
                        );
                    }
                },
                job.Cancellation.Token
            );

            if (conversionExit != 0 ||
                !File.Exists(assFile))
            {
                throw new InvalidOperationException(
                    "Pretvorba podnapisov v ASS ni uspela. Koda FFmpeg: " +
                    conversionExit
                );
            }

            ApplyTransparentAssBackground(
                assFile,
                job.SubtitleBackgroundOpacity
            );

            return assFile;
        }

        private string AddAssGapBetweenSubtitleLines(
            string dialogueLine
        )
        {
            if (string.IsNullOrWhiteSpace(dialogueLine))
            {
                return dialogueLine;
            }

            // V vrstici Dialogue je pred besedilom devet vejic.
            // Besedilo je lahko večvrstično z oznako \N ali \n.
            int commaCount = 0;
            int textStart = -1;

            for (
                int index = 0;
                index < dialogueLine.Length;
                index++
            )
            {
                if (dialogueLine[index] == ',')
                {
                    commaCount++;

                    if (commaCount == 9)
                    {
                        textStart = index + 1;
                        break;
                    }
                }
            }

            if (textStart < 0 ||
                textStart >= dialogueLine.Length)
            {
                return dialogueLine;
            }

            string prefix =
                dialogueLine.Substring(0, textStart);

            string subtitleText =
                dialogueLine.Substring(textStart);

            // Med vrsticama vstavi prazno vrstico višine 8 ASS enot.
            // Prazna vrstica nima črnega polja, zato se prosojni ozadji
            // zgornje in spodnje vrstice ne seštevata v temnejšo črto.
            string spacer =
                "\\N{\\fs8}\\N{\\rDefault}";

            subtitleText = subtitleText
                .Replace("\\N", spacer)
                .Replace("\\n", spacer);

            return prefix + subtitleText;
        }

        private void ApplyTransparentAssBackground(
            string assFile,
            int opacityPercent
        )
        {
            ApplyTransparentAssBackground(
                assFile,
                opacityPercent,
                52,
                120,
                Color.White,
                74
            );
        }

        private void ApplyTransparentAssBackground(
            string assFile,
            int opacityPercent,
            int fontSize,
            int marginV,
            Color textColor,
            int safeWidthPercent
        )
        {
            int opacity = Math.Max(
                0,
                Math.Min(95, opacityPercent)
            );
            fontSize = Math.Max(
                28,
                Math.Min(80, fontSize)
            );
            marginV = Math.Max(
                20,
                Math.Min(300, marginV)
            );

            int alpha = 255 - Convert.ToInt32(
                Math.Round(
                    opacity / 100.0 * 255.0
                )
            );

            string alphaHex =
                alpha.ToString("X2");
            string edgeColour =
                "&H" + alphaHex + "000000";
            string primaryColour =
                "&H00" +
                textColor.B.ToString("X2") +
                textColor.G.ToString("X2") +
                textColor.R.ToString("X2");

            List<string> lines =
                File.ReadAllLines(
                    assFile,
                    Encoding.UTF8
                ).ToList();

            int scriptInfoIndex =
                lines.FindIndex(
                    delegate(string line)
                    {
                        return string.Equals(
                            line.Trim(),
                            "[Script Info]",
                            StringComparison.OrdinalIgnoreCase
                        );
                    }
                );

            if (scriptInfoIndex < 0)
            {
                lines.Insert(0, "[Script Info]");
                scriptInfoIndex = 0;
            }

            int scriptInfoEnd =
                lines.FindIndex(
                    scriptInfoIndex + 1,
                    delegate(string line)
                    {
                        string trimmed =
                            line.Trim();

                        return
                            trimmed.StartsWith("[") &&
                            !string.Equals(
                                trimmed,
                                "[Script Info]",
                                StringComparison.OrdinalIgnoreCase
                            );
                    }
                );

            if (scriptInfoEnd < 0)
            {
                scriptInfoEnd = lines.Count;
            }

            bool hasPlayResX = false;
            bool hasPlayResY = false;
            bool hasScaledBorder = false;
            bool hasWrapStyle = false;

            for (
                int index = scriptInfoIndex + 1;
                index < scriptInfoEnd;
                index++
            )
            {
                string trimmed =
                    lines[index].Trim();

                if (
                    trimmed.StartsWith(
                        "PlayResX:",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    lines[index] =
                        "PlayResX: 1920";
                    hasPlayResX = true;
                }
                else if (
                    trimmed.StartsWith(
                        "PlayResY:",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    lines[index] =
                        "PlayResY: 1080";
                    hasPlayResY = true;
                }
                else if (
                    trimmed.StartsWith(
                        "ScaledBorderAndShadow:",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    lines[index] =
                        "ScaledBorderAndShadow: yes";
                    hasScaledBorder = true;
                }
                else if (
                    trimmed.StartsWith(
                        "WrapStyle:",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    lines[index] =
                        "WrapStyle: 0";
                    hasWrapStyle = true;
                }
            }

            int insertPosition =
                scriptInfoIndex + 1;

            if (!hasPlayResX)
            {
                lines.Insert(
                    insertPosition,
                    "PlayResX: 1920"
                );
                insertPosition++;
                scriptInfoEnd++;
            }

            if (!hasPlayResY)
            {
                lines.Insert(
                    insertPosition,
                    "PlayResY: 1080"
                );
                insertPosition++;
                scriptInfoEnd++;
            }

            if (!hasScaledBorder)
            {
                lines.Insert(
                    insertPosition,
                    "ScaledBorderAndShadow: yes"
                );
                insertPosition++;
            }

            if (!hasWrapStyle)
            {
                lines.Insert(
                    insertPosition,
                    "WrapStyle: 0"
                );
            }

            safeWidthPercent = Math.Max(55, Math.Min(92, safeWidthPercent));
            int horizontalMargin = Convert.ToInt32(
                Math.Round(1920.0 * (100.0 - safeWidthPercent) / 200.0)
            );

            string styleLine =
                "Style: Default,Arial," +
                fontSize + "," +
                primaryColour + "," +
                primaryColour + "," +
                edgeColour + "," +
                edgeColour + "," +
                "0,0,0,0," +
                "100,100,0,0," +
                "1,2,1,2," +
                horizontalMargin + "," + horizontalMargin + "," +
                marginV +
                ",1";

            bool styleFound = false;

            for (
                int index = 0;
                index < lines.Count;
                index++
            )
            {
                string line = lines[index];
                string trimmed = line.Trim();

                if (
                    trimmed.StartsWith(
                        "Style:",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    string stylePart =
                        trimmed.Substring(6).Trim();
                    int firstComma =
                        stylePart.IndexOf(',');
                    string styleName =
                        firstComma > 0
                            ? stylePart.Substring(
                                0,
                                firstComma
                            ).Trim()
                            : "Default";

                    lines[index] =
                        styleLine.Replace(
                            "Style: Default,",
                            "Style: " +
                            styleName +
                            ","
                        );
                    styleFound = true;
                    continue;
                }

                if (
                    trimmed.StartsWith(
                        "Dialogue:",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    Match dialogueMatch =
                        Regex.Match(
                            line,
                            @"^(Dialogue:\s*[^,]*,[^,]*,[^,]*,)[^,]*,(.*)$",
                            RegexOptions.IgnoreCase
                        );

                    if (dialogueMatch.Success)
                    {
                        lines[index] =
                            dialogueMatch.Groups[1].Value +
                            "Default," +
                            dialogueMatch.Groups[2].Value;

                        // Naravni kino/TV slog ohrani običajen razmik med vrsticami.
                    }
                }
            }

            if (!styleFound)
            {
                int styleSection =
                    lines.FindIndex(
                        delegate(string line)
                        {
                            return string.Equals(
                                line.Trim(),
                                "[V4+ Styles]",
                                StringComparison.OrdinalIgnoreCase
                            );
                        }
                    );

                if (styleSection >= 0)
                {
                    int insertIndex =
                        Math.Min(
                            styleSection + 2,
                            lines.Count
                        );
                    lines.Insert(
                        insertIndex,
                        styleLine
                    );
                }
            }

            File.WriteAllLines(
                assFile,
                lines.ToArray(),
                new UTF8Encoding(true)
            );
        }

        private async Task<string> EnsureSrtSubtitleAsync(
            DownloadJob job,
            string subtitleFile,
            string workFolder,
            string ffmpeg,
            int subtitleIndex
        )
        {
            string rawSrt = Path.Combine(
                workFolder,
                "Podnapisi_raw_" +
                subtitleIndex.ToString() +
                "_" +
                Guid.NewGuid().ToString("N") +
                ".srt"
            );

            string outputFile = Path.Combine(
                workFolder,
                "Podnapisi_42x2_" +
                subtitleIndex.ToString() +
                "_" +
                Guid.NewGuid().ToString("N") +
                ".srt"
            );

            if (
                string.Equals(
                    Path.GetExtension(subtitleFile),
                    ".srt",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                File.Copy(
                    subtitleFile,
                    rawSrt,
                    true
                );
            }
            else
            {
                List<string> arguments = new List<string>();
                arguments.Add("-y");
                arguments.Add("-hide_banner");
                arguments.Add("-loglevel");
                arguments.Add("warning");
                arguments.Add("-i");
                arguments.Add(subtitleFile);
                arguments.Add("-c:s");
                arguments.Add("srt");
                arguments.Add(rawSrt);

                int exitCode = await RunProcessAsync(
                    job,
                    ffmpeg,
                    arguments,
                    delegate(string line)
                    {
                        if (!IsFfmpegTechnicalLine(line))
                        {
                            Log(
                                line,
                                JobPrefix(job) + " SRT"
                            );
                        }
                    },
                    delegate(string line)
                    {
                        if (!IsFfmpegTechnicalLine(line))
                        {
                            Log(
                                line,
                                JobPrefix(job) + " SRT"
                            );
                        }
                    },
                    job.Cancellation.Token
                );

                if (
                    exitCode != 0 ||
                    !File.Exists(rawSrt)
                )
                {
                    throw new InvalidOperationException(
                        "Pretvorba podnapisov v SRT ni uspela. Koda FFmpeg: " +
                        exitCode
                    );
                }
            }

            NormalizeSrtFileToFortyTwoCharacters(
                rawSrt,
                outputFile
            );

            return outputFile;
        }

        private async Task<string> EmbedSelectableSubtitlesInMkvAsync(
            DownloadJob job,
            string videoFile,
            List<string> subtitleFiles,
            string workFolder,
            string ffmpeg,
            string ffprobe
        )
        {
            List<string> srtFiles = new List<string>();

            for (
                int index = 0;
                index < subtitleFiles.Count;
                index++
            )
            {
                srtFiles.Add(
                    await EnsureSrtSubtitleAsync(
                        job,
                        subtitleFiles[index],
                        workFolder,
                        ffmpeg,
                        index + 1
                    )
                );
            }

            double duration = await ReadDurationAsync(
                job,
                ffprobe,
                videoFile,
                job.Cancellation.Token
            );

            string outputFile = Path.Combine(
                workFolder,
                SanitizeFileName(
                    Path.GetFileNameWithoutExtension(videoFile)
                ) +
                " - izbirni podnapisi.mkv"
            );

            List<string> arguments = new List<string>();
            arguments.Add("-y");
            arguments.Add("-hide_banner");
            arguments.Add("-loglevel");
            arguments.Add("warning");
            arguments.Add("-fflags");
            arguments.Add("+genpts");
            arguments.Add("-i");
            arguments.Add(videoFile);

            foreach (string subtitleFile in srtFiles)
            {
                arguments.Add("-i");
                arguments.Add(subtitleFile);
            }

            arguments.Add("-map");
            arguments.Add("0:v:0");
            arguments.Add("-map");
            arguments.Add("0:a:0?");

            for (
                int index = 0;
                index < srtFiles.Count;
                index++
            )
            {
                arguments.Add("-map");
                arguments.Add(
                    (index + 1).ToString() + ":0"
                );
            }

            arguments.Add("-c:v");
            arguments.Add("copy");
            arguments.Add("-c:a");
            arguments.Add("copy");
            arguments.Add("-c:s");
            arguments.Add("srt");

            arguments.Add("-avoid_negative_ts");
            arguments.Add("make_zero");
            arguments.Add("-max_interleave_delta");
            arguments.Add("0");
            arguments.Add("-cluster_time_limit");
            arguments.Add("1000");
            arguments.Add("-cues_to_front");
            arguments.Add("1");
            arguments.Add("-reserve_index_space");
            arguments.Add("1048576");

            for (
                int index = 0;
                index < subtitleFiles.Count;
                index++
            )
            {
                string language = GuessSubtitleLanguage(
                    subtitleFiles[index]
                );

                if (string.IsNullOrWhiteSpace(language))
                {
                    language = "und";
                }

                arguments.Add(
                    "-metadata:s:s:" + index.ToString()
                );
                arguments.Add("language=" + language);

                arguments.Add(
                    "-metadata:s:s:" + index.ToString()
                );

                string subtitleTitle =
                    language == "sl"
                        ? "Slovenski"
                        : (
                            language == "en"
                                ? "English"
                                : language
                        );

                arguments.Add(
                    "title=" + subtitleTitle
                );

                arguments.Add(
                    "-disposition:s:" + index.ToString()
                );
                arguments.Add(
                    index == 0
                        ? "default"
                        : "0"
                );
            }

            arguments.Add("-progress");
            arguments.Add("pipe:1");
            arguments.Add("-nostats");
            arguments.Add(outputFile);

            string lastSpeed = "";

            int exitCode = await RunProcessAsync(
                job,
                ffmpeg,
                arguments,
                delegate(string line)
                {
                    if (line.StartsWith(
                        "speed=",
                        StringComparison.Ordinal
                    ))
                    {
                        lastSpeed = line.Substring(6);
                        return;
                    }

                    if (
                        line.StartsWith(
                            "out_time_us=",
                            StringComparison.Ordinal
                        ) ||
                        line.StartsWith(
                            "out_time_ms=",
                            StringComparison.Ordinal
                        )
                    )
                    {
                        int equals = line.IndexOf('=');
                        long value;

                        if (
                            equals >= 0 &&
                            long.TryParse(
                                line.Substring(equals + 1),
                                out value
                            ) &&
                            duration > 0
                        )
                        {
                            double seconds =
                                value / 1000000.0;

                            double percent = Math.Max(
                                0.0,
                                Math.Min(
                                    99.9,
                                    seconds / duration * 100.0
                                )
                            );

                            job.Progress =
                                percent.ToString("0.0") + " %";
                            job.Speed = lastSpeed;
                            UpdateJobRow(job);
                        }

                        return;
                    }

                    if (line == "progress=end")
                    {
                        job.Progress = "100 %";
                        UpdateJobRow(job);
                        return;
                    }

                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(
                            line,
                            JobPrefix(job) + " MKV-SRT"
                        );
                    }
                },
                delegate(string line)
                {
                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(
                            line,
                            JobPrefix(job) + " MKV-SRT"
                        );
                    }
                },
                job.Cancellation.Token
            );

            if (exitCode != 0 ||
                !File.Exists(outputFile))
            {
                throw new InvalidOperationException(
                    "Vgradnja izbirnih SRT podnapisov v MKV ni uspela. Koda FFmpeg: " +
                    exitCode
                );
            }

            Log(
                "Podnapisi so vgrajeni kot združljive izbirne SRT steze. MKV indeks je zapisan na začetek datoteke za boljše preskakovanje.",
                JobPrefix(job)
            );

            return outputFile;
        }

        private string EscapeSubtitleFilterPath(
            string filePath
        )
        {
            return filePath
                .Replace("\\", "/")
                .Replace(":", "\\:")
                .Replace("'", "\\'");
        }

        private string SelectSubtitleForBurnIn(
            List<string> subtitleFiles
        )
        {
            if (subtitleFiles == null ||
                subtitleFiles.Count == 0)
            {
                return "";
            }

            string slovenian = subtitleFiles.FirstOrDefault(
                delegate(string file)
                {
                    return GuessSubtitleLanguage(file) == "sl";
                }
            );

            if (!string.IsNullOrWhiteSpace(slovenian))
            {
                return slovenian;
            }

            string english = subtitleFiles.FirstOrDefault(
                delegate(string file)
                {
                    return GuessSubtitleLanguage(file) == "en";
                }
            );

            if (!string.IsNullOrWhiteSpace(english))
            {
                return english;
            }

            return subtitleFiles[0];
        }

