        private string GuessSubtitleLanguage(string subtitleFile)
        {
            string fileName = Path.GetFileNameWithoutExtension(subtitleFile);
            string[] parts = fileName.Split(new char[] { '.' });

            for (int index = parts.Length - 1; index >= 0; index--)
            {
                string candidate = NormalizeLanguageCode(parts[index]);
                string baseCode = GetBaseLanguageCode(candidate);

                if (baseCode.Length >= 2 && baseCode.Length <= 3 &&
                    Regex.IsMatch(baseCode, "^[a-z]{2,3}$", RegexOptions.IgnoreCase))
                {
                    return baseCode;
                }
            }

            return "";
        }

        private async Task PublishSubtitleFilesAsync(
            DownloadJob job,
            List<string> subtitleFiles,
            string completedVideo
        )
        {
            string videoBase = Path.GetFileNameWithoutExtension(
                completedVideo
            );
            string ffmpeg = ToolLocator.FindFfmpeg();
            int subtitleIndex = 0;

            foreach (string subtitleFile in subtitleFiles)
            {
                subtitleIndex++;

                if (!File.Exists(subtitleFile))
                {
                    continue;
                }

                string sourceToPublish = subtitleFile;

                if (!string.IsNullOrWhiteSpace(ffmpeg))
                {
                    sourceToPublish =
                        await EnsureSrtSubtitleAsync(
                            job,
                            subtitleFile,
                            Path.GetDirectoryName(subtitleFile),
                            ffmpeg,
                            5000 + subtitleIndex
                        );
                }

                string language = GuessSubtitleLanguage(subtitleFile);
                string extension = Path.GetExtension(sourceToPublish);

                string preferredName =
                    videoBase +
                    (
                        string.IsNullOrWhiteSpace(language)
                            ? ""
                            : "." + language
                    ) +
                    extension;

                string published = await PublishFinalFileAsync(
                    sourceToPublish,
                    job.OutputFolder,
                    preferredName,
                    false,
                    job.Cancellation.Token
                );

                if (IsOneDrivePath(published))
                {
                    await EnsureOneDriveFileAvailableLocallyAsync(
                        published,
                        job.Cancellation.Token
                    );
                }

                Log(
                    "Podnapisi 42 × 2: " + published,
                    JobPrefix(job)
                );
            }
        }

        private string GetYtDlpFormat(int qualityIndex, int outputIndex)
        {
            bool audioOnly = outputIndex >= 7;

            if (audioOnly)
            {
                return "ba/b";
            }

            switch (qualityIndex)
            {
                case 1:
                    return "bv*[height<=1080]+ba/b[height<=1080]";
                case 2:
                    return "bv*[height<=720]+ba/b[height<=720]";
                case 3:
                    return "bv*[height<=480]+ba/b[height<=480]";
                default:
                    return "bv*+ba/b";
            }
        }

        private async Task<string> ConvertFileAsync(
            DownloadJob job,
            string inputFile,
            string workFolder,
            string ffmpeg,
            string ffprobe
        )
        {
            double duration = await ReadDurationAsync(
                job,
                ffprobe,
                inputFile,
                job.Cancellation.Token
            );

            string extension = GetOutputExtension(job.OutputIndex);
            string baseName = SanitizeFileName(
                Path.GetFileNameWithoutExtension(inputFile)
            );
            string outputFile = Path.Combine(
                workFolder,
                baseName + " - " + GetOutputSuffix(job.OutputIndex) + extension
            );

            List<string> arguments = new List<string>();
            arguments.Add("-y");
            arguments.Add("-hide_banner");
            arguments.Add("-loglevel");
            arguments.Add("warning");
            arguments.Add("-progress");
            arguments.Add("pipe:1");
            arguments.Add("-nostats");
            arguments.Add("-i");
            arguments.Add(inputFile);

            bool audioOutput = job.OutputIndex >= 7;

            if (audioOutput)
            {
                arguments.Add("-vn");

                if (job.OutputIndex == 7)
                {
                    arguments.Add("-c:a");
                    arguments.Add("libmp3lame");
                    arguments.Add("-q:a");
                    arguments.Add("0");
                }
                else if (job.OutputIndex == 8)
                {
                    arguments.Add("-c:a");
                    arguments.Add("flac");
                }
                else
                {
                    arguments.Add("-c:a");
                    arguments.Add("pcm_s16le");
                }
            }
            else
            {
                arguments.Add("-map");
                arguments.Add("0:v:0");
                arguments.Add("-map");
                arguments.Add("0:a:0?");
                arguments.Add("-sn");

                string scale = GetScaleFilter(job.QualityIndex);
                if (!string.IsNullOrWhiteSpace(scale))
                {
                    arguments.Add("-vf");
                    arguments.Add(scale);
                }

                switch (job.OutputIndex)
                {
                    case 1:
                        AddH264Aac(arguments);
                        arguments.Add("-movflags");
                        arguments.Add("+faststart");
                        break;

                    case 2:
                        arguments.Add("-c:v");
                        arguments.Add("libx265");
                        arguments.Add("-preset");
                        arguments.Add("medium");
                        arguments.Add("-crf");
                        arguments.Add("24");
                        arguments.Add("-pix_fmt");
                        arguments.Add("yuv420p");
                        arguments.Add("-tag:v");
                        arguments.Add("hvc1");
                        arguments.Add("-c:a");
                        arguments.Add("aac");
                        arguments.Add("-b:a");
                        arguments.Add("160k");
                        arguments.Add("-movflags");
                        arguments.Add("+faststart");
                        break;

                    case 3:
                        AddH264Aac(arguments);
                        break;

                    case 4:
                        arguments.Add("-c:v");
                        arguments.Add("libvpx-vp9");
                        arguments.Add("-crf");
                        arguments.Add("24");
                        arguments.Add("-b:v");
                        arguments.Add("0");
                        arguments.Add("-row-mt");
                        arguments.Add("1");
                        arguments.Add("-c:a");
                        arguments.Add("libopus");
                        arguments.Add("-b:a");
                        arguments.Add("128k");
                        break;

                    case 5:
                        AddH264Aac(arguments);
                        arguments.Add("-movflags");
                        arguments.Add("+faststart");
                        break;

                    case 6:
                        arguments.Add("-c:v");
                        arguments.Add("mpeg4");
                        arguments.Add("-q:v");
                        arguments.Add("4");
                        arguments.Add("-c:a");
                        arguments.Add("libmp3lame");
                        arguments.Add("-b:a");
                        arguments.Add("320k");
                        break;

                    default:
                        AddH264Aac(arguments);
                        arguments.Add("-movflags");
                        arguments.Add("+faststart");
                        break;
                }
            }

            arguments.Add(outputFile);

            string lastSpeed = "";

            int exitCode = await RunProcessAsync(
                job,
                ffmpeg,
                arguments,
                delegate(string line)
                {
                    if (line.StartsWith("speed=", StringComparison.Ordinal))
                    {
                        lastSpeed = line.Substring(6);
                        return;
                    }

                    if (line.StartsWith("out_time_us=", StringComparison.Ordinal) ||
                        line.StartsWith("out_time_ms=", StringComparison.Ordinal))
                    {
                        int equals = line.IndexOf('=');
                        long value;
                        if (equals >= 0 && long.TryParse(line.Substring(equals + 1), out value) && duration > 0)
                        {
                            double seconds = value / 1000000.0;
                            double percent = Math.Max(
                                0.0,
                                Math.Min(99.9, seconds / duration * 100.0)
                            );

                            job.Progress = percent.ToString("0.0") + " %";
                            job.Speed = lastSpeed;
                            job.Eta = "";
                            UpdateJobRow(job);
                        }
                        return;
                    }

                    if (line == "progress=end")
                    {
                        job.Progress = "100 %";
                        UpdateJobRow(job);
                        return;
                    }

                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(line, JobPrefix(job));
                    }
                },
                delegate(string line)
                {
                    if (!IsFfmpegTechnicalLine(line))
                    {
                        Log(line, JobPrefix(job) + " FFMPEG");
                    }
                },
                job.Cancellation.Token
            );

            if (exitCode != 0 || !File.Exists(outputFile))
            {
                throw new InvalidOperationException(
                    "FFmpeg pretvorba ni uspela. Koda: " + exitCode +
                    ". Preveri, ali nameščeni FFmpeg vsebuje zahtevani kodek."
                );
            }

            return outputFile;
        }

        private void AddH264Aac(List<string> arguments)
        {
            arguments.Add("-c:v");
