            arguments.Add("-preset");
            arguments.Add("medium");
            arguments.Add("-crf");
            arguments.Add("16");
            arguments.Add("-pix_fmt");
            arguments.Add("yuv420p");
            arguments.Add("-profile:v");
            arguments.Add("high");
            arguments.Add("-c:a");
            arguments.Add("aac");
            arguments.Add("-b:a");
            arguments.Add("160k");
            arguments.Add("-ar");
            arguments.Add("48000");
            arguments.Add("-ac");
            arguments.Add("2");
        }

        private string GetScaleFilter(int qualityIndex)
        {
            int maximum;

            switch (qualityIndex)
            {
                case 1:
                    maximum = 1920;
                    break;
                case 2:
                    maximum = 1280;
                    break;
                case 3:
                    maximum = 854;
                    break;
                default:
                    return "";
            }

            return
                "scale='min(" + maximum + ",iw)':'min(" + maximum +
                ",ih)':force_original_aspect_ratio=decrease:force_divisible_by=2";
        }

        private string GetOutputExtension(int outputIndex)
        {
            switch (outputIndex)
            {
                case 1:
                case 2:
                    return ".mp4";
                case 3:
                    return ".mkv";
                case 4:
                    return ".webm";
                case 5:
                    return ".mov";
                case 6:
                    return ".avi";
                case 7:
                    return ".mp3";
                case 8:
                    return ".flac";
                case 9:
                    return ".wav";
                default:
                    return ".mp4";
            }
        }

        private string GetOutputSuffix(int outputIndex)
        {
            switch (outputIndex)
            {
                case 1:
                    return "MP4-H264-AAC";
                case 2:
                    return "MP4-H265-AAC";
                case 3:
                    return "MKV-H264-AAC";
                case 4:
                    return "WebM-VP9-Opus";
                case 5:
                    return "MOV-H264-AAC";
                case 6:
                    return "AVI-MPEG4-MP3";
                case 7:
                    return "MP3";
                case 8:
                    return "FLAC";
                case 9:
                    return "WAV";
                default:
                    return "pretvorjeno";
            }
        }

        private bool IsFfmpegTechnicalLine(string line)
        {
            if (string.IsNullOrWhiteSpace(line))
            {
                return true;
            }

            string[] prefixes = new string[]
            {
                "frame=",
                "fps=",
                "stream_",
                "bitrate=",
                "total_size=",
                "out_time=",
                "out_time_ms=",
                "out_time_us=",
                "dup_frames=",
                "drop_frames=",
                "speed=",
                "progress=continue"
            };

            if (
                line.IndexOf(
                    "level limit",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0 ||
                line.IndexOf(
                    "frame MB size",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0 ||
                line.IndexOf(
                    "DPB size",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0 ||
                line.IndexOf(
                    "MB rate",
                    StringComparison.OrdinalIgnoreCase
                ) >= 0
            )
            {
                return true;
            }

            return prefixes.Any(
                delegate(string prefix)
                {
                    return line.StartsWith(prefix, StringComparison.Ordinal);
                }
            );
        }

        private async Task<double> ReadDurationAsync(
            DownloadJob job,
            string ffprobe,
            string input,
            CancellationToken cancellationToken
        )
        {
            StringBuilder output = new StringBuilder();

            List<string> arguments = new List<string>();
            arguments.Add("-v");
            arguments.Add("error");
            arguments.Add("-show_entries");
            arguments.Add("format=duration");
            arguments.Add("-of");
            arguments.Add("default=noprint_wrappers=1:nokey=1");
            arguments.Add(input);

            int exitCode = await RunProcessAsync(
                job,
                ffprobe,
                arguments,
                delegate(string line)
                {
                    output.AppendLine(line);
                },
                delegate(string line)
                {
                },
                cancellationToken
            );

            if (exitCode != 0)
            {
                return 0.0;
            }

            double duration;
            if (double.TryParse(
                output.ToString().Trim(),
                System.Globalization.NumberStyles.Float,
                System.Globalization.CultureInfo.InvariantCulture,
                out duration
            ))
            {
                return duration;
            }

            return 0.0;
        }

        private Task<int> RunProcessAsync(
            DownloadJob job,
            string executable,
            IEnumerable<string> arguments,
            Action<string> outputHandler,
            Action<string> errorHandler,
            CancellationToken cancellationToken
        )
        {
            TaskCompletionSource<int> completion =
                new TaskCompletionSource<int>();

            ProcessStartInfo info = new ProcessStartInfo();
            info.FileName = executable;
            info.Arguments = ToolLocator.JoinArguments(arguments);
            info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
            info.CreateNoWindow = true;
            info.WindowStyle = ProcessWindowStyle.Hidden;
            info.RedirectStandardOutput = true;
            info.RedirectStandardError = true;
            info.StandardOutputEncoding = Encoding.UTF8;
            info.StandardErrorEncoding = Encoding.UTF8;
            info.WorkingDirectory = AppDomain.CurrentDomain.BaseDirectory;

            Process process = new Process();
            process.StartInfo = info;
            process.EnableRaisingEvents = true;

            int processExited = 0;
            int outputClosed = 0;
            int errorClosed = 0;
            int exitCode = -1;

            Action tryComplete = delegate
            {
                if (
                    Interlocked.CompareExchange(ref processExited, 0, 0) == 1 &&
                    Interlocked.CompareExchange(ref outputClosed, 0, 0) == 1 &&
                    Interlocked.CompareExchange(ref errorClosed, 0, 0) == 1
                )
                {
                    completion.TrySetResult(exitCode);
                }
            };

            DataReceivedEventHandler outputEvent =
                delegate(object sender, DataReceivedEventArgs eventArgs)
            {
                if (eventArgs.Data == null)
                {
                    Interlocked.Exchange(ref outputClosed, 1);
                    tryComplete();
                    return;
                }

                try
                {
                    outputHandler(eventArgs.Data);
                }
                catch (Exception handlerError)
                {
                    ErrorLogger.Write(
                        "Obdelava standardnega izhoda procesa",
                        handlerError
                    );
                }
            };

            DataReceivedEventHandler errorEvent =
                delegate(object sender, DataReceivedEventArgs eventArgs)
            {
                if (eventArgs.Data == null)
                {
                    Interlocked.Exchange(ref errorClosed, 1);
                    tryComplete();
                    return;
                }

                try
                {
                    errorHandler(eventArgs.Data);
                }
                catch (Exception handlerError)
                {
                    ErrorLogger.Write(
                        "Obdelava standardnega izhoda za napake",
                        handlerError
                    );
                }
            };

            process.OutputDataReceived += outputEvent;
            process.ErrorDataReceived += errorEvent;

            process.Exited += delegate
            {
                try
                {
                    exitCode = process.ExitCode;
                    Interlocked.Exchange(ref processExited, 1);
                    tryComplete();
                }
                catch (Exception exception)
                {
                    completion.TrySetException(exception);
                }
            };

            try
            {
                if (!process.Start())
                {
                    throw new InvalidOperationException(
                        "Procesa ni bilo mogoče zagnati: " + executable
                    );
                }

                job.CurrentProcess = process;
                process.BeginOutputReadLine();
                process.BeginErrorReadLine();

                // Proces je lahko končan še preden je priključen dogodek Exited.
                if (process.HasExited)
                {
                    exitCode = process.ExitCode;
                    Interlocked.Exchange(ref processExited, 1);
                    tryComplete();
                }
            }
            catch (Exception exception)
            {
                completion.TrySetException(exception);
            }

            CancellationTokenRegistration registration =
                cancellationToken.Register(
                    delegate
                    {
                        try
                        {
                            if (!process.HasExited)
                            {
                                KillProcessTree(process.Id);
                            }
                        }
                        catch
                        {
                        }

                        completion.TrySetCanceled();
                    }
                );

            return completion.Task.ContinueWith(
                delegate(Task<int> task)
                {
                    registration.Dispose();

                    try
                    {
                        process.OutputDataReceived -= outputEvent;
                        process.ErrorDataReceived -= errorEvent;
                        process.Dispose();
                    }
                    catch
                    {
                    }

                    if (task.IsCanceled)
                    {
                        throw new OperationCanceledException(
                            cancellationToken
                        );
                    }

                    if (task.IsFaulted)
                    {
                        throw task.Exception.InnerException;
                    }

                    return task.Result;
                },
                CancellationToken.None,
                TaskContinuationOptions.ExecuteSynchronously,
                TaskScheduler.Default
            );
        }

        private void KillProcessTree(int processId)
        {
            try
            {
                ProcessStartInfo info = new ProcessStartInfo();
                info.FileName = "taskkill.exe";
                info.Arguments = "/PID " + processId + " /T /F";
                info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
                info.CreateNoWindow = true;
                info.WindowStyle = ProcessWindowStyle.Hidden;

                using (Process killer = Process.Start(info))
                {
                    killer.WaitForExit(5000);
                }
            }
            catch
            {
            }
        }

        private bool IsOneDrivePath(
            string filePath
        )
        {
            if (string.IsNullOrWhiteSpace(filePath))
            {
                return false;
            }

            string fullPath;

            try
            {
                fullPath = Path.GetFullPath(filePath);
            }
            catch
            {
                fullPath = filePath;
            }

            string[] environmentNames =
                new string[]
                {
                    "OneDrive",
                    "OneDriveConsumer",
                    "OneDriveCommercial"
                };

            foreach (
                string environmentName
                in environmentNames
            )
            {
                string oneDriveRoot =
                    Environment.GetEnvironmentVariable(
                        environmentName
                    );

                if (
                    !string.IsNullOrWhiteSpace(
                        oneDriveRoot
                    ) &&
                    fullPath.StartsWith(
                        Path.GetFullPath(
                            oneDriveRoot
                        ).TrimEnd(
                            Path.DirectorySeparatorChar
                        ) +
                        Path.DirectorySeparatorChar,
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    return true;
                }
            }

            return
                fullPath.IndexOf(
                    Path.DirectorySeparatorChar +
                    "OneDrive" +
                    Path.DirectorySeparatorChar,
                    StringComparison.OrdinalIgnoreCase
                ) >= 0;
        }

        private async Task<bool> EnsureOneDriveFileAvailableLocallyAsync(
            string filePath,
            CancellationToken cancellationToken
        )
        {
            if (!IsOneDrivePath(filePath))
            {
                return false;
            }

            return await Task.Run(
                delegate
                {
                    cancellationToken.ThrowIfCancellationRequested();

                    try
                    {
                        ProcessStartInfo info =
                            new ProcessStartInfo();

                        info.FileName = "attrib.exe";
                        info.Arguments =
                            "+P -U " +
                            ToolLocator.Quote(filePath);
                        info.UseShellExecute = false;
                        ToolLocator.ConfigureUtf8Process(info);
                        info.CreateNoWindow = true;
                        info.WindowStyle =
                            ProcessWindowStyle.Hidden;
                        info.RedirectStandardOutput = true;
                        info.RedirectStandardError = true;

                        using (
                            Process process =
                                Process.Start(info)
                        )
                        {
                            process.WaitForExit(15000);
                        }
                    }
                    catch (Exception attributeError)
                    {
                        ErrorLogger.Write(
                            "OneDrive – nastavitev vedno lokalne datoteke",
                            attributeError
                        );
                    }

                    long previousLength = -1;
                    int stableChecks = 0;

                    for (
                        int attempt = 0;
                        attempt < 60;
                        attempt++
                    )
                    {
                        cancellationToken.ThrowIfCancellationRequested();

                        try
                        {
                            if (File.Exists(filePath))
                            {
                                long length =
                                    new FileInfo(filePath).Length;

                                using (
                                    FileStream stream =
                                        new FileStream(
                                            filePath,
                                            FileMode.Open,
                                            FileAccess.Read,
                                            FileShare.ReadWrite |
                                            FileShare.Delete
                                        )
                                )
                                {
                                    if (stream.Length > 0)
                                    {
                                        stream.Position = 0;
                                        stream.ReadByte();

                                        if (stream.Length > 1)
                                        {
                                            stream.Position =
                                                stream.Length - 1;
                                            stream.ReadByte();
                                        }
                                    }
                                }

                                if (
                                    length > 0 &&
                                    length == previousLength
                                )
                                {
                                    stableChecks++;
                                }
                                else
                                {
                                    stableChecks = 0;
                                }

                                previousLength = length;

                                if (stableChecks >= 3)
                                {
                                    return true;
                                }
                            }
                        }
                        catch
                        {
                            stableChecks = 0;
                        }

                        Thread.Sleep(500);
                    }

                    return false;
                },
                cancellationToken
            );
        }

        private async Task<string> PublishFinalFileAsync(
            string sourceFile,
            string outputFolder,
            string preferredName,
            bool keepSource,
            CancellationToken cancellationToken
        )
        {
            return await Task.Run(
                delegate
                {
                    cancellationToken.ThrowIfCancellationRequested();

                    Directory.CreateDirectory(outputFolder);

                    string safeName = SanitizeFileName(
                        Path.GetFileNameWithoutExtension(preferredName)
                    ) + Path.GetExtension(preferredName);

                    string finalPath = GetUniquePath(
                        Path.Combine(outputFolder, safeName)
                    );

                    string stagingFolder = Path.Combine(
                        outputFolder,
                        ".VideoDownloader_Temp"
                    );
                    Directory.CreateDirectory(stagingFolder);
                    TryHideFolder(stagingFolder);

                    string stagingPath = Path.Combine(
                        stagingFolder,
                        Guid.NewGuid().ToString("N") +
                        Path.GetExtension(finalPath)
                    );

                    bool sameDrive = string.Equals(
                        Path.GetPathRoot(sourceFile),
                        Path.GetPathRoot(outputFolder),
                        StringComparison.OrdinalIgnoreCase
                    );

                    if (!keepSource && sameDrive)
                    {
                        File.Move(sourceFile, stagingPath);
                    }
                    else
                    {
                        CopyFileWithCancellation(
                            sourceFile,
                            stagingPath,
                            cancellationToken
                        );

                        if (!keepSource)
                        {
                            try
                            {
                                File.Delete(sourceFile);
                            }
                            catch
                            {
                            }
                        }
                    }

                    cancellationToken.ThrowIfCancellationRequested();
                    File.Move(stagingPath, finalPath);

                    try
                    {
                        if (!Directory.EnumerateFileSystemEntries(stagingFolder).Any())
                        {
                            Directory.Delete(stagingFolder);
                        }
                    }
                    catch
                    {
                    }

                    return finalPath;
                },
                cancellationToken
            );
        }

        private void CopyFileWithCancellation(
            string source,
            string destination,
            CancellationToken cancellationToken
        )
        {
            byte[] buffer = new byte[1024 * 1024];

            using (FileStream input = new FileStream(
                source,
                FileMode.Open,
                FileAccess.Read,
                FileShare.Read,
                buffer.Length,
                FileOptions.SequentialScan
            ))
            using (FileStream output = new FileStream(
                destination,
                FileMode.CreateNew,
                FileAccess.Write,
                FileShare.None,
                buffer.Length,
                FileOptions.SequentialScan
            ))
            {
                while (true)
                {
                    cancellationToken.ThrowIfCancellationRequested();
                    int read = input.Read(buffer, 0, buffer.Length);
                    if (read <= 0)
                    {
                        break;
                    }

                    output.Write(buffer, 0, read);
                }
            }
        }

        private string GetUniquePath(string requestedPath)
        {
            if (!File.Exists(requestedPath))
            {
                return requestedPath;
            }

            string folder = Path.GetDirectoryName(requestedPath);
            string name = Path.GetFileNameWithoutExtension(requestedPath);
            string extension = Path.GetExtension(requestedPath);

            for (int number = 2; number < 10000; number++)
            {
                string candidate = Path.Combine(
                    folder,
                    name + " (" + number + ")" + extension
                );

                if (!File.Exists(candidate))
                {
                    return candidate;
                }
            }

            return Path.Combine(
                folder,
                name + " - " + DateTime.Now.ToString("yyyyMMdd_HHmmss") + extension
            );
        }

        private string FindLargestMediaFile(string folder)
        {
            string[] ignored = new string[]
            {
                ".part",
                ".ytdl",
                ".json",
                ".txt",
                ".temp",
                ".tmp",
                ".description",
                ".vtt",
                ".srt"
            };

            FileInfo file = new DirectoryInfo(folder)
                .GetFiles("*", SearchOption.AllDirectories)
                .Where(
                    delegate(FileInfo item)
                    {
                        return !ignored.Contains(
                            item.Extension,
                            StringComparer.OrdinalIgnoreCase
                        );
                    }
                )
                .OrderByDescending(delegate(FileInfo item) { return item.Length; })
                .FirstOrDefault();

            return file == null ? "" : file.FullName;
        }

        private string SanitizeFileName(string name)
        {
            if (string.IsNullOrWhiteSpace(name))
            {
                name = "Video_" + DateTime.Now.ToString("yyyy-MM-dd_HH-mm-ss");
            }

            foreach (char invalid in Path.GetInvalidFileNameChars())
            {
                name = name.Replace(invalid, '_');
            }

            name = name.Trim().TrimEnd('.');
            if (name.Length > 145)
            {
                name = name.Substring(0, 145);
            }

            return name;
        }

        private void TryHideFolder(string folder)
        {
            try
            {
                File.SetAttributes(
                    folder,
                    File.GetAttributes(folder) | FileAttributes.Hidden
                );
            }
            catch
            {
            }
        }

        private string EnsureOutputFolder()
        {
            string folder = txtFolder.Text.Trim();

            if (string.IsNullOrWhiteSpace(folder))
            {
                folder = new AppSettings().OutputFolder;
                txtFolder.Text = folder;
            }

            Directory.CreateDirectory(folder);
            SaveCurrentSettings();
            return folder;
        }

        private string NormalizeInputUrl(string inputUrl)
        {
            if (string.IsNullOrWhiteSpace(inputUrl))
            {
                return inputUrl;
            }

            string trimmed = inputUrl.Trim();

            try
            {
                Uri uri = new Uri(trimmed);
                string host = uri.Host.ToLowerInvariant();
                string path = uri.AbsolutePath.TrimEnd('/');

                // RTV 365 stran »Kratki« je enostranska spletna aplikacija.
                // ID posnetka je v fragmentu, na primer:
                // https://365.rtvslo.si/kratki#175233956-0
                //
                // yt-dlp podpira arhivsko obliko /arhiv/<slug>/<id>, zato
                // fragment pretvorimo v:
                // https://365.rtvslo.si/arhiv/kratki/175233956
                if (
                    (host == "365.rtvslo.si" ||
                     host == "www.365.rtvslo.si") &&
                    string.Equals(
                        path,
                        "/kratki",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    Match fragmentMatch = Regex.Match(
                        uri.Fragment ?? "",
                        @"^#(?<id>\d+)(?:-\d+)?(?:$|[^\d].*)",
                        RegexOptions.IgnoreCase
                    );

                    if (fragmentMatch.Success)
                    {
                        string recordingId =
                            fragmentMatch.Groups["id"].Value;

                        return
                            "https://365.rtvslo.si/arhiv/kratki/" +
                            recordingId;
                    }
                }
            }
            catch
            {
                // Če URL ni veljaven za System.Uri, ga nespremenjenega
                // prepustimo yt-dlp, ki lahko podpira tudi posebne oblike.
            }

            return trimmed;
        }

        private string GetSiteName(string url)
        {
            try
            {
                Uri uri = new Uri(url);
                string host = uri.Host.ToLowerInvariant();

                if (host.StartsWith("www."))
                {
                    host = host.Substring(4);
                }

                if (host.StartsWith("m."))
                {
                    host = host.Substring(2);
                }

                if (
                    host == "youtube.com" ||
                    host == "youtu.be"
                )
                {
                    return "YouTube";
                }

                if (
                    host == "facebook.com" ||
                    host.EndsWith(
                        ".facebook.com",
                        StringComparison.OrdinalIgnoreCase
