                    host == "atkhairy.com" ||
                    host.EndsWith(
                        ".atkhairy.com",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    return "ATK Hairy";
                }

                return host;
            }
            catch
            {
                return "splet";
            }
        }

        private string StatusText(JobStatus status)
        {
            switch (status)
            {
                case JobStatus.Waiting:
                    return "Čaka";
                case JobStatus.Starting:
                    return "Zagon";
                case JobStatus.Downloading:
                    return "Prenašanje";
                case JobStatus.Converting:
                    return "Obdelava videa";
                case JobStatus.Finalizing:
                    return "Zaključevanje";
                case JobStatus.Completed:
                    return "Končano";
                case JobStatus.Failed:
                    return "Napaka";
                case JobStatus.Cancelled:
                    return "Preklicano";
                default:
                    return status.ToString();
            }
        }

        private string JobPrefix(DownloadJob job)
        {
            return job.Id.ToString("N").Substring(0, 6);
        }

        private void SetJobStatus(DownloadJob job, JobStatus status)
        {
            job.Status = status;
            UpdateJobRow(job);
        }

        private void UpdateJobRow(DownloadJob job)
        {
            SafeUi(
                delegate
                {
                    if (job.Row == null || job.Row.DataGridView == null)
                    {
                        return;
                    }

                    job.Row.Cells[0].Value = StatusText(job.Status);
                    job.Row.Cells[1].Value = job.Progress;
                    job.Row.Cells[2].Value = job.Speed;
                    job.Row.Cells[3].Value = job.Eta;
                    job.Row.Cells[7].Value = job.DisplayTitle;
                }
            );
        }

        private void SetRowColor(DownloadJob job, Color color)
        {
            SafeUi(
                delegate
                {
                    if (job.Row != null)
                    {
                        job.Row.DefaultCellStyle.BackColor = color;
                    }
                }
            );
        }

        private void SafeUi(Action action)
        {
            if (IsDisposed || Disposing)
            {
                return;
            }

            try
            {
                if (InvokeRequired)
                {
                    BeginInvoke(action);
                }
                else
                {
                    action();
                }
            }
            catch (ObjectDisposedException)
            {
            }
            catch (InvalidOperationException)
            {
            }
        }

        private void Log(string text, string prefix)
        {
            if (string.IsNullOrWhiteSpace(text))
            {
                return;
            }

            SafeUi(
                delegate
                {
                    string safeText =
                        SanitizeSensitiveText(
                            text
                        );

                    string line =
                        "[" + DateTime.Now.ToString("HH:mm:ss") + "]" +
                        (string.IsNullOrWhiteSpace(prefix) ? "" : "[" + prefix + "]") +
                        " " + safeText + Environment.NewLine;

                    string severity =
                        ((prefix ?? "") + " " + safeText)
                        .ToUpperInvariant();

                    bool error =
                        severity.IndexOf("NAPAKA") >= 0 ||
                        severity.IndexOf("ERROR") >= 0 ||
                        severity.IndexOf("FAILED") >= 0 ||
                        severity.IndexOf("NEUSPE") >= 0;

                    bool warning =
                        severity.IndexOf("WARNING") >= 0 ||
                        severity.IndexOf("OPOZOR") >= 0 ||
                        severity.IndexOf("POZOR") >= 0;

                    bool success =
                        severity.IndexOf("KONČANO") >= 0 ||
                        severity.IndexOf("KONCANO") >= 0 ||
                        severity.IndexOf("USPEŠNO") >= 0 ||
                        severity.IndexOf("SUCCESS") >= 0;

                    logBox.SelectionStart =
                        logBox.TextLength;
                    logBox.SelectionLength = 0;
                    logBox.SelectionColor =
                        error
                            ? Color.FromArgb(176, 0, 32)
                            : (
                                warning
                                    ? Color.FromArgb(0, 91, 165)
                                    : (
                                        success
                                            ? Color.Black
                                            : Color.FromArgb(55, 58, 64)
                                    )
                            );
                    logBox.SelectionFont =
                        error || warning || success
                            ? logBoldFont
                            : logBox.Font;
                    logBox.AppendText(line);
                    logBox.SelectionColor =
                        logBox.ForeColor;
                    logBox.SelectionFont =
                        logBox.Font;
                    logBox.SelectionStart =
                        logBox.TextLength;
                    logBox.ScrollToCaret();
                }
            );
        }


        private void RefreshQueueStatus()
        {
            SafeUi(
                delegate
                {
                    int waiting;
                    int active;
                    int completed;
                    int failed;

                    lock (queueLock)
                    {
                        waiting = allJobs.Count(
                            delegate(DownloadJob job)
                            {
                                return job.Status == JobStatus.Waiting;
                            }
                        );

                        active = allJobs.Count(
                            delegate(DownloadJob job)
                            {
                                return job.Status == JobStatus.Starting ||
                                       job.Status == JobStatus.Downloading ||
                                       job.Status == JobStatus.Converting ||
                                       job.Status == JobStatus.Finalizing;
                            }
                        );

                        completed = allJobs.Count(
                            delegate(DownloadJob job)
                            {
                                return job.Status == JobStatus.Completed;
                            }
                        );

                        failed = allJobs.Count(
                            delegate(DownloadJob job)
                            {
                                return job.Status == JobStatus.Failed ||
                                       job.Status == JobStatus.Cancelled;
                            }
                        );
                    }

                    lblQueueStatus.Text =
                        "Čaka: " + waiting +
                        "   Aktivni: " + active +
                        "   Končani: " + completed +
                        "   Napake: " + failed +
                        (queueRunning ? "   • VRSTA TEČE" : "");
                }
            );
        }

        private void CancelSelected()
        {
            foreach (DataGridViewRow row in grid.SelectedRows)
            {
                DownloadJob job = row.Tag as DownloadJob;
                if (job == null)
                {
                    continue;
                }

                if (job.Status == JobStatus.Waiting)
                {
                    job.Status = JobStatus.Cancelled;
                    job.Cancellation.Cancel();
                    UpdateJobRow(job);
                    SetRowColor(job, Color.LightGray);
                }
                else if (
                    job.Status == JobStatus.Starting ||
                    job.Status == JobStatus.Downloading ||
                    job.Status == JobStatus.Converting ||
                    job.Status == JobStatus.Finalizing
                )
                {
                    job.Cancellation.Cancel();
                    try
                    {
                        if (job.CurrentProcess != null && !job.CurrentProcess.HasExited)
                        {
                            KillProcessTree(job.CurrentProcess.Id);
                        }
                    }
                    catch
                    {
                    }
                }
            }

            RefreshQueueStatus();
        }

        private void RemoveFinished()
        {
            List<DownloadJob> remove;

            lock (queueLock)
            {
                remove = allJobs.Where(
                    delegate(DownloadJob job)
                    {
                        return job.Status == JobStatus.Completed ||
                               job.Status == JobStatus.Failed ||
                               job.Status == JobStatus.Cancelled;
                    }
                ).ToList();

                foreach (DownloadJob job in remove)
                {
                    allJobs.Remove(job);
                }
            }

            foreach (DownloadJob job in remove)
            {
                if (job.Row != null && job.Row.DataGridView != null)
                {
                    grid.Rows.Remove(job.Row);
                }
            }

            RefreshQueueStatus();
        }

