        private async Task UpdateToolsAsync()
        {
            if (updateRunning)
            {
                return;
            }

            updateRunning = true;
            btnUpdate.Enabled = false;

            try
            {
                string winget = ToolLocator.FindWinget();
                string ytDlp = ToolLocator.FindYtDlp();

                if (string.IsNullOrWhiteSpace(ytDlp) && string.IsNullOrWhiteSpace(winget))
                {
                    throw new InvalidOperationException(
                        "Niti yt-dlp niti winget nista bila najdena."
                    );
                }

                if (string.IsNullOrWhiteSpace(ytDlp))
                {
                    Log("Nameščam yt-dlp prek winget ...", "POSODOBITEV");
                    await RunSimpleToolAsync(
                        winget,
                        new string[]
                        {
                            "install",
                            "--id",
                            "yt-dlp.yt-dlp",
                            "-e",
                            "--silent",
                            "--disable-interactivity",
                            "--accept-source-agreements",
                            "--accept-package-agreements"
                        },
                        "POSODOBITEV"
                    );
                    ytDlp = ToolLocator.FindYtDlp();
                }

                if (!string.IsNullOrWhiteSpace(ytDlp))
                {
                    string channel = cmbUpdateChannel.SelectedIndex == 1
                        ? "nightly"
                        : "stable";

                    Log("Posodabljam yt-dlp na kanal " + channel + " ...", "POSODOBITEV");

                    int updateCode = await RunSimpleToolAsync(
                        ytDlp,
                        new string[]
                        {
                            "--update-to",
                            channel
                        },
                        "POSODOBITEV"
                    );

                    if (updateCode != 0 && !string.IsNullOrWhiteSpace(winget))
                    {
                        Log("Samoposodobitev ni uspela; poskušam prek winget.", "POSODOBITEV");

                        await RunSimpleToolAsync(
                            winget,
                            new string[]
                            {
                                "upgrade",
                                "--id",
                                "yt-dlp.yt-dlp",
                                "-e",
                                "--silent",
                                "--disable-interactivity",
                                "--accept-source-agreements",
                                "--accept-package-agreements"
                            },
                            "POSODOBITEV"
                        );
                    }
                }

                if (chkUpdateFfmpeg.Checked && !string.IsNullOrWhiteSpace(winget))
                {
                    string ffmpeg = ToolLocator.FindFfmpeg();
                    string operation = string.IsNullOrWhiteSpace(ffmpeg)
                        ? "install"
                        : "upgrade";

                    Log(operation == "install"
                        ? "Nameščam FFmpeg ..."
                        : "Posodabljam FFmpeg ...", "POSODOBITEV");

                    await RunSimpleToolAsync(
                        winget,
                        new string[]
                        {
                            operation,
                            "--id",
                            "yt-dlp.FFmpeg",
                            "-e",
                            "--silent",
                            "--disable-interactivity",
                            "--accept-source-agreements",
                            "--accept-package-agreements"
                        },
                        "POSODOBITEV"
                    );
                }

                ytDlp = ToolLocator.FindYtDlp();

                if (!string.IsNullOrWhiteSpace(ytDlp))
                {
                    List<string> extractors = new List<string>();

                    await RunProcessNoJobAsync(
                        ytDlp,
                        new string[]
                        {
                            "--plugin-dirs",
                            AppPaths.PluginFolder,
                            "--list-extractors"
                        },
                        delegate(string line)
                        {
                            if (!string.IsNullOrWhiteSpace(line))
                            {
                                lock (extractors)
                                {
                                    extractors.Add(line);
                                }
                            }
                        },
                        delegate(string line)
                        {
                            Log(line, "POSODOBITEV");
                        }
                    );

                    lock (extractors)
                    {
                        File.WriteAllLines(
                            AppPaths.ExtractorList,
                            extractors.ToArray(),
                            Encoding.UTF8
                        );
                    }

                    Log(
                        "Seznam izvlečevalnikov je osvežen. Število: " +
                        extractors.Count,
                        "POSODOBITEV"
                    );
                }

                RefreshToolStatus();
                Log("Posodobitev je končana.", "POSODOBITEV");
            }
            catch (Exception e)
            {
                ShowError("Posodobitev ni uspela.", e);
                Log(e.Message, "POSODOBITEV NAPAKA");
            }
            finally
            {
                updateRunning = false;
                btnUpdate.Enabled = true;
            }
        }

        private async Task<int> RunSimpleToolAsync(
            string executable,
            IEnumerable<string> arguments,
            string prefix
        )
        {
            return await RunProcessNoJobAsync(
                executable,
                arguments,
                delegate(string line)
                {
                    Log(line, prefix);
                },
                delegate(string line)
                {
                    Log(line, prefix);
                }
            );
        }

        private Task<int> RunProcessNoJobAsync(
            string executable,
            IEnumerable<string> arguments,
            Action<string> output,
            Action<string> error
        )
        {
            DownloadJob fake = new DownloadJob();
            return RunProcessAsync(
                fake,
                executable,
                arguments,
                output,
                error,
                CancellationToken.None
            );
        }

