        private void InstallPluginPackage()
        {
            using (OpenFileDialog dialog = new OpenFileDialog())
            {
                dialog.Title = "Izberi zaupanja vreden yt-dlp vtičnik";
                dialog.Multiselect = false;
                dialog.Filter =
                    "yt-dlp vtičniki|*.zip;*.whl;*.egg|" +
                    "Vse datoteke|*.*";

                if (dialog.ShowDialog(this) != DialogResult.OK)
                {
                    return;
                }

                DialogResult answer = MessageBox.Show(
                    this,
                    "Vtičniki yt-dlp vsebujejo programsko kodo in se samodejno naložijo pri vsakem prenosu.\r\n\r\n" +
                    "Namesti samo datoteko iz vira, ki mu zaupaš.\r\n\r\n" +
                    "Želiš nadaljevati?",
                    "Varnostno opozorilo",
                    MessageBoxButtons.YesNo,
                    MessageBoxIcon.Warning
                );

                if (answer != DialogResult.Yes)
                {
                    return;
                }

                try
                {
                    AppPaths.Ensure();

                    string fileName = Path.GetFileName(dialog.FileName);
                    string destination = Path.Combine(
                        AppPaths.PluginFolder,
                        fileName
                    );

                    if (File.Exists(destination))
                    {
                        string baseName = Path.GetFileNameWithoutExtension(fileName);
                        string extension = Path.GetExtension(fileName);
                        destination = Path.Combine(
                            AppPaths.PluginFolder,
                            baseName + " - " +
                            DateTime.Now.ToString("yyyyMMdd_HHmmss") +
                            extension
                        );
                    }

                    File.Copy(dialog.FileName, destination, false);

                    Log(
                        "Vtičnik je kopiran v: " + destination,
                        "VTIČNIK"
                    );
                    Log(
                        "Klikni »Namesti/posodobi orodja in seznam«, da preveriš, ali ga yt-dlp naloži.",
                        "VTIČNIK"
                    );

                    MessageBox.Show(
                        this,
                        "Vtičnik je nameščen.\r\n\r\n" +
                        "Zdaj osveži seznam izvlečevalnikov. Če je paket pravilno izdelan in podpira tvoj URL, ga bo yt-dlp samodejno uporabil.",
                        "Vtičnik nameščen",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information
                    );
                }
                catch (Exception exception)
                {
                    ShowError("Vtičnika ni bilo mogoče namestiti.", exception);
                }
            }
        }

        private void OpenPluginFolder()
        {
            try
            {
                AppPaths.Ensure();
                Process.Start(
                    "explorer.exe",
