                );
            }
            catch (Exception exception)
            {
                ShowError("Mape vtičnikov ni bilo mogoče odpreti.", exception);
            }
        }

        private bool IsVoyoUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
            {
                return false;
            }

            try
            {
                Uri uri = new Uri(url);
                string host = uri.Host.ToLowerInvariant();

                return
                    host == "voyo.si" ||
                    host.EndsWith(
                        ".voyo.si",
                        StringComparison.OrdinalIgnoreCase
                    );
            }
            catch
            {
                return false;
            }
        }

