        private void OpenSupportedSiteUrl(
            string url
        )
        {
            if (
                string.IsNullOrWhiteSpace(
                    url
                )
            )
            {
                return;
            }

            try
            {
                Process.Start(url);
            }
            catch (Exception e)
            {
                ShowError(
                    "Spletne strani ni bilo mogoče odpreti.",
                    e
                );
            }
        }

        private string GetSupportedSiteSupportText(
            string extractorKey,
            string description
        )
        {
            string key =
                (extractorKey ?? "")
                .Split(':')[0]
                .Trim();

            string details =
                (description ?? "")
                .ToLowerInvariant();

            if (
                string.Equals(
                    key,
                    "generic",
                    StringComparison.OrdinalIgnoreCase
                )
            )
            {
                return
                    "Generični poskus – prenos ni zagotovljen. Program ne obide prijave, naročnine ali DRM.";
            }

            bool authenticationLikely =
                details.IndexOf("login") >= 0 ||
                details.IndexOf("authentication") >= 0 ||
                details.IndexOf("account") >= 0 ||
                details.IndexOf("premium") >= 0 ||
                details.IndexOf("subscription") >= 0 ||
                details.IndexOf("cookies") >= 0 ||
                details.IndexOf("netrc") >= 0;

            string[] fullySupported =
                new string[]
                {
                    "youtube",
                    "facebook",
                    "twitter",
                    "instagram",
                    "tiktok",
                    "vimeo",
                    "dailymotion",
                    "reddit",
                    "twitch",
                    "soundcloud",
                    "bandcamp",
                    "magellantv"
                };

            if (
                fullySupported.Contains(
                    key,
                    StringComparer.OrdinalIgnoreCase
                )
            )
            {
                return authenticationLikely
                    ? "Polno podprto z namenskim izvlečevalnikom; prijava ali piškotki so lahko potrebni. Brez obhoda naročnine ali DRM."
                    : "Polno podprto z namenskim izvlečevalnikom yt-dlp.";
            }

            return authenticationLikely
                ? "Podprto z namenskim izvlečevalnikom; prijava ali piškotki so lahko potrebni. Brez obhoda naročnine ali DRM."
                : "Podprto z namenskim izvlečevalnikom yt-dlp.";
        }

        private Task<List<SupportedSiteEntry>>
            LoadSupportedSitesCatalogAsync()
        {
            return Task.Run(
                delegate
                {
                    Dictionary<string, SupportedSiteMetadata> metadata =
                        LoadOfficialSupportedSitesMetadata();

                    List<string> extractorLines =
                        LoadYtDlpExtractorLines();

                    Dictionary<string, string> knownUrls =
                        BuildKnownSupportedSiteUrls();

                    List<SupportedSiteEntry> result =
                        new List<SupportedSiteEntry>();

                    foreach (
                        string rawLine
                        in extractorLines
                    )
                    {
                        string line =
                            (rawLine ?? "")
                            .Trim();

                        if (
                            line.Length == 0 ||
                            line.IndexOf(
                                "CURRENTLY BROKEN",
                                StringComparison.OrdinalIgnoreCase
                            ) >= 0 ||
                            line.IndexOf(
                                "Currently broken",
                                StringComparison.OrdinalIgnoreCase
                            ) >= 0
                        )
                        {
                            continue;
                        }

                        string extractorKey =
                            GetExtractorKeyFromLine(
                                line
                            );

                        if (
                            string.IsNullOrWhiteSpace(
                                extractorKey
                            ) ||
                            string.Equals(
                                extractorKey,
                                "generic",
                                StringComparison.OrdinalIgnoreCase
                            )
                        )
                        {
                            continue;
                        }

                        SupportedSiteMetadata itemMetadata = null;

                        if (
                            metadata.ContainsKey(
                                extractorKey
                            )
                        )
                        {
                            itemMetadata =
                                metadata[extractorKey];
                        }
                        else
                        {
                            string baseKey =
                                extractorKey.Split(
                                    ':'
                                )[0];

                            if (
                                metadata.ContainsKey(
                                    baseKey
                                )
                            )
                            {
                                itemMetadata =
                                    metadata[baseKey];
                            }
                        }

                        if (
                            itemMetadata != null &&
                            itemMetadata.Broken
                        )
                        {
                            continue;
                        }

                        string description =
                            itemMetadata == null
                                ? ""
                                : itemMetadata.Description;

                        bool searchFallback;
                        string url =
                            ResolveSupportedSiteUrl(
                                extractorKey,
                                line,
                                description,
                                knownUrls,
                                out searchFallback
                            );

                        if (
                            string.IsNullOrWhiteSpace(
                                url
                            )
                        )
                        {
                            continue;
                        }

                        string name =
                            GetSupportedSiteDisplayName(
                                extractorKey,
                                description,
                                url
                            );

                        string support =
                            GetSupportedSiteSupportText(
                                extractorKey,
                                description
                            );

                        result.Add(
                            new SupportedSiteEntry(
                                name,
                                url,
                                extractorKey,
                                support,
                                description,
                                searchFallback
                            )
                        );
                    }

                    AddManualRecognizedSites(
                        result
                    );

                    return result
                        .GroupBy(
                            delegate(
                                SupportedSiteEntry entry
                            )
                            {
                                return entry.Url;
                            },
                            StringComparer.OrdinalIgnoreCase
                        )
                        .Select(
                            delegate(
                                IGrouping<
                                    string,
                                    SupportedSiteEntry
                                > group
                            )
                            {
                                return group.First();
                            }
                        )
                        .OrderBy(
                            delegate(
                                SupportedSiteEntry entry
                            )
                            {
                                return entry.Name;
                            },
                            StringComparer.OrdinalIgnoreCase
                        )
                        .ToList();
                }
            );
        }

        private List<string> LoadYtDlpExtractorLines()
        {
            string ytDlp =
                ToolLocator.FindYtDlp();

            if (
                string.IsNullOrWhiteSpace(
                    ytDlp
                ) ||
                !File.Exists(ytDlp)
            )
            {
                throw new InvalidOperationException(
                    "yt-dlp ni nameščen. Odpri »Orodja in nastavitve« in namesti orodja."
                );
            }

            ProcessStartInfo info =
                new ProcessStartInfo();
            info.FileName =
                ytDlp;
            info.Arguments =
                "--list-extractors";
            info.UseShellExecute = false;
            ToolLocator.ConfigureUtf8Process(info);
            info.CreateNoWindow = true;
            info.WindowStyle =
                ProcessWindowStyle.Hidden;
            info.RedirectStandardOutput = true;
            info.RedirectStandardError = true;
            info.StandardOutputEncoding =
                Encoding.UTF8;
            info.StandardErrorEncoding =
                Encoding.UTF8;

            using (
                Process process =
                    Process.Start(info)
            )
            {
                if (process == null)
                {
                    throw new InvalidOperationException(
                        "yt-dlp se ni zagnal."
                    );
                }

                string output =
                    process.StandardOutput.ReadToEnd();
                string error =
                    process.StandardError.ReadToEnd();

                process.WaitForExit();

                if (
                    process.ExitCode != 0
                )
                {
                    throw new InvalidOperationException(
                        string.IsNullOrWhiteSpace(
                            error
                        )
                            ? "yt-dlp je vrnil napako."
                            : error.Trim()
                    );
                }

                return output
                    .Replace(
                        "\r\n",
                        "\n"
                    )
                    .Split(
                        new char[]
                        {
                            '\n'
                        },
                        StringSplitOptions.RemoveEmptyEntries
                    )
                    .Select(
                        delegate(
                            string value
                        )
                        {
                            return value.Trim();
                        }
                    )
                    .Where(
                        delegate(
                            string value
                        )
                        {
                            return
                                value.Length > 0 &&
                                value.IndexOf(
                                    "CURRENTLY BROKEN",
                                    StringComparison.OrdinalIgnoreCase
                                ) < 0;
                        }
                    )
                    .ToList();
            }
        }

        private Dictionary<string, SupportedSiteMetadata>
            LoadOfficialSupportedSitesMetadata()
        {
            Dictionary<string, SupportedSiteMetadata> result =
                new Dictionary<string, SupportedSiteMetadata>(
                    StringComparer.OrdinalIgnoreCase
                );

            try
            {
                ServicePointManager.SecurityProtocol =
                    ServicePointManager.SecurityProtocol |
                    (SecurityProtocolType)3072;

                using (
                    WebClient client =
                        new WebClient()
                )
                {
                    client.Encoding =
                        Encoding.UTF8;
                    client.Headers[
                        HttpRequestHeader.UserAgent
                    ] =
                        "VideoDownloader/9.3";

                    string markdown =
                        client.DownloadString(
                            "https://raw.githubusercontent.com/yt-dlp/yt-dlp/master/supportedsites.md"
                        );

                    string[] lines =
                        markdown.Replace(
                            "\r\n",
                            "\n"
                        )
                        .Split('\n');

                    foreach (
                        string rawLine in lines
                    )
                    {
                        Match match =
                            Regex.Match(
                                rawLine,
                                @"^\s*-\s+\*\*(?<key>.+?)\*\*(?:\s*:\s*(?<description>.*))?\s*$"
                            );

                        if (!match.Success)
                        {
                            continue;
                        }

                        string key =
                            match.Groups["key"]
                            .Value
                            .Replace(
                                "\u200b",
                                ""
                            )
                            .Trim();

                        string description =
                            CleanSupportedSitesMarkdown(
                                match.Groups[
                                    "description"
                                ].Value
                            );

                        bool broken =
                            rawLine.IndexOf(
                                "Currently broken",
                                StringComparison.OrdinalIgnoreCase
                            ) >= 0 ||
                            rawLine.IndexOf(
                                "CURRENTLY BROKEN",
                                StringComparison.OrdinalIgnoreCase
                            ) >= 0;

                        if (
                            key.Length > 0 &&
                            !result.ContainsKey(
                                key
                            )
                        )
                        {
                            result.Add(
                                key,
                                new SupportedSiteMetadata(
                                    key,
                                    description,
                                    broken
                                )
                            );
                        }
                    }
                }
            }
            catch
            {
                // Brez interneta še vedno uporabimo izhod lokalnega yt-dlp.
            }

            return result;
        }

        private string CleanSupportedSitesMarkdown(
            string value
        )
        {
            string cleaned =
                value ?? "";

            cleaned =
                Regex.Replace(
                    cleaned,
                    @"\[\*(?<text>.*?)\*\]\([^)]+\)",
                    "${text}"
                );

            cleaned =
                cleaned.Replace(
                    "**",
                    ""
                )
                .Replace(
                    "*",
                    ""
                )
                .Replace(
                    "`",
                    ""
                )
                .Replace(
                    "(Currently broken)",
                    ""
                )
                .Replace(
                    "(CURRENTLY BROKEN)",
                    ""
                )
                .Trim();

            return cleaned;
        }

        private string GetExtractorKeyFromLine(
            string line
        )
        {
            Match match =
                Regex.Match(
                    line ?? "",
                    @"^\s*(?<key>[^\s]+)"
                );

            return match.Success
                ? match.Groups["key"].Value.Trim()
                : "";
        }

