        private string ResolveSupportedSiteUrl(
            string extractorKey,
            string extractorLine,
            string description,
            Dictionary<string, string> knownUrls,
            out bool searchFallback
        )
        {
            searchFallback = false;

            string baseKey =
                (extractorKey ?? "")
                .Split(':')[0]
                .Trim();

            string known;

            if (
                knownUrls.TryGetValue(
                    extractorKey,
                    out known
                ) ||
                knownUrls.TryGetValue(
                    baseKey,
                    out known
                )
            )
            {
                return known;
            }

            string combined =
                (description ?? "") +
                " " +
                (extractorLine ?? "");

            Match domainMatch =
                Regex.Match(
                    combined,
                    @"(?i)(?<![@\w])(?:https?://)?(?:www\.)?(?<domain>[a-z0-9][a-z0-9\-]*(?:\.[a-z0-9\-]+)+)"
                );

            if (domainMatch.Success)
            {
                string domain =
                    domainMatch.Groups[
                        "domain"
                    ].Value
                    .TrimEnd(
                        '.',
                        ',',
                        ';',
                        ':'
                    );

                if (
                    domain.IndexOf(
                        "github.com",
                        StringComparison.OrdinalIgnoreCase
                    ) < 0 &&
                    domain.IndexOf(
                        "machine",
                        StringComparison.OrdinalIgnoreCase
                    ) < 0
                )
                {
                    return
                        "https://" +
                        domain;
                }
            }

            if (
                baseKey.IndexOf('.') > 0 &&
                Regex.IsMatch(
                    baseKey,
                    @"^[a-z0-9][a-z0-9\-]*(?:\.[a-z0-9\-]+)+$",
                    RegexOptions.IgnoreCase
                )
            )
            {
                return
                    "https://" +
                    baseKey;
            }

            searchFallback = false;
            return "";
        }

        private string GetSupportedSiteDisplayName(
            string extractorKey,
            string description,
            string url
        )
        {
            string baseKey =
                (extractorKey ?? "")
                .Split(':')[0]
                .Trim();

            Dictionary<string, string> names =
                new Dictionary<string, string>(
                    StringComparer.OrdinalIgnoreCase
                );

            names["youtube"] =
                "YouTube";
            names["facebook"] =
                "Facebook";
            names["twitter"] =
                "X / Twitter";
            names["instagram"] =
                "Instagram";
            names["tiktok"] =
                "TikTok";
            names["vimeo"] =
                "Vimeo";
            names["dailymotion"] =
                "Dailymotion";
            names["reddit"] =
                "Reddit";
            names["twitch"] =
                "Twitch";
            names["soundcloud"] =
                "SoundCloud";
            names["bandcamp"] =
                "Bandcamp";
            names["magellantv"] =
                "MagellanTV";
            names["lbry"] =
                "Odysee";
            names["niconico"] =
                "Niconico";

            string friendly;

            if (
                names.TryGetValue(
                    baseKey,
                    out friendly
                )
            )
            {
                return friendly;
            }

            if (
                !string.IsNullOrWhiteSpace(
                    description
                ) &&
                description.Length <= 65 &&
                description.IndexOf(
                    "netrc",
                    StringComparison.OrdinalIgnoreCase
                ) < 0
            )
            {
                return description;
            }

            try
            {
                Uri uri =
                    new Uri(url);

                if (
                    !uri.Host.EndsWith(
                        "google.com",
                        StringComparison.OrdinalIgnoreCase
                    )
                )
                {
                    return
                        uri.Host.StartsWith(
                            "www.",
                            StringComparison.OrdinalIgnoreCase
                        )
                            ? uri.Host.Substring(4)
                            : uri.Host;
                }
            }
            catch
            {
            }

            return baseKey.Length > 0
                ? baseKey
                : extractorKey;
        }

