            AddManualRecognizedSite(
                result,
                "HQPorn",
                "https://hqporn.xxx",
                "generic",
                "Samo generični poskus za javni nezaščiten video; brez garancije."
            );

            AddManualRecognizedSite(
                result,
                "ATK Hairy",
                "https://www.atkhairy.com",
                "generic",
                "Samo generični poskus; program ne obide prijave, naročnine ali DRM."
            );
        }

        private void AddManualRecognizedSite(
            List<SupportedSiteEntry> result,
            string name,
            string url,
            string extractor,
            string support
        )
        {
            bool exists =
                result.Any(
                    delegate(
                        SupportedSiteEntry entry
                    )
                    {
                        return
                            string.Equals(
                                entry.Url,
                                url,
                                StringComparison.OrdinalIgnoreCase
                            ) ||
                            string.Equals(
                                entry.Name,
                                name,
                                StringComparison.OrdinalIgnoreCase
                            );
                    }
                );

            if (exists)
            {
                return;
            }

            result.Add(
                new SupportedSiteEntry(
                    name,
                    url,
                    extractor,
                    support,
                    "",
                    false
                )
            );
        }

        private List<SupportedSiteEntry>
            CreateFallbackSupportedSites()
        {
            List<SupportedSiteEntry> result =
                new List<SupportedSiteEntry>();

            AddManualRecognizedSites(
                result
            );

            string[,] sites =
                new string[,]
                {
                    {
                        "YouTube",
                        "https://www.youtube.com",
                        "youtube"
                    },
                    {
                        "Facebook",
                        "https://www.facebook.com",
                        "facebook"
                    },
                    {
                        "X / Twitter",
                        "https://x.com",
                        "twitter"
                    },
                    {
                        "Instagram",
                        "https://www.instagram.com",
                        "instagram"
                    },
                    {
                        "TikTok",
                        "https://www.tiktok.com",
                        "tiktok"
                    },
                    {
                        "Vimeo",
                        "https://vimeo.com",
                        "vimeo"
                    },
                    {
                        "Dailymotion",
                        "https://www.dailymotion.com",
                        "dailymotion"
                    },
                    {
                        "Reddit",
                        "https://www.reddit.com",
                        "reddit"
                    },
                    {
                        "Twitch",
                        "https://www.twitch.tv",
                        "twitch"
                    },
                    {
                        "SoundCloud",
                        "https://soundcloud.com",
                        "soundcloud"
                    },
                    {
                        "Bandcamp",
                        "https://bandcamp.com",
                        "bandcamp"
                    }
                };

            for (
                int index = 0;
                index < sites.GetLength(0);
                index++
            )
            {
                AddManualRecognizedSite(
                    result,
                    sites[index, 0],
                    sites[index, 1],
                    sites[index, 2],
                    "Pogosta stran, ki jo običajno podpira yt-dlp."
                );
            }

            return result
                .OrderBy(
                    delegate(
                        SupportedSiteEntry entry
                    )
                    {
                        return entry.Name;
                    },
                    StringComparer.OrdinalIgnoreCase
                )
                .ToList();
        }

        private void OpenExtractorList()
        {
            try
            {
                if (!File.Exists(AppPaths.ExtractorList))
                {
                    MessageBox.Show(
                        this,
                        "Seznam še ne obstaja. Najprej klikni »Namesti/posodobi orodja in seznam«.",
                        "Ni seznama",
                        MessageBoxButtons.OK,
                        MessageBoxIcon.Information
                    );
                    return;
                }

                Process.Start("notepad.exe", ToolLocator.Quote(AppPaths.ExtractorList));
            }
            catch (Exception e)
            {
                ShowError("Seznama ni bilo mogoče odpreti.", e);
            }
        }

        private void ShowError(string message, Exception exception)
        {
            ErrorLogger.Write(message, exception);
            MessageBox.Show(
                this,
                message + Environment.NewLine + Environment.NewLine +
                exception.Message,
                "Video Downloader",
                MessageBoxButtons.OK,
                MessageBoxIcon.Error
            );
        }

        private void OnFormClosing(object sender, FormClosingEventArgs e)
        {
            StopEditorPreview(
                false
            );

            if (
                editorPreviewPicture != null &&
                editorPreviewPicture.Image != null
            )
            {
                try
                {
                    editorPreviewPicture.Image.Dispose();
                }
                catch
                {
                }
            }

            SaveCurrentSettings();

            List<DownloadJob> active;

            lock (queueLock)
            {
                active = activeJobs.Values.ToList();
            }

            if (active.Count == 0)
            {
                return;
            }

            DialogResult result = MessageBox.Show(
                this,
                "Aktivnih je še " + active.Count +
                " opravil. Ali jih želiš preklicati in zapreti program?",
                "Aktivni prenosi",
                MessageBoxButtons.YesNo,
                MessageBoxIcon.Question
            );

            if (result != DialogResult.Yes)
            {
                e.Cancel = true;
                return;
            }

            foreach (DownloadJob job in active)
            {
                try
                {
                    job.Cancellation.Cancel();
                    if (job.CurrentProcess != null && !job.CurrentProcess.HasExited)
                    {
                        KillProcessTree(job.CurrentProcess.Id);
                    }
                }
                catch
                {
                }
            }
        }
    }
}
